// ─── SUPABASE CLIENT ──────────────────────────────────────────────────────────
const SUPABASE_URL = "https://lmixuubgislgultzjeqs.supabase.co";
const SUPABASE_ANON_KEY = "sb_publishable_-QR4-pdtY3lvjUaNyYsKew_r-2fY5Rd";
const SUPA_HEADERS = {
  "Content-Type": "application/json",
  "apikey": SUPABASE_ANON_KEY,
  "Authorization": `Bearer ${SUPABASE_ANON_KEY}`,
  "Prefer": "return=minimal"
};

// Only use Supabase on production (Netlify). Localhost uses localStorage only.
// This keeps your local test data completely separate from the live database.
const IS_PROD = typeof window !== "undefined" &&
  !window.location.hostname.includes("localhost") &&
  !window.location.hostname.includes("127.0.0.1");

// Read a key from Supabase
async function supaGet(key) {
  if (!IS_PROD) return null; // localhost: skip Supabase
  try {
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/structo_store?key=eq.${encodeURIComponent(key)}&select=value`,
      { headers: { ...SUPA_HEADERS, "Prefer": "" } }
    );
    if (!res.ok) return null;
    const rows = await res.json();
    return rows.length > 0 ? rows[0].value : null;
  } catch(e) { console.warn("supaGet error:", e); return null; }
}

// Write a key to Supabase (upsert)
async function supaSet(key, value) {
  if (!IS_PROD) return; // localhost: skip Supabase, localStorage already written
  try {
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/structo_store`,
      {
        method: "POST",
        headers: { ...SUPA_HEADERS, "Prefer": "resolution=merge-duplicates" },
        body: JSON.stringify({ key, value, updated_at: new Date().toISOString() })
      }
    );
    if (!res.ok) {
      const txt = await res.text();
      console.warn("supaSet error:", res.status, txt);
    }
  } catch(e) { console.warn("supaSet error:", e); }
}

// Load all keys at once (one round trip)
async function supaLoadAll(keys) {
  if (!IS_PROD) return {}; // localhost: skip Supabase, use localStorage
  try {
    const keysParam = `(${keys.map(k=>`"${k}"`).join(",")})`;
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/structo_store?key=in.${encodeURIComponent(keysParam)}&select=key,value`,
      { headers: { ...SUPA_HEADERS, "Prefer": "" } }
    );
    if (!res.ok) throw new Error(`Supabase load failed: HTTP ${res.status}`);
    const rows = await res.json();
    // A completely empty store on a database that should have data is far more
    // likely an outage/permissions problem than a genuinely blank system — refuse
    // to hydrate (and later overwrite) from it if a local cache disagrees.
    if (rows.length === 0) {
      const localOrders = JSON.parse(localStorage.getItem("structo_orders")||"[]");
      if (Array.isArray(localOrders) && localOrders.length > 0)
        throw new Error("Supabase returned an empty store but local cache has data — refusing to wipe");
    }
    const out = {};
    rows.forEach(r => { out[r.key] = r.value; });
    return out;
  } catch(e) { console.warn("supaLoadAll error:", e); throw e; }
}


