const _msalConfig = {
  auth: {
    clientId: "b20e88f1-2bfe-4e1c-8736-b261c60d294b",
    authority: "https://starsoftonline.b2clogin.com/31af8a23-e5e2-4659-ab1b-2a5d527ed211/b2c_1_sign",
    knownAuthorities: ["starsoftonline.b2clogin.com"],
    redirectUri: "http://localhost:5173",
    postLogoutRedirectUri: "http://localhost:5173",
  },
  cache: { cacheLocation: "sessionStorage", storeAuthStateInCookie: false }
};
const _nestingScopes = ["https://starsoftonline.onmicrosoft.com/81588f52-db64-40bd-8096-e75159abdd9a/NestingCenter"];
let _msalInstance = null;
let _msalRedirectResult = null;
let _msalRedirectHandled = false;

async function _getMsalInstance() {
  if (!_msalInstance) {
    _msalInstance = new msal.PublicClientApplication(_msalConfig);
    await _msalInstance.initialize();
  }
  return _msalInstance;
}

// Runs once on page load — processes any redirect return from B2C login.
// Clears the #state= hash that MSAL leaves in the URL.
(async () => {
  try {
    const inst = await _getMsalInstance();
    const result = await inst.handleRedirectPromise();
    if (result) {
      _msalRedirectResult = result;
      // Clean up MSAL's #state= hash from the URL bar
      if (window.location.hash) {
        window.history.replaceState({}, document.title, window.location.pathname + window.location.search);
      }
    }
  } catch(e) {
    console.warn("MSAL handleRedirectPromise error:", e);
  } finally {
    _msalRedirectHandled = true;
  }
})();

async function _awaitRedirectHandled() {
  if (_msalRedirectHandled) return;
  await new Promise(resolve => {
    const t = setInterval(() => { if (_msalRedirectHandled) { clearInterval(t); resolve(); } }, 50);
  });
}

// Returns access token via silent flow only. No popup ever.
// If silent fails → initiates redirect and throws {isMsalRedirect:true} so the
// caller can show "Redirecting…" and let the page navigate away.
async function getNestingToken() {
  await _awaitRedirectHandled();

  // Consume token from a completed redirect login
  if (_msalRedirectResult) {
    const token = _msalRedirectResult.accessToken;
    _msalRedirectResult = null;
    return token;
  }

  const inst = await _getMsalInstance();
  const accounts = inst.getAllAccounts();
  if (accounts.length > 0) {
    try {
      const r = await inst.acquireTokenSilent({ scopes: _nestingScopes, account: accounts[0] });
      return r.accessToken;
    } catch (_) { /* session expired — fall through to redirect */ }
  }

  // No popup. Initiate redirect — page will navigate away to B2C login.
  inst.acquireTokenRedirect({ scopes: _nestingScopes }).catch(e =>
    console.error("MSAL acquireTokenRedirect error:", e)
  );
  // Throw so the caller can show a "Redirecting…" message and stop processing
  const err = new Error("Nesting Center login required. Redirecting to login page…");
  err.msalErrorCode = "redirect_initiated";
  err.isMsalRedirect = true;
  throw err;
}

// Called from UI "Login with Nesting Center" button (explicit login before run)
async function initiateNestingRedirect() {
  const inst = await _getMsalInstance();
  await inst.acquireTokenRedirect({ scopes: _nestingScopes });
}

// True if a redirect login just completed (user was sent back from B2C)
function nestingJustLoggedIn() {
  return !!_msalRedirectResult;
}

// ─── NESTING CENTER — API SERVICE ─────────────────────────────────────────────
// In dev: Vite proxy forwards /nesting-api → https://api-nesting.nestingcenter.com/nesting
// (avoids CORS — browser talks to localhost, Vite relays server-side)
const NESTING_BASE = "/nesting-api";

async function _nestFetch(token, path, method = "GET", body = null) {
  const opts = {
    method,
    headers: { "Authorization": `Bearer ${token}`, "Content-Type": "application/json" }
  };
  if (body) opts.body = JSON.stringify(body);
  const res = await fetch(`${NESTING_BASE}${path}`, opts);
  if (!res.ok) {
    const txt = await res.text().catch(() => "");
    throw new Error(`Nesting API ${method} ${path} → ${res.status}: ${txt}`);
  }
  if (method === "DELETE") return null;
  return res.json();
}

async function nestingStart(token, inputJson) {
  const data = await _nestFetch(token, "/start", "POST", inputJson);
  return data.JobId;
}

async function nestingPoll(token, jobId) {
  return _nestFetch(token, `/${jobId}`);
}

async function nestingResult(token, jobId, version) {
  return _nestFetch(token, `/${jobId}/result/${version}`);
}

async function nestingDelete(token, jobId) {
  await _nestFetch(token, `/${jobId}`, "DELETE").catch(() => {});
}

// Orchestrator: start → poll 5s → get result → delete → return result
// onProgress(pct 0-100, message)
async function runNestingJob(inputJson, onProgress, getToken) {
  let token = await getToken();
  const jobId = await nestingStart(token, inputJson);
  onProgress(5, `Job ${jobId} started…`);
  const pollStart = Date.now();

  while (true) {
    await new Promise(r => setTimeout(r, 5000));
    let status;
    try {
      token = await getToken(); // re-auth silently; if expired shows "logging in again"
      status = await nestingPoll(token, jobId);
    } catch (e) {
      throw Object.assign(e, { jobId });
    }
    const elapsed = ((Date.now() - pollStart) / 1000).toFixed(1);
    const pct = Math.min(90, 5 + Math.floor(elapsed / 0.2));
    onProgress(pct, `Polling ${jobId} — ${elapsed}s`);

    if (status.StateString === "Stopped") {
      onProgress(95, "Fetching result…");
      // Use latest ResultVersion (highest integer in status.Results array or fallback 1)
      let latestVersion = 1;
      if (Array.isArray(status.Results) && status.Results.length > 0) {
        latestVersion = Math.max(...status.Results.map(r => r.ResultVersion || 0));
      }
      const result = await nestingResult(token, jobId, latestVersion);
      await nestingDelete(token, jobId);
      onProgress(100, "Complete");
      return result;
    }
  }
}

// ─── NESTING CENTER — DXF FETCH HELPER ────────────────────────────────────────
// Tries to fetch a DXF file URL and return base64 string, or null on failure.
// Handles Google Drive share links by converting to direct download URL.
// Transform a share link into a direct-download URL where a known pattern exists.
// OneDrive personal: shares-API form (CORS-enabled endpoint). SharePoint/OneDrive
// for Business: ?download=1 (usually still CORS-blocked in browser — proxy handles it).
function directDownloadUrl(url) {
  const driveMatch = url.match(/\/d\/([a-zA-Z0-9_-]+)\//);
  if (driveMatch) return `https://drive.google.com/uc?export=download&id=${driveMatch[1]}`;
  if (/1drv\.ms|onedrive\.live\.com/i.test(url)) {
    const enc = btoa(url).replace(/=+$/,"").replace(/\//g,"_").replace(/\+/g,"-");
    return `https://api.onedrive.com/v1.0/shares/u!${enc}/root/content`;
  }
  if (/sharepoint\.com/i.test(url)) {
    return url + (url.includes("?") ? "&" : "?") + "download=1";
  }
  return url;
}
function looksLikeDxf(bytes) {
  // DXF files are text starting with group codes ("0\r\nSECTION" typically).
  // An HTML error/viewer page starts with "<" — reject those instead of
  // silently feeding HTML to the nesting engine.
  const head = String.fromCharCode(...bytes.slice(0, 200)).trim().toUpperCase();
  return !head.startsWith("<") && (head.includes("SECTION") || head.includes("HEADER") || /^\d/.test(head));
}
async function fetchDxfBase64(url) {
  if (!url) return null;
  const target = directDownloadUrl(url);
  const attempts = [target, `/dxf-proxy?url=${encodeURIComponent(target)}`];
  for (const fetchUrl of attempts) {
    try {
      const res = await fetch(fetchUrl, { mode: "cors" });
      if (!res.ok) continue;
      const buf = await res.arrayBuffer();
      const bytes = new Uint8Array(buf);
      if (!bytes.length || !looksLikeDxf(bytes)) continue;
      let binary = "";
      for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
      return btoa(binary);
    } catch (_) { /* try next */ }
  }
  return null;
}

// ─── DXF → API CONTOURS ──────────────────────────────────────────────────────
// The nesting API takes explicit geometry (Contours: vertices + arc bulges — the
// DXF bulge convention exactly), NOT DXF files. This converts a fetched DXF's
// closed LWPOLYLINEs and CIRCLEs into that format. Exploded line/arc DXFs are
// rejected with a reason — re-export the profile as a joined closed polyline.
function b64ToText(b64) {
  try { return atob(b64); }
  catch(_) { return null; }
}
function dxfToContours(dxfText) {
  if (!dxfText) return { error: "empty file" };
  const lines = dxfText.split(/\r\n|\r|\n/);
  const pairs = [];
  for (let i=0; i+1<lines.length; i+=2) pairs.push([lines[i].trim(), lines[i+1]]);
  let inEntities = false;
  const contoursRaw = [];
  let cur = null; const unsupported = new Set();
  for (let i=0; i<pairs.length; i++) {
    const code = pairs[i][0]; const val = (pairs[i][1]||"").trim();
    if (code==="2" && val==="ENTITIES") { inEntities = true; continue; }
    if (inEntities && code==="0" && val==="ENDSEC") break;
    if (!inEntities) continue;
    if (code==="0") {
      // R12-style POLYLINE owns its following VERTEX entities until SEQEND
      if (cur && cur.kind==="plv" && val==="VERTEX") { cur.inVertex = true; cur.verts.push({ X:0, Y:0, B:0 }); continue; }
      if (cur && cur.kind==="plv" && val==="SEQEND") { contoursRaw.push(cur); cur = null; continue; }
      if (cur) { contoursRaw.push(cur); cur = null; }
      if (val==="LWPOLYLINE") cur = { kind:"pl", verts:[], closed:false };
      else if (val==="POLYLINE") cur = { kind:"plv", verts:[], closed:false, inVertex:false };
      else if (val==="CIRCLE") cur = { kind:"circle", cx:0, cy:0, r:0 };
      else if (["LINE","ARC","SPLINE","ELLIPSE"].includes(val)) unsupported.add(val);
      continue;
    }
    if (!cur) continue;
    if (cur.kind==="pl") {
      if (code==="70") cur.closed = ((parseInt(val)||0) & 1) === 1;
      else if (code==="10") cur.verts.push({ X:+val, Y:0, B:0 });
      else if (code==="20" && cur.verts.length) cur.verts[cur.verts.length-1].Y = +val;
      else if (code==="42" && cur.verts.length) cur.verts[cur.verts.length-1].B = +val;
    } else if (cur.kind==="plv") {
      if (!cur.inVertex) {
        // POLYLINE header: closed flag lives here; its 10/20/30 dummy point is ignored
        if (code==="70") cur.closed = ((parseInt(val)||0) & 1) === 1;
      } else if (cur.verts.length) {
        const v = cur.verts[cur.verts.length-1];
        if (code==="10") v.X = +val;
        else if (code==="20") v.Y = +val;
        else if (code==="42") v.B = +val;
      }
    } else if (cur.kind==="circle") {
      if (code==="10") cur.cx=+val; else if (code==="20") cur.cy=+val; else if (code==="40") cur.r=+val;
    }
  }
  if (cur) contoursRaw.push(cur);
  const contours = [];
  contoursRaw.forEach(c => {
    if (c.kind==="circle" && c.r>0) {
      // CW by default (bulge -1) — matches the API docs' hole example; the
      // orientation pass below flips it if the circle turns out to be the outer.
      contours.push({ Vertices: [ { X:c.cx-c.r, Y:c.cy, B:-1 }, { X:c.cx+c.r, Y:c.cy, B:-1 } ] });
    } else if (c.kind==="pl" || c.kind==="plv") {
      let v = c.verts;
      if (!c.closed && v.length>2) {
        const f=v[0], l=v[v.length-1];
        if (Math.abs(f.X-l.X)<0.01 && Math.abs(f.Y-l.Y)<0.01) v = v.slice(0,-1);
        else return; // open polyline — skip
      }
      if (v.length>=3 || (v.length===2 && (v[0].B||v[1].B))) contours.push({ Vertices: v.map(p=>({ X:p.X, Y:p.Y, ...(p.B?{B:p.B}:{}) })) });
    }
  });
  if (!contours.length) {
    const why = unsupported.size ? `only ${[...unsupported].join("/")} entities found — re-export as a closed polyline profile` : "no closed polylines or circles found";
    return { error: why };
  }
  // Orientation + ordering: largest |area| = outer contour (must be CCW for parts),
  // remaining = holes (must be CW). Reversing a contour negates and shifts bulges.
  const signedArea = (vs) => { let a=0; for (let i=0;i<vs.length;i++){ const p=vs[i], q=vs[(i+1)%vs.length]; a += p.X*q.Y - q.X*p.Y; } return a/2; };
  const reverseContour = (vs) => {
    const n = vs.length;
    const out = [];
    for (let i=0;i<n;i++) out.push({ X: vs[n-1-i].X, Y: vs[n-1-i].Y });
    for (let i=0;i<n;i++) { const b = vs[(2*n-2-i)%n].B; if (b) out[i].B = -b; }
    return out;
  };
  const withArea = contours.map(c=>{
    let area = signedArea(c.Vertices);
    if (area===0 && c.Vertices.length===2 && c.Vertices[0].B) {
      const dx=c.Vertices[1].X-c.Vertices[0].X, dy=c.Vertices[1].Y-c.Vertices[0].Y;
      const r=Math.sqrt(dx*dx+dy*dy)/2;
      area = Math.PI*r*r*((c.Vertices[0].B>0)?1:-1);   // signed by winding
    }
    return { c, area };
  });
  withArea.sort((a,b)=>Math.abs(b.area)-Math.abs(a.area));
  const result = withArea.map((w, idx) => {
    const wantCCW = idx===0;
    // Two-vertex bulge contours (circles) have zero shoelace area — orientation
    // comes from the bulge sign instead (positive bulge = CCW).
    const isCCW = w.area !== 0 ? w.area > 0 : ((w.c.Vertices[0].B||0) > 0);
    return { Vertices: (isCCW===wantCCW) ? w.c.Vertices : reverseContour(w.c.Vertices) };
  });
  let minX=Infinity, minY=Infinity;
  result.forEach(c=>c.Vertices.forEach(v=>{ if(v.X<minX)minX=v.X; if(v.Y<minY)minY=v.Y; }));
  result.forEach(c=>c.Vertices.forEach(v=>{ v.X=+(v.X-minX).toFixed(3); v.Y=+(v.Y-minY).toFixed(3); }));
  return { contours: result };
}

// ─── NESTING CENTER — BUILD INPUT ─────────────────────────────────────────────
// sectionType: string from part.section ("PLATE","ISA","ISMB",etc.)
// plateTypes: set of section strings considered plates
const PLATE_SECTIONS = new Set(["PLATE","PLATES","PL","FLAT PLATE","CHECKER PLATE"]);

function isPlateSection(section) {
  return PLATE_SECTIONS.has((section||"").toUpperCase().trim());
}

// Build the API input JSON for one matCode group.
// parts: [{ markNo, length, width, qtyPerDrg, partLink, section, ... }]
// rawMaterials: [{ length, width, qty, name }] — sheets for plates, bars for sections
// machineName: string
// batchId: string
// dxfMap: { markNo: base64string|null } — pre-fetched DXF content
async function buildNestingInput(parts, rawMaterials, machineName, batchId, dxfMap = {}, kerfPartPart = 10, kerfPartEdge = 10) {
  const isPlate = parts.length > 0 && isPlateSection(parts[0].section);

  // Deduplicate parts by markNo — API wants unique Names, Quantity = total across drawings
  const partMap = {};
  parts.forEach(p => {
    if (!partMap[p.markNo]) partMap[p.markNo] = { ...p, totalQty: 0 };
    // Use totalQty if pre-computed (from buildInputData), else fall back to qtyPerDrg * drgQty
    partMap[p.markNo].totalQty += p.totalQty || ((p.qtyPerDrg||0) * (p.drgQty||1));
  });
  const uniqueParts = Object.values(partMap);

  // Check if any part has a valid DXF
  const hasDxfParts = uniqueParts.some(p => dxfMap[p.markNo]);

  const apiParts = uniqueParts.map(p => {
    const b64 = dxfMap[p.markNo];
    if (b64) {
      const conv = dxfToContours(b64ToText(b64));
      if (conv && conv.contours) {
        return { Name: p.markNo, Contours: conv.contours, Quantity: p.totalQty };
      }
      // conversion failed — falls through to rectangle; caller pre-validates and warns
    }
    return {
      Name: p.markNo,
      RectangularShape: {
        Length: isPlate ? (p.length || 100) : (p.length || 100),
        Width:  isPlate ? (p.width  || 100) : 100
      },
      Quantity: p.totalQty
    };
  });

  let settings;
  if (isPlate) {
    settings = {
      DistancePartPart: kerfPartPart,
      DistancePartRawPlate: kerfPartEdge,
      RotationControl: hasDxfParts ? "Free" : "Fixed90",
      MirrorControl: "Never",
      NestingInHoles: false
    };
  } else {
    // Sections/bars: use width=100 trick
    settings = {
      DistancePartPart: kerfPartPart,
      DistancePartRawPlate: 0,
      RotationControl: "Never",
      MirrorControl: "Never",
      NestingInHoles: false
    };
  }

  const apiRawPlates = rawMaterials.map((rm, i) => ({
    Name: rm.name || `Sheet${i+1}`,
    RectangularShape: {
      Length: rm.length,
      Width:  isPlate ? rm.width : 100
    },
    Quantity: rm.qty || 1
  }));

  const stopJson = hasDxfParts
    ? { SmartStop: true, Timeout: 60000 }
    : { AllPartsNested: true, SmartStop: true, Timeout: 10000 };

  return {
    Context: {
      Settings: settings,
      Problem: {
        Parts: apiParts,
        RawPlates: apiRawPlates
      }
    },
    InputName: batchId,
    MachineNameClient: machineName || "PLASMA-1",
    StopJson: stopJson
  };
}

