// Default permissions per role — used to pre-populate when creating a user
// ROLE_DEFAULT_PERMS and can imported from helpers.js
// Unified engine for all backward stage movements (corrections + QC rejections)
// Returns { ok, blocked, reason, summary }
const validateStageTransition = ({ instances, targetStage, reasonType, physicalHappened, instanceIds }) => {
  const affected = instances.filter(i => instanceIds.includes(i.id));
  if (affected.length === 0) return { ok:false, blocked:true, reason:"No instances found" };

  // Check downstream work
  const STAGE_ORDER = ['cutting','cutting_qc','fitup','fitup_qc','tpi_fitup','welding','welding_qc','tpi_weld','blasting','blasting_qc','painting','painting_qc','mdcc','dispatch'];
  const targetIdx = STAGE_ORDER.indexOf(targetStage);
  const downstreamBlocked = affected.some(i => {
    const currentIdx = STAGE_ORDER.indexOf(i.currentStage);
    return currentIdx > targetIdx + 1; // more than one stage ahead
  });

  if (downstreamBlocked && !physicalHappened) {
    return { ok:false, blocked:true, reason:"Downstream work exists — cannot fully revert. Use NCR route instead." };
  }
  return { ok:true, blocked:false };
};

// Generate NCR number: NCR-FXL26-27/0001-001
const genNcrNo = (orderId, existingNcrs) => {
  const orderNcrs = (existingNcrs||[]).filter(n => n.orderId === orderId);
  const seq = String(orderNcrs.length + 1).padStart(3, '0');
  return `NCR-${orderId}-${seq}`;
};

// Create notification for affected parties
const createNotification = ({ type, message, forRoles, forUsers, entityId, entityType, orderId, raisedBy }) => ({
  id: `NOTIF-${Date.now()}-${Math.random().toString(36).slice(2,6)}`,
  type, // "correction" | "qc_rejection" | "ncr" | "scrap_queue"
  message,
  forRoles: forRoles||[], // roles that see this
  forUsers: forUsers||[], // specific user ids
  entityId, entityType, orderId,
  raisedBy, raisedAt: new Date().toISOString(),
  readBy: [], // user ids who have dismissed it
});

// Create correction log entry
const createCorrectionEntry = ({ action, entityId, entityType, orderId, fromValue, toValue, reason, physicalHappened, triggeredBy }) => ({
  id: `CORR-${Date.now()}`,
  action, entityId, entityType, orderId,
  fromValue: JSON.stringify(fromValue),
  toValue: JSON.stringify(toValue),
  reason, physicalHappened,
  triggeredBy: triggeredBy?.name||triggeredBy?.username||"Unknown",
  triggeredAt: new Date().toISOString(),
});

