const QuickAddContractor = ({ contractors, setContractors, onSelect }) => {
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({ name:"", phone:"", contactPerson:"", address:"", capabilities:[], isInHouse:false });
  const CAPS = ["cutting","fit_up","welding","blasting","painting"];

  const save = () => {
    if (!form.name.trim()) return;
    const id = `CON-${String((contractors||[]).length+1).padStart(3,"0")}`;
    const next = { id, ...form, createdAt: new Date().toISOString() };
    setContractors(prev=>[...(prev||[]), next]);
    if (onSelect) onSelect(id);
    setOpen(false);
    setForm({ name:"", phone:"", contactPerson:"", address:"", capabilities:[], isInHouse:false });
  };

  const toggleCap = (c) => setForm(p=>({...p, capabilities: p.capabilities.includes(c) ? p.capabilities.filter(x=>x!==c) : [...p.capabilities,c]}));

  return (
    <>
      <button onClick={()=>setOpen(true)} style={{...css.btn.ghost, fontSize:11, padding:"3px 8px", marginLeft:6}}>+ New Contractor</button>
      {open&&<Modal title="Add New Contractor" onClose={()=>setOpen(false)} width={480}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <div style={{gridColumn:"span 2"}}><label style={css.label}>Contractor Name *</label><input value={form.name} onChange={e=>setForm(p=>({...p,name:e.target.value}))} style={css.input} autoFocus /></div>
          <div><label style={css.label}>Contact Person</label><input value={form.contactPerson} onChange={e=>setForm(p=>({...p,contactPerson:e.target.value}))} style={css.input}/></div>
          <div><label style={css.label}>Phone</label><input value={form.phone} onChange={e=>setForm(p=>({...p,phone:e.target.value}))} style={css.input}/></div>
          <div style={{gridColumn:"span 2"}}><label style={css.label}>Address</label><input value={form.address} onChange={e=>setForm(p=>({...p,address:e.target.value}))} style={css.input}/></div>
          <div style={{gridColumn:"span 2"}}>
            <label style={css.label}>Capabilities</label>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginTop:4}}>
              {CAPS.map(c=>(
                <label key={c} style={{display:"flex",gap:4,alignItems:"center",fontSize:12,cursor:"pointer"}}>
                  <input type="checkbox" checked={form.capabilities.includes(c)} onChange={()=>toggleCap(c)}/>
                  {c.replace("_","-")}
                </label>
              ))}
            </div>
          </div>
          <div style={{gridColumn:"span 2"}}>
            <label style={{display:"flex",gap:8,alignItems:"center",fontSize:12,cursor:"pointer"}}>
              <input type="checkbox" checked={form.isInHouse} onChange={e=>setForm(p=>({...p,isInHouse:e.target.checked}))}/>
              In-House Team (not external contractor)
            </label>
          </div>
        </div>
        <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:14}}>
          <button onClick={()=>setOpen(false)} style={css.btn.ghost}>Cancel</button>
          <button onClick={save} disabled={!form.name.trim()} style={{...css.btn.primary,opacity:form.name.trim()?1:0.4}}>Add Contractor</button>
        </div>
      </Modal>}
    </>
  );
};


const SeedMastersBtn = () => {
  const [status, setStatus] = useState("idle"); // idle | seeding | done | error
  const [log, setLog]       = useState([]);

  const seed = async () => {
    setStatus("seeding");
    setLog([]);
    const addLog = (msg) => setLog(prev=>[...prev, msg]);

    const upsert = async (key, value) => {
      const res = await fetch(
        `https://lmixuubgislgultzjeqs.supabase.co/rest/v1/structo_store`,
        {
          method:"POST",
          headers:{
            "Content-Type":"application/json",
            "apikey":"sb_publishable_-QR4-pdtY3lvjUaNyYsKew_r-2fY5Rd",
            "Authorization":"Bearer sb_publishable_-QR4-pdtY3lvjUaNyYsKew_r-2fY5Rd",
            "Prefer":"resolution=merge-duplicates"
          },
          body:JSON.stringify({ key, value, updated_at:new Date().toISOString() })
        }
      );
      if (!res.ok) { const t=await res.text(); throw new Error(`${key}: ${res.status} ${t}`); }
    };

    try {
      addLog("Seeding clients...");
      await upsert("structo_clients", CLIENTS_FULL);
      addLog(`✅ ${CLIENTS_FULL.length} clients seeded`);

      addLog("Seeding vendors...");
      await upsert("structo_vendors", VENDORS);
      addLog(`✅ ${VENDORS.length} vendors seeded`);

      addLog("Seeding contractors...");
      await upsert("structo_contractors", CONTRACTORS);
      addLog(`✅ ${CONTRACTORS.length} contractors seeded`);

      addLog("Seeding welders...");
      await upsert("structo_welders", WELDERS_SEED);
      addLog(`✅ ${WELDERS_SEED.length} welders seeded`);

      addLog("Seeding machines...");
      await upsert("structo_machines", MACHINES_SEED);
      addLog(`✅ ${MACHINES_SEED.length} machines seeded`);

      addLog("Seeding TPI agencies...");
      await upsert("structo_tpiTemplates", TPI_AGENCIES);
      addLog(`✅ ${TPI_AGENCIES.length} TPI agencies seeded`);

      setStatus("done");
      addLog("🎉 All masters seeded successfully! Refresh the page to see them.");
    } catch(e) {
      setStatus("error");
      addLog(`❌ Error: ${e.message}`);
    }
  };

  return (
    <div>
      <button onClick={seed} disabled={status==="seeding"}
        style={{...css.btn.primary, opacity:status==="seeding"?0.6:1}}>
        {status==="seeding"?"Seeding...":status==="done"?"✅ Done — Seed Again":"🌱 Seed Masters to Supabase"}
      </button>
      {log.length>0&&(
        <div style={{marginTop:10,fontFamily:T.fontMono,fontSize:11,background:T.bgInput,
          borderRadius:6,padding:"8px 12px",maxHeight:160,overflowY:"auto"}}>
          {log.map((l,i)=><div key={i} style={{color:l.startsWith("❌")?T.red:l.startsWith("✅")||l.startsWith("🎉")?T.green:T.textMid}}>{l}</div>)}
        </div>
      )}
    </div>
  );
};


