// ─── NESTING PO HELPERS ───────────────────────────────────────────────────────
// Parse matCode segments for PO line fields: "PLATE/MS/E350/10mm" → {sectionType,matType,grade,size}
const parseNestingMatCode = (matCode) => {
  const segs = (matCode||"").split("/");
  return {
    sectionType: segs[0]||"PLATE",
    matType:     segs[1]||"MS",
    grade:       segs[2]||"E250",
    size:        segs[3]||"",
  };
};
// Weight per unit: PLATE = L×W×t×7.85/1e6, sections = barLength(m)×wtPerMetre from library
// sheetDim: plate = "6000X1250" (LxW in mm), section = "12000" (bar length in mm)
// ─── RFC-4180 CSV PARSER ─────────────────────────────────────────────────────
// Full-text CSV -> array of row arrays. Commas and newlines inside "quoted"
// fields stay in one cell; "" inside quotes is a literal quote. Replaces the
// old per-line split(",") which sheared any field containing a comma (e.g.
// pipe sizes exported as "42,9*3,2") and silently shifted later columns right.
function parseCsvText(txt) {
  const out=[[]]; let cell="", inQ=false;
  for (let i=0;i<txt.length;i++){
    const ch=txt[i];
    if (inQ) {
      if (ch==='"') { if (txt[i+1]==='"'){ cell+='"'; i++; } else inQ=false; }
      else cell+=ch;
    }
    else if (ch==='"') inQ=true;
    else if (ch===',') { out[out.length-1].push(cell.trim()); cell=""; }
    else if (ch==='\n') { out[out.length-1].push(cell.trim()); cell=""; out.push([]); }
    else cell+=ch;
  }
  out[out.length-1].push(cell.trim());
  return out;
}

// Decode a CSV upload: UTF-8 first; if the bytes weren't valid UTF-8 (any
// \uFFFD replacement char appears), fall back to windows-1252 so Excel's
// Latin-1 exports (degree signs, multiplication signs, accents) survive.
async function readCsvText(file) {
  const buf = await file.arrayBuffer();
  let txt = new TextDecoder("utf-8").decode(buf);
  if (txt.includes("\uFFFD")) txt = new TextDecoder("windows-1252").decode(buf);
  return txt;
}

const nestingSheetWt = (matCode, sheetDim) => {
  const segs = (matCode||"").split("/");
  const sectionType = (segs[0]||"").toUpperCase();
  const size = segs[3] || "";
  if (sectionType === "PLATE") {
    const t = parseFloat(size.replace(/mm$/i,""))||0;
    const parts = (sheetDim||"").toUpperCase().split("X").map(Number);
    const L = parts[0]||0, W = parts[1]||0;
    return (L && W && t) ? Math.round(L * W * t * 7.85 / 1e6 * 100) / 100 : 0;
  } else {
    const barLengthM = (parseFloat(sheetDim)||0) / 1000;
    const matEntry = MATERIALS_LIBRARY.find(m =>
      (m.sectionType||"").toUpperCase() === sectionType &&
      (m.size||"").toUpperCase() === (size||"").toUpperCase() &&
      !m.isPlate
    );
    const wtPerMetre = matEntry?.wtPerMetre || 0;
    return (barLengthM > 0 && wtPerMetre > 0) ? Math.round(barLengthM * wtPerMetre * 100) / 100 : 0;
  }
};

// One weight resolver for the whole app: library constant -> materials master ->
// geometric formulas. Every screen that shows a sheet/bar weight must use this,
// so MRP Planning and Purchase can never disagree about the same requisition.
function resolveMatWt(materialsList, mc, dim) {
  const w = nestingSheetWt(mc, dim);
  if (w) return w;
  const lib = (materialsList||[]).find(m=>normMatCode(m.matCode)===normMatCode(mc));
  if (lib?.nosOnly) return 0;
  const segs = (mc||"").split("/");
  if (lib && lib.isPlate) {
    const t = parseFloat(segs[3]||"")||0;
    const p = (dim||"").toUpperCase().split("X").map(Number);
    return (p[0]&&p[1]&&t) ? Math.round(p[0]*p[1]*t*7.85/1e6*100)/100 : 0;
  }
  const lenM = (parseFloat(dim)||0)/1000;
  if (lenM>0 && lib && lib.wtPerMetre>0) return Math.round(lenM*lib.wtPerMetre*100)/100;
  const g = geometricKgPerM(segs[0], segs[3]);
  return (lenM>0 && g>0) ? Math.round(lenM*g*100)/100 : 0;
}

// Pure-geometry kg/m for sections whose weight derives from the size itself.
// ROD d²×0.006165; BAR/FLAT w×t×0.00785; SQ a²×0.00785. (mm inputs, kg/m out)
const geometricKgPerM = (sectionType, size) => {
  const st = (sectionType||"").toUpperCase().trim();
  const nums = (size||"").toUpperCase().replace(/MM/g,"").split(/[X×]/).map(n=>parseFloat(n)).filter(n=>!isNaN(n));
  if (["ROD","ROUND","ROUND BAR"].includes(st) && nums.length>=1) return Math.round(nums[0]*nums[0]*0.006165*1000)/1000;
  if (["BAR","FLAT","FLT","FLAT BAR"].includes(st) && nums.length>=2) return Math.round(nums[0]*nums[1]*0.00785*1000)/1000;
  if (["SQ","SQUARE","SQUARE BAR"].includes(st) && nums.length>=1) return Math.round(nums[0]*nums[0]*0.00785*1000)/1000;
  return 0;
};

// Cross-module handoff: Nesting Runs' Convert button deep-links into the unified
// quantity-split convert flow in Purchase (one code path — see issues log #16).
let pendingPrPreselect = null;

const PurchaseModule = ({ user, pos, setPos, purchaseReqs, setPurchaseReqs, stock, setStock, orders, vendors, setVendors, materials, setMaterials, paint, consumables, setMod, nestingBatches }) => {
  const [purTab, setPurTab] = useState(pendingPrPreselect ? "requisitions" : "pos"); // "pos" | "requisitions"
  useEffect(()=>{
    if (pendingPrPreselect) {
      setSelectedPrs([pendingPrPreselect]);
      pendingPrPreselect = null;
    }
  }, []);
  const [view, setView] = useState("list");
  const [selected, setSelected] = useState(null);
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState({});
  const [grnModal, setGrnModal] = useState(null);
  const [grnForm, setGrnForm] = useState({ lines:[] });
  const [editGrnModal, setEditGrnModal] = useState(null); // {poId, grnId}
  const [editGrnForm, setEditGrnForm] = useState({});
  const [toast, setToast] = useState(null);
  const [poImpModal, setPoImpModal] = useState(false);
  const [poImpRows,  setPoImpRows]  = useState([]);
  const [poImpErr,   setPoImpErr]   = useState("");
  const [poImpMode,  setPoImpMode]  = useState("append");
  const poImpRef = useRef(null);
  const [showCancelled, setShowCancelled] = useState(false);
  const [selectedPrs, setSelectedPrs] = useState([]);   // Part 3: multi-PR combine
  const [prOrderFilter, setPrOrderFilter] = useState("");
  const [prTypeFilter, setPrTypeFilter] = useState("");
  const [showCancelledPrs, setShowCancelledPrs] = useState(false);
  const [prCatFilter, setPrCatFilter] = useState("");
  const [prMakeFilter, setPrMakeFilter] = useState("");
  // Rolled structural sections typically share vendors, distinct from plate mills
  const ROLLED_TYPES = ["ISA","ISMC","ISMB","ISLB","ISHB","ISJB","ISJC","UB","UC","NPB","WPB","UBP","BEAM","CHANNEL","ANGLE","ISNT","RSJ"];
  const prSectionTypes = (pr) => [...new Set((pr.lots||[]).map(l=>((l.matCode||"").split("/")[0]||"").toUpperCase()).filter(Boolean))];
  const prMatchesType = (pr) => {
    if (!prTypeFilter) return true;
    const types = prSectionTypes(pr);
    if (prTypeFilter==="PLATE")  return types.includes("PLATE");
    if (prTypeFilter==="ROLLED") return types.some(t=>ROLLED_TYPES.includes(t));
    return types.includes(prTypeFilter);
  };
  const [combineModal, setCombineModal] = useState(false);
  const [combineForm, setCombineForm] = useState({});
  const [convertSingleModal, setConvertSingleModal] = useState(null); // PR object
  const [convertSingleForm, setConvertSingleForm] = useState({});    // vendorId/poDate/notes/rates
  const [linePickerModal, setLinePickerModal] = useState(null); // Part 4: null | {category:null|"rm"|"paint"|"consumable"}
  const [linePickerForm, setLinePickerForm] = useState({});

  const showToast = (msg,color="green") => { setToast({msg,color}); setTimeout(()=>setToast(null),3000); };
  const [addToLibModal, setAddToLibModal] = useState(null);
  const [addToLibForm, setAddToLibForm] = useState({});
  const [addToLibSuccess, setAddToLibSuccess] = useState(false);

  const downloadPOTemplate = () => {
    const hdr    = ["Section Type","Size","Grade","Material Type","Length (mm)","Width (mm)","Qty (units)","Weight Required (kg)","Unit","Pricing Method (PerUnit/PerKg)","Unit Price (₹)","Manual Wt (kg/m or kg/m2)","Expected Delivery (DD-MM-YYYY)","Remarks"];
    const hints  = ["e.g. PLATE","12mm","E250","MS","6000","1250","5 (fill OR Weight — not both)","(leave blank if Qty filled)","Sheets","PerUnit","65000","(leave blank if library match found)","20-03-2026","Any notes"];
    const sample = ["ISA","75x75x8","E250","MS","12000","","40","","Pcs","PerUnit","780","","20-03-2026","Main columns"];
    const csv = [hdr,hints,sample].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a = Object.assign(document.createElement("a"),{ href:URL.createObjectURL(new Blob([csv],{type:"text/csv"})), download:"po_lines_template.csv" });
    a.click(); URL.revokeObjectURL(a.href);
  };

  const handlePOImpFile = async e => {
    setPoImpErr(""); setPoImpRows([]);
    const file = e.target.files[0]; if (!file) return;
    if (!file.name.toLowerCase().endsWith(".csv")) { setPoImpErr("Please upload a .csv file — save your spreadsheet as CSV first."); return; }
    try {
      const { rows, errors, warnings } = parsePOLineCSV(await file.text(), materials);
      if (errors.length) { setPoImpErr(errors.join(" ")); return; }
      setPoImpErr(warnings.length ? "⚠ " + warnings.join(" ") : "");
      setPoImpRows(rows);
    } catch(err) { setPoImpErr("Error reading file: " + err.message); }
  };

  const confirmPOImp = () => {
    const base  = poImpMode==="replace" ? [] : (form.lines||[]);
    const clean = poImpRows.map(({_libMatched,...r})=>r);
    setForm(f=>({...f, lines:[...base,...clean]}));
    setPoImpModal(false); setPoImpRows([]); setPoImpErr(""); poImpRef.current.value="";
  };

  const canEdit = ["super_admin","purchase_admin","planning_admin"].includes(user.role);

  const statusSummary = { pending:0, partially_received:0, fully_received:0, cancelled:0 };
  pos.forEach(p=>{ statusSummary[p.status]=(statusSummary[p.status]||0)+1; });
  const totalPoValue = pos.reduce((s,p)=>s+p.lines.reduce((ss,l)=>ss+(l.totalPrice||0),0),0);

  const savePO = () => {
    const lines = form.lines||[];
    const v = vendors.find(x=>x.id===form.vendorId);
    // Compute ID before updater so we can reference it for PR status update
    const yr = new Date().getFullYear();
    const maxSeq = pos.reduce((m,p)=>{ const mt=p.id.match(/^PO-(\d{4})-(\d+)$/); return mt&&+mt[1]===yr?Math.max(m,+mt[2]):m; }, 0);
    const newPoId = `PO-${yr}-${String(maxSeq+1).padStart(3,"0")}`;
    setPos(prev => {
      const newPO = {
        ...form,
        id: newPoId,
        vendorCode: v?.vendorCode||"",
        status:"pending",
        grns:[],
        lines: lines.map((l,i)=>{ const calcWt=calcPoLineWt(l); const wtOrdered=(l.orderMode||"ByUnits")==="ByWeight"?(l.wtRequired||l.wtOrdered||0):Math.max(calcWt, l.wtOrdered||0); const totalPrice=l.pricingMethod==="PerKg"?wtOrdered*(l.unitPrice||0):(l.qty||0)*(l.unitPrice||0); const effectiveRateKg=wtOrdered>0?Math.round(totalPrice/wtOrdered*100)/100:0; const effectiveRateUnit=l.pricingMethod==="PerKg"?(l.qty||0)>0?Math.round(totalPrice/(l.qty||0)*100)/100:0:(l.unitPrice||0); return {...l, id:`POL-${Date.now()}-${i}`, wtReceived:0, status:"pending", wtOrdered, totalPrice, effectiveRateKg, effectiveRateUnit, itemCode:buildItemCode(l)}; }),
        createdBy: user.name,
        createdDate: today(),
      };
      return [...prev, newPO];
    });
    // Mark source PR as converted (for nesting-originated POs)
    if (form.prId) setPurchaseReqs(prev=>prev.map(r=>r.id===form.prId?{...r,status:"converted",poId:newPoId}:r));
    showToast("Purchase Order created");
    setModal(null);
  };

  // Partial-conversion tracking: pr.convertedLines maps a stable line key to the
  // qty already carried onto POs; remaining = line qty − converted. A PR is
  // "converted" when nothing remains, "partially_converted" while some does.
  const prLineKey = (prId, matCode, dim) => `${prId}|${matCode}|${dim||""}`;
  const prLineRemaining = (pr, l, ln) => Math.max(0, (ln.qty||0) - ((pr.convertedLines||{})[prLineKey(pr.id, l.matCode, ln.sheetDim||ln.dims)]||0));
  const prRemainingTotal = (pr) => (pr.lots||[]).reduce((s,l)=>s+(l.lines||[]).reduce((ss,ln)=>ss+prLineRemaining(pr,l,ln),0),0);
  // Sheet/bar weight with DB-materials fallback: the module-level nestingSheetWt
  // only knows the hardcoded library constant, which lacks later additions
  // (UC/UB etc. added directly to the materials master) — hence Wt Req showing 0.
  const sheetWt = (mc, dim) => resolveMatWt(materials, mc, dim);
  const matLib = (mc) => (materials||[]).find(m=>normMatCode(m.matCode)===normMatCode(mc));
  const isNosOnly = (mc) => matLib(mc)?.nosOnly===true;
  // "sheet" (plates), "bar" (length-stock sections), "nos" (count-only items)
  const matClass = (mc) => isNosOnly(mc) ? "nos" : ((mc||"").split("/")[0].toUpperCase()==="PLATE" ? "sheet" : "bar");
  // Store-PR line weight per unit: kg lines weigh 1/unit; m lines use kg-per-metre;
  // nos lines resolve per-piece kg from the stored length/plate dim via the SAME
  // resolver as nesting PRs (resolveMatWt) — fixes the "25x, 0 kg, unweighed" bug.
  const storeUnitWt = (l, ln) => {
    const u = (ln.unit||"nos");
    if (u==="kg") return 1;
    if (l.itemType!=="rm") return 0;
    if (u==="m") return sheetWt(l.matCode, "1000");
    return sheetWt(l.matCode, String(ln.sheetDim||ln.dims||"").replace(/\u00d7/g,"X"));
  };
  const prLineWt = (pr, l, ln) => pr.type==="store" ? storeUnitWt(l, ln) : sheetWt(l.matCode, ln.sheetDim||ln.dims);
  // Quick-add: writes kg/m or the nos-only flag into the materials master so the
  // fix is permanent everywhere, not patched on one PR.
  const applyQuickWt = (mc, kgpm, nosOnly) => {
    setMaterials(prev=>{
      const list = prev||[];
      const idx = list.findIndex(m=>normMatCode(m.matCode)===normMatCode(mc));
      if (idx>=0) return list.map((m,i)=>i===idx?{...m, wtPerMetre: nosOnly?(m.wtPerMetre||0):kgpm, nosOnly:!!nosOnly}:m);
      const segs = (mc||"").split("/");
      return [...list, { id:"ML-Q"+Date.now(), matCode:mc, sectionType:segs[0]||"", matType:segs[1]||"MS",
        grade:segs[2]||"", size:segs[3]||"", isPlate:false, wtPerMetre:nosOnly?0:kgpm, nosOnly:!!nosOnly,
        standardLengths:[6000,12000], active:true, addedVia:"quick-add" }];
    });
  };
  const [quickWtModal, setQuickWtModal] = useState(null);
  const [quickWtVals, setQuickWtVals] = useState({});
  // ── Store Requisitions (type:"store") — RM & consumables without nesting.
  // Same purchaseReqs collection so combine/split/partial conversion apply as-is.
  const isStoreRole = ["store_admin","super_admin"].includes(user.role);
  const [sprModal, setSprModal] = useState(false);
  const [repTab, setRepTab] = useState("pr");
  const [repItemType, setRepItemType] = useState("all");
  const [repOrder, setRepOrder] = useState("");
  const [repFrom, setRepFrom] = useState("");
  const [repTo, setRepTo] = useState("");
  const [repPoView, setRepPoView] = useState("outstanding");
  const [repChart, setRepChart] = useState(false);
  const [sprForm, setSprForm] = useState({ orderId:"", neededBy:"", remarks:"", lines:[] });
  const blankSprLine = () => ({ itemType:"rm", itemKey:"", desc:"", qty:"", unit:"kg", make:"", category:"", dim:"" });
  const stockOnHand = (ln) => {
    if (ln.itemType==="consumable") {
      const c = (consumables||[]).find(x=>x.id===ln.itemKey || x.name===ln.itemKey);
      return c ? `${c.currentStock??c.stock??0} ${c.unit||""}`.trim() : "—";
    }
    const key = normMatCode(ln.itemKey);
    if (!key) return "—";
    const kg = (stock||[]).filter(s=>normMatCode(s.matCode)===key && !["rejected","returned","written_off"].includes(s.status))
      .reduce((a,s)=>a+(s.wtAvailable||0),0);
    return `${fmt.num(Math.round(kg))} kg`;
  };
  const saveSpr = () => {
    const lines = sprForm.lines.filter(l=>(l.itemKey||l.desc) && parseFloat(l.qty)>0);
    if (!lines.length) { showToast("Add at least one line with a quantity"); return; }
    const normDim = d => String(d||"").trim().toUpperCase().replace(/\u00d7/g,"X").replace(/\s+/g,"");
    // Weight-resolution guard: RM lines in nos need a length/dim so kg is known
    // from birth. Block missing dims; warn if the resolver still returns 0.
    const noDim = lines.filter(l=>l.itemType==="rm" && (l.unit||"nos")==="nos" && !isNosOnly(l.itemKey) && !normDim(l.dim));
    if (noDim.length) { showToast(`Enter length/dimension for: ${noDim.map(l=>l.itemKey).join(", ")}`,"red"); return; }
    const zeroWt = lines.filter(l=>{
      if (l.itemType!=="rm" || (l.unit||"nos")==="kg" || isNosOnly(l.itemKey)) return false;
      const each = (l.unit==="m") ? sheetWt(l.itemKey,"1000") : sheetWt(l.itemKey, normDim(l.dim));
      return !(each>0);
    });
    if (zeroWt.length && !window.confirm(`No weight data for: ${zeroWt.map(l=>l.itemKey).join(", ")}.\nThe PR will show these as unweighed (fix via kg/m in Materials master).\n\nRaise anyway?`)) return;
    // Duplicate guard: warn if an OPEN PR already carries any of these items
    const openStatuses = ["pending","pending_store","forwarded","partially_converted"];
    const dupes = [];
    lines.forEach(l=>{
      const key = l.itemType==="rm" ? normMatCode(l.itemKey) : (l.desc||l.itemKey||"").trim().toLowerCase();
      (purchaseReqs||[]).filter(r=>openStatuses.includes(r.status)).forEach(r=>{
        const hit = (r.lots||[]).some(lot=> l.itemType==="rm"
          ? normMatCode(lot.matCode)===key
          : (lot.matCode||"").trim().toLowerCase()===key);
        if (hit) dupes.push(`${l.itemType==="rm"?l.itemKey:(l.desc||l.itemKey)} → already open on ${r.id} (${r.status})`);
      });
    });
    if (dupes.length && !window.confirm(`Possible duplicate requisition:\n${[...new Set(dupes)].join("\n")}\n\nRaise anyway?`)) return;
    const id = `PR-STORE-${Date.now()}`;
    const lots = lines.map(l=>({
      matCode: l.itemType==="rm" ? l.itemKey : (l.desc||l.itemKey),
      itemType: l.itemType, category: l.category||"", make: l.make||"",
      lines: [{ qty: parseFloat(l.qty)||0, unit: l.unit||"nos", desc: l.desc||"", sheetDim: l.itemType==="rm" ? normDim(l.dim) : "" }],
      parts: [], drawingNos: [],
    }));
    setPurchaseReqs(prev=>[...(prev||[]), { id, type:"store", status: isStoreRole ? "forwarded" : "pending_store",
      orderId: sprForm.orderId||"", neededBy: sprForm.neededBy||"", remarks: sprForm.remarks||"",
      createdAt: today(), createdBy: user.username||user.name, forwardedAt: isStoreRole ? today() : "",
      forwardedBy: isStoreRole ? (user.username||user.name) : "", lots }]);
    setSprModal(false); setSprForm({ orderId:"", neededBy:"", remarks:"", lines:[] });
    showToast(`${id} raised${isStoreRole?" and forwarded to purchase":""}`);
  };
  const forwardSpr = (pr) => setPurchaseReqs(prev=>prev.map(r=>r.id!==pr.id?r:
    {...r, status:"forwarded", forwardedAt:today(), forwardedBy:user.username||user.name}));
  // Orders a PR belongs to, via its source nesting batch (orderIds → drawingNos → part marks)
  const prOrderNos = (pr) => {
    const b = (nestingBatches||[]).find(x=>x.id===pr.nestingBatchId);
    const found = new Set();
    if (b?.orderIds?.length) b.orderIds.forEach(oid=>{ const o=(orders||[]).find(x=>x.id===oid); if(o) found.add(o.orderNo||o.id); });
    if (!found.size && b) {
      const drg = new Set((b.lots||[]).flatMap(l=>l.drawingNos||[]).map(d=>String(d).trim().toUpperCase()));
      if (drg.size) (orders||[]).forEach(o=>{ if((o.drawings||[]).some(d=>drg.has((d.drawingNo||"").trim().toUpperCase()))) found.add(o.orderNo||o.id); });
      if (!found.size) {
        const marks = new Set((b.lots||[]).flatMap(l=>l.parts||[]));
        if (marks.size) (orders||[]).forEach(o=>{ if((o.parts||[]).some(p=>marks.has(p.markNo))) found.add(o.orderNo||o.id); });
      }
    }
    return [...found];
  };
  const createCombinedPO = () => {
    const yr = new Date().getFullYear();
    const maxSeq = pos.reduce((m,p)=>{ const mt=p.id.match(/^PO-(\d{4})-(\d+)$/); return mt&&+mt[1]===yr?Math.max(m,+mt[2]):m; },0);
    const newPoId = `PO-${yr}-${String(maxSeq+1).padStart(3,"0")}`;
    const v = vendors.find(x=>x.id===combineForm.vendorId);
    // Last-gate duplicate guard: same material + overlapping order across the
    // SELECTED PRs almost always means an uncaught re-nest — double procurement.
    {
      const sel = (purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id));
      const seen = {};
      const clashes = [];
      sel.forEach(pr=>{
        const ordKey = pr.type==="store" ? (pr.orderId||"gen") : prOrderNos(pr).sort().join(",");
        (pr.lots||[]).forEach(l=>{
          const k = normMatCode(l.matCode)+"|"+ordKey;
          if (seen[k] && seen[k]!==pr.id) clashes.push(`${l.matCode} (${seen[k]} + ${pr.id})`);
          else seen[k] = pr.id;
        });
      });
      if (clashes.length && !window.confirm(`⚠ The selection contains the SAME material for the SAME order more than once — likely duplicate re-nests:\n${[...new Set(clashes)].join("\n")}\n\nThis will order the material twice. Create the PO anyway?`)) return;
    }
    const ts = Date.now();
    const inclQty = (pr,l,ln) => {
      const rem = prLineRemaining(pr,l,ln);
      const k = prLineKey(pr.id, l.matCode, ln.sheetDim||ln.dims);
      const v = combineForm.lineQtys?.[k];
      return Math.max(0, Math.min(rem, v===undefined||v==="" ? rem : (parseInt(v)||0)));
    };
    // Order linkage for auto-reservation at GRN: each line carries its source
    // order(s) so receiving can reserve the material for the right project.
    const prOrderIdsFor = (pr) => {
      if (pr.type==="store") return pr.orderId ? [pr.orderId] : [];
      const b = (nestingBatches||[]).find(x=>x.id===pr.nestingBatchId);
      return (b?.orderIds||[]).filter(Boolean);
    };
    const allLines = (purchaseReqs||[])
      .filter(r=>selectedPrs.includes(r.id))
      .flatMap((pr,prIdx)=>
        (pr.lots||[]).filter(l=>!l.fulfilledFromStock).flatMap((l,lotIdx)=>
          (l.lines||[]).map((ln,lineIdx)=>{
            const qty = inclQty(pr,l,ln);
            if (qty<=0) return null;
            const p = parseNestingMatCode(l.matCode);
            const isStoreLine = pr.type==="store";
            const lineUnit = isStoreLine ? (ln.unit||"nos") : "Sheets";
            const perUnit = isNosOnly(l.matCode) || (isStoreLine && lineUnit!=="kg") || l.itemType==="consumable";
            const wtPerSheet = isStoreLine ? storeUnitWt(l, ln) : sheetWt(l.matCode, ln.sheetDim||ln.dims);
            const dimParts = (ln.sheetDim||ln.dims||"").toUpperCase().split("X").map(Number);
            return {
              id:`POL-${ts}-${prIdx}-${lotIdx}-${lineIdx}`,
              matCode:l.matCode, sectionType:p.sectionType, matType:p.matType, grade:p.grade, size:p.size,
              sheetDim:ln.sheetDim||ln.dims, isPlate:p.sectionType?.toUpperCase()==='PLATE',
              sheetLength:dimParts[0]||0, sheetWidth:dimParts[1]||0,
              orderMode:"ByUnits", qty, qtyOrdered:qty, unit: perUnit ? (isStoreLine?lineUnit:"Nos") : (isStoreLine?"kg":"Sheets"),
              pricingMethod: perUnit?"PerUnit":"PerKg", unitPrice:parseFloat(combineForm.rates?.[l.matCode])||0,
              wtPerSheet, wtOrdered:Math.round(wtPerSheet*qty*100)/100,
              wtRequired:Math.round(wtPerSheet*qty*100)/100,
              totalPrice: perUnit
                ? Math.round(qty*(parseFloat(combineForm.rates?.[l.matCode])||0)*100)/100
                : Math.round(Math.round(wtPerSheet*qty*100)/100*(parseFloat(combineForm.rates?.[l.matCode])||0)*100)/100,
              wtReceived:0, qtyReceived:0, status:"pending",
              sourceType:"nesting", sourcePrId:pr.id,
              orderAllocations: (()=>{ const oids = prOrderIdsFor(pr); const wt = Math.round(wtPerSheet*qty*100)/100;
                return (oids.length===1 && wt>0) ? [{ orderId:oids[0], kg:wt }] : []; })(),
              itemCode: l.matCode + ((ln.sheetDim||ln.dims) ? "/"+(ln.sheetDim||ln.dims) : ""),
            };
          }).filter(Boolean)
        )
      );
    if (allLines.length===0) { showToast("Nothing to convert — all quantities are 0"); return; }
    const newPO = {
      id:newPoId, vendorId:combineForm.vendorId, vendorCode:v?.vendorCode||"",
      vendorName:v?.name||combineForm.vendorName||"", poDate:combineForm.poDate||today(),
      expectedDelivery:combineForm.expectedDelivery||"", remarks:combineForm.notes||"",
      status:"pending", sourceType:"nesting",
      poType:combineForm.poType||"rm",
      transportScope:combineForm.transportScope||"",
      paymentTerms:combineForm.paymentTerms||[],
      prIds:selectedPrs,
      servedOrders:[], coveredOrders:[], includesStock:false,
      totalValue:allLines.reduce((s,l)=>s+(l.totalPrice||0),0),
      lines:allLines, grns:[], createdBy:user.name, createdDate:today(),
    };
    newPO.coveredOrders = [...new Set(allLines.flatMap(l=>(l.orderAllocations||[]).map(a=>a.orderId)))];
    setPos(prev=>[...prev, newPO]);
    setPurchaseReqs(prev=>prev.map(r=>{
      if (!selectedPrs.includes(r.id)) return r;
      const newConverted = {...(r.convertedLines||{})};
      (r.lots||[]).forEach(l=>(l.lines||[]).forEach(ln=>{
        const q = inclQty(r,l,ln);
        if (q>0) { const k = prLineKey(r.id, l.matCode, ln.sheetDim||ln.dims); newConverted[k] = (newConverted[k]||0)+q; }
      }));
      const remaining = (r.lots||[]).reduce((s,l)=>s+(l.lines||[]).reduce((ss,ln)=>ss+Math.max(0,(ln.qty||0)-(newConverted[prLineKey(r.id,l.matCode,ln.sheetDim||ln.dims)]||0)),0),0);
      const anyConverted = Object.values(newConverted).some(v=>v>0);
      return {...r, convertedLines:newConverted,
        poIds:[...(r.poIds||[]), newPoId], poId:newPoId,
        status: remaining<=0 ? "converted" : (anyConverted ? "partially_converted" : r.status)};
    }));
    showToast(`${newPoId} created from ${selectedPrs.length} requisition(s)`);
    setCombineModal(false); setCombineForm({}); setSelectedPrs([]);
    // Stay on Requisitions tab — user can click "View PO" on the PR cards
  };

  const saveSingleConvertPO = () => {
    const pr = convertSingleModal;
    const csf = convertSingleForm;
    if (!pr || !csf.vendorId) return;
    const yr = new Date().getFullYear();
    const maxSeq = pos.reduce((m,p)=>{ const mt=p.id.match(/^PO-(\d{4})-(\d+)$/); return mt&&+mt[1]===yr?Math.max(m,+mt[2]):m; },0);
    const newPoId = `PO-${yr}-${String(maxSeq+1).padStart(3,"0")}`;
    const v = vendors.find(x=>x.id===csf.vendorId);
    const ts = Date.now();
    const lines = (pr.lots||[]).flatMap((l,li)=>
      (l.lines||[]).map((ln,di)=>{
        const p = parseNestingMatCode(l.matCode);
        const wtPerSheet = sheetWt(l.matCode, ln.sheetDim||ln.dims);
        const qty = ln.qty||0;
        const rate = parseFloat(csf.lineRates?.[`${li}-${di}`]??csf.rates?.[l.matCode])||0;
        const totalWt = Math.round(wtPerSheet*qty*100)/100;
        return {
          id:`POL-${ts}-${li}-${di}`,
          matCode:l.matCode, sectionType:p.sectionType, matType:p.matType, grade:p.grade, size:p.size,
          sheetDim:ln.sheetDim||ln.dims, description:ln.sheetDim||ln.dims, isPlate:p.sectionType?.toUpperCase()==='PLATE',
          orderMode:'ByUnits', qty, qtyOrdered:qty, unit:'Sheets',
          pricingMethod:'PerKg', unitPrice:rate,
          wtPerSheet, wtOrdered:totalWt, wtRequired:totalWt,
          totalPrice:Math.round(totalWt*rate*100)/100,
          wtReceived:0, qtyReceived:0, status:'pending',
          sourceType:'nesting', prId:pr.id,
          itemCode:`${l.matCode}/${ln.sheetDim||ln.dims}`,
        };
      })
    );
    const newPO = {
      id:newPoId, vendorId:csf.vendorId, vendorCode:v?.vendorCode||"",
      vendorName:v?.name||"", poDate:csf.poDate||today(),
      expectedDelivery:csf.expectedDelivery||"", remarks:csf.notes||"",
      status:"pending", sourceType:"nesting", prId:pr.id,
      poType:csf.poType||"rm",
      transportScope:csf.transportScope||"",
      paymentTerms:csf.paymentTerms||[],
      servedOrders:[], coveredOrders:[], includesStock:false,
      lines, grns:[], createdBy:user.name, createdDate:today(),
    };
    setPos(prev=>[...prev, newPO]);
    setPurchaseReqs(prev=>prev.map(r=>r.id!==pr.id?r:{...r,status:"converted",poId:newPoId}));
    setConvertSingleModal(null); setConvertSingleForm({});
    showToast(`${newPoId} created`);
  };

  const saveEditGRN = () => {
    if (!editGrnModal) return;
    const {poId, grnId} = editGrnModal;
    setPos(prev=>prev.map(p=>{
      if(p.id!==poId) return p;
      return {...p, grns:(p.grns||[]).map(g=>g.id!==grnId?g:{...g,...editGrnForm,id:grnId})};
    }));
    // Update stock lots linked to this GRN
    setStock(prev=>prev.map(lot=>{
      if(lot.grnId!==grnId) return lot;
      // Find matching edited line by poLineId
      const editedLine=(editGrnForm.lines||[]).find(l=>l.poLineId===lot.poLineId&&(!l.heatNo||l.heatNo===lot.heatNo||!lot.heatNo));
      if(!editedLine) return lot;
      const newWt=editedLine.actualWt||editedLine.wtReceived||lot.wtReceived;
      return {...lot,
        wtReceived:newWt,
        wtAvailable:Math.max(0,newWt-(lot.wtIssued||0)),
        heatNo:editedLine.heatNo||lot.heatNo||"",
        mtcNo:editedLine.mtcNo||lot.mtcNo||"",
        bayId:editGrnForm.bayId||lot.bayId,
        receivedDate:editGrnForm.date||lot.receivedDate,
        qtyReceived:editedLine.qtyReceived||lot.qtyReceived||0,
      };
    }));
    showToast("GRN updated successfully");
    setEditGrnModal(null);
    setEditGrnForm({});
  };
  const saveGRN = (poId) => {
    const po = pos.find(p=>p.id===poId);
    const ts = Date.now();
    const yr = new Date().getFullYear();
    const grnId = nextGrnId(pos);
    const batchNoGrn = po?.vendorCode ? genBatchNo(po.vendorCode, pos, yr) : "";
    const newGrn = { ...grnForm, id:grnId, batchNo:batchNoGrn, date:today(), createdBy:user.name, lines:(grnForm.lines||[]) };
    setPos(prev => prev.map(p => {
      if (p.id!==poId) return p;
      const updatedLines = p.lines.map(pl => {
        const grnLine = newGrn.lines.find(gl=>gl.poLineId===pl.id);
        if (!grnLine) return pl;
        const newReceived = (pl.wtReceived||0)+(grnLine.actualWt||grnLine.wtReceived||0);
        const newQtyRec = (pl.qtyReceived||0)+(grnLine.qtyReceived||0);
        return { ...pl, wtReceived:newReceived, qtyReceived:newQtyRec, status:newReceived>=pl.wtOrdered?"fully_received":"partially_received" };
      });
      const allFull = updatedLines.every(l=>l.status==="fully_received");
      const anyRec = updatedLines.some(l=>l.status==="fully_received"||l.status==="partially_received");
      return { ...p, grns:[...p.grns, newGrn], lines:updatedLines, status:allFull?"fully_received":anyRec?"partially_received":"pending" };
    }));
    if (po && setStock) {
      const rawLots = buildStockLots(newGrn, po, grnId, ts);
      if (rawLots.length>0) setStock(prev=>{
        const numberedLots = [];
        rawLots.forEach(lot=>numberedLots.push({...lot, lotNo:genLotNo([...prev, ...numberedLots])}));
        const coveredOrders = po.coveredOrders||[];
        const finalLots = numberedLots.map(lot => {
          if (!coveredOrders.length) return lot;
          const poLine = (po.lines||[]).find(pl=>pl.id===lot.poLineId)||{};
          const allocs = (poLine.orderAllocations||[]).filter(a=>coveredOrders.includes(a.orderId));
          const reservations = allocs.length
            ? (() => { const totKg=allocs.reduce((s,a)=>s+(a.kg||0),0)||1; let left=lot.wtReceived; return allocs.map(a=>{ const k=Math.min(left, Math.round((a.kg/totKg)*lot.wtReceived*10)/10); left=Math.max(0,left-k); return {orderId:a.orderId,kg:k,reservedAt:today(),reservedBy:user.name,source:'grn_auto',grnId,poId:po.id}; }); })()
            : coveredOrders.map(oid=>({orderId:oid,kg:Math.round(lot.wtReceived/coveredOrders.length*10)/10,reservedAt:today(),reservedBy:user.name,source:'grn_auto',grnId,poId:po.id}));
          return {...lot, reservations};
        });
        return [...prev, ...finalLots];
      });
    }
    showToast("GRN saved — materials pending RM QC inspection");
    setGrnModal(null);
    setGrnForm({lines:[]});
  };

  if (selected) return <PODetail po={pos.find(p=>p.id===selected)||{}} onBack={()=>setSelected(null)} user={user} pos={pos} setPos={setPos} stock={stock} setStock={setStock} showToast={showToast} materials={materials} editGrnModal={editGrnModal} setEditGrnModal={setEditGrnModal} editGrnForm={editGrnForm} setEditGrnForm={setEditGrnForm} saveEditGRN={saveEditGRN} purchaseReqs={purchaseReqs} setPurchaseReqs={setPurchaseReqs} />;

  return (
    <div>
      {toast && <div style={{ position:"fixed", top:20, right:20, zIndex:2000, background:toast.color==="green"?T.greenBg:T.redBg, border:`1px solid ${toast.color==="green"?T.green:T.red}`, borderRadius:8, padding:"12px 20px", color:toast.color==="green"?T.green:T.red, fontSize:13, fontWeight:600 }}>{toast.msg}</div>}

      <div style={{ marginBottom:16 }}>
        <div style={{ fontSize:20, fontWeight:800, color:T.text }}>Purchase</div>
        <div style={{ fontSize:12, color:T.textMid }}>Purchase Orders · Requisitions · GRN · Multi-order coverage</div>
      </div>

      {/* Tab navigation */}
      <div style={{ display:"flex", gap:0, marginBottom:20, borderBottom:`2px solid ${T.border}` }}>
        {[["pos","Purchase Orders"],["requisitions","Requisitions"],["reports","Reports"]].map(([tab,lbl])=>{
          const nestPrs = (purchaseReqs||[]).filter(r=>r.type==="nesting"&&r.status==="pending");
          const badge = tab==="requisitions" && nestPrs.length>0 ? nestPrs.length : null;
          return (
            <button key={tab} onClick={()=>setPurTab(tab)} style={{ padding:"8px 18px", background:"none", border:"none", borderBottom:`2px solid ${purTab===tab?T.accent:"transparent"}`, marginBottom:-2, color:purTab===tab?T.accent:T.textMid, fontWeight:purTab===tab?700:400, fontSize:13, cursor:"pointer", display:"flex", alignItems:"center", gap:6 }}>
              {lbl}
              {badge && <span style={{ background:T.amber, color:"#000", borderRadius:10, padding:"1px 6px", fontSize:10, fontWeight:700 }}>{badge}</span>}
            </button>
          );
        })}
      </div>

      {purTab === "pos" && (<>
      <div style={{ display:"flex", gap:10, marginBottom:16, flexWrap:"wrap" }}>
        <StatCard label="Total POs" value={pos.length} color={T.text} />
        <StatCard label="Total Value" value={fmt.currency(totalPoValue)} color={T.accent} />
        <StatCard label="Pending" value={statusSummary.pending} color={T.amber} />
        <StatCard label="Part Received" value={statusSummary.partially_received} color={T.gold} />
        <StatCard label="Fully Received" value={statusSummary.fully_received} color={T.green} />
      </div>

      <div style={{ display:"flex", justifyContent:"flex-end", gap:8, marginBottom:12, alignItems:"center" }}>
        <label style={{ display:"flex", alignItems:"center", gap:6, fontSize:12, color:T.textMid, cursor:"pointer" }}>
          <input type="checkbox" checked={showCancelled} onChange={e=>setShowCancelled(e.target.checked)} />
          Show cancelled
        </label>
        {canEdit && <button onClick={()=>{setForm({servedOrders:[],coveredOrders:[],includesStock:false,lines:[],poDate:today()});setModal("new_po");}} style={css.btn.primary}>+ New PO</button>}
      </div>

      {pos.filter(po => showCancelled || po.status !== "cancelled").map(po => {
        const totalVal = po.lines.reduce((s,l)=>s+(l.totalPrice||0),0);
        const totalWtOrd = po.lines.reduce((s,l)=>s+resolvePoLineWt(l),0);
        const _grnWt = (g) => g.totalActualWt || (g.lines||[]).reduce((s,l)=>s+(l.actualWt||l.wtReceived||0),0);
        const totalWtRec = (po.grns||[]).filter(g=>g.status!=='reversed').reduce((s,g)=>s+_grnWt(g),0);
        return (
          <div key={po.id} onClick={()=>setSelected(po.id)} style={{ ...css.card, marginBottom:10, cursor:"pointer" }}
            onMouseEnter={e=>e.currentTarget.style.borderColor=T.borderHi}
            onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:8 }}>
              <div>
                <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                  <span style={{ fontFamily:T.fontMono, color:T.accentHi, fontSize:13, fontWeight:700 }}>{po.id}</span>
                  <Badge color={poStatusBadge[po.status]||"gray"}>{po.status.replace("_"," ")}</Badge>
                  {po.grns?.length>0 && <Badge color="teal">{po.grns.length} GRN(s)</Badge>}
                </div>
                <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{po.vendorName}</div>
                <div style={{ fontSize:12, color:T.textMid, marginTop:2 }}>
                  PO Date: {fmt.date(po.poDate)} · Expected: {fmt.date(po.expectedDelivery)} · {po.lines.length} line(s)
                </div>
                <div style={{ display:"flex", gap:12, marginTop:6, flexWrap:"wrap" }}>
                  <span style={{ fontSize:12, color:T.textMid }}>Value: <strong style={{color:T.green,fontFamily:T.fontMono}}>{fmt.currency(totalVal)}</strong></span>
                  <span style={{ fontSize:12, color:T.textMid }}>Wt Ordered: <strong style={{color:T.text,fontFamily:T.fontMono}}>{fmt.wtT(totalWtOrd)}</strong></span>
                  <span style={{ fontSize:12, color:T.textMid }}>Wt Received: <strong style={{color:totalWtRec>0?T.green:T.textLow,fontFamily:T.fontMono}}>{fmt.wtT(totalWtRec)}</strong></span>
                </div>
                <div style={{ display:"flex", gap:4, marginTop:6 }}>
                  {po.servedOrders.map(oid=><Badge key={oid} color="blue">{oid}</Badge>)}
                </div>
              </div>
              <div style={{ textAlign:"right" }}>
                <div style={{ fontSize:11, color:T.textMid, marginBottom:4 }}>Received</div>
                <div style={{ height:6, background:T.border, borderRadius:3, width:120, overflow:"hidden" }}>
                  <div style={{ height:"100%", width:`${totalWtOrd>0?Math.round(totalWtRec/totalWtOrd*100):0}%`, background:totalWtRec>=totalWtOrd?T.green:T.amber, borderRadius:3 }} />
                </div>
                <div style={{ fontSize:11, color:T.textMid, marginTop:4 }}>{totalWtOrd>0?Math.round(totalWtRec/totalWtOrd*100):0}%</div>
              </div>
            </div>
          </div>
        );
      })}
      </>)}

      {/* Requisitions Tab */}
      {purTab === "reports" && (()=>{
        const openPrStatuses = ["pending","pending_store","forwarded","partially_converted"];
        const inDate = (d) => (!repFrom || (d||"")>=repFrom) && (!repTo || (d||"")<=repTo);
        const ageDays = (d) => { const n = Math.round((Date.now()-new Date(d).getTime())/86400000); return isNaN(n)?0:n; };
        const ageColor = (d) => d>30 ? T.red : d>14 ? "#EA580C" : d>7 ? T.amber : T.green;
        const AgePill = ({days}) => days ? (
          <span style={{ background:ageColor(days)+"22", color:ageColor(days), fontWeight:700, fontFamily:T.fontMono,
            borderRadius:10, padding:"1px 8px", fontSize:10 }}>{days}d</span>
        ) : null;
        const prIsRm = (pr) => pr.type!=="store" || (pr.lots||[]).some(l=>l.itemType!=="consumable");
        const prQtyWt = (pr) => {
          let sheets=0, bars=0, nos=0, wt=0; const other=[];
          (pr.lots||[]).forEach(l=>(l.lines||[]).forEach(ln=>{
            if (pr.type==="store") {
              const u=(ln.unit||"nos").toLowerCase();
              if (l.itemType!=="consumable" && u==="kg") wt += ln.qty||0;
              else other.push(`${ln.qty} ${ln.unit||"nos"}`);
            } else {
              const cls = matClass(l.matCode);
              if (cls==="sheet") sheets+=prLineRemaining(pr,l,ln)+((pr.convertedLines||{})[prLineKey(pr.id,l.matCode,ln.sheetDim||ln.dims)]||0);
              else if (cls==="nos") nos+=ln.qty||0;
              else bars+=ln.qty||0;
              wt += sheetWt(l.matCode, ln.sheetDim||ln.dims)*(ln.qty||0);
            }
          }));
          const qty = [sheets?`${sheets} sh`:null, bars?`${bars} bars`:null, nos?`${nos} nos`:null, ...other].filter(Boolean).join(" + ")||"\u2014";
          return { qty, wt: Math.round(wt) };
        };
        // ── PR rows ──
        const prRowsAll = (purchaseReqs||[]).filter(r=>r.type==="nesting"||r.type==="store")
          .filter(r=> repItemType==="all" || (repItemType==="rm" ? prIsRm(r) : !prIsRm(r)))
          .filter(r=> !repOrder || (r.type==="store" ? r.orderId===repOrder : prOrderNos(r).includes((orders||[]).find(o=>o.id===repOrder)?.orderNo||repOrder)))
          .filter(r=> inDate(r.createdAt))
          .sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||""));
        const prRows = prRowsAll.map(pr=>{
          const qw = prQtyWt(pr);
          return { _pr:pr, "PR No":pr.id, "Type":pr.type==="store"?"Store":"Nesting",
            "Order": pr.type==="store" ? ((orders||[]).find(o=>o.id===pr.orderId)?.orderNo||(pr.orderId||"General")) : prOrderNos(pr).join(", "),
            "Items":(pr.lots||[]).map(l=>l.matCode).join("; "),
            "Qty":qw.qty, "Wt (kg)":qw.wt||"", "Status":pr.status, "Raised":pr.createdAt||"", "By":pr.createdBy||"",
            "PO(s)":(pr.poIds||[pr.poId]).filter(Boolean).join(", "),
            "Age": openPrStatuses.includes(pr.status) ? ageDays(pr.createdAt) : "" };
        });
        const prTotWt = prRows.reduce((s,r)=>s+(parseFloat(r["Wt (kg)"])||0),0);
        const prOpenCnt = prRows.filter(r=>openPrStatuses.includes(r.Status)).length;
        // ── PO rows ──
        const poRowsAll = [];
        (pos||[]).filter(p=>p.status!=="cancelled").filter(p=>inDate(p.poDate)).forEach(p=>{
          (p.lines||[]).forEach(ln=>{
            const perUnit = ln.pricingMethod==="PerUnit";
            if (repItemType==="rm" && perUnit && (ln.unit||"").toLowerCase()!=="kg" && !ln.matCode?.includes("/")) return;
            if (repItemType==="consumables" && !perUnit) return;
            const ordered = perUnit ? (ln.qtyOrdered||ln.qty||0) : (ln.wtOrdered||0);
            const received = perUnit ? (ln.qtyReceived||0) : (ln.wtReceived||0);
            const bal = Math.max(0, ordered-received);
            if (repPoView==="outstanding" && bal<=0.01) return;
            if (repPoView==="outstanding" && ln.shortClosed) return;
            poRowsAll.push({ _po:p, _ln:ln, "PO No":p.id, "Vendor":p.vendorName||"", "PO Date":p.poDate||"",
              "Item":ln.itemCode||ln.matCode||"", "Unit":perUnit?(ln.unit||"nos"):"kg",
              "Ordered":Math.round(ordered*100)/100, "Received":Math.round(received*100)/100,
              "Balance":Math.round(bal*100)/100, "Recd %":ordered>0?Math.round(received/ordered*100):0,
              "Age": bal>0.01 ? ageDays(p.poDate) : "" });
          });
        });
        const poRows = repOrder ? poRowsAll : poRowsAll;   // POs are multi-order; order filter applies to PRs
        const poTotBalKg = poRows.filter(r=>r.Unit==="kg").reduce((s,r)=>s+(r.Balance||0),0);
        const poTotBalUnits = poRows.filter(r=>r.Unit!=="kg").reduce((s,r)=>s+(r.Balance||0),0);
        const exportXlsx = (rows, name) => {
          if (!rows.length) { showToast("Nothing to export"); return; }
          const clean = rows.map(({_pr,_po,...r})=>r);
          const wb = XLSX.utils.book_new();
          XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(clean), name.slice(0,31));
          XLSX.writeFile(wb, `${name.replace(/\s+/g,"_")}_${today()}.xlsx`);
        };
        // ── mini bar chart (pure SVG) ──
        const BarChart = ({data, unit}) => {
          const max = Math.max(...data.map(d=>d.v), 1);
          const w=560, bh=18, gap=6, lw=170;
          return (
            <svg width={w} height={data.length*(bh+gap)+6} style={{ display:"block" }}>
              {data.map((d,i)=>(
                <g key={i} transform={`translate(0,${i*(bh+gap)})`}>
                  <text x={lw-6} y={bh-5} textAnchor="end" fontSize={10} fill={T.textMid} fontFamily={T.fontMono}>{d.k.slice(0,26)}</text>
                  <rect x={lw} y={2} width={Math.max(2,(w-lw-70)*(d.v/max))} height={bh-6} rx={3} fill={T.accent} opacity={0.8} />
                  <text x={lw+Math.max(2,(w-lw-70)*(d.v/max))+6} y={bh-5} fontSize={10} fill={T.text} fontFamily={T.fontMono}>{fmt.num(Math.round(d.v))}{unit}</text>
                </g>
              ))}
            </svg>
          );
        };
        const prChart = (()=>{ const m={}; prRows.filter(r=>openPrStatuses.includes(r.Status)).forEach(r=>{ const k=r.Order||"\u2014"; m[k]=(m[k]||0)+(parseFloat(r["Wt (kg)"])||0); }); return Object.entries(m).map(([k,v])=>({k,v})).sort((a,b)=>b.v-a.v).slice(0,8); })();
        const poChart = (()=>{ const m={}; poRows.forEach(r=>{ if(r.Unit!=="kg")return; m[r.Vendor]=(m[r.Vendor]||0)+(r.Balance||0); }); return Object.entries(m).map(([k,v])=>({k,v})).sort((a,b)=>b.v-a.v).slice(0,8); })();
        const th = { textAlign:"left", padding:"6px 8px", color:T.text, fontWeight:700, borderBottom:`2px solid ${T.border}`, borderRight:`1px solid ${T.border}`, fontSize:11, whiteSpace:"nowrap", background:T.bgInput, position:"sticky", top:0 };
        const td = { padding:"4px 8px", borderBottom:`1px solid ${T.border}`, borderRight:`1px solid ${T.border}`, fontSize:11, whiteSpace:"nowrap" };
        const renderTable = (rows, onRowJump, totals) => rows.length===0
          ? <div style={{ ...css.card, textAlign:"center", padding:24, color:T.textLow, fontSize:12 }}>No rows match the filters.</div>
          : (
            <div style={{ ...css.card, overflow:"auto", padding:0, maxHeight:560 }}>
              <table style={{ borderCollapse:"collapse", width:"100%" }}>
                <thead><tr>
                  {Object.keys(rows[0]).filter(k=>!k.startsWith("_")).map(h=><th key={h} style={th}>{h}</th>)}
                  {onRowJump && <th style={th}></th>}
                </tr></thead>
                <tbody>
                  {rows.map((r,i)=>(
                    <tr key={i} style={{ background:i%2?T.bg:"transparent" }}>
                      {Object.entries(r).filter(([k])=>!k.startsWith("_")).map(([k,v])=>(
                        <td key={k} style={{ ...td, fontFamily:["PR No","PO No","PO(s)","Items","Item"].includes(k)?T.fontMono:T.font }}>
                          {k==="Age" ? <AgePill days={v} /> : String(v)}
                        </td>
                      ))}
                      {onRowJump && <td style={{ ...td, whiteSpace:"nowrap" }}>
                        <button onClick={()=>onRowJump(r)} style={{ ...css.btn.sm, fontSize:10, padding:"2px 8px" }}>→ GRN</button>
                        {r._ln && (r.Balance||0)>0 && !r._ln.shortClosed && canEdit && (
                          <button onClick={()=>{
                            const reason = window.prompt(`Short-close ${r["PO No"]} · ${r.Item}? Balance ${r.Balance} ${r.Unit} will no longer be expected. Reason:`);
                            if (reason===null) return;
                            setPos(prev=>prev.map(p=>p.id!==r._po.id?p:{...p, lines:(p.lines||[]).map(l=>l!==r._ln && l.id!==r._ln.id ? l : {...l, shortClosed:true, shortCloseReason:reason||"", shortClosedAt:today(), shortClosedBy:user.username||user.name})}));
                            showToast("Line short-closed");
                          }} style={{ ...css.btn.sm, fontSize:10, padding:"2px 8px", marginLeft:4, background:T.redBg, color:T.red, border:`1px solid ${T.redLo}` }}>Short-close</button>
                        )}
                      </td>}
                    </tr>
                  ))}
                  {totals && (
                    <tr>
                      {totals.map((t,i)=><td key={i} style={{ ...td, fontWeight:700, background:T.bgInput, fontFamily:T.fontMono }}>{t}</td>)}
                      {onRowJump && <td style={{ ...td, background:T.bgInput }}></td>}
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          );
        return (
          <div>
            <div style={{ display:"flex", gap:10, alignItems:"center", flexWrap:"wrap", marginBottom:12 }}>
              {[["pr","PR Register"],["po","PO Register"]].map(([t,l])=>(
                <button key={t} onClick={()=>setRepTab(t)} style={{ ...css.btn.sm,
                  background:repTab===t?T.accent:T.bgInput, color:repTab===t?T.bg:T.textMid, fontWeight:700 }}>{l}</button>
              ))}
              <span style={{ width:1, height:22, background:T.border }} />
              <Sel value={repItemType} onChange={e=>setRepItemType(e.target.value)} style={{ width:130 }}>
                <option value="all">RM + Consumables</option><option value="rm">RM only</option><option value="consumables">Consumables only</option>
              </Sel>
              <Sel value={repOrder} onChange={e=>setRepOrder(e.target.value)} style={{ width:190 }}>
                <option value="">All orders</option>
                {(orders||[]).map(o=><option key={o.id} value={o.id}>{o.orderNo||o.id}</option>)}
              </Sel>
              <span style={{ fontSize:11, color:T.textMid }}>From</span>
              <input type="date" value={repFrom} onChange={e=>setRepFrom(e.target.value)} style={{ ...css.input, width:135 }} />
              <span style={{ fontSize:11, color:T.textMid }}>To</span>
              <input type="date" value={repTo} onChange={e=>setRepTo(e.target.value)} style={{ ...css.input, width:135 }} />
              {repTab==="po" && (
                <Sel value={repPoView} onChange={e=>setRepPoView(e.target.value)} style={{ width:150 }}>
                  <option value="outstanding">GRN outstanding</option><option value="all">All PO lines</option>
                </Sel>
              )}
              <label style={{ fontSize:11, color:T.textMid, display:"flex", alignItems:"center", gap:4, cursor:"pointer" }}>
                <input type="checkbox" checked={repChart} onChange={e=>setRepChart(e.target.checked)} /> Chart
              </label>
              <div style={{ marginLeft:"auto" }}>
                <button onClick={()=>exportXlsx(repTab==="pr"?prRows:poRows, repTab==="pr"?"PR Register":"PO Register")} style={css.btn.secondary}>⬇ Export XLSX</button>
              </div>
            </div>
            {repTab==="pr" ? (
              <>
                <div style={{ fontSize:12, color:T.textMid, marginBottom:6 }}>
                  <b style={{ color:T.text }}>{prRows.length}</b> PRs ({prOpenCnt} open) · total RM weight <b style={{ fontFamily:T.fontMono, color:T.text }}>{fmt.num(Math.round(prTotWt))} kg</b>
                </div>
                {repChart && prChart.length>0 && (
                  <div style={{ ...css.card, marginBottom:10, padding:"10px 14px" }}>
                    <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:6 }}>OPEN PR WEIGHT BY ORDER (kg)</div>
                    <BarChart data={prChart} unit="" />
                  </div>
                )}
                {renderTable(prRows, null, ["TOTAL","","","",`${prRows.length} PRs`,fmt.num(Math.round(prTotWt)),"","","","",""])}
              </>
            ) : (
              <>
                <div style={{ fontSize:12, color:T.textMid, marginBottom:6 }}>
                  <b style={{ color:T.text }}>{poRows.length}</b> lines · balance <b style={{ fontFamily:T.fontMono, color:T.text }}>{fmt.num(Math.round(poTotBalKg))} kg</b>{poTotBalUnits>0 && <> + <b style={{ fontFamily:T.fontMono, color:T.text }}>{fmt.num(Math.round(poTotBalUnits))} units</b></>}
                </div>
                {repChart && poChart.length>0 && (
                  <div style={{ ...css.card, marginBottom:10, padding:"10px 14px" }}>
                    <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:6 }}>GRN BALANCE BY VENDOR (kg)</div>
                    <BarChart data={poChart} unit="" />
                  </div>
                )}
                {renderTable(poRows, (r)=>{ setSelected(r._po.id); setPurTab("pos"); }, ["TOTAL","","","","",`—`,`—`,fmt.num(Math.round(poTotBalKg))+" kg"+(poTotBalUnits>0?` + ${fmt.num(Math.round(poTotBalUnits))} u`:""),"",""])}
              </>
            )}
          </div>
        );
      })()}

      {purTab === "requisitions" && (()=>{
        const nestingPrs = (purchaseReqs||[]).filter(r=>r.type==="nesting"||r.type==="store")
          .filter(r=>showCancelledPrs || !["cancelled","stale"].includes(r.status))
          .filter(r=>!prOrderFilter || prOrderNos(r).includes(prOrderFilter))
          .filter(prMatchesType)
          .filter(r=>!prCatFilter || (r.lots||[]).some(l=>(l.category||"").toLowerCase()===prCatFilter.toLowerCase()))
          .filter(r=>!prMakeFilter || (r.lots||[]).some(l=>(l.make||"").toLowerCase()===prMakeFilter.toLowerCase()))
          .sort((a,b)=>(b.createdAt||"").localeCompare(a.createdAt||""));
        const catOptions = [...new Set((purchaseReqs||[]).flatMap(r=>(r.lots||[]).map(l=>l.category)).filter(Boolean))].sort();
        const makeOptions = [...new Set((purchaseReqs||[]).flatMap(r=>(r.lots||[]).map(l=>l.make)).filter(Boolean))].sort();
        const otherTypes = [...new Set((purchaseReqs||[]).filter(r=>r.type==="nesting").flatMap(prSectionTypes))]
          .filter(t=>t!=="PLATE" && !ROLLED_TYPES.includes(t)).sort();
        const selectableIds = nestingPrs.filter(pr=>["pending","partially_converted"].includes(pr.status)).map(pr=>pr.id);
        const prStatusBadge = { pending:"amber", pending_store:"amber", forwarded:"blue", converted:"green", fulfilled:"green", partially_converted:"purple", cancelled:"gray", stale:"red" };
        return (
          <div>
            {(()=>{
              // Duplicate open PRs for the same material + order (typically re-nests)
              const groups = {};
              nestingPrs.filter(r=>r.type==="nesting" && ["pending","partially_converted"].includes(r.status)).forEach(r=>{
                (r.lots||[]).forEach(l=>{
                  const key = normMatCode(l.matCode)+"|"+prOrderNos(r).sort().join(",");
                  if(!groups[key]) groups[key] = { matCode:l.matCode, orders:prOrderNos(r).join(", "), prs:[] };
                  if(!groups[key].prs.includes(r)) groups[key].prs.push(r);
                });
              });
              const dupGroups = Object.values(groups).filter(g=>g.prs.length>1);
              if (!dupGroups.length) return null;
              return (
                <div style={{ ...css.card, border:`1px solid ${T.amber}`, background:T.amberBg, padding:"10px 16px", marginBottom:12 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:"#92400E", marginBottom:6 }}>
                    ⚠ Possible duplicate requisitions — same material and order ({dupGroups.length} group{dupGroups.length>1?"s":""}). Keep one; the rest are discarded as superseded.
                  </div>
                  {dupGroups.map((g,gi)=>(
                    <div key={gi} style={{ display:"flex", alignItems:"center", gap:8, flexWrap:"wrap", fontSize:11, padding:"4px 0", borderTop:gi?`1px solid ${T.amber}44`:"none" }}>
                      <span style={{ fontFamily:T.fontMono, fontWeight:700 }}>{g.matCode}</span>
                      <span style={{ color:T.textMid }}>{g.orders}</span>
                      {g.prs.map(p=>(
                        <span key={p.id} style={{ display:"flex", alignItems:"center", gap:4, background:"#fff", border:`1px solid ${T.border}`, borderRadius:6, padding:"2px 6px" }}>
                          <span style={{ fontFamily:T.fontMono, fontSize:10 }}>{p.id.slice(-8)} · {p.createdAt}</span>
                          {canEdit && <button onClick={()=>{
                            const others = g.prs.filter(x=>x.id!==p.id);
                            if (!window.confirm(`Keep ${p.id} and discard ${others.map(o=>o.id).join(", ")} as superseded?`)) return;
                            setPurchaseReqs(prev=>prev.map(r=>others.some(o=>o.id===r.id)?{...r,status:"cancelled",cancelledAt:today(),cancelReason:`Superseded — kept ${p.id}`}:r));
                            showToast(`Kept ${p.id}; ${others.length} discarded`);
                          }} style={{ ...css.btn.sm, fontSize:9, padding:"1px 6px" }}>Keep this</button>}
                        </span>
                      ))}
                    </div>
                  ))}
                </div>
              );
            })()}
            {(()=>{
              const s = { openWt:0, convWt:0, openSheets:0, openBars:0, openNos:0, convSheets:0, convBars:0, convNos:0, unweighed:new Set() };
              nestingPrs.forEach(pr=>{
                if (["cancelled","stale"].includes(pr.status)) return;
                (pr.lots||[]).filter(l=>!l.fulfilledFromStock).forEach(l=>(l.lines||[]).forEach(ln=>{
                  const rem = prLineRemaining(pr,l,ln);
                  const conv = Math.max(0,(ln.qty||0)-rem);
                  const cls = l.itemType==="consumable" ? "nos" : matClass(l.matCode);
                  if (cls==="nos") { s.openNos+=rem; s.convNos+=conv; return; }
                  const w = prLineWt(pr, l, ln);
                  if (w>0) { s.openWt+=w*rem; s.convWt+=w*conv; }
                  else if (rem+conv>0) s.unweighed.add(l.matCode);
                  if (pr.type==="store" && (ln.unit||"nos")!=="nos") return; // kg/m lines: weight-only, no piece count
                  if (cls==="sheet") { s.openSheets+=rem; s.convSheets+=conv; }
                  else { s.openBars+=rem; s.convBars+=conv; }
                }));
              });
              const qtyStr = (sh,br,ns) => [sh>0?sh+" sheet"+(sh!==1?"s":""):null, br>0?br+" bar"+(br!==1?"s":"")+"/lengths":null, ns>0?ns+" nos":null].filter(Boolean).join(" + ")||"0";
              return (
                <div style={{ ...css.card, padding:"10px 16px", marginBottom:12 }}>
                  <div style={{ fontSize:13, marginBottom:4 }}>
                    <span style={{ fontWeight:700, color:T.textMid }}>Weight&nbsp;&nbsp;</span>
                    Open: <b style={{ fontFamily:T.fontMono }}>{(s.openWt/1000).toFixed(2)} T</b>
                    {s.unweighed.size>0 && (
                      <button onClick={()=>{ setQuickWtVals({}); setQuickWtModal([...s.unweighed]); }}
                        style={{ ...css.btn.ghost, color:T.amber, fontWeight:700, fontSize:11, padding:"1px 6px" }}
                        title="Click to add weights for these materials">
                        &#9888; excl. {s.unweighed.size} unweighed material{s.unweighed.size!==1?"s":""}
                      </button>
                    )}
                    <span style={{ color:T.textLow }}> &nbsp;&middot;&nbsp; </span>
                    Converted: <b style={{ fontFamily:T.fontMono }}>{(s.convWt/1000).toFixed(2)} T</b>
                  </div>
                  <div style={{ fontSize:12, color:T.textMid }}>
                    <span style={{ fontWeight:700 }}>Quantity&nbsp;&nbsp;</span>
                    Open: {qtyStr(s.openSheets,s.openBars,s.openNos)}
                    <span style={{ color:T.textLow }}> &nbsp;&middot;&nbsp; </span>
                    Converted: {qtyStr(s.convSheets,s.convBars,s.convNos)}
                  </div>
                </div>
              );
            })()}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12, gap:12 }}>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <div style={{ fontSize:13, color:T.textMid }}>{nestingPrs.length} requisition{nestingPrs.length!==1?"s":""}</div>
                {["store_admin","purchase_admin","super_admin"].includes(user.role) && (
                  <button onClick={()=>{ setSprForm({ orderId:"", neededBy:"", remarks:"", lines:[blankSprLine()] }); setSprModal(true); }}
                    style={{ ...css.btn.sm, background:T.accent, color:T.bg }}>+ Store Requisition</button>
                )}
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:8, flexWrap:"wrap" }}>
                <span style={{ fontSize:11, color:T.textMid, fontWeight:700 }}>Order:</span>
                <Sel value={prOrderFilter} onChange={e=>setPrOrderFilter(e.target.value)} style={{ width:220 }}>
                  <option value="">All orders</option>
                  {(orders||[]).map(o=><option key={o.id} value={o.orderNo||o.id}>{o.orderNo||o.id}{o.clientName?` — ${o.clientName}`:""}</option>)}
                </Sel>
                <span style={{ fontSize:11, color:T.textMid, fontWeight:700 }}>Type:</span>
                <Sel value={prTypeFilter} onChange={e=>setPrTypeFilter(e.target.value)} style={{ width:190 }}>
                  <option value="">All types</option>
                  <option value="PLATE">Plates</option>
                  <option value="ROLLED">Rolled sections (ISA/ISMC/ISMB/UB/UC…)</option>
                  {otherTypes.map(t=><option key={t} value={t}>{t}</option>)}
                </Sel>
                {catOptions.length>0 && (
                  <Sel value={prCatFilter} onChange={e=>setPrCatFilter(e.target.value)} style={{ width:130 }}>
                    <option value="">All categories</option>
                    {catOptions.map(c=><option key={c} value={c}>{c}</option>)}
                  </Sel>
                )}
                {makeOptions.length>0 && (
                  <Sel value={prMakeFilter} onChange={e=>setPrMakeFilter(e.target.value)} style={{ width:130 }}>
                    <option value="">All makes</option>
                    {makeOptions.map(m=><option key={m} value={m}>{m}</option>)}
                  </Sel>
                )}
                <label style={{ fontSize:11, color:T.textMid, display:"flex", alignItems:"center", gap:4, cursor:"pointer" }}>
                  <input type="checkbox" checked={showCancelledPrs} onChange={e=>setShowCancelledPrs(e.target.checked)} />
                  Show cancelled
                </label>
                {selectableIds.length>0 && canEdit && (
                  <button onClick={()=>setSelectedPrs(prev=>[...new Set([...prev, ...selectableIds])])}
                    style={{ ...css.btn.secondary, fontSize:11, padding:"5px 10px" }}>
                    Select all {selectableIds.length}
                  </button>
                )}
              </div>
            </div>
            {nestingPrs.length===0 && (
              <div style={{ ...css.card, textAlign:"center", padding:40, color:T.textLow, fontSize:13 }}>
                No purchase requisitions yet. Raise one from MRP → Nesting Runs.
              </div>
            )}
            {nestingPrs.map(pr=>{
              const po = pr.poId ? pos.find(p=>p.id===pr.poId) : null;
              return (
                <div key={pr.id} style={{ ...css.card, marginBottom:10 }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:8 }}>
                    <div style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
                      {(pr.status==="pending"||pr.status==="forwarded"||pr.status==="partially_converted") && canEdit && (
                        <input type="checkbox" checked={selectedPrs.includes(pr.id)}
                          onChange={e=>setSelectedPrs(prev=>e.target.checked?[...prev,pr.id]:prev.filter(x=>x!==pr.id))}
                          style={{ marginTop:3, accentColor:T.accent, width:15, height:15, cursor:"pointer" }} />
                      )}
                    <div>
                      <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                        <span style={{ fontFamily:T.fontMono, color:T.accentHi, fontSize:13, fontWeight:700 }}>{pr.id}</span>
                        <Badge color={prStatusBadge[pr.status]||"gray"}>{pr.status}</Badge>
                        {prOrderNos(pr).map(on=><Badge key={on} color="teal">{on}</Badge>)}
                      </div>
                      <div style={{ fontSize:12, color:T.textMid }}>
                        {fmt.date(pr.createdAt)} · by {pr.createdBy}
                      </div>
                      <div style={{ fontSize:12, color:T.textMid, marginTop:2 }}>
                        {pr.type==="store"
                          ? <>Store requisition{pr.orderId ? <> · Order: <span style={{ fontFamily:T.fontMono, color:T.accent }}>{(orders||[]).find(o=>o.id===pr.orderId)?.orderNo||pr.orderId}</span></> : " · General stock"}{pr.neededBy?` · Needed by ${fmt.date(pr.neededBy)}`:""}</>
                          : <>Source: <span style={{ fontFamily:T.fontMono, color:T.accent }}>{pr.nestingBatchId}</span></>}
                      </div>
                      {pr.cancelReason && (
                        <div style={{ fontSize:11, color:T.textLow, marginTop:4 }}>Cancel reason: {pr.cancelReason}</div>
                      )}
                      {(pr.lots||[]).some(l=>l.fulfilledFromStock) && (
                        <div style={{ fontSize:11, color:T.green, marginTop:4 }}>
                          ✓ {(pr.lots||[]).filter(l=>l.fulfilledFromStock).map(l=>l.matCode).join(", ")} fulfilled from stock
                        </div>
                      )}
                      {pr.status==="partially_converted" && (
                        <div style={{ fontSize:11, color:T.amber, marginTop:4 }}>
                          {prRemainingTotal(pr)} sheet(s) remaining · POs: {(pr.poIds||[pr.poId]).filter(Boolean).join(", ")}
                        </div>
                      )}
                      {(()=>{
                        // Orphaned conversion: converted, but every linked PO is cancelled or
                        // missing (pre-8-Jul cancellations happened before revert existed).
                        if (pr.status!=="converted") return null;
                        const linked = (pr.poIds||[pr.poId]).filter(Boolean);
                        if (!linked.length) return null;
                        const live = linked.some(id=>{ const po=(pos||[]).find(p=>p.id===id); return po && po.status!=="cancelled"; });
                        if (live) return null;
                        return (
                          <div style={{ fontSize:11, color:T.red, marginTop:4, display:"flex", alignItems:"center", gap:8 }}>
                            All linked PO(s) cancelled — quantities are stranded.
                            {canEdit && <button onClick={()=>{
                              if(!window.confirm(`Revert ${pr.id} to pending? Its quantities become convertible again.`)) return;
                              setPurchaseReqs(prev=>prev.map(r=>r.id!==pr.id?r:{...r, status:"pending", convertedLines:{}, poId:null, poIds:[],
                                remarks:((r.remarks||"")+` · Reverted to pending ${today()} — linked PO(s) ${linked.join(", ")} cancelled`).trim()}));
                            }} style={{ ...css.btn.sm, background:T.redBg, color:T.red, border:`1px solid ${T.redLo}` }}>Revert to pending</button>}
                          </div>
                        );
                      })()}
                    </div>{/* end pr info */}
                    </div>{/* end left col (checkbox + info) */}
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                      {pr.type==="store" && pr.status==="pending_store" && isStoreRole && (
                        <>
                          {(pr.lots||[]).some(l=>l.itemType==="rm" && !l.fulfilledFromStock) && (
                            <button onClick={()=>{
                              const cands = (pr.lots||[]).map((l,li)=>({l,li})).filter(({l})=>{
                                if (l.itemType!=="rm" || l.fulfilledFromStock) return false;
                                const ln = (l.lines||[])[0]; if (!ln || (ln.unit||"")!=="kg") return false;
                                const kg = (stock||[]).filter(s=>normMatCode(s.matCode)===normMatCode(l.matCode) && !["rejected","returned","written_off"].includes(s.status)).reduce((a,s)=>a+(s.wtAvailable||0),0);
                                return kg >= (ln.qty||0);
                              });
                              if (!cands.length) { showToast("No RM line is fully coverable from current stock"); return; }
                              const names = cands.map(({l})=>`${l.matCode} (${(l.lines[0]||{}).qty} kg)`).join(", ");
                              if (!window.confirm(`Mark as fulfilled from stock: ${names}? These lines will NOT go to purchase. Issue the material via Stock as usual.`)) return;
                              setPurchaseReqs(prev=>prev.map(r=>{
                                if (r.id!==pr.id) return r;
                                const lots = r.lots.map((l,li)=> cands.some(c=>c.li===li) ? {...l, fulfilledFromStock:true, fulfilledAt:today(), fulfilledBy:user.username||user.name} : l);
                                const allDone = lots.every(l=>l.fulfilledFromStock);
                                return {...r, lots, status: allDone ? "fulfilled" : r.status,
                                  remarks:((r.remarks||"")+` · ${cands.length} line(s) fulfilled from stock ${today()}`).trim()};
                              }));
                            }} style={{ ...css.btn.sm, background:T.greenBg, color:T.green, border:`1px solid ${T.green}` }}>Fulfil from stock</button>
                          )}
                          <button onClick={()=>forwardSpr(pr)} style={{ ...css.btn.sm, background:T.accent, color:T.bg }}>Forward to Purchase</button>
                        </>
                      )}
                      {pr.type==="store" && ["pending_store","forwarded"].includes(pr.status) && (isStoreRole||canEdit) && (
                        <button onClick={()=>{
                          // Converted-guard: once any qty is on a PO the PR can no
                          // longer be withdrawn — cancel/revert the PO first.
                          const convQty = Object.values(pr.convertedLines||{}).reduce((a,b)=>a+(b||0),0);
                          if (convQty>0) { showToast("Quantities already carried onto a PO — cancel/revert the PO first","red"); return; }
                          const reason = window.prompt(`Cancel ${pr.id}? Reason (optional):`, "");
                          if (reason===null) return;
                          setPurchaseReqs(prev=>prev.map(r=>r.id!==pr.id?r:{...r, status:"cancelled", cancelledAt:today(), cancelledBy:user.username||user.name, cancelReason:(reason||`Withdrawn by ${user.username||user.name}`)}));
                          showToast(`${pr.id} cancelled`);
                        }} style={{ ...css.btn.sm, background:T.redBg, color:T.red, border:`1px solid ${T.redLo}` }}>Cancel Requisition</button>
                      )}
                      {(pr.status==="pending"||pr.status==="forwarded"||pr.status==="partially_converted") && canEdit && (
                        <>
                          <button onClick={()=>{
                            setSelectedPrs([pr.id]);
                            setCombineForm({vendorId:"",poDate:today(),expectedDelivery:"",notes:"",rates:{},lineQtys:{}});
                            setCombineModal(true);
                          }} style={{ ...css.btn.sm, background:T.accent, color:T.bg }}>{pr.status==="partially_converted"?"Convert Remaining":"Convert to PO"}</button>
                          {pr.status==="pending" && <button onClick={()=>{
                            if (!window.confirm("Cancel this purchase requisition?")) return;
                            setPurchaseReqs(prev=>prev.map(r=>r.id!==pr.id?r:{...r,status:"cancelled",cancelledAt:today(),cancelReason:"Manually cancelled"}));
                          }} style={{ ...css.btn.sm, background:T.redBg, color:T.red, border:`1px solid ${T.redLo}` }}>Discard PR</button>}
                        </>
                      )}
                      {pr.status==="converted" && po && (
                        <button onClick={()=>{setPurTab("pos");setSelected(po.id);}} style={{ ...css.btn.sm, background:T.greenBg, color:T.green, border:`1px solid ${T.green}` }}>View {po.id}</button>
                      )}
                    </div>
                  </div>
                  {/* Line items */}
                  {(pr.lots||[]).length>0 && (
                    <div style={{ marginTop:10, borderTop:`1px solid ${T.border}`, paddingTop:10 }}>
                      <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                        <thead><tr>
                          {["Material Code","Total Sheets","Breakdown by Dimension","Wt Req (kg)","Parts"].map(h=><th key={h} style={{ textAlign:"left",padding:"3px 8px",color:T.textMid,fontWeight:600,borderBottom:`1px solid ${T.border}` }}>{h}</th>)}
                        </tr></thead>
                        <tbody>
                          {(pr.lots||[]).map((l,i)=>(
                            <tr key={i} style={{ background:i%2===0?"transparent":T.bg }}>
                              <td style={{ padding:"4px 8px", fontFamily:T.fontMono, fontSize:11, color:T.text, fontWeight:700 }}>{l.matCode}</td>
                              <td style={{ padding:"4px 8px", fontFamily:T.fontMono, color:T.accent, fontWeight:700 }}>{pr.type==="store" ? `${(l.lines||[]).reduce((s,ln)=>s+(ln.qty||0),0)} ${(l.lines||[])[0]?.unit||"nos"}` : l.sheetCount}</td>
                              <td style={{ padding:"4px 8px", fontSize:11 }}>
                                {(l.lines||[]).length>0
                                  ? <div style={{ display:"flex", flexDirection:"column", gap:3 }}>
                                      {(l.lines||[]).map((ln,li)=>(
                                        <span key={li}>
                                          <span style={{ fontFamily:T.fontMono, color:T.amber, fontWeight:700 }}>{ln.qty}</span>
                                          {pr.type==="store" ? (
                                            <>
                                              <span style={{ color:T.textMid }}> {ln.unit||"nos"}</span>
                                              {ln.sheetDim ? <span style={{ fontFamily:T.fontMono, color:T.accentHi }}> × {ln.sheetDim}{/^\d+$/.test(String(ln.sheetDim))?" mm":""}</span> : null}
                                            </>
                                          ) : (
                                            <>
                                              <span style={{ color:T.textMid }}> × </span>
                                              <span style={{ fontFamily:T.fontMono, color:T.accentHi }}>{ln.sheetDim}</span>
                                            </>
                                          )}
                                        </span>
                                      ))}
                                    </div>
                                  : <span style={{ color:T.textLow }}>—</span>}
                              </td>
                              <td style={{ padding:"4px 8px", fontFamily:T.fontMono, color:T.accent, fontSize:11 }}>
                                {(()=>{
                                  const rmWt = (l.lines||[]).reduce((s,ln)=>s+prLineWt(pr,l,ln)*(ln.qty||0),0);
                                  const b = (nestingBatches||[]).find(x=>x.id===pr.nestingBatchId);
                                  const bl = b ? (b.lots||[]).find(x=>normMatCode(x.matCode)===normMatCode(l.matCode)) : null;
                                  const utils = bl ? (bl.sheets||[]).map(sh=>sh.utilisPct).filter(u=>u>0) : [];
                                  const util = utils.length ? utils.reduce((a,c)=>a+c,0)/utils.length : (bl&&bl.npPct>0 ? bl.npPct : 0);
                                  return (<>
                                    {fmt.num(Math.round(rmWt))}
                                    {util>0 && <div style={{ fontSize:9, color:T.textLow }}>≈ {fmt.num(Math.round(rmWt*util/100))} kg net parts · {util.toFixed(0)}%</div>}
                                  </>);
                                })()}
                              </td>
                              <td style={{ padding:"4px 8px", color:T.textMid }}>{(l.parts||[]).length}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              );
            })}

            {/* Sticky combine bar */}
            {selectedPrs.length >= 1 && canEdit && (
              <div style={{ position:"sticky", bottom:16, background:T.bgCard, border:`2px solid ${T.accent}`, borderRadius:10, padding:"12px 20px", display:"flex", alignItems:"center", justifyContent:"space-between", boxShadow:"0 4px 24px #0008", zIndex:200, marginTop:12 }}>
                <span style={{ color:T.accent, fontWeight:700, fontSize:13 }}>
                  {selectedPrs.length} requisition{selectedPrs.length>1?"s":""} selected
                  {" · "}<span style={{ color:T.textMid, fontWeight:400 }}>
                    {fmt.num((purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id)).reduce((s,pr)=>{
                      return s + (pr.lots||[]).reduce((ss,l)=>(l.lines||[]).reduce((sss,ln)=>sss+(prLineWt(pr,l,ln)*prLineRemaining(pr,l,ln)),ss),0);
                    },0))} kg to convert
                  </span>
                </span>
                <div style={{ display:"flex", gap:8 }}>
                  <button onClick={()=>setSelectedPrs([])} style={css.btn.secondary}>Clear</button>
                  <button onClick={()=>{ setCombineForm({vendorId:"",poDate:today(),expectedDelivery:"",notes:"",rates:{},lineQtys:{}}); setCombineModal(true); }} style={css.btn.primary}>{selectedPrs.length>1?"Combine into PO →":"Convert to PO →"}</button>
                </div>
              </div>
            )}
          </div>
        );
      })()}

      {/* Combined PO Modal */}
      {sprModal && (
        <Modal title="New Store Requisition" onClose={()=>setSprModal(false)} width={880}>
          <G2>
            <Field label="Order / Project (optional)">
              <Sel value={sprForm.orderId} onChange={e=>setSprForm(f=>({...f,orderId:e.target.value}))}>
                <option value="">General stock (no order)</option>
                {(orders||[]).map(o=><option key={o.id} value={o.id}>{o.orderNo||o.id}{o.clientName?` — ${o.clientName}`:""}</option>)}
              </Sel>
            </Field>
            <Field label="Needed by">
              <input type="date" value={sprForm.neededBy} onChange={e=>setSprForm(f=>({...f,neededBy:e.target.value}))} style={css.input} />
            </Field>
          </G2>
          <div style={{ fontSize:11, fontWeight:700, color:T.textMid, margin:"10px 0 6px", letterSpacing:"0.05em" }}>LINES</div>
          {(sprForm.lines||[]).map((ln,i)=>(
            <div key={i} style={{ display:"grid", gridTemplateColumns:"100px 1fr 92px 66px 62px 96px 130px auto", gap:6, marginBottom:6, alignItems:"center" }}>
              <Sel value={ln.itemType} onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,itemType:e.target.value,itemKey:"",unit:e.target.value==="rm"?"kg":"nos"}:x)}))}>
                <option value="rm">RM</option><option value="consumable">Consumable</option>
              </Sel>
              {ln.itemType==="rm" ? (
                <Sel value={ln.itemKey} onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,itemKey:e.target.value,category:(e.target.value||"").split("/")[0]}:x)}))}>
                  <option value="">Select material…</option>
                  {(materials||[]).filter(m=>m.active!==false).map(m=><option key={m.id} value={m.matCode}>{m.matCode}</option>)}
                </Sel>
              ) : ln.itemKey==="__other" ? (
                <input value={ln.desc} placeholder="Item description (free text)" autoFocus
                  onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,desc:e.target.value}:x)}))} style={css.input} />
              ) : (
                <Sel value={ln.itemKey} onChange={e=>{
                  const v = e.target.value;
                  const c = (consumables||[]).find(x=>x.id===v);
                  setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi!==i?x:{...x,itemKey:v,
                    desc:c?c.name:"", category:c?(c.subCategory||c.category||""):"",
                    unit:c?((c.unit||"nos").toLowerCase()):x.unit, make:""})}));
                }}>
                  <option value="">Select consumable…</option>
                  {[...new Set((consumables||[]).map(c=>c.subCategory||c.category||"other"))].sort().map(cat=>(
                    <optgroup key={cat} label={cat.toUpperCase()}>
                      {(consumables||[]).filter(c=>(c.subCategory||c.category||"other")===cat).map(c=>
                        <option key={c.id} value={c.id}>{c.name}</option>)}
                    </optgroup>
                  ))}
                  <option value="__other">Other (type manually)…</option>
                </Sel>
              )}
              {(()=>{
                // Dim/length cell: what the shared resolver needs to weigh the line.
                if (ln.itemType!=="rm" || !ln.itemKey || isNosOnly(ln.itemKey))
                  return <span style={{ fontSize:10, color:T.textLow, textAlign:"center" }}>—</span>;
                const u = ln.unit||"nos";
                if (u==="kg") return <span style={{ fontSize:10, color:T.textLow, textAlign:"center" }}>by weight</span>;
                if (u==="m")  return <span style={{ fontSize:10, color:T.textLow, textAlign:"center" }}>per metre</span>;
                const isSheet = matClass(ln.itemKey)==="sheet";
                const stds = matLib(ln.itemKey)?.standardLengths||[];
                return (
                  <div>
                    <input list={isSheet?undefined:`spr-len-${i}`} value={ln.dim||""} placeholder={isSheet?"LxW mm":"Length mm"}
                      onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,dim:e.target.value}:x)}))} style={css.input} />
                    {!isSheet && stds.length>0 && <datalist id={`spr-len-${i}`}>{stds.map(sl=><option key={sl} value={sl} />)}</datalist>}
                  </div>
                );
              })()}
              <input type="number" min={0} value={ln.qty} placeholder="Qty"
                onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,qty:e.target.value}:x)}))} style={css.input} />
              <Sel value={ln.unit} onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,unit:e.target.value}:x)}))}>
                {["kg","nos","m","L","set","box"].map(u=><option key={u} value={u}>{u}</option>)}
              </Sel>
              {(()=>{
                const c = ln.itemType==="consumable" ? (consumables||[]).find(x=>x.id===ln.itemKey) : null;
                return (c?.approvedMakes||[]).length ? (
                  <Sel value={ln.make} onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,make:e.target.value}:x)}))}>
                    <option value="">Any make</option>
                    {c.approvedMakes.map(m=><option key={m} value={m}>{m}</option>)}
                  </Sel>
                ) : (
                  <input value={ln.make} placeholder="Preferred make"
                    onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,make:e.target.value}:x)}))} style={css.input} />
                );
              })()}
              {ln.itemType==="consumable" ? (
                <input value={ln.category} placeholder="Category"
                  onChange={e=>setSprForm(f=>({...f,lines:f.lines.map((x,xi)=>xi===i?{...x,category:e.target.value}:x)}))} style={css.input} />
              ) : (
                (()=>{
                  // Live computed kg via the shared resolver — same math the PR
                  // card, conversion and PO will use, so no surprises downstream.
                  const qty = parseFloat(ln.qty)||0;
                  const u = ln.unit||"nos";
                  const dimNorm = String(ln.dim||"").trim().toUpperCase().replace(/\u00d7/g,"X").replace(/\s+/g,"");
                  const each = !ln.itemKey ? 0
                    : u==="kg" ? 1
                    : isNosOnly(ln.itemKey) ? 0
                    : u==="m" ? sheetWt(ln.itemKey,"1000")
                    : dimNorm ? sheetWt(ln.itemKey, dimNorm) : 0;
                  const kg = Math.round(each*qty*100)/100;
                  const needsDim = u==="nos" && ln.itemKey && !isNosOnly(ln.itemKey) && !dimNorm;
                  const noWt = !needsDim && u!=="kg" && ln.itemKey && !isNosOnly(ln.itemKey) && !(each>0);
                  return (
                    <div style={{ fontSize:10, fontFamily:T.fontMono, lineHeight:1.5 }}>
                      <div style={{ color: kg>0 ? T.green : (needsDim||noWt) ? T.amber : T.textMid, fontWeight:700 }}>
                        {kg>0 ? `≈ ${fmt.num(kg)} kg` : needsDim ? "needs dim ←" : noWt ? "no wt data" : "—"}
                      </div>
                      <div style={{ color:T.textMid }}>On hand: {stockOnHand(ln)}</div>
                    </div>
                  );
                })()
              )}
              <button onClick={()=>setSprForm(f=>({...f,lines:f.lines.filter((_,xi)=>xi!==i)}))} style={{ ...css.btn.ghost, color:T.red, padding:"3px 8px" }}>✕</button>
            </div>
          ))}
          <button onClick={()=>setSprForm(f=>({...f,lines:[...(f.lines||[]),blankSprLine()]}))} style={{ ...css.btn.ghost, fontSize:11 }}>+ Add line</button>
          <Field label="Remarks" style={{ marginTop:10 }}>
            <input value={sprForm.remarks} onChange={e=>setSprForm(f=>({...f,remarks:e.target.value}))} style={css.input} />
          </Field>
          <div style={{ display:"flex", justifyContent:"flex-end", gap:8, marginTop:14 }}>
            <button onClick={()=>setSprModal(false)} style={css.btn.secondary}>Cancel</button>
            <button onClick={saveSpr} style={css.btn.primary}>{isStoreRole?"Raise & Forward to Purchase":"Raise Requisition"}</button>
          </div>
        </Modal>
      )}
      {quickWtModal && quickWtModal.length>0 && (
        <Modal title="Add missing weights" onClose={()=>setQuickWtModal(null)} width={560}>
          <div style={{ fontSize:12, color:T.textMid, marginBottom:12 }}>
            These materials have no weight data. Enter kg/m to weigh them everywhere permanently, or mark
            count-only items (covers, fittings) as <b>Nos only</b> — they will then be priced per piece and
            excluded from tonnage totals without warnings.
          </div>
          {quickWtModal.map(mc=>{
            const segs = (mc||"").split("/");
            const suggested = geometricKgPerM(segs[0], segs[3]);
            return (
              <div key={mc} style={{ display:"flex", alignItems:"center", gap:8, padding:"8px 0", borderBottom:`1px solid ${T.border}` }}>
                <span style={{ fontFamily:T.fontMono, fontSize:11, color:T.accentHi, flex:1 }}>{mc}</span>
                <input type="number" min={0} step="0.001" placeholder={suggested>0?`≈ ${suggested}`:"kg/m"}
                  value={quickWtVals[mc]||""}
                  onChange={e=>setQuickWtVals(v=>({...v,[mc]:e.target.value}))}
                  style={{ ...css.input, width:100, fontSize:11 }} />
                <button onClick={()=>{
                  const v = parseFloat(quickWtVals[mc]) || suggested;
                  if (!(v>0)) return;
                  applyQuickWt(mc, v, false);
                  setQuickWtModal(list=>{ const next=list.filter(x=>x!==mc); return next.length?next:null; });
                }} style={{ ...css.btn.sm }}>Save kg/m</button>
                <button onClick={()=>{
                  applyQuickWt(mc, 0, true);
                  setQuickWtModal(list=>{ const next=list.filter(x=>x!==mc); return next.length?next:null; });
                }} style={{ ...css.btn.secondary, fontSize:11, padding:"4px 10px" }}>Nos only</button>
              </div>
            );
          })}
        </Modal>
      )}
      {combineModal && (
        <Modal title="Create Combined Purchase Order" onClose={()=>setCombineModal(false)} width={520}>
          <div style={{ marginBottom:14, padding:"10px 14px", background:T.bgInput, borderRadius:6, fontSize:12 }}>
            <div style={{ fontWeight:700, color:T.textMid, marginBottom:6 }}>{selectedPrs.length>1?`Combining ${selectedPrs.length} requisitions`:"Converting 1 requisition"} — adjust quantities to split across POs; the remainder stays open on the PR:</div>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
              <thead><tr>
                {["PR","Material","Dim","Remaining","Qty to this PO","Wt (kg)"].map(h=><th key={h} style={{ textAlign:"left", padding:"3px 6px", color:T.textMid, fontWeight:600, borderBottom:`1px solid ${T.border}` }}>{h}</th>)}
              </tr></thead>
              <tbody>
                {(purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id)).flatMap(pr=>
                  (pr.lots||[]).filter(l=>!l.fulfilledFromStock).flatMap(l=>(l.lines||[]).map((ln,i)=>{
                    const dim = ln.sheetDim||ln.dims||"";
                    const k = prLineKey(pr.id, l.matCode, dim);
                    const rem = prLineRemaining(pr,l,ln);
                    if (rem<=0) return null;
                    const val = combineForm.lineQtys?.[k]===undefined ? rem : combineForm.lineQtys[k];
                    const q = Math.max(0, Math.min(rem, parseInt(val)||0));
                    return (
                      <tr key={k+i}>
                        <td style={{ padding:"3px 6px", fontFamily:T.fontMono, fontSize:10, color:T.accentHi }}>{pr.id.slice(-6)}</td>
                        <td style={{ padding:"3px 6px", fontFamily:T.fontMono }}>{l.matCode}</td>
                        <td style={{ padding:"3px 6px", fontFamily:T.fontMono }}>{dim}</td>
                        <td style={{ padding:"3px 6px", fontFamily:T.fontMono, textAlign:"right" }}>{rem}</td>
                        <td style={{ padding:"3px 6px" }}>
                          <input type="number" min={0} max={rem} value={val}
                            onChange={e=>setCombineForm(f=>({...f, lineQtys:{...(f.lineQtys||{}), [k]:e.target.value}}))}
                            style={{ ...css.input, width:70, padding:"3px 6px", fontSize:11 }} />
                        </td>
                        <td style={{ padding:"3px 6px", fontFamily:T.fontMono, textAlign:"right" }}>{fmt.num(Math.round(sheetWt(l.matCode,dim)*q))}</td>
                      </tr>
                    );
                  })).filter(Boolean)
                )}
              </tbody>
            </table>
          </div>
          <G2>
            <Field label="Vendor" required>
              <Sel value={combineForm.vendorId||""} onChange={e=>{ if(e.target.value==="__add_new__"){ setCombineModal(false); if(setMod) setMod("masters"); } else { const v=vendors.find(x=>x.id===e.target.value); setCombineForm(f=>({...f,vendorId:e.target.value,vendorName:v?.name||""})); } }}>
                <option value="">Select vendor...</option>
                {vendors.filter(v=>v.active!==false).sort((a,b)=>a.name.localeCompare(b.name)).map(v=><option key={v.id} value={v.id}>{v.name}</option>)}
                <option value="__add_new__">+ Add New Vendor (goes to Masters)</option>
              </Sel>
            </Field>
            <Field label="PO Date"><Input type="date" value={combineForm.poDate||""} onChange={e=>setCombineForm(f=>({...f,poDate:e.target.value}))} /></Field>
            <Field label="Expected Delivery"><Input type="date" value={combineForm.expectedDelivery||""} onChange={e=>setCombineForm(f=>({...f,expectedDelivery:e.target.value}))} /></Field>
            <Field label="Notes"><Input value={combineForm.notes||""} onChange={e=>setCombineForm(f=>({...f,notes:e.target.value}))} placeholder="Optional..." /></Field>
            <Field label="PO Type">
              <Sel value={combineForm.poType||"rm"} onChange={e=>setCombineForm(f=>({...f,poType:e.target.value}))}>
                <option value="rm">RM (Raw Material)</option>
                <option value="welding_consumable">Welding Consumable</option>
                <option value="cutting_consumable">Cutting Consumable</option>
                <option value="blasting_consumable">Blasting Consumable</option>
                <option value="paint_consumable">Paint Consumable</option>
                <option value="paint">Paint (tracked separately)</option>
                <option value="general">General</option>
              </Sel>
            </Field>
            <Field label="Transport Scope">
              <Sel value={combineForm.transportScope||""} onChange={e=>setCombineForm(f=>({...f,transportScope:e.target.value}))}>
                <option value="">Select...</option>
                <option value="supplier">Supplier's scope (FOR destination)</option>
                <option value="buyer">Buyer's scope (ex-works)</option>
                <option value="partial">Partial — see notes</option>
              </Sel>
            </Field>
          </G2>
          {/* Payment Terms for combined PO */}
          <div style={{ margin:"8px 0 12px" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
              <div style={{ fontSize:12, fontWeight:700, color:T.textMid, textTransform:"uppercase", letterSpacing:"0.06em" }}>Payment Terms</div>
              <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                {(()=>{ const total=(combineForm.paymentTerms||[]).reduce((s,t)=>s+(+t.pct||0),0); return <span style={{ fontSize:11, fontWeight:700, color:total===100?T.green:total>100?T.red:T.amber }}>{total}% of 100%</span>; })()}
                <button onClick={()=>setCombineForm(f=>({...f,paymentTerms:[...(f.paymentTerms||[]),{id:Date.now(),pct:"",milestone:"",daysFromMilestone:""}]}))} style={{ ...css.btn.sm }}>+ Add Term</button>
              </div>
            </div>
            {(combineForm.paymentTerms||[]).map((term,ti)=>(
              <div key={term.id||ti} style={{ display:"grid", gridTemplateColumns:"70px 1fr 70px auto", gap:6, marginBottom:5, alignItems:"center" }}>
                <input type="number" min={0} max={100} value={term.pct||""} onChange={e=>setCombineForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,pct:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="%" />
                <input value={term.milestone||""} onChange={e=>setCombineForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,milestone:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="Milestone / condition" />
                <input type="number" min={0} value={term.daysFromMilestone||""} onChange={e=>setCombineForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,daysFromMilestone:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="Days" />
                <button onClick={()=>setCombineForm(f=>({...f,paymentTerms:f.paymentTerms.filter((_,i)=>i!==ti)}))} style={{ ...css.btn.ghost, color:T.red, padding:"3px 6px" }}>✕</button>
              </div>
            ))}
          </div>
          {(()=>{
            const matCodes = [...new Set((purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id)).flatMap(pr=>(pr.lots||[]).map(l=>l.matCode)))];
            const anyRateZero = matCodes.some(mc=>!(parseFloat(combineForm.rates?.[mc])||0));
            if (!matCodes.length) return null;
            return (
              <div style={{ marginTop:12 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:8, letterSpacing:"0.05em" }}>RATES — mandatory (₹/kg, or ₹/pc for nos-only items)</div>
                {matCodes.map(mc=>{
                  const mcWt = (purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id)).reduce((s,pr)=>(pr.lots||[]).filter(l=>l.matCode===mc).reduce((ss,l)=>(l.lines||[]).reduce((sss,ln)=>sss+sheetWt(mc,ln.sheetDim||ln.dims)*(ln.qty||0),ss),s),0);
                  return (
                    <div key={mc} style={{ display:"flex", alignItems:"center", gap:10, padding:"6px 0", borderBottom:`1px solid ${T.border}` }}>
                      <span style={{ fontFamily:T.fontMono, fontSize:11, color:T.accentHi, minWidth:160 }}>{mc}</span>
                      <span style={{ fontSize:11, color:T.textMid }}>{isNosOnly(mc) ? "nos-only item" : fmt.num(Math.round(mcWt))+" kg"}</span>
                      <input type="number" min={0} value={combineForm.rates?.[mc]||""} placeholder={isNosOnly(mc)?"Rate ₹/pc":"Rate ₹/kg"}
                        onChange={e=>setCombineForm(f=>({...f,rates:{...(f.rates||{}),[mc]:e.target.value}}))}
                        style={{ width:90, background:T.bgInput, border:`1px solid ${!(parseFloat(combineForm.rates?.[mc])||0)?T.red:T.border}`, borderRadius:4, padding:"3px 7px", color:T.text, fontFamily:T.fontMono, fontSize:11 }} />
                      <span style={{ fontSize:11, color:T.green }}>{(parseFloat(combineForm.rates?.[mc])||0)>0?fmt.currency(Math.round(mcWt*(parseFloat(combineForm.rates?.[mc])||0))):"—"}</span>
                    </div>
                  );
                })}
                {anyRateZero && combineForm.vendorId && <div style={{ marginTop:6, fontSize:11, color:T.red }}>Enter rate for all material codes before creating PO</div>}
              </div>
            );
          })()}
          <div style={{ display:"flex", justifyContent:"flex-end", gap:8, marginTop:16 }}>
            <button onClick={()=>setCombineModal(false)} style={css.btn.secondary}>Cancel</button>
            <button onClick={createCombinedPO} disabled={(()=>{
              if (!combineForm.vendorId) return true;
              const inclMats = new Set();
              (purchaseReqs||[]).filter(r=>selectedPrs.includes(r.id)).forEach(pr=>(pr.lots||[]).filter(l=>!l.fulfilledFromStock).forEach(l=>(l.lines||[]).forEach(ln=>{
                const k = prLineKey(pr.id, l.matCode, ln.sheetDim||ln.dims);
                const rem = prLineRemaining(pr,l,ln);
                const v = combineForm.lineQtys?.[k];
                const q = Math.max(0, Math.min(rem, v===undefined||v==="" ? rem : (parseInt(v)||0)));
                if (q>0) inclMats.add(l.matCode);
              })));
              if (inclMats.size===0) return true;
              return [...inclMats].some(mc=>!(parseFloat(combineForm.rates?.[mc])||0));
            })()} style={{ ...css.btn.primary }}>Create PO</button>
          </div>
        </Modal>
      )}

      {/* Single PR → Convert to PO Modal */}
      {convertSingleModal && (()=>{
        const pr = convertSingleModal;
        const csf = convertSingleForm;
        const lineGroups = (pr.lots||[]).map((l,li)=>{
          const dimLines = (l.lines||[]).map((d,di)=>{
            const wt = sheetWt(l.matCode, d.sheetDim);
            const lineRate = parseFloat(csf.lineRates?.[`${li}-${di}`]??csf.rates?.[l.matCode])||0;
            const totalWt = Math.round(wt*(d.qty||0)*100)/100;
            return { ...d, di, wt, totalWt, lineRate, lineValue:Math.round(totalWt*lineRate*100)/100 };
          });
          const subtotalQty = dimLines.reduce((s,d)=>s+(d.qty||0),0);
          const subtotalWt  = dimLines.reduce((s,d)=>s+(d.totalWt||0),0);
          const groupTotal  = dimLines.reduce((s,d)=>s+d.lineValue,0);
          return { matCode:l.matCode, dimLines, subtotalQty, subtotalWt, groupTotal, li };
        });
        const grandWt    = lineGroups.reduce((s,g)=>s+g.subtotalWt,0);
        const grandTotal = lineGroups.reduce((s,g)=>s+g.groupTotal,0);
        return (
          <Modal title={`Convert ${pr.id} to Purchase Order`} onClose={()=>setConvertSingleModal(null)} width={640}>
            <div style={{ fontSize:12, color:T.textMid, marginBottom:12 }}>
              Source batch: <span style={{ fontFamily:T.fontMono, color:T.accent }}>{pr.nestingBatchId}</span>
            </div>
            <G2>
              <Field label="Vendor" required>
                <Sel value={csf.vendorId||""} onChange={e=>{ if(e.target.value==="__add_new__"){ setConvertSingleModal(null); if(setMod) setMod("masters"); } else setConvertSingleForm(f=>({...f,vendorId:e.target.value})); }}>
                  <option value="">Select vendor...</option>
                  {vendors.filter(v=>v.active!==false).sort((a,b)=>a.name.localeCompare(b.name)).map(v=><option key={v.id} value={v.id}>{v.name}</option>)}
                  <option value="__add_new__">+ Add New Vendor (goes to Masters)</option>
                </Sel>
              </Field>
              <Field label="PO Date"><Input type="date" value={csf.poDate||""} onChange={e=>setConvertSingleForm(f=>({...f,poDate:e.target.value}))} /></Field>
              <Field label="Expected Delivery"><Input type="date" value={csf.expectedDelivery||""} onChange={e=>setConvertSingleForm(f=>({...f,expectedDelivery:e.target.value}))} /></Field>
              <Field label="Notes"><Input value={csf.notes||""} onChange={e=>setConvertSingleForm(f=>({...f,notes:e.target.value}))} placeholder="Optional..." /></Field>
              <Field label="PO Type">
                <Sel value={csf.poType||"rm"} onChange={e=>setConvertSingleForm(f=>({...f,poType:e.target.value}))}>
                  <option value="rm">RM (Raw Material)</option>
                  <option value="welding_consumable">Welding Consumable</option>
                  <option value="cutting_consumable">Cutting Consumable</option>
                  <option value="blasting_consumable">Blasting Consumable</option>
                  <option value="paint_consumable">Paint Consumable</option>
                  <option value="paint">Paint (tracked separately)</option>
                  <option value="general">General</option>
                </Sel>
              </Field>
              <Field label="Transport Scope">
                <Sel value={csf.transportScope||""} onChange={e=>setConvertSingleForm(f=>({...f,transportScope:e.target.value}))}>
                  <option value="">Select...</option>
                  <option value="supplier">Supplier's scope (FOR destination)</option>
                  <option value="buyer">Buyer's scope (ex-works)</option>
                  <option value="partial">Partial — see notes</option>
                </Sel>
              </Field>
            </G2>
            <div style={{ margin:"12px 0 4px" }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.textMid, textTransform:"uppercase", letterSpacing:"0.06em" }}>Payment Terms</div>
                <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                  {(()=>{ const total=(csf.paymentTerms||[]).reduce((s,t)=>s+(+t.pct||0),0); return <span style={{ fontSize:11, fontWeight:700, color:total===100?T.green:total>100?T.red:T.amber }}>{total}% of 100%</span>; })()}
                  <button onClick={()=>setConvertSingleForm(f=>({...f,paymentTerms:[...(f.paymentTerms||[]),{id:Date.now(),pct:"",milestone:"",daysFromMilestone:""}]}))} style={{ ...css.btn.sm }}>+ Add Term</button>
                </div>
              </div>
              {(csf.paymentTerms||[]).map((term,ti)=>(
                <div key={term.id||ti} style={{ display:"grid", gridTemplateColumns:"70px 1fr 70px auto", gap:6, marginBottom:5, alignItems:"center" }}>
                  <input type="number" min={0} max={100} value={term.pct||""} onChange={e=>setConvertSingleForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,pct:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="%" />
                  <input value={term.milestone||""} onChange={e=>setConvertSingleForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,milestone:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="Milestone / condition" />
                  <input type="number" min={0} value={term.daysFromMilestone||""} onChange={e=>setConvertSingleForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,daysFromMilestone:e.target.value}:t)}))} style={{ ...css.input, fontSize:11 }} placeholder="Days" />
                  <button onClick={()=>setConvertSingleForm(f=>({...f,paymentTerms:f.paymentTerms.filter((_,i)=>i!==ti)}))} style={{ ...css.btn.ghost, color:T.red, padding:"3px 6px" }}>✕</button>
                </div>
              ))}
            </div>
            <div style={{ marginTop:14 }}>
              {(()=>{
                const anyRateZero = lineGroups.some(g=>g.dimLines.some(d=>!(d.lineRate>0)));
                return (<>
                {lineGroups.map(g=>(
                  <div key={g.matCode} style={{ marginBottom:14, border:`1px solid ${T.border}`, borderRadius:8, overflow:"hidden" }}>
                    <div style={{ background:T.bgCard, padding:"8px 12px", display:"flex", justifyContent:"space-between", alignItems:"center", gap:10 }}>
                      <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.accentHi, fontSize:12 }}>{g.matCode}</span>
                      <span style={{ fontSize:11, color:T.textMid }}>{g.subtotalQty} sheets · {fmt.num(g.subtotalWt)} kg</span>
                      <div style={{ display:"flex", alignItems:"center", gap:6, marginLeft:"auto" }}>
                        <span style={{ fontSize:10, color:T.textMid }}>Group rate ₹/kg:</span>
                        <input type="number" min={0} value={csf.rates?.[g.matCode]||""} placeholder="Enter rate..."
                          onChange={e=>{
                            const r=e.target.value;
                            setConvertSingleForm(f=>{
                              const lr={...(f.lineRates||{})};
                              g.dimLines.forEach(d=>{ lr[`${g.li}-${d.di}`]=r; });
                              return {...f,rates:{...(f.rates||{}),[g.matCode]:r},lineRates:lr};
                            });
                          }}
                          style={{ width:80, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"2px 6px", color:T.text, fontFamily:T.fontMono, fontSize:11 }} />
                        <span style={{ fontSize:11, fontWeight:700, color:T.green }}>= {fmt.currency(g.groupTotal)}</span>
                      </div>
                    </div>
                    <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                      <thead><tr style={{ borderBottom:`1px solid ${T.border}` }}>
                        <th style={{ padding:"3px 10px", textAlign:"left", color:T.textMid, fontWeight:600 }}>Dims</th>
                        <th style={{ padding:"3px 10px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Sheets</th>
                        <th style={{ padding:"3px 10px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Calc Wt</th>
                        <th style={{ padding:"3px 10px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Rate ₹/kg</th>
                        <th style={{ padding:"3px 10px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Value</th>
                      </tr></thead>
                      <tbody>
                        {g.dimLines.map((d,i)=>(
                          <tr key={i} style={{ background:i%2===0?"transparent":T.bg }}>
                            <td style={{ padding:"3px 10px", fontFamily:T.fontMono, color:T.text }}>{d.sheetDim}</td>
                            <td style={{ padding:"3px 10px", textAlign:"right", fontFamily:T.fontMono }}>{d.qty}</td>
                            <td style={{ padding:"3px 10px", textAlign:"right", fontFamily:T.fontMono, color:T.textMid }}>{fmt.num(d.totalWt)} kg</td>
                            <td style={{ padding:"2px 6px", textAlign:"right" }}>
                              <input type="number" min={0} value={csf.lineRates?.[`${g.li}-${d.di}`]??csf.rates?.[g.matCode]??""} placeholder="0.00"
                                onChange={e=>{
                                  const r=e.target.value;
                                  setConvertSingleForm(f=>{
                                    const lr={...(f.lineRates||{})};
                                    lr[`${g.li}-${d.di}`]=r;
                                    // if first dim, auto-fill all others in this group
                                    if(d.di===0) g.dimLines.forEach(dd=>{ if(dd.di>0&&!(f.lineRates?.[`${g.li}-${dd.di}`]>0)) lr[`${g.li}-${dd.di}`]=r; });
                                    return {...f,lineRates:lr};
                                  });
                                }}
                                style={{ width:72, background:T.bgInput, border:`1px solid ${!(d.lineRate>0)?T.red:T.border}`, borderRadius:4, padding:"2px 5px", color:T.text, fontFamily:T.fontMono, fontSize:11, textAlign:"right" }} />
                            </td>
                            <td style={{ padding:"3px 10px", textAlign:"right", fontFamily:T.fontMono, color:d.lineValue>0?T.green:T.textLow }}>{d.lineValue>0?fmt.currency(d.lineValue):"—"}</td>
                          </tr>
                        ))}
                        <tr style={{ background:T.bgInput }}>
                          <td colSpan={2} style={{ padding:"4px 10px", fontSize:11, color:T.textMid, fontWeight:700 }}>Subtotal</td>
                          <td style={{ padding:"4px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700 }}>{fmt.num(g.subtotalWt)} kg</td>
                          <td />
                          <td style={{ padding:"4px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.currency(g.groupTotal)}</td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                ))}
                <div style={{ background:T.bgCard, borderRadius:6, padding:"8px 14px", display:"flex", justifyContent:"space-between", alignItems:"center", fontSize:12, fontWeight:700 }}>
                  <span style={{ color:T.textMid }}>Grand Total</span>
                  <div style={{ display:"flex", gap:24 }}>
                    <span style={{ fontFamily:T.fontMono }}>{fmt.num(grandWt)} kg</span>
                    <span style={{ fontFamily:T.fontMono, color:T.green }}>{fmt.currency(grandTotal)}</span>
                  </div>
                </div>
                {anyRateZero && csf.vendorId && <div style={{ marginTop:8, fontSize:11, color:T.red, textAlign:"right" }}>Enter rate for all lines before creating PO</div>}
                </>);
              })()}
            </div>
            <div style={{ display:"flex", justifyContent:"flex-end", gap:8, marginTop:16 }}>
              <button onClick={()=>setConvertSingleModal(null)} style={css.btn.secondary}>Cancel</button>
              <button onClick={saveSingleConvertPO} disabled={!csf.vendorId||lineGroups.some(g=>g.dimLines.some(d=>!(d.lineRate>0)))} style={{ ...css.btn.primary, opacity:(!csf.vendorId||lineGroups.some(g=>g.dimLines.some(d=>!(d.lineRate>0))))?0.4:1 }}>Create PO</button>
            </div>
          </Modal>
        );
      })()}

      {/* New PO Modal */}
      {modal==="new_po" && (
        <Modal title="New Purchase Order" onClose={()=>setModal(null)} width={720}>
          <G2>
            <Field label="Vendor" required>
              <Sel value={form.vendorId||""} onChange={e=>{ if(e.target.value==="__add_new__"){ setModal(null); if(setMod) setMod("masters"); } else { const v=vendors.find(x=>x.id===e.target.value); setForm(f=>({...f,vendorId:e.target.value,vendorName:v?.name||""})); } }}>
                <option value="">Select vendor...</option>
                {vendors.filter(v=>v.active!==false).sort((a,b)=>a.name.localeCompare(b.name)).map(v=><option key={v.id} value={v.id}>{v.name}</option>)}
                <option value="__add_new__">+ Add New Vendor (goes to Masters)</option>
              </Sel>
            </Field>
            <Field label="PO Date" required><Input type="date" value={form.poDate||""} onChange={e=>setForm(f=>({...f,poDate:e.target.value}))} /></Field>
            <Field label="Expected Delivery"><Input type="date" value={form.expectedDelivery||""} onChange={e=>setForm(f=>({...f,expectedDelivery:e.target.value}))} /></Field>
            <Field label="PO Type">
              <Sel value={form.poType||""} onChange={e=>setForm(f=>({...f,poType:e.target.value}))}>
                <option value="">Select type...</option>
                <option value="rm">RM (Raw Material)</option>
                <option value="welding_consumable">Welding Consumable</option>
                <option value="cutting_consumable">Cutting Consumable</option>
                <option value="blasting_consumable">Blasting Consumable</option>
                <option value="paint_consumable">Paint Consumable</option>
                <option value="paint">Paint (tracked separately)</option>
                <option value="general">General</option>
              </Sel>
            </Field>
            <Field label="Transport Scope">
              <Sel value={form.transportScope||""} onChange={e=>setForm(f=>({...f,transportScope:e.target.value}))}>
                <option value="">Select...</option>
                <option value="supplier">Supplier's scope (FOR destination)</option>
                <option value="buyer">Buyer's scope (ex-works)</option>
                <option value="partial">Partial — see remarks</option>
              </Sel>
            </Field>
            <Field label="Orders Served">
              <div style={{ display:"flex", gap:8 }}>
                {orders.map(o=>(
                  <label key={o.id} style={{ display:"flex", alignItems:"center", gap:6, cursor:"pointer" }}>
                    <input type="checkbox" checked={(form.servedOrders||[]).includes(o.id)} onChange={e=>setForm(f=>({...f,servedOrders:e.target.checked?[...(f.servedOrders||[]),o.id]:(f.servedOrders||[]).filter(x=>x!==o.id)}))} />
                    <span style={{ fontSize:12, color:T.text }}>{o.id}</span>
                  </label>
                ))}
              </div>
            </Field>
            <Field label="Orders Covered">
              <div>
                <div style={{ fontSize:11, color:T.textMid, marginBottom:6 }}>Material earmarked for these orders — enables GRN auto-reservation</div>
                <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                  {orders.filter(o=>o.status==="Active").slice(0,5).map(o=>(
                    <label key={o.id} style={{ display:"flex", alignItems:"center", gap:6, cursor:"pointer" }}>
                      <input type="checkbox" checked={(form.coveredOrders||[]).includes(o.id)} onChange={e=>setForm(f=>({...f,coveredOrders:e.target.checked?[...(f.coveredOrders||[]),o.id]:(f.coveredOrders||[]).filter(x=>x!==o.id)}))} />
                      <span style={{ fontSize:12, color:T.text }}>{o.id}</span>
                    </label>
                  ))}
                  <label style={{ display:"flex", alignItems:"center", gap:6, cursor:"pointer" }}>
                    <input type="checkbox" checked={!!form.includesStock} onChange={e=>setForm(f=>({...f,includesStock:e.target.checked}))} />
                    <span style={{ fontSize:12, color:T.textMid }}>Stock (general)</span>
                  </label>
                </div>
              </div>
            </Field>
            <Field label="Remarks"><Input value={form.remarks||""} onChange={e=>setForm(f=>({...f,remarks:e.target.value}))} /></Field>
          </G2>
          {/* Payment Terms */}
          <div style={{ marginTop:12, marginBottom:4 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
              <div style={{ fontSize:12, fontWeight:700, color:T.textMid, textTransform:"uppercase", letterSpacing:"0.06em" }}>Payment Terms</div>
              <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                {(()=>{
                  const terms = form.paymentTerms||[];
                  const total = terms.reduce((s,t)=>s+(+t.pct||0),0);
                  return <span style={{ fontSize:11, fontWeight:700, color:total===100?T.green:total>100?T.red:T.amber }}>{total}% of 100%</span>;
                })()}
                <button onClick={()=>setForm(f=>({...f,paymentTerms:[...(f.paymentTerms||[]),{id:Date.now(),pct:"",milestone:"",daysFromMilestone:""}]}))} style={{ ...css.btn.sm }}>+ Add Term</button>
              </div>
            </div>
            {(form.paymentTerms||[]).length===0 && (
              <div style={{ fontSize:11, color:T.textLow, padding:"8px 0" }}>No payment terms added. Click "+ Add Term" to define payment schedule.</div>
            )}
            {(form.paymentTerms||[]).map((term,ti)=>(
              <div key={term.id||ti} style={{ display:"grid", gridTemplateColumns:"80px 1fr 80px auto", gap:8, marginBottom:6, alignItems:"center" }}>
                <div>
                  <label style={css.label}>% of PO</label>
                  <input type="number" min={0} max={100} value={term.pct||""} onChange={e=>setForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,pct:e.target.value}:t)}))}
                    style={{ ...css.input, fontSize:12 }} placeholder="e.g. 40" />
                </div>
                <div>
                  <label style={css.label}>Milestone / Condition</label>
                  <input value={term.milestone||""} onChange={e=>setForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,milestone:e.target.value}:t)}))}
                    style={{ ...css.input, fontSize:12 }} placeholder="e.g. Against delivery + QC clearance" />
                </div>
                <div>
                  <label style={css.label}>Days</label>
                  <input type="number" min={0} value={term.daysFromMilestone||""} onChange={e=>setForm(f=>({...f,paymentTerms:f.paymentTerms.map((t,i)=>i===ti?{...t,daysFromMilestone:e.target.value}:t)}))}
                    style={{ ...css.input, fontSize:12 }} placeholder="0" />
                </div>
                <button onClick={()=>setForm(f=>({...f,paymentTerms:f.paymentTerms.filter((_,i)=>i!==ti)}))} style={{ ...css.btn.ghost, color:T.red, padding:"3px 8px", marginTop:16 }}>✕</button>
              </div>
            ))}
          </div>
          <div style={{ marginTop:12, marginBottom:8 }}>
            <SectionHd title="PO Lines" action={
              <div style={{ display:"flex", gap:6 }}>
                <button onClick={downloadPOTemplate} style={css.btn.secondary}>⬇ Template</button>
                <button onClick={()=>setPoImpModal(true)} style={css.btn.amber}>📥 Import CSV</button>
                {!form.prId && form.sourceType!=="nesting"
                  ? <button onClick={()=>{ setLinePickerForm({}); setLinePickerModal({category:null}); }} style={css.btn.sm}>+ Add Line</button>
                  : null
                }
              </div>
            } />
            {/* Nesting source summary (read-only) */}
            {form.sourceType==="nesting" && (form.lines||[]).length>0 && (()=>{
              const grpMap = {};
              (form.lines||[]).forEach(l=>{ const k=l.matCode||"?"; if(!grpMap[k]) grpMap[k]=[]; grpMap[k].push(l); });
              return (
                <div style={{ marginBottom:10 }}>
                  <div style={{ fontSize:11, color:T.textMid, marginBottom:6 }}>Lines pre-filled from nesting batch — prices can be set after PO creation.</div>
                  {Object.entries(grpMap).map(([mc,lines])=>(
                    <div key={mc} style={{ background:T.bgInput, borderRadius:6, padding:"8px 12px", marginBottom:6, fontSize:12 }}>
                      <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.accentHi }}>{mc}</span>
                      <span style={{ color:T.textMid, marginLeft:8 }}>{lines.length} dimension{lines.length!==1?"s":""}</span>
                      <span style={{ color:T.textMid, marginLeft:8 }}>· {fmt.num(lines.reduce((s,l)=>s+(l.wtOrdered||0),0))} kg</span>
                    </div>
                  ))}
                </div>
              );
            })()}
            {(form.lines||[]).filter(l=>l.sourceType!=="nesting").map((l, _fi)=>{
              const i = (form.lines||[]).indexOf(l);
              return (
  <div key={i} style={{ ...css.card, background:T.bg, marginBottom:8 }}>
    {/* Row 1: Material type selectors */}
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:8, marginBottom:8 }}>
      <Field label="Section Type">
        <Sel value={l.sectionType||""} onChange={e=>{
          const st=e.target.value;
          const isPlate=st==="PLATE";
          setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],sectionType:st,isPlate,matLibId:"",wtPerM2:null,wtPerMetre:null}; return {...f,lines:n}; });
        }}>
          <option value="">— Select —</option>
          {["ISA","ISMC","ISMB","PLATE","RHS","SHS","Flat Bar","Other"].map(s=><option key={s}>{s}</option>)}
        </Sel>
      </Field>
      <Field label="Size / Thickness">
        <Sel value={l.matLibId||"__ns__"} onChange={e=>{
          if(e.target.value==="__ns__"){setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],matLibId:"",size:"",wtPerM2:null,wtPerMetre:null,isPlate:l.sectionType==="PLATE"}; return {...f,lines:n}; });}
          else{ const m=(materials||[]).find(x=>x.id===e.target.value); if(m) setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],matLibId:m.id,matCode:m.matCode,sectionType:m.sectionType,size:m.size,grade:m.grade,matType:m.matType,isPlate:m.isPlate,wtPerMetre:m.wtPerMetre||null,wtPerM2:m.wtPerM2||null}; return {...f,lines:n}; }); }
        }}>
          <option value="__ns__">— Free text —</option>
          {(materials||[]).filter(m=>m.active&&(!l.sectionType||m.sectionType===l.sectionType)).map(m=>(
            <option key={m.id} value={m.id}>{m.size} ({m.wtPerMetre?m.wtPerMetre+" kg/m":m.wtPerM2+" kg/m²"})</option>
          ))}
        </Sel>
      </Field>
      {!l.matLibId && <Field label="Size (manual)"><Input value={l.size||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],size:e.target.value}; return {...f,lines:n}; })} placeholder="e.g. 75x75x8" /></Field>}
      <Field label="Grade">
        <Sel value={l.grade||"E250"} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],grade:e.target.value}; return {...f,lines:n}; })}>
          <option>E250</option><option>E350</option><option>304</option><option>316</option><option>Other</option>
        </Sel>
      </Field>
      <Field label="Mat Type">
        <Sel value={l.matType||"MS"} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],matType:e.target.value}; return {...f,lines:n}; })}>
          <option>MS</option><option>SS</option><option>AL</option>
        </Sel>
      </Field>
    </div>
    {/* No-library-match: manual weight entry + Add to Library */}
    {!l.matLibId && l.size && (()=>{
      const tentMatch = (materials||[]).find(m => m.sectionType.toLowerCase()===(l.sectionType||"").toLowerCase() && normalize(m.size)===normalize(l.size) && (m.grade||"").toLowerCase()===(l.grade||"").toLowerCase());
      if (tentMatch) return null;
      return (
        <div style={{ marginBottom:8 }}>
          <InfoBanner color="amber">No library match — enter weight manually or add this section to the library.</InfoBanner>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginTop:6 }}>
            {!l.isPlate && (
              <Field label="Wt per Metre (kg/m)">
                <Input type="number" step="0.01" value={l.wtPerMetre||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],wtPerMetre:+e.target.value||null,wtSource:"manual",libraryMatch:false}; return {...f,lines:n}; })} placeholder="e.g. 5.64" />
              </Field>
            )}
            {l.isPlate && (
              <Field label="Wt per m² (kg/m²)">
                <Input type="number" step="0.01" value={l.wtPerM2||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],wtPerM2:+e.target.value||null,wtSource:"manual",libraryMatch:false}; return {...f,lines:n}; })} placeholder="e.g. 31.4" />
              </Field>
            )}
            {["super_admin","purchase_admin"].includes(user.role) && (
              <div style={{ alignSelf:"flex-end", paddingBottom:2 }}>
                <button style={{ ...css.btn.amber, fontSize:11 }} onClick={()=>{
                  const maxNum = Math.max(...(materials||[]).map(m=>{ const mt=m.id.match(/^ML-(\d+)$/); return mt?+mt[1]:0; }),0);
                  const newId = `ML-${String(maxNum+1).padStart(3,"0")}`;
                  const mc = buildMatCode(l.sectionType||"",l.matType||"MS",l.grade||"E250",l.size||"");
                  setAddToLibForm({ id:newId, sectionType:l.sectionType||"", size:l.size||"", grade:l.grade||"E250", matType:l.matType||"MS", isPlate:l.isPlate||false, wtPerMetre:l.wtPerMetre||null, wtPerM2:l.wtPerM2||null, standardLengths:[6000,8000,10000,12000], active:true, matCode:mc });
                  setAddToLibSuccess(false);
                  setAddToLibModal({ lineIdx:i });
                }}>+ Add to Library</button>
              </div>
            )}
          </div>
        </div>
      );
    })()}
    {/* Row 2: Dimensions (shown for count-based units) */}
    {((l.unit||"Pcs").toUpperCase()!=="MT"||(l.orderMode||"ByUnits")==="ByWeight")&&(
      <div style={{ display:"grid", gridTemplateColumns:l.isPlate?"1fr 1fr 2fr":"1fr 2fr", gap:8, marginBottom:8 }}>
        <Field label="Length (mm)"><Input type="number" value={l.length||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],length:+e.target.value||null}; return {...f,lines:n}; })} /></Field>
        {l.isPlate&&<Field label="Width (mm)"><Input type="number" value={l.width||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],width:+e.target.value||null}; return {...f,lines:n}; })} /></Field>}
        <div style={{ alignSelf:"flex-end", paddingBottom:6, fontSize:11, color:T.textLow }}>
          {l.isPlate?"Plate dims: Length × Width (mm)":"Bar/section: full bar length in mm"}
        </div>
      </div>
    )}
    {/* Order mode toggle */}
    <div style={{ display:"flex", gap:0, marginBottom:8, width:"fit-content", border:`1px solid ${T.border}`, borderRadius:6, overflow:"hidden" }}>
      {["ByUnits","ByWeight"].map(mode=>(
        <button key={mode} onClick={()=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],orderMode:mode,unit:mode==="ByWeight"?"KG":n[i].unit==="KG"?"Pcs":n[i].unit}; return {...f,lines:n}; })} style={{ padding:"5px 14px", fontSize:12, fontWeight:(l.orderMode||"ByUnits")===mode?700:400, color:(l.orderMode||"ByUnits")===mode?T.bg:T.textMid, background:(l.orderMode||"ByUnits")===mode?T.accent:"transparent", border:"none", cursor:"pointer", fontFamily:T.font }}>
          {mode==="ByUnits"?"Order by Units":"Order by Weight"}
        </button>
      ))}
    </div>
    {/* Row 3: Qty + Pricing */}
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr auto", gap:8, alignItems:"end" }}>
      {(l.orderMode||"ByUnits")==="ByUnits" ? (
        <Field label="Qty (sheets/pcs/bars)"><Input type="number" value={l.qty||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; const nq=+e.target.value; const wt=calcPoLineWt({...n[i],qty:nq}); const tp=n[i].pricingMethod==="PerKg"?wt*(n[i].unitPrice||0):nq*(n[i].unitPrice||0); const ekg=wt>0?tp/wt:0; const eunit=n[i].pricingMethod==="PerKg"?nq>0?tp/nq:0:(n[i].unitPrice||0); n[i]={...n[i],qty:nq,qtyOrdered:nq,wtOrdered:wt,totalPrice:tp,effectiveRateKg:ekg,effectiveRateUnit:eunit}; return {...f,lines:n}; })} /></Field>
      ) : (
        <Field label="Weight Required (kg)"><Input type="number" value={l.wtRequired||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; const wr=+e.target.value; const lib=(materials||[]).find(m=>m.id===n[i].matLibId); let wp=0; if(lib){if(lib.isPlate&&n[i].length>0&&n[i].width>0)wp=(n[i].length/1000)*(n[i].width/1000)*(lib.wtPerM2||0);else if(!lib.isPlate&&n[i].length>0)wp=(n[i].length/1000)*(lib.wtPerMetre||0);} const hq=wp>0?Math.ceil(wr/wp):0; const tp=n[i].pricingMethod==="PerKg"?wr*(n[i].unitPrice||0):hq*(n[i].unitPrice||0); n[i]={...n[i],wtRequired:wr,wtOrdered:wr,qty:hq,qtyOrdered:hq,totalPrice:tp,effectiveRateKg:wr>0?tp/wr:0}; return {...f,lines:n}; })} /></Field>
      )}
      {(l.orderMode||"ByUnits")==="ByUnits" ? (
        <Field label="Unit">
          <Sel value={l.unit||"Pcs"} onChange={e=>setForm(f=>{ const n=[...f.lines]; const nu=e.target.value; const wt=calcPoLineWt({...n[i],unit:nu}); const tp=n[i].pricingMethod==="PerKg"?wt*(n[i].unitPrice||0):(n[i].qty||0)*(n[i].unitPrice||0); const ekg=wt>0?tp/wt:0; n[i]={...n[i],unit:nu,wtOrdered:wt,totalPrice:tp,effectiveRateKg:ekg}; return {...f,lines:n}; })}>
            <option>Sheets</option><option>Pcs</option><option>NOS</option>
          </Sel>
        </Field>
      ) : (
        <div />
      )}
      <Field label="Pricing">
        <div style={{ display:"flex", gap:4, marginTop:4 }}>
          {["PerUnit","PerKg"].map(pm=>(
            <button key={pm} onClick={()=>setForm(f=>{ const n=[...f.lines]; const wt=calcPoLineWt(n[i]); const tp=pm==="PerKg"?wt*(n[i].unitPrice||0):(n[i].qty||0)*(n[i].unitPrice||0); const ekg=wt>0?tp/wt:0; const eunit=pm==="PerKg"?(n[i].qty||0)>0?tp/(n[i].qty||0):0:(n[i].unitPrice||0); n[i]={...n[i],pricingMethod:pm,totalPrice:tp,effectiveRateKg:ekg,effectiveRateUnit:eunit}; return {...f,lines:n}; })} style={{ flex:1, padding:"4px 6px", fontSize:11, fontWeight:l.pricingMethod===pm?700:400, color:l.pricingMethod===pm?T.accent:T.textMid, background:l.pricingMethod===pm?T.bgCard:"transparent", border:`1px solid ${l.pricingMethod===pm?T.accent:T.border}`, borderRadius:4, cursor:"pointer", fontFamily:T.font }}>{pm==="PerUnit"?"/unit":"/kg"}</button>
          ))}
        </div>
      </Field>
      <Field label={l.pricingMethod==="PerKg"?"Price/kg (₹)":"Price/unit (₹)"}><Input type="number" value={l.unitPrice||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; const up=+e.target.value; const wt=calcPoLineWt(n[i]); const tp=n[i].pricingMethod==="PerKg"?wt*up:(n[i].qty||0)*up; n[i]={...n[i],unitPrice:up,totalPrice:tp,effectiveRateKg:wt>0?tp/wt:0,effectiveRateUnit:n[i].pricingMethod==="PerKg"?(n[i].qty||0)>0?tp/(n[i].qty||0):0:up}; return {...f,lines:n}; })} /></Field>
      <button onClick={()=>setForm(f=>({...f,lines:f.lines.filter((_,j)=>j!==i)}))} style={{ ...css.btn.ghost, color:T.red, paddingTop:18 }}>✕</button>
    </div>
    {/* Row 4: Live calc preview */}
    {(()=>{
      const isWtMode=(l.orderMode||"ByUnits")==="ByWeight";
      const wt=isWtMode?(l.wtRequired||0):calcPoLineWt(l);
      const tp=l.pricingMethod==="PerKg"?wt*(l.unitPrice||0):(l.qty||0)*(l.unitPrice||0);
      const effKg=wt>0?tp/wt:0;
      const mc=l.matCode||buildMatCode(l.sectionType||l.section,l.matType,l.grade,l.size);
      const ic=buildItemCode({...l,matCode:mc});
      let byWtHint=null;
      if(isWtMode&&l.matLibId){
        const lib=(materials||[]).find(m=>m.id===l.matLibId);
        if(lib){
          if(lib.isPlate&&l.length>0&&l.width>0){const wp=(l.length/1000)*(l.width/1000)*(lib.wtPerM2||0);const hq=wp>0?Math.ceil((l.wtRequired||0)/wp):null;if(hq!=null)byWtHint=`≈ ${hq} sheet${hq!==1?"s":""} of ${l.length}×${l.width}mm`;}
          else if(!lib.isPlate&&l.length>0){const wp=(l.length/1000)*(lib.wtPerMetre||0);const hq=wp>0?Math.ceil((l.wtRequired||0)/wp):null;if(hq!=null)byWtHint=`≈ ${hq} bar${hq!==1?"s":""} of ${l.length}mm`;}
        }
      }
      return (
        <div style={{ marginTop:8, padding:"8px 12px", background:T.bgCard, borderRadius:6, display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:8 }}>
          <div>
            <div style={css.label}>{isWtMode?"Qty Hint":"Wt Ordered"}</div>
            <div style={{ fontSize:12,fontFamily:T.fontMono,fontWeight:700 }}>
              {isWtMode
                ? <span style={{color:byWtHint?T.textLow:T.textLow}}>{byWtHint||"— enter dimensions"}</span>
                : <span style={{color:wt>0?T.green:T.textLow}}>{wt>0?`${fmt.num(Math.round(wt))} kg (${(wt/1000).toFixed(2)} T)`:"—"}</span>}
            </div>
          </div>
          <div><div style={css.label}>Line Total</div><div style={{ fontSize:12,color:T.green,fontFamily:T.fontMono,fontWeight:700 }}>{fmt.currency(tp)}</div></div>
          <div><div style={css.label}>Eff. Rate/kg</div><div style={{ fontSize:12,color:T.accent,fontFamily:T.fontMono }}>{effKg>0?`₹${effKg.toFixed(2)}/kg`:"—"}</div></div>
          <div><div style={css.label}>Item Code</div><div style={{ fontSize:11,color:ic?T.accentHi:T.textLow,fontFamily:T.fontMono }}>{ic||"—"}{l.matLibId&&<span style={{color:T.green,marginLeft:4}}>✓</span>}</div></div>
        </div>
      );
    })()}
    {/* MRP Order Allocation */}
    {(form.coveredOrders||[]).length>0 && l.matCode && (() => {
      const totalKg = l.wtOrdered>0?l.wtOrdered:l.wtRequired||0;
      if (!totalKg) return null;
      const totalDemand = (form.coveredOrders||[]).reduce((s,oid)=>{
        const ord=orders.find(o=>o.id===oid);
        return s+(ord?(ord.parts||[]).filter(p=>p.matCode===l.matCode&&(p.fabType||"").toLowerCase()==="fabricate").reduce((ss,p)=>ss+(p.clientTotalWt||0),0):0);
      },0)||1;
      const suggested = (form.coveredOrders||[]).map(oid=>{
        const ord=orders.find(o=>o.id===oid);
        const reqKg=ord?(ord.parts||[]).filter(p=>p.matCode===l.matCode&&(p.fabType||"").toLowerCase()==="fabricate").reduce((ss,p)=>ss+(p.clientTotalWt||0),0):0;
        return {orderId:oid, kg:Math.round(totalKg*(reqKg/totalDemand)*10)/10, unit:l.unit||"MT"};
      });
      const allocs = ((l.orderAllocations||[]).length===suggested.length)?l.orderAllocations:suggested;
      return (
        <div style={{ marginTop:8, padding:"8px 12px", background:`${T.accent}11`, border:`1px solid ${T.accent}33`, borderRadius:6 }}>
          <div style={{ fontSize:11, fontWeight:700, color:T.accent, marginBottom:6 }}>MRP Allocation — {l.matCode} ({totalKg.toFixed(0)} kg total)</div>
          <div style={{ display:"flex", gap:8, flexWrap:"wrap", alignItems:"flex-end" }}>
            {allocs.map((a,ai)=>(
              <div key={a.orderId} style={{ background:T.bgCard, borderRadius:4, padding:"6px 10px", minWidth:110 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.accentHi }}>{a.orderId}</div>
                <div style={{ display:"flex", alignItems:"center", gap:4, marginTop:4 }}>
                  <input type="number" step="0.1" value={a.kg} style={{ ...css.input, fontSize:11, padding:"2px 6px", width:70 }}
                    onChange={e=>setForm(f=>{const ls=[...f.lines];const na=[...allocs];na[ai]={...na[ai],kg:+e.target.value||0};ls[i]={...ls[i],orderAllocations:na};return {...f,lines:ls};})} />
                  <span style={{ fontSize:10, color:T.textMid }}>kg</span>
                </div>
              </div>
            ))}
            <button onClick={()=>setForm(f=>{const ls=[...f.lines];ls[i]={...ls[i],orderAllocations:suggested};return {...f,lines:ls};})} style={{ ...css.btn.sm, alignSelf:"flex-end" }}>⟳ Reset</button>
          </div>
        </div>
      );
    })()}
    {/* Row 5: Delivery + Remarks */}
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginTop:8 }}>
      <Field label="Expected Delivery"><Input type="date" value={l.expectedDelivery||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],expectedDelivery:e.target.value}; return {...f,lines:n}; })} /></Field>
      <Field label="Remarks"><Input value={l.remarks||""} onChange={e=>setForm(f=>{ const n=[...f.lines]; n[i]={...n[i],remarks:e.target.value}; return {...f,lines:n}; })} /></Field>
    </div>
  </div>
              );
            })}
          </div>
          <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
            <button onClick={()=>setModal(null)} style={css.btn.secondary}>Cancel</button>
            <button onClick={savePO} style={css.btn.primary}>Create Purchase Order</button>
          </div>
        </Modal>
      )}
      {/* Add to Library Modal */}
      {addToLibModal && (
        <Modal title="Add to Materials Library" onClose={()=>setAddToLibModal(null)} width={560}>
          {addToLibSuccess
            ? <div style={{ textAlign:"center", padding:32 }}>
                <div style={{ fontSize:32, marginBottom:12 }}>✓</div>
                <div style={{ color:T.green, fontWeight:700, fontSize:15 }}>Added to library!</div>
                <button style={{ ...css.btn.primary, marginTop:16 }} onClick={()=>setAddToLibModal(null)}>Close</button>
              </div>
            : <>
                <G2>
                  <Field label="Section Type">
                    <Sel value={addToLibForm.sectionType||""} onChange={e=>setAddToLibForm(f=>({...f,sectionType:e.target.value,isPlate:e.target.value==="PLATE",matCode:buildMatCode(e.target.value,f.matType,f.grade,f.size)}))}>
                      {["ISA","ISMC","ISMB","PLATE","RHS","SHS","Flat Bar","Other"].map(s=><option key={s}>{s}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Size"><Input value={addToLibForm.size||""} onChange={e=>setAddToLibForm(f=>({...f,size:e.target.value,matCode:buildMatCode(f.sectionType,f.matType,f.grade,e.target.value)}))} placeholder="e.g. 100x50x4" /></Field>
                  <Field label="Grade">
                    <Sel value={addToLibForm.grade||"E250"} onChange={e=>setAddToLibForm(f=>({...f,grade:e.target.value,matCode:buildMatCode(f.sectionType,f.matType,e.target.value,f.size)}))}>
                      <option>E250</option><option>E350</option><option>304</option><option>316</option><option>Other</option>
                    </Sel>
                  </Field>
                  <Field label="Mat Type">
                    <Sel value={addToLibForm.matType||"MS"} onChange={e=>setAddToLibForm(f=>({...f,matType:e.target.value,matCode:buildMatCode(f.sectionType,e.target.value,f.grade,f.size)}))}>
                      <option>MS</option><option>SS</option><option>AL</option>
                    </Sel>
                  </Field>
                </G2>
                <Field label="Mat Code (auto-generated)"><Input value={addToLibForm.matCode||""} readOnly style={{ color:T.textMid }} /></Field>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:12 }}>
                  <label style={{ fontSize:12, color:T.text }}>Is Plate?</label>
                  <input type="checkbox" checked={!!addToLibForm.isPlate} onChange={e=>setAddToLibForm(f=>({...f,isPlate:e.target.checked,wtPerMetre:e.target.checked?null:f.wtPerMetre,wtPerM2:e.target.checked?f.wtPerM2:null}))} />
                </div>
                {!addToLibForm.isPlate && <Field label="Wt per Metre (kg/m)"><Input type="number" step="0.01" value={addToLibForm.wtPerMetre||""} onChange={e=>setAddToLibForm(f=>({...f,wtPerMetre:+e.target.value||null}))} /></Field>}
                {addToLibForm.isPlate  && <Field label="Wt per m² (kg/m²)"><Input type="number" step="0.01" value={addToLibForm.wtPerM2||""} onChange={e=>setAddToLibForm(f=>({...f,wtPerM2:+e.target.value||null}))} /></Field>}
                <Field label="Standard Lengths (mm, comma-separated)"><Input value={(addToLibForm.standardLengths||[]).join(",")} onChange={e=>setAddToLibForm(f=>({...f,standardLengths:e.target.value.split(",").map(s=>parseInt(s.trim(),10)).filter(n=>!isNaN(n)&&n>0)}))} placeholder="6000,8000,10000,12000" /></Field>
                <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
                  <button onClick={()=>setAddToLibModal(null)} style={css.btn.secondary}>Cancel</button>
                  <button onClick={()=>{
                    if (!addToLibForm.sectionType||!addToLibForm.size||(!addToLibForm.wtPerMetre&&!addToLibForm.wtPerM2)) return;
                    const saved = {...addToLibForm};
                    setMaterials(prev=>[...prev,{...saved,active:true}]);
                    setForm(f=>{ const n=[...f.lines]; n[addToLibModal.lineIdx]={...n[addToLibModal.lineIdx],matLibId:saved.id,matCode:saved.matCode,isPlate:saved.isPlate,wtPerMetre:saved.wtPerMetre||null,wtPerM2:saved.wtPerM2||null,wtSource:"",libraryMatch:true}; return {...f,lines:n}; });
                    setAddToLibSuccess(true);
                  }} style={css.btn.primary}>Save to Library</button>
                </div>
              </>
          }
        </Modal>
      )}
      {/* Line Picker Modal — structured line entry for manual POs */}
      {linePickerModal && (
        <Modal title={linePickerModal.category ? "Add PO Line" : "Select Line Category"} onClose={()=>setLinePickerModal(null)} width={560}>
          {!linePickerModal.category && (
            <div style={{ display:"flex", flexDirection:"column", gap:12, padding:"8px 0" }}>
              <div style={{ fontSize:12, color:T.textMid, marginBottom:4 }}>What are you purchasing?</div>
              {[
                { id:"rm",          label:"Raw Material",  icon:"🔩", desc:"Steel sections, plates, bars" },
                { id:"paint",       label:"Paint",         icon:"🎨", desc:"Primers, coatings, thinners" },
                { id:"consumable",  label:"Consumable",    icon:"🔧", desc:"Welding, grinding, PPE, blasting" },
              ].map(c=>(
                <button key={c.id} onClick={()=>{ setLinePickerForm({ category:c.id, unit:c.id==="rm"?"Pcs":c.id==="paint"?"Litre":"Piece", pricingMethod:"PerUnit", qty:1, unitPrice:0 }); setLinePickerModal({category:c.id}); }}
                  style={{ display:"flex", alignItems:"center", gap:14, padding:"14px 18px", background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:8, cursor:"pointer", textAlign:"left" }}
                  onMouseEnter={e=>e.currentTarget.style.borderColor=T.accent} onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
                  <span style={{ fontSize:24 }}>{c.icon}</span>
                  <div>
                    <div style={{ fontWeight:700, fontSize:14, color:T.text }}>{c.label}</div>
                    <div style={{ fontSize:12, color:T.textMid }}>{c.desc}</div>
                  </div>
                </button>
              ))}
            </div>
          )}
          {linePickerModal.category === "rm" && (()=>{
            const sectionTypes = ["PLATE","ISA","ISMB","ISMC","RHS","SHS","Flat Bar","Pipe","Round Bar","Other"];
            const grades = ["E250","E350","E410","SS304","SS316","Other"];
            const plateSizes = ["6mm","8mm","10mm","12mm","16mm","20mm","25mm","32mm","40mm"];
            const st = linePickerForm.sectionType||"";
            const availSizes = st==="PLATE" ? plateSizes : [...new Set((materials||[]).filter(m=>m.sectionType===st&&m.active!==false).map(m=>m.size))];
            const wtPerSheet = (st==="PLATE"&&linePickerForm.length&&linePickerForm.width&&linePickerForm.size)
              ? Math.round((linePickerForm.length||0)*(linePickerForm.width||0)*(parseFloat((linePickerForm.size||"").replace(/mm$/i,""))||0)*7.85/1e6*100)/100 : 0;
            const autoDesc = [st, st!=="PLATE"&&linePickerForm.size, linePickerForm.grade].filter(Boolean).join(" ");
            return (
              <div>
                <G2>
                  <Field label="Section Type">
                    <Sel value={st} onChange={e=>setLinePickerForm(f=>({...f,sectionType:e.target.value,size:"",matLibId:""}))}>
                      <option value="">— Select —</option>
                      {sectionTypes.map(s=><option key={s}>{s}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Grade">
                    <Sel value={linePickerForm.grade||"E250"} onChange={e=>setLinePickerForm(f=>({...f,grade:e.target.value}))}>
                      {grades.map(g=><option key={g}>{g}</option>)}
                    </Sel>
                  </Field>
                  {st && <Field label="Size / Thickness">
                    <Sel value={linePickerForm.size||""} onChange={e=>setLinePickerForm(f=>({...f,size:e.target.value}))}>
                      <option value="">— Select —</option>
                      {availSizes.map(s=><option key={s}>{s}</option>)}
                    </Sel>
                  </Field>}
                  <Field label="Unit">
                    <Sel value={linePickerForm.unit||"Pcs"} onChange={e=>setLinePickerForm(f=>({...f,unit:e.target.value}))}>
                      {["Pcs","Sheets","Metres","Kg"].map(u=><option key={u}>{u}</option>)}
                    </Sel>
                  </Field>
                  {st==="PLATE" && <>
                    <Field label="Length (mm)"><Input type="number" value={linePickerForm.length||""} onChange={e=>setLinePickerForm(f=>({...f,length:+e.target.value}))} placeholder="e.g. 6000" /></Field>
                    <Field label="Width (mm)"><Input type="number" value={linePickerForm.width||""} onChange={e=>setLinePickerForm(f=>({...f,width:+e.target.value}))} placeholder="e.g. 1250" /></Field>
                  </>}
                  <Field label="Qty"><Input type="number" value={linePickerForm.qty||""} onChange={e=>setLinePickerForm(f=>({...f,qty:+e.target.value}))} /></Field>
                  <Field label="Unit Price (₹)"><Input type="number" value={linePickerForm.unitPrice||""} onChange={e=>setLinePickerForm(f=>({...f,unitPrice:+e.target.value}))} /></Field>
                </G2>
                {wtPerSheet>0 && <div style={{ fontSize:12, color:T.textMid, margin:"8px 0" }}>Wt/sheet: <strong style={{color:T.text}}>{fmt.num(wtPerSheet)} kg</strong> · Total: <strong style={{color:T.green}}>{fmt.num(wtPerSheet*(linePickerForm.qty||1))} kg</strong></div>}
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginTop:14 }}>
                  <button onClick={()=>setLinePickerModal({category:null})} style={css.btn.ghost}>← Back</button>
                  <button onClick={()=>{
                    const wt = wtPerSheet>0 ? wtPerSheet*(linePickerForm.qty||1) : 0;
                    const tp = linePickerForm.pricingMethod==="PerKg" ? wt*(linePickerForm.unitPrice||0) : (linePickerForm.qty||1)*(linePickerForm.unitPrice||0);
                    const newLine = { matLibId:"", matCode:`${st}/${linePickerForm.matType||"MS"}/${linePickerForm.grade||"E250"}/${linePickerForm.size||""}`, sectionType:st, matType:linePickerForm.matType||"MS", grade:linePickerForm.grade||"E250", size:linePickerForm.size||"", isPlate:st==="PLATE", orderMode:"ByUnits", qty:linePickerForm.qty||1, qtyOrdered:linePickerForm.qty||1, unit:linePickerForm.unit||"Pcs", pricingMethod:linePickerForm.pricingMethod||"PerUnit", unitPrice:linePickerForm.unitPrice||0, wtOrdered:wt, wtRequired:wt, totalPrice:tp, length:linePickerForm.length||null, width:linePickerForm.width||null, wtSource:"", effectiveRateKg:wt>0?tp/wt:0, qtyReceived:0, wtReceived:0, status:"pending", category:"raw_material", itemDescription:autoDesc };
                    setForm(f=>({...f,lines:[...(f.lines||[]),newLine]}));
                    setLinePickerModal(null);
                  }} disabled={!st||!linePickerForm.size} style={{ ...css.btn.primary, opacity:(!st||!linePickerForm.size)?0.4:1 }}>Add to PO</button>
                </div>
              </div>
            );
          })()}
          {linePickerModal.category === "paint" && (()=>{
            const paintTypes = ["Primer","Intermediate/MIO","Finish Coat","Thinner","Hardener","Putty"];
            const paintItems = (paint||[]).filter(p=>p.active!==false);
            const makes = [...new Set(paintItems.map(p=>p.make).filter(Boolean))];
            const packs = ["1 Litre","4 Litre","10 Litre","20 Litre","200 Litre"];
            const autoDesc = [linePickerForm.paintType, linePickerForm.product, linePickerForm.make, linePickerForm.packSize].filter(Boolean).join(" — ");
            return (
              <div>
                <G2>
                  <Field label="Type">
                    <Sel value={linePickerForm.paintType||""} onChange={e=>setLinePickerForm(f=>({...f,paintType:e.target.value,product:""}))}>
                      <option value="">— Select —</option>
                      {paintTypes.map(t=><option key={t}>{t}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Make">
                    <Sel value={linePickerForm.make||""} onChange={e=>setLinePickerForm(f=>({...f,make:e.target.value,product:""}))}>
                      <option value="">— Select —</option>
                      {makes.map(m=><option key={m}>{m}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Product">
                    <Sel value={linePickerForm.product||""} onChange={e=>setLinePickerForm(f=>({...f,product:e.target.value}))}>
                      <option value="">— Select —</option>
                      {paintItems.filter(p=>!linePickerForm.make||p.make===linePickerForm.make).map(p=><option key={p.id} value={p.product}>{p.product}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Pack Size">
                    <Sel value={linePickerForm.packSize||""} onChange={e=>setLinePickerForm(f=>({...f,packSize:e.target.value}))}>
                      <option value="">— Select —</option>
                      {packs.map(p=><option key={p}>{p}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Qty (packs)"><Input type="number" value={linePickerForm.qty||""} onChange={e=>setLinePickerForm(f=>({...f,qty:+e.target.value}))} /></Field>
                  <Field label="Unit Price (₹/pack)"><Input type="number" value={linePickerForm.unitPrice||""} onChange={e=>setLinePickerForm(f=>({...f,unitPrice:+e.target.value}))} /></Field>
                </G2>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginTop:14 }}>
                  <button onClick={()=>setLinePickerModal({category:null})} style={css.btn.ghost}>← Back</button>
                  <button onClick={()=>{
                    const qty = linePickerForm.qty||1;
                    const tp = qty*(linePickerForm.unitPrice||0);
                    const newLine = { matLibId:"", matCode:"", sectionType:"Paint", size:linePickerForm.packSize||"", grade:"", matType:"", isPlate:false, orderMode:"ByUnits", qty, qtyOrdered:qty, unit:linePickerForm.packSize?.includes("Litre")?"Litre":"Pack", pricingMethod:"PerUnit", unitPrice:linePickerForm.unitPrice||0, wtOrdered:0, wtRequired:0, totalPrice:tp, effectiveRateKg:0, qtyReceived:0, wtReceived:0, status:"pending", category:"paint", itemDescription:autoDesc, paintType:linePickerForm.paintType, make:linePickerForm.make, product:linePickerForm.product };
                    setForm(f=>({...f,lines:[...(f.lines||[]),newLine]}));
                    setLinePickerModal(null);
                  }} disabled={!linePickerForm.paintType||!linePickerForm.product} style={{ ...css.btn.primary, opacity:(!linePickerForm.paintType||!linePickerForm.product)?0.4:1 }}>Add to PO</button>
                </div>
              </div>
            );
          })()}
          {linePickerModal.category === "consumable" && (()=>{
            const subCats = [...new Set((consumables||[]).map(c=>c.subCategory))].sort();
            const subCatItems = (consumables||[]).filter(c=>!linePickerForm.subCategory||c.subCategory===linePickerForm.subCategory);
            const selItem = (consumables||[]).find(c=>c.id===linePickerForm.consumableId);
            const autoDesc = selItem ? `${selItem.name}${linePickerForm.size?" "+linePickerForm.size:""}${linePickerForm.make?" — "+linePickerForm.make:""}${linePickerForm.packSize?" "+linePickerForm.packSize:""}` : "";
            return (
              <div>
                <G2>
                  <Field label="Sub-category">
                    <Sel value={linePickerForm.subCategory||""} onChange={e=>setLinePickerForm(f=>({...f,subCategory:e.target.value,consumableId:"",size:"",make:"",packSize:""}))}>
                      <option value="">— Select —</option>
                      {subCats.map(s=><option key={s} value={s}>{s.charAt(0).toUpperCase()+s.slice(1)}</option>)}
                    </Sel>
                  </Field>
                  <Field label="Item">
                    <Sel value={linePickerForm.consumableId||""} onChange={e=>{ const item=(consumables||[]).find(c=>c.id===e.target.value); setLinePickerForm(f=>({...f,consumableId:e.target.value,size:"",make:"",packSize:"",unit:item?.unit||"Piece"})); }}>
                      <option value="">— Select —</option>
                      {subCatItems.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                    </Sel>
                  </Field>
                  {selItem?.sizes?.length>0 && <Field label="Size">
                    <Sel value={linePickerForm.size||""} onChange={e=>setLinePickerForm(f=>({...f,size:e.target.value}))}>
                      <option value="">— Select —</option>
                      {selItem.sizes.map(s=><option key={s}>{s}</option>)}
                    </Sel>
                  </Field>}
                  {selItem?.approvedMakes?.length>0 && <Field label="Brand">
                    <Sel value={linePickerForm.make||""} onChange={e=>setLinePickerForm(f=>({...f,make:e.target.value}))}>
                      <option value="">— Select —</option>
                      {selItem.approvedMakes.map(m=><option key={m}>{m}</option>)}
                    </Sel>
                  </Field>}
                  {selItem?.packSizes?.length>0 && <Field label="Pack Size">
                    <Sel value={linePickerForm.packSize||""} onChange={e=>setLinePickerForm(f=>({...f,packSize:e.target.value}))}>
                      <option value="">— Select —</option>
                      {selItem.packSizes.map(p=><option key={p}>{p}</option>)}
                    </Sel>
                  </Field>}
                  <Field label="Qty"><Input type="number" value={linePickerForm.qty||""} onChange={e=>setLinePickerForm(f=>({...f,qty:+e.target.value}))} /></Field>
                  <Field label={`Unit Price (₹/${selItem?.unit||"unit"})`}><Input type="number" value={linePickerForm.unitPrice||""} onChange={e=>setLinePickerForm(f=>({...f,unitPrice:+e.target.value}))} /></Field>
                </G2>
                {autoDesc && <div style={{ fontSize:11, color:T.textMid, margin:"8px 0" }}>Description: <strong style={{color:T.text}}>{autoDesc}</strong></div>}
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginTop:14 }}>
                  <button onClick={()=>setLinePickerModal({category:null})} style={css.btn.ghost}>← Back</button>
                  <button onClick={()=>{
                    const qty = linePickerForm.qty||1;
                    const tp = qty*(linePickerForm.unitPrice||0);
                    const newLine = { matLibId:"", matCode:"", sectionType:"Consumable", size:linePickerForm.size||"", grade:"", matType:"", isPlate:false, orderMode:"ByUnits", qty, qtyOrdered:qty, unit:selItem?.unit||"Piece", pricingMethod:"PerUnit", unitPrice:linePickerForm.unitPrice||0, wtOrdered:0, wtRequired:0, totalPrice:tp, effectiveRateKg:0, qtyReceived:0, wtReceived:0, status:"pending", category:"consumable", consumableId:linePickerForm.consumableId, itemDescription:autoDesc };
                    setForm(f=>({...f,lines:[...(f.lines||[]),newLine]}));
                    setLinePickerModal(null);
                  }} disabled={!linePickerForm.consumableId} style={{ ...css.btn.primary, opacity:!linePickerForm.consumableId?0.4:1 }}>Add to PO</button>
                </div>
              </div>
            );
          })()}
        </Modal>
      )}

      {/* Hidden file input for New PO CSV import */}
      <input ref={poImpRef} type="file" accept=".csv" style={{display:"none"}} onChange={handlePOImpFile} />
      {/* PO Line CSV Import Preview Modal */}
      {poImpModal && <POLineImportModal
        rows={poImpRows} err={poImpErr} mode={poImpMode} setMode={setPoImpMode}
        fileRef={poImpRef} onFile={handlePOImpFile}
        onDownload={downloadPOTemplate}
        onConfirm={confirmPOImp}
        onClose={()=>{setPoImpModal(false);setPoImpRows([]);setPoImpErr("");poImpRef.current.value="";}}
      />}
    </div>
  );
};

// Resolve wtOrdered for legacy PO lines where wtPerSheet was 0 (sections created before fix)
const resolvePoLineWt = (pl) => {
  if (pl.wtOrdered > 0) return pl.wtOrdered;
  const wps = sheetWt(pl.matCode, pl.sheetDim||pl.description||"");
  return wps > 0 ? Math.round(wps * (pl.qty||0) * 100) / 100 : 0;
};
const resolvePoLineWtPS = (pl) =>
  pl.wtPerSheet || sheetWt(pl.matCode, pl.sheetDim||pl.description||"");

// ─── PO DETAIL VIEW ───────────────────────────────────────────────────────────
const PODetail = ({ po, onBack, user, pos, setPos, stock, setStock, showToast, materials, editGrnModal, setEditGrnModal, editGrnForm, setEditGrnForm, saveEditGRN, correctionsLog, setCorrectionsLog, purchaseReqs, setPurchaseReqs }) => {
  const [tab, setTab] = useState("lines");
  const [unloadGrn, setUnloadGrn] = useState(null);   // GRN record for the printable unloading sheet
  const [grnModal, setGrnModal] = useState(false);
  const [grnForm, setGrnForm] = useState({ lines:[] });
  const [grnGroupRates, setGrnGroupRates] = useState({}); // {[matCode]: groupRate} for GRN bulk-fill
  const [inspModal, setInspModal] = useState(null);
  const [groupRates, setGroupRates] = useState({}); // {[matCode]: ratePerKg} for nesting POs
  const [poImpModal, setPoImpModal] = useState(false);
  const [poImpRows,  setPoImpRows]  = useState([]);
  const [poImpErr,   setPoImpErr]   = useState("");
  const [poImpMode,  setPoImpMode]  = useState("append");
  const poImpRef = useRef(null);
  const [cancelModal, setCancelModal] = useState(false);
  const [cancelReason, setCancelReason] = useState("");
  const [reverseModal, setReverseModal] = useState(null);
  const [reverseReason, setReverseReason] = useState("");
  const [deleteConfirm, setDeleteConfirm] = useState(false);

  const canEdit = ["super_admin","purchase_admin","store_admin"].includes(user.role);
  const canInspect = can(user,"rmqc.approve");

  const downloadPOTemplate = () => {
    const hdr    = ["Section Type","Size","Grade","Material Type","Length (mm)","Width (mm)","Qty (units)","Weight Required (kg)","Unit","Pricing Method (PerUnit/PerKg)","Unit Price (₹)","Manual Wt (kg/m or kg/m2)","Expected Delivery (DD-MM-YYYY)","Remarks"];
    const hints  = ["e.g. PLATE","12mm","E250","MS","6000","1250","5 (fill OR Weight — not both)","(leave blank if Qty filled)","Sheets","PerUnit","65000","(leave blank if library match found)","20-03-2026","Any notes"];
    const sample = ["ISA","75x75x8","E250","MS","12000","","40","","Pcs","PerUnit","780","","20-03-2026","Main columns"];
    const csv = [hdr,hints,sample].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a = Object.assign(document.createElement("a"),{ href:URL.createObjectURL(new Blob([csv],{type:"text/csv"})), download:`po_lines_template_${po.id}.csv` });
    a.click(); URL.revokeObjectURL(a.href);
  };

  const handlePOImpFile = async e => {
    setPoImpErr(""); setPoImpRows([]);
    const file = e.target.files[0]; if (!file) return;
    if (!file.name.toLowerCase().endsWith(".csv")) { setPoImpErr("Please upload a .csv file."); return; }
    try {
      const { rows, errors, warnings } = parsePOLineCSV(await file.text(), materials);
      if (errors.length) { setPoImpErr(errors.join(" ")); return; }
      setPoImpErr(warnings.length ? "⚠ " + warnings.join(" ") : "");
      setPoImpRows(rows);
    } catch(err) { setPoImpErr("Error reading file: " + err.message); }
  };

  const confirmPOImpDetail = () => {
    const ts   = Date.now();
    const base = poImpMode==="replace" ? [] : (po.lines||[]);
    const clean = poImpRows.map(({_libMatched,...r},i)=>({...r, id:`POL-${ts}-${i}`}));
    setPos(prev=>prev.map(p=>p.id===po.id?{...p,lines:[...base,...clean]}:p));
    showToast(`${clean.length} PO line(s) imported`);
    setPoImpModal(false); setPoImpRows([]); setPoImpErr(""); poImpRef.current.value="";
  };

  const saveGRN = () => {
    const checkedLines = (grnForm.lines||[]).filter(l=>l.checked!==false && (l.actualWt||l.wtReceived||0)>0);
    if (!checkedLines.length) { showToast("No lines selected for receipt", "red"); return; }
    const ts = Date.now();
    const yr = new Date().getFullYear();
    const grnId = nextGrnId(pos);
    const batchNo = po.vendorCode ? genBatchNo(po.vendorCode, pos, yr) : "";
    const grnDate = grnForm.date||today();
    const newGrn = { ...grnForm, id:grnId, batchNo, date:grnDate, createdBy:user.name, lines:checkedLines, status:"received",
      totalActualWt: checkedLines.reduce((s,l)=>s+(l.actualWt||l.wtReceived||0),0) };
    setPos(prev => prev.map(p => {
      if (p.id!==po.id) return p;
      const updLines = p.lines.map(pl=>{
        const gl = newGrn.lines.find(x=>x.poLineId===pl.id);
        if(!gl) return pl;
        const nw=(pl.wtReceived||0)+(gl.actualWt||gl.wtReceived||0);
        const nq=(pl.qtyReceived||0)+(gl.rcvgQty||gl.qtyReceived||0);
        return {...pl, wtReceived:nw, qtyReceived:nq, status:nw>=pl.wtOrdered?"fully_received":"partially_received"};
      });
      const allF=updLines.every(l=>l.status==="fully_received");
      const anyR=updLines.some(l=>l.status==="fully_received"||l.status==="partially_received");
      return {...p, grns:[...p.grns,newGrn], lines:updLines, status:allF?"fully_received":anyR?"partially_received":"pending"};
    }));
    if (setStock) {
      const rawLots = buildStockLots(newGrn, po, grnId, ts);
      if (rawLots.length>0) setStock(prev=>{
        const numberedLots = [];
        rawLots.forEach(lot=>numberedLots.push({...lot, lotNo:genLotNo([...prev, ...numberedLots])}));
        const coveredOrders = po.coveredOrders||[];
        const finalLots = numberedLots.map(lot => {
          if (!coveredOrders.length) return lot;
          const poLine = (po.lines||[]).find(pl=>pl.id===lot.poLineId)||{};
          const allocs = (poLine.orderAllocations||[]).filter(a=>coveredOrders.includes(a.orderId));
          const reservations = allocs.length
            ? (() => { const totKg=allocs.reduce((s,a)=>s+(a.kg||0),0)||1; let left=lot.wtReceived; return allocs.map(a=>{ const k=Math.min(left, Math.round((a.kg/totKg)*lot.wtReceived*10)/10); left=Math.max(0,left-k); return {orderId:a.orderId,kg:k,reservedAt:today(),reservedBy:user.name,source:'grn_auto',grnId,poId:po.id}; }); })()
            : coveredOrders.map(oid=>({orderId:oid,kg:Math.round(lot.wtReceived/coveredOrders.length*10)/10,reservedAt:today(),reservedBy:user.name,source:'grn_auto',grnId,poId:po.id}));
          return {...lot, reservations};
        });
        return [...prev, ...finalLots];
      });
    }
    showToast(`GRN saved — ${checkedLines.length} lots added to RM QC queue`);
    setGrnModal(false); setGrnForm({lines:[]}); setGrnGroupRates({});
  };

  const cancelPO = () => {
    if (!cancelReason.trim()) return;
    const hasReceived = (po.grns||[]).some(g => g.status === "received");
    if (hasReceived) { showToast("Cancel all GRNs first", "red"); setCancelModal(false); return; }
    setPos(prev => prev.map(p => p.id !== po.id ? p : {
      ...p, status:"cancelled",
      cancellationReason: cancelReason,
      cancelledBy: user.name,
      cancelledDate: today()
    }));
    // Revert source PRs so their quantities become convertible again.
    // Partial-era POs: decrement convertedLines per line (sourcePrId + matCode + dim + qty).
    // Legacy POs (pre-partial): matched via po.prId, reverted to pending outright.
    if (setPurchaseReqs) setPurchaseReqs(prev => (prev||[]).map(r => {
      const lines = (po.lines||[]).filter(pl => pl.sourcePrId === r.id);
      const legacy = !lines.length && po.prId === r.id;
      if (!lines.length && !legacy) return r;
      const conv = {...(r.convertedLines||{})};
      lines.forEach(pl => {
        const k = r.id+"|"+pl.matCode+"|"+(pl.sheetDim||"");
        if (conv[k] !== undefined) conv[k] = Math.max(0, conv[k]-(pl.qty||0));
      });
      const anyConv = Object.values(conv).some(v => v>0);
      const poIds = (r.poIds||[]).filter(id => id !== po.id);
      return {...r, convertedLines: conv, poIds, poId: poIds[poIds.length-1]||null,
        status: (legacy || !anyConv) ? "pending" : "partially_converted",
        remarks: ((r.remarks||"")+" \u00b7 "+po.id+" cancelled "+today()+" \u2014 quantities reverted").trim()};
    }));
    showToast("PO cancelled \u2014 source requisition(s) reverted");
    setCancelModal(false);
    onBack();
  };

  const reverseGRN = (grnId) => {
    if (!reverseReason.trim()) return;
    // Step 1 — validate: cannot reverse if any lot is allocated/issued/consumed (material committed to production)
    const grnLots = (stock||[]).filter(s => s.grnId === grnId);
    const blockedLot = grnLots.find(s => ['allocated','issued','consumed'].includes(s.status));
    if (blockedLot) {
      showToast(`Cannot reverse — lot ${blockedLot.lotNo} is ${blockedLot.status} (committed to production). Deallocate first.`, "red");
      return;
    }
    // Step 2 — mark lots as rejected (NOT deleted — physical material still in yard)
    const rejectedAt = new Date().toISOString();
    setStock(prev => prev.map(s => s.grnId !== grnId ? s : {
      ...s, status:'rejected', wtAvailable:0,
      rmQcStatus:'na', clientInspStatus:'na',
      rejectedAt, rejectedBy:user.name,
      rejectionReason:'GRN reversed', grnReversed:true
    }));
    // Steps 3-5 — update PO lines, GRN status, and PO status atomically
    // Read GRN lines from the pos functional updater to avoid stale-closure bugs
    setPos(prev => prev.map(p => {
      if (p.id !== po.id) return p;
      const grn = p.grns.find(g => g.id === grnId);
      if (!grn) return p;
      // Step 3 — reverse wtReceived / qtyReceived on each matching PO line
      const updLines = p.lines.map(pl => {
        const gl = grn.lines?.find(x => x.poLineId === pl.id);
        if (!gl) return pl;
        const nw = Math.max(0, (pl.wtReceived||0) - (gl.actualWt||gl.wtReceived||0));
        const nq = Math.max(0, (pl.qtyReceived||0) - (gl.rcvgQty||gl.qtyReceived||0));
        return { ...pl, wtReceived:nw, qtyReceived:nq,
          status: nw <= 0 ? "pending" : nw >= pl.wtOrdered ? "fully_received" : "partially_received" };
      });
      // Step 4 — recalculate PO status from updated lines
      const allFull = updLines.every(l => l.status === "fully_received");
      const anyRec  = updLines.some(l => l.status === "fully_received" || l.status === "partially_received");
      const newPoStatus = p.status === "cancelled" ? "cancelled"
        : allFull ? "fully_received" : anyRec ? "partially_received" : "pending";
      // Step 5 — mark GRN reversed with audit fields
      const updGrns = p.grns.map(g => g.id !== grnId ? g : {
        ...g, status:"reversed",
        reversalReason: reverseReason,
        reversedBy: user.name,
        reversedDate: today()
      });
      return { ...p, grns:updGrns, lines:updLines, status:newPoStatus };
    }));
    if (setCorrectionsLog) setCorrectionsLog(prev=>[...prev, createCorrectionEntry({
      action:"grn-reversed", entityId:grnId, entityType:"grn",
      fromValue:{status:"received"}, toValue:{status:"reversed"},
      reason:reverseReason, triggeredBy:user
    })]);
    showToast("GRN reversed — lots marked rejected (material remains in yard)");
    setReverseModal(null);
    setReverseReason("");
  };

  const deletePO = () => {
    setPos(prev => prev.filter(p => p.id !== po.id));
    showToast("PO deleted");
    setDeleteConfirm(false);
    onBack();
  };

  // ── Edit PO Line ──────────────────────────────────────────────────────────
  const [editPoLineModal, setEditPoLineModal] = useState(null); // line object
  const [editPoLineForm, setEditPoLineForm] = useState({});
  const [editPoLineReason, setEditPoLineReason] = useState("");

  const saveEditPoLine = () => {
    if (!editPoLineReason.trim()) return showToast("Reason required","amber");
    const line = editPoLineModal;
    const hasGrnAgainstLine = (po.grns||[]).filter(g=>g.status!=="reversed")
      .some(g=>(g.lines||[]).some(l=>l.poLineId===line.id));
    if (hasGrnAgainstLine) return showToast("Cannot edit — GRN already raised against this line. Edit the GRN instead.","amber");
    const newQty = parseFloat(editPoLineForm.qty)||line.qty||0;
    const newRate = parseFloat(editPoLineForm.rate)||line.unitRate||0;
    const newTotal = +(newQty * newRate).toFixed(2);
    setPos(prev=>prev.map(p=>p.id!==po.id?p:{
      ...p, lines:p.lines.map(l=>l.id!==line.id?l:{
        ...l, qty:newQty, unitRate:newRate, totalPrice:newTotal,
        editHistory:[...(l.editHistory||[]),{
          by:user.name, date:today(), reason:editPoLineReason,
          from:{qty:line.qty,unitRate:line.unitRate,totalPrice:line.totalPrice},
          to:{qty:newQty,unitRate:newRate,totalPrice:newTotal}
        }]
      })
    }));
    if (setCorrectionsLog) setCorrectionsLog(prev=>[...prev, createCorrectionEntry({
      action:"po-line-edited", entityId:line.id, entityType:"po_line",
      fromValue:{qty:line.qty,rate:line.unitRate}, toValue:{qty:newQty,rate:newRate},
      reason:editPoLineReason, triggeredBy:user
    })]);
    showToast("PO line updated"); setEditPoLineModal(null); setEditPoLineForm({}); setEditPoLineReason("");
  };

  const totalWtOrd = po.lines?.reduce((s,l)=>s+resolvePoLineWt(l),0)||0;
  const totalVal = po.lines?.reduce((s,l)=>s+(l.totalPrice||0),0)||0;
  // Compute from non-reversed GRNs — always accurate regardless of line wtReceived state
  const grnWt = (g) => g.totalActualWt || (g.lines||[]).reduce((s,l)=>s+(l.actualWt||l.wtReceived||0),0);
  const totalWtRec = (po.grns||[]).filter(g=>g.status!=='reversed').reduce((s,g)=>s+grnWt(g),0);

  return (
    <div>
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:4 }}>
        <button onClick={onBack} style={{ ...css.btn.ghost, color:T.accent }}>← Purchase Orders</button>
        <span style={{ color:T.textLow }}>/</span>
        <span style={{ fontFamily:T.fontMono, color:T.accentHi, fontSize:14, fontWeight:700 }}>{po.id}</span>
        <Badge color={poStatusBadge[po.status]||"gray"}>{po.status?.replace("_"," ")}</Badge>
      </div>
      <div style={{ fontSize:18, fontWeight:800, color:T.text, marginBottom:2 }}>{po.vendorName}</div>
      <div style={{ fontSize:12, color:T.textMid, marginBottom:8 }}>PO Date: {fmt.date(po.poDate)} · Expected: {fmt.date(po.expectedDelivery)}</div>
      <div style={{ display:"flex", gap:10, marginBottom:16, flexWrap:"wrap" }}>
        <StatCard label="Lines" value={po.lines?.length||0} color={T.text} />
        <StatCard label="Total Value" value={fmt.currency(totalVal)} color={T.green} />
        <StatCard label="Wt Ordered" value={`${fmt.num(totalWtOrd)} kg`} sub={`${(totalWtOrd/1000).toFixed(2)} T`} color={T.accent} />
        <StatCard label="Wt Received" value={`${fmt.num(totalWtRec)} kg`} sub={totalWtOrd>0?`${Math.round(totalWtRec/totalWtOrd*100)}%`:""} color={totalWtRec>0?T.green:T.textLow} />
        <StatCard label="GRNs" value={po.grns?.length||0} color={T.textMid} />
      </div>

      <div style={{ display:"flex", gap:8, marginBottom:16 }}>
        {unloadGrn && (()=>{
          const grnLots = (stock||[]).filter(s=>s.grnId===unloadGrn.id);
          const bayName = (bid) => bid ? `Bay ${String((BAYS.find(b=>b.id===bid)||{}).number||"?").padStart(2,"0")}` : "—";
          const totWt = grnLots.reduce((s,l)=>s+(l.wtReceived||0),0);
          return (
            <div style={{ position:"fixed", inset:0, background:"#E2E8F0", overflowY:"auto", zIndex:950 }}>
              <style>{`@media print { .no-print{display:none!important} body{background:#fff!important} } @page { size: A4 portrait; margin: 10mm; }`}</style>
              <div className="no-print" style={{ position:"sticky", top:0, zIndex:10, background:T.bgSidebar, padding:"10px 20px", display:"flex", gap:12, alignItems:"center" }}>
                <button onClick={()=>setUnloadGrn(null)} style={{ ...css.btn.secondary, color:"#fff", borderColor:"#ffffff55" }}>← Back</button>
                <div style={{ color:"#fff", fontWeight:700, fontSize:14 }}>Unloading Sheet — {unloadGrn.id}</div>
                <button onClick={()=>window.print()} style={{ ...css.btn.primary, marginLeft:"auto" }}>Print</button>
              </div>
              <div style={{ width:820, margin:"20px auto", background:"#fff", boxShadow:"0 2px 12px #0003", padding:28, fontFamily:T.font, color:"#0F172A" }}>
                <div style={{ borderBottom:"2px solid #1E3A5F", paddingBottom:8, marginBottom:10, display:"flex", justifyContent:"space-between" }}>
                  <div>
                    <div style={{ fontSize:17, fontWeight:800, color:"#1E3A5F" }}>RM UNLOADING SHEET</div>
                    <div style={{ fontSize:11, fontFamily:T.fontMono }}>{unloadGrn.id} · against {po.id}</div>
                  </div>
                  <div style={{ textAlign:"right", fontSize:11 }}>
                    <div><b>Vendor:</b> {po.vendorName||"—"}</div>
                    <div><b>Date:</b> {unloadGrn.date||""} · <b>Vehicle:</b> {unloadGrn.vehicleNo||"—"} · <b>Challan:</b> {unloadGrn.challanNo||"—"}</div>
                    <div><b>Received by:</b> {unloadGrn.receivedByName||unloadGrn.receivedBy||user.name}</div>
                  </div>
                </div>
                <div style={{ fontSize:11, color:"#475569", marginBottom:8 }}>
                  For the unloading team: place each lot in its assigned bay and write the LOT NO clearly on the material with paint marker. Verify heat numbers against MTC stamps on the plates.
                </div>
                <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                  <thead><tr>
                    {["Lot No","Material","Size / Dim","Qty","Wt (kg)","Grade","Heat No","MTC No","→ Bay"].map(h=>
                      <th key={h} style={{ border:"1px solid #94A3B8", padding:"5px 8px", background:"#F1F5F9", textAlign:"left", fontWeight:700 }}>{h}</th>)}
                  </tr></thead>
                  <tbody>
                    {grnLots.map(l=>(
                      <tr key={l.id}>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono, fontWeight:800, fontSize:12 }}>{l.lotNo||l.id}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{l.matCode}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{l.dims||l.sheetDim||l.size||"—"}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{l.qtyRcv||l.qtyReceived||l.qty||"—"}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{fmt.num(Math.round(l.wtReceived||0))}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px" }}>{l.grade||"—"}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{l.heatNo||"—"}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontFamily:T.fontMono }}>{l.mtcNo||"—"}</td>
                        <td style={{ border:"1px solid #CBD5E1", padding:"5px 8px", fontWeight:800, fontSize:12 }}>{bayName(l.bayId)}</td>
                      </tr>
                    ))}
                    <tr>
                      <td colSpan={4} style={{ border:"1px solid #94A3B8", padding:"5px 8px", fontWeight:700, textAlign:"right", background:"#F8FAFC" }}>TOTAL</td>
                      <td style={{ border:"1px solid #94A3B8", padding:"5px 8px", fontFamily:T.fontMono, fontWeight:700, background:"#F8FAFC" }}>{fmt.num(Math.round(totWt))}</td>
                      <td colSpan={4} style={{ border:"1px solid #94A3B8", background:"#F8FAFC" }}></td>
                    </tr>
                  </tbody>
                </table>
                <div style={{ display:"flex", justifyContent:"space-between", marginTop:26, fontSize:11, color:"#475569" }}>
                  <div>Unloaded by: __________________</div>
                  <div>Lot nos marked: ☐ Yes</div>
                  <div>Verified by (Store): __________________</div>
                </div>
              </div>
            </div>
          );
        })()}
        {["lines","grns"].map(t=>(
          <button key={t} onClick={()=>setTab(t)} style={{ padding:"7px 14px", fontSize:12, fontWeight:tab===t?700:400, color:tab===t?T.accent:T.textMid, background:"transparent", border:"none", borderBottom:tab===t?`2px solid ${T.accent}`:"2px solid transparent", cursor:"pointer", fontFamily:T.font }}>
            {t==="lines"?"PO Lines":"GRNs"} {t==="grns"&&po.grns?.length>0?`(${po.grns.length})`:""}
          </button>
        ))}
        <div style={{ flex:1 }} />
        {user.role==="super_admin" && po.status==="pending" && (po.grns||[]).length===0 && (
          <button onClick={()=>setDeleteConfirm(true)} style={{ ...css.btn.ghost, color:T.red, border:`1px solid ${T.red}` }}>Delete PO</button>
        )}
        {user.role==="super_admin" && po.status!=="cancelled" && !((po.grns||[]).length===0 && po.status==="pending") && (
          <button onClick={()=>{ setCancelReason(""); setCancelModal(true); }} style={{ ...css.btn.ghost, color:T.red, border:`1px solid ${T.red}` }}>Cancel PO</button>
        )}
        {canEdit && tab==="grns" && po.status!=="cancelled" && <button onClick={()=>{
          const yr=new Date().getFullYear();
          const preview=po.vendorCode?genBatchNo(po.vendorCode,pos,yr):"";
          const autoLines=(po.lines||[]).filter(pl=>resolvePoLineWt(pl)>(pl.wtReceived||0)).map(pl=>{
            const balQty=Math.max(0,(pl.qtyOrdered||pl.qty||0)-(pl.qtyReceived||0));
            const resolvedWtOrd=resolvePoLineWt(pl);
            const balWt=Math.round(resolvedWtOrd-(pl.wtReceived||0));
            const wtPS=resolvePoLineWtPS(pl);
            const calcWt=wtPS>0?Math.round(wtPS*balQty*100)/100:Math.max(0,balWt);
            return {
              poLineId:pl.id,
              materialDesc:pl.itemCode||pl.matCode||`${pl.sectionType||""} ${pl.size||""}`.trim(),
              checked:true,
              rcvgQty:balQty,
              calculatedWt:calcWt,
              actualWt:calcWt,
              wtReceived:calcWt,
              variance:0,
              rate:pl.unitPrice||0, manualRate:false,
              lineValue:Math.round(calcWt*(pl.unitPrice||0)*100)/100,
              heatNo:"", mtcId:"", condition:"good", inspStatus:"approved"
            };
          });
          setGrnGroupRates({});
          setGrnForm({lines:autoLines,batchNo:preview,date:today(),receivedBy:user.name,mtcs:[]});
          setGrnModal(true);
        }} style={css.btn.primary}>+ Raise GRN</button>}
        {canEdit && tab==="lines" && po.status==="pending" && (
          <div style={{ display:"flex", gap:6 }}>
            <button onClick={downloadPOTemplate} style={css.btn.secondary}>⬇ Template</button>
            <button onClick={()=>setPoImpModal(true)} style={css.btn.amber}>📥 Import CSV</button>
          </div>
        )}
      </div>

      {/* PO Lines */}
      {tab==="lines" && (
        <div>
          {po.lines?.some(l=>l.wtSource==="manual") && (
            <InfoBanner color="amber">One or more lines have manually entered weights — verify with vendor before raising GRN.</InfoBanner>
          )}
          {(po.sourceType==="nesting"||(po.lines||[]).some(l=>l.prId)) ? (()=>{
            // GROUP by matCode for nesting POs
            const grpMap = {};
            (po.lines||[]).forEach(l => {
              const k = l.matCode||"unknown";
              if (!grpMap[k]) grpMap[k] = [];
              grpMap[k].push(l);
            });
            const grpTotal = (po.lines||[]).reduce((s,l)=>s+(l.totalPrice||0),0);
            const grpWtOrd = (po.lines||[]).reduce((s,l)=>s+(l.wtOrdered||0),0);
            return (
              <div>
                {Object.entries(grpMap).map(([matCode, lines])=>{
                  const gWt = lines.reduce((s,l)=>s+(l.wtOrdered||0),0);
                  const gTotal = lines.reduce((s,l)=>s+(l.totalPrice||0),0);
                  const rate = groupRates[matCode]||"";
                  return (
                    <div key={matCode} style={{ marginBottom:20, border:`1px solid ${T.border}`, borderRadius:8, overflow:"hidden" }}>
                      <div style={{ background:T.bgCard, padding:"10px 14px", display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:8 }}>
                        <div>
                          <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.accentHi, fontSize:13 }}>{matCode}</span>
                          <span style={{ fontSize:12, color:T.textMid, marginLeft:12 }}>{lines.length} dimension{lines.length!==1?"s":""} · {fmt.num(gWt)} kg total</span>
                        </div>
                        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                          <span style={{ fontSize:12, color:T.textMid }}>₹/kg (applies to all):</span>
                          <input type="number" value={rate} min={0} placeholder="0.00"
                            onChange={e=>{
                              const r = parseFloat(e.target.value)||0;
                              setGroupRates(prev=>({...prev,[matCode]:e.target.value}));
                              setPos(prev=>prev.map(p=>{
                                if(p.id!==po.id) return p;
                                return {...p, lines:p.lines.map(l=>{
                                  if(l.matCode!==matCode) return l;
                                  const totalPrice = Math.round((l.wtOrdered||0)*r*100)/100;
                                  return {...l, pricingMethod:"PerKg", unitPrice:r, totalPrice, effectiveRateKg:r};
                                })};
                              }));
                            }}
                            style={{ width:100, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"4px 8px", color:T.text, fontFamily:T.fontMono, fontSize:12 }} />
                          <span style={{ fontSize:12, fontWeight:700, color:T.green }}>= {fmt.currency(gTotal)}</span>
                        </div>
                      </div>
                      <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
                        <thead><tr style={{ borderBottom:`1px solid ${T.border}` }}>
                          <TH>Dimensions</TH><TH right>Sheets</TH><TH right>Wt/Sheet (kg)</TH><TH right>Total Wt (kg)</TH><TH right>Total Value</TH><TH>Status</TH>
                        </tr></thead>
                        <tbody>
                          {lines.map((l,i)=>(
                            <tr key={l.id} style={{ background:i%2===0?"transparent":T.bg }}>
                              <TD mono>{l.sheetDim||l.description||"—"}</TD>
                              <TD right mono>{l.qty||0}</TD>
                              <TD right mono>{l.wtPerSheet ? fmt.num(l.wtPerSheet) : "—"}</TD>
                              <TD right mono>{fmt.num(l.wtOrdered||0)}</TD>
                              <TD right mono color={l.totalPrice>0?T.green:T.textLow}>{fmt.currency(l.totalPrice)}</TD>
                              <TD><Badge color={l.status==="fully_received"?"green":l.status==="partially_received"?"amber":"gray"}>{l.status?.replace("_"," ")}</Badge></TD>
                            </tr>
                          ))}
                          <tr style={{ background:T.bgInput, fontWeight:700 }}>
                            <td colSpan={3} style={{ padding:"6px 10px", fontSize:12, color:T.textMid }}>Subtotal</td>
                            <td style={{ padding:"6px 10px", textAlign:"right", fontFamily:T.fontMono, fontSize:12 }}>{fmt.num(gWt)}</td>
                            <td style={{ padding:"6px 10px", textAlign:"right", fontFamily:T.fontMono, fontSize:12, color:T.green }}>{fmt.currency(gTotal)}</td>
                            <td/>
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  );
                })}
                <div style={{ background:T.bgCard, borderRadius:6, padding:"10px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                  <span style={{ fontSize:13, fontWeight:700, color:T.textMid }}>Grand Total</span>
                  <div style={{ display:"flex", gap:24 }}>
                    <span style={{ fontFamily:T.fontMono, fontWeight:700 }}>{fmt.num(grpWtOrd)} kg</span>
                    <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.currency(grpTotal)}</span>
                  </div>
                </div>
              </div>
            );
          })() : (
          <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
            <thead><tr><TH>#</TH><TH>Section</TH><TH>Size</TH><TH>Grade</TH><TH right>Qty / Weight</TH><TH right>Unit Price</TH><TH>Pricing</TH><TH right>Eff ₹/kg</TH><TH right>Total</TH><TH right>Wt Ord (kg)</TH><TH right>Wt Rcvd (kg)</TH><TH>Status</TH></tr></thead>
            <tbody>
              {po.lines?.map((l,i)=>{
                return (
                <tr key={l.id} style={{ background:i%2===0?"transparent":T.bg }}>
                  <TD mono color={T.textLow}>{i+1}</TD>
                  <TD><span style={{fontFamily:T.fontMono,fontSize:11,color:l.matLibId?T.accentHi:T.text}}>{l.sectionType||l.section||"—"}</span></TD>
                  <TD mono>{l.size||"—"}</TD>
                  <TD>{l.grade||"—"}</TD>
                  <TD right mono>
                    {(l.orderMode||"ByUnits")==="ByWeight"
                      ? <>{fmt.num(resolvePoLineWt(l))} kg <span style={{color:T.textLow,fontSize:11}}>(≈ {l.qtyOrdered||l.qty} {l.unit==="KG"?"pcs":l.unit||"pcs"})</span></>
                      : <>{l.qtyOrdered||l.qty} {l.unit||"MT"} <span style={{color:T.textLow,fontSize:11}}>({fmt.num(Math.round(resolvePoLineWt(l)))} kg){!l.wtOrdered&&resolvePoLineWt(l)>0&&<span style={{color:T.amber}}> ↻</span>}</span></>
                    }
                  </TD>
                  <TD right mono>{fmt.currency(l.unitPrice)}</TD>
                  <TD><span style={{fontSize:11,color:T.textMid}}>{l.pricingMethod||"PerUnit"}</span></TD>
                  <TD right mono>
                    {l.effectiveRateKg>0?`₹${Number(l.effectiveRateKg).toFixed(1)}/kg`:"—"}
                    {l.pricingMethod==="PerKg"&&l.effectiveRateUnit>0&&<div style={{color:T.textLow,fontSize:10}}>₹{fmt.num(Math.round(l.effectiveRateUnit))}/{l.unit||"unit"}</div>}
                  </TD>
                  <TD right mono bold color={T.green}>{fmt.currency(l.totalPrice)}</TD>
                  <TD right mono>{fmt.num(resolvePoLineWt(l))}{!l.wtOrdered&&resolvePoLineWt(l)>0&&<span style={{color:T.amber,fontSize:10,marginLeft:2}}>↻</span>}</TD>
                  <TD right mono color={l.wtReceived>0?T.green:T.textLow}>{fmt.num(l.wtReceived||0)}</TD>
                  <TD><Badge color={l.status==="fully_received"?"green":l.status==="partially_received"?"amber":l.status==="pending"?"gray":"red"}>{l.status?.replace("_"," ")}</Badge>{l.wtSource==="manual"&&<span style={{marginLeft:4}}><Badge color="amber">Manual wt</Badge></span>}</TD>
                  <TD>
                    {can(user,"purchase.edit_po")&&l.status!=="fully_received"&&(
                      <button onClick={()=>{setEditPoLineModal(l);setEditPoLineForm({qty:l.qtyOrdered||l.qty||"",rate:l.unitRate||l.effectiveRateKg||""});setEditPoLineReason("");}}
                        style={{...css.btn.sm,fontSize:10}}>✏ Edit</button>
                    )}
                  </TD>
                </tr>
                );
              })}
              <tr style={{ background:T.bgInput }}>
                <td colSpan={8} style={{ padding:"6px 10px", fontWeight:700, fontSize:12, color:T.textMid }}>Total</td>
                <td style={{ padding:"6px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.currency(totalVal)}</td>
                <td style={{ padding:"6px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700 }}>{fmt.num(totalWtOrd)}</td>
                <td style={{ padding:"6px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.num(totalWtRec)}</td>
                <td/>
              </tr>
            </tbody>
          </table>
          </div>
          )}
        </div>
      )}

      {/* GRNs */}
      {tab==="grns" && (
        <div>
          {po.grns?.length===0 && <div style={{ ...css.card, textAlign:"center", color:T.textLow, padding:32 }}>No GRNs raised yet</div>}
          {po.grns?.map(grn=>(
            <div key={grn.id} style={{ ...css.card, marginBottom:12, opacity:grn.status==="reversed"?0.7:1 }}>
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:10 }}>
                <div>
                  <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                    <span style={{ fontFamily:T.fontMono, color:T.accentHi, fontSize:13, fontWeight:700 }}>{grn.id}</span>
                    <Badge color={grn.status==="reversed"?"red":"green"}>{grn.status==="reversed"?"Reversed":"Received"}</Badge>
                  </div>
                  <div style={{ fontSize:12, color:T.textMid }}>Date: {fmt.date(grn.date)} · Vehicle: {grn.vehicleNo} · Challan: {grn.challanNo} · By: {grn.createdBy}</div>
                  {grn.batchNo&&<div style={{ fontSize:11, color:T.textMid, marginTop:2 }}>Batch: <span style={{fontFamily:T.fontMono,color:T.accentHi,fontWeight:700}}>{grn.batchNo}</span></div>}
                  {grn.supplierInvoiceNo&&<div style={{ fontSize:11, color:T.textMid, marginTop:2 }}>Invoice: <span style={{fontFamily:T.fontMono,color:T.text}}>{grn.supplierInvoiceNo}</span>{grn.supplierInvoiceWt>0?` · Inv Wt: ${fmt.num(grn.supplierInvoiceWt)} kg`:""}{grn.supplierInvoiceAmt>0?` · Inv Amt: ${fmt.currency(grn.supplierInvoiceAmt)}`:""}</div>}
                  {grn.remarks && <div style={{ fontSize:12, color:T.textMid, marginTop:4 }}>{grn.remarks}</div>}
                  {grn.status==="reversed" && <div style={{ fontSize:11, color:T.red, marginTop:4 }}>Reversed by {grn.reversedBy} on {fmt.date(grn.reversedDate)} — {grn.reversalReason}</div>}
                </div>
                {grn.status!=="reversed" && (
                  <button onClick={()=>setUnloadGrn(grn)} style={{ ...css.btn.sm, background:T.bgInput, color:T.accent, border:`1px solid ${T.accent}`, marginRight:6, alignSelf:"flex-start" }}>Unloading Sheet</button>
                )}
                {user.role==="super_admin" && grn.status!=="reversed" && (
                  <>
                  <button onClick={()=>{
                    setEditGrnModal({poId:po.id, grnId:grn.id});
                    setEditGrnForm({...grn});
                  }} style={{ ...css.btn.ghost, fontSize:11 }}>Edit GRN</button>
                  <button onClick={()=>{ setReverseReason(""); setReverseModal(grn.id); }} style={{ ...css.btn.ghost, color:T.red, border:`1px solid ${T.red}`, alignSelf:"flex-start", fontSize:11 }}>Reverse GRN</button>
                  </>
                )}
              </div>
              <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
                <thead><tr><TH>PO Line</TH><TH>Material</TH><TH right>Qty Rcvd</TH><TH right>Calc Wt (kg)</TH><TH right>Actual Wt (kg)</TH><TH right>Variance</TH><TH right>Rate ₹/kg</TH><TH right>Value ₹</TH><TH>Insp</TH></tr></thead>
                <tbody>
                  {grn.lines?.map((l,i)=>(
                    <tr key={i} style={{ background:i%2===0?"transparent":T.bg }}>
                      <TD mono color={T.textLow}>{l.poLineId}</TD>
                      <TD><span style={{fontFamily:T.fontMono,fontSize:11}}>{l.materialDesc||l.poLineId}</span></TD>
                      <TD right mono>{l.rcvgQty||l.qtyReceived||"—"}</TD>
                      <TD right mono>{fmt.num(l.calculatedWt||l.wtReceived)}</TD>
                      <TD right mono bold color={T.green}>{fmt.num(l.actualWt||l.wtReceived)}</TD>
                      <TD right mono color={(()=>{ const vp=l.calculatedWt>0?Math.abs(l.variance||0)/l.calculatedWt*100:0; return vp<=2?T.green:vp<=5?T.amber:T.red; })()}>{l.variance!=null?`${l.variance>=0?"+":""}${l.variance}`:"—"}</TD>
                      <TD right mono>{l.rate>0?`₹${Number(l.rate).toFixed(1)}`:"—"}</TD>
                      <TD right mono bold>{l.lineValue>0?fmt.currency(l.lineValue):"—"}</TD>
                      <TD><Badge color={grnStatusBadge[l.inspStatus]||"gray"}>{l.inspStatus||"—"}</Badge></TD>
                    </tr>
                  ))}
                </tbody>
                {(()=>{
                  const totalCalc=(grn.lines||[]).reduce((s,l)=>s+(l.calculatedWt||0),0);
                  const totalAct=(grn.lines||[]).reduce((s,l)=>s+(l.actualWt||l.wtReceived||0),0);
                  const totalVar=totalAct-totalCalc;
                  const totalVal=(grn.lines||[]).reduce((s,l)=>s+(l.lineValue||0),0);
                  return (
                    <tfoot><tr style={{ background:T.bgInput, borderTop:`1px solid ${T.border}` }}>
                      <td colSpan={3} style={{ padding:"5px 10px", fontSize:11, fontWeight:700, color:T.textMid }}>Total ({grn.lines?.length||0} lines)</td>
                      <td style={{ padding:"5px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700 }}>{fmt.num(Math.round(totalCalc))}</td>
                      <td style={{ padding:"5px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.num(Math.round(totalAct))}</td>
                      <td style={{ padding:"5px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:totalVar>=0?T.green:T.red }}>{totalVar>=0?"+":""}{Math.round(totalVar)}</td>
                      <td/>
                      <td style={{ padding:"5px 10px", textAlign:"right", fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{totalVal>0?fmt.currency(totalVal):"—"}</td>
                      <td/>
                    </tr></tfoot>
                  );
                })()}
              </table>
              {/* MTCs */}
              {(grn.mtcs||[]).length>0 && (
                <div style={{ marginTop:10, paddingTop:10, borderTop:`1px solid ${T.border}` }}>
                  <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:6, letterSpacing:"0.05em" }}>MILL TEST CERTIFICATES</div>
                  <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                    <thead><tr><TH>#</TH><TH>MTC No</TH><TH>Heat No</TH><TH>Grade</TH><TH>Drive Link</TH></tr></thead>
                    <tbody>
                      {(grn.mtcs||[]).map((m,mi)=>(
                        <tr key={m.id} style={{ background:mi%2===0?"transparent":T.bg }}>
                          <TD mono color={T.textLow}>MTC-{mi+1}</TD>
                          <TD mono>{m.mtcNo||"—"}</TD>
                          <TD mono>{m.heatNo||"—"}</TD>
                          <TD>{m.grade||"—"}</TD>
                          <TD>{m.driveLink?<a href={m.driveLink} target="_blank" rel="noreferrer" style={{ color:T.accentHi, fontSize:11 }}>View</a>:"—"}</TD>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {/* Stock weight summary */}
              {(()=>{
                const grnLots=(stock||[]).filter(s=>s.grnId===grn.id);
                if(!grnLots.length) return null;
                const recvWt=grnLots.reduce((s,l)=>s+(l.wtReceived||0),0);
                const rejWt=grnLots.filter(l=>['rejected','returned'].includes(l.status)).reduce((s,l)=>s+(l.wtReceived||0),0);
                const netWt=recvWt-rejWt;
                return (
                  <div style={{ display:"flex", gap:20, marginTop:10, paddingTop:10, borderTop:`1px solid ${T.border}`, fontSize:12 }}>
                    <span style={{ color:T.textMid }}>Lots: <span style={{ fontFamily:T.fontMono, color:T.green }}>{fmt.num(Math.round(recvWt))} kg received</span></span>
                    {rejWt>0 && <span style={{ color:T.red }}>— <span style={{ fontFamily:T.fontMono }}>{fmt.num(Math.round(rejWt))} kg rejected/returned</span></span>}
                    {rejWt>0 && <span style={{ color:T.green, fontWeight:700 }}>Net good: <span style={{ fontFamily:T.fontMono }}>{fmt.num(Math.round(netWt))} kg</span></span>}
                  </div>
                );
              })()}
            </div>
          ))}
        </div>
      )}

      {/* GRN Modal */}
      {grnModal && (()=>{
        const grnPreviewId = nextGrnId(pos);
        // Group lines by matCode for Excel-like table
        const matCodeOf = (l) => po.lines?.find(pl=>pl.id===l.poLineId)?.matCode || l.materialDesc || "Other";
        const grpMap = {};
        (grnForm.lines||[]).forEach((l,i)=>{ const mc=matCodeOf(l); if(!grpMap[mc]) grpMap[mc]=[]; grpMap[mc].push({l,i}); });
        const matCodes = Object.keys(grpMap);
        const checkedLines = (grnForm.lines||[]).filter(l=>l.checked!==false&&(l.actualWt||0)>0);
        const totalCalcWt = checkedLines.reduce((s,l)=>s+(l.calculatedWt||0),0);
        const totalActualWt = checkedLines.reduce((s,l)=>s+(l.actualWt||0),0);
        const totalVariance = totalActualWt - totalCalcWt;
        const totalValue = checkedLines.reduce((s,l)=>s+(l.lineValue||0),0);
        const updLine = (i,patch) => setGrnForm(f=>{ const n=[...f.lines]; n[i]={...n[i],...patch}; return {...f,lines:n}; });
        return (
        <Modal title={`Raise GRN — ${po.id}`} onClose={()=>{setGrnModal(false);setGrnForm({lines:[]});setGrnGroupRates({});}} width={960}>

          {/* SECTION A — Header */}
          <div style={{ background:T.bgCard, border:`1px solid ${T.border}`, borderRadius:8, padding:"12px 16px", marginBottom:16 }}>
            <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:10, letterSpacing:"0.06em" }}>SECTION A — GRN HEADER</div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10 }}>
              <div><div style={css.label}>GRN No (auto)</div><div style={{ fontFamily:T.fontMono, fontSize:13, fontWeight:800, color:T.accentHi }}>{grnPreviewId}</div></div>
              <div><div style={css.label}>Against PO</div><div style={{ fontFamily:T.fontMono, fontSize:13, fontWeight:700, color:T.text }}>{po.id}</div></div>
              <div><div style={css.label}>Received By</div><div style={{ fontSize:12, color:T.text }}>{user.name}</div></div>
              <Field label="Date"><Input type="date" value={grnForm.date||today()} onChange={e=>setGrnForm(f=>({...f,date:e.target.value}))} /></Field>
              <Field label="Vehicle No"><Input value={grnForm.vehicleNo||""} onChange={e=>setGrnForm(f=>({...f,vehicleNo:e.target.value}))} placeholder="MH-31-AB-1234" /></Field>
              <Field label="Mill / Make"><Input value={grnForm.millMake||""} onChange={e=>setGrnForm(f=>({...f,millMake:e.target.value}))} placeholder="e.g. JSW (if vendor is a trader)" /></Field>
              <Field label="Challan No"><Input value={grnForm.challanNo||""} onChange={e=>setGrnForm(f=>({...f,challanNo:e.target.value}))} /></Field>
              <Field label="Supplier DC No"><Input value={grnForm.dcNo||""} onChange={e=>setGrnForm(f=>({...f,dcNo:e.target.value}))} /></Field>
              <Field label="Storage Bay">
                <Sel value={grnForm.bayId||""} onChange={e=>setGrnForm(f=>({...f,bayId:e.target.value}))}>
                  <option value="">Select bay...</option>
                  {BAYS.map(b=><option key={b.id} value={b.id}>Bay {String(b.number).padStart(2,"0")}</option>)}
                </Sel>
              </Field>
              <Field label="Remarks"><Input value={grnForm.remarks||""} onChange={e=>setGrnForm(f=>({...f,remarks:e.target.value}))} /></Field>
            </div>
            {grnForm.batchNo && <div style={{ marginTop:10, display:"flex", alignItems:"center", gap:10 }}>
              <span style={{ fontSize:11, color:T.textMid }}>BATCH NO:</span>
              <span style={{ fontFamily:T.fontMono, fontSize:14, fontWeight:800, color:T.accentHi }}>{grnForm.batchNo}</span>
            </div>}
            {["super_admin","store_admin","store_user"].includes(user.role) && (
              <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginTop:10, paddingTop:10, borderTop:`1px solid ${T.border}` }}>
                <Field label="Supplier Invoice No"><Input value={grnForm.supplierInvoiceNo||""} onChange={e=>setGrnForm(f=>({...f,supplierInvoiceNo:e.target.value}))} /></Field>
                <Field label="Inv Wt (kg)"><Input type="number" value={grnForm.supplierInvoiceWt||""} onChange={e=>setGrnForm(f=>({...f,supplierInvoiceWt:+e.target.value}))} /></Field>
                <Field label="Inv Amt (₹)"><Input type="number" value={grnForm.supplierInvoiceAmt||""} onChange={e=>setGrnForm(f=>({...f,supplierInvoiceAmt:+e.target.value}))} /></Field>
                <Field label="Reconciliation">
                  <Sel value={grnForm.reconciliationStatus||"pending"} onChange={e=>setGrnForm(f=>({...f,reconciliationStatus:e.target.value}))}>
                    <option value="pending">Pending</option><option value="matched">Matched</option><option value="variance">Variance</option><option value="dispute">Dispute</option>
                  </Sel>
                </Field>
              </div>
            )}
          </div>

          {/* SECTION B — MTC Definition */}
          <div style={{ background:T.bgCard, border:`1px solid ${T.border}`, borderRadius:8, padding:"12px 16px", marginBottom:16 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
              <div style={{ fontSize:11, fontWeight:700, color:T.textMid, letterSpacing:"0.06em" }}>SECTION B — MILL TEST CERTIFICATES</div>
              <button onClick={()=>setGrnForm(f=>({...f,mtcs:[...(f.mtcs||[]),{id:`MTC-${Date.now()}`,mtcNo:"",heatNo:"",grade:"",driveLink:""}]}))} style={css.btn.sm}>+ Add MTC</button>
            </div>
            {(grnForm.mtcs||[]).length===0 && <div style={{ fontSize:12, color:T.textLow }}>No MTCs added. Add MTC certificates received with this delivery.</div>}
            {(grnForm.mtcs||[]).map((m,mi)=>{ const updMtc=(field,val)=>setGrnForm(f=>{ const ms=[...(f.mtcs||[])]; ms[mi]={...ms[mi],[field]:val}; return {...f,mtcs:ms}; }); return (
              <div key={m.id} style={{ display:"grid", gridTemplateColumns:"auto 1fr 1fr 1fr 2fr auto", gap:8, alignItems:"end", marginBottom:6 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.accent, paddingBottom:6 }}>MTC-{mi+1}</div>
                <Field label="MTC No"><Input value={m.mtcNo} onChange={e=>updMtc('mtcNo',e.target.value)} placeholder="MTC-001" /></Field>
                <Field label="Heat No"><Input value={m.heatNo} onChange={e=>updMtc('heatNo',e.target.value)} placeholder="JSW-HEAT-001" /></Field>
                <Field label="Grade"><Input value={m.grade} onChange={e=>updMtc('grade',e.target.value)} placeholder="IS 2062 E250" /></Field>
                <Field label="Drive Link"><Input value={m.driveLink} onChange={e=>updMtc('driveLink',e.target.value)} placeholder="https://drive.google.com/..." /></Field>
                <button onClick={()=>setGrnForm(f=>({...f,mtcs:(f.mtcs||[]).filter((_,j)=>j!==mi)}))} style={{ ...css.btn.ghost, color:T.red, paddingTop:20 }}>✕</button>
              </div>
            ); })}
            {(grnForm.mtcs||[]).length>0 && (
              <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginTop:8, paddingTop:8, borderTop:`1px solid ${T.border}` }}>
                <span style={{ fontSize:11, color:T.textMid, alignSelf:"center" }}>Quick assign:</span>
                <button onClick={()=>setGrnForm(f=>({...f,lines:(f.lines||[]).map(l=>({...l,mtcId:(f.mtcs||[])[0]?.id||""}))}))
                } style={css.btn.sm}>MTC-1 → ALL lines</button>
                {matCodes.map(mc=>(
                  <button key={mc} onClick={()=>setGrnForm(f=>({...f,lines:(f.lines||[]).map(l=>matCodeOf(l)===mc?{...l,mtcId:(f.mtcs||[])[0]?.id||""}:l)}))} style={{ ...css.btn.sm, fontSize:10 }}>MTC-1 → {mc.split("/").slice(-2).join("/")}</button>
                ))}
              </div>
            )}
          </div>

          {/* SECTION C — Line Items Table */}
          <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:10, letterSpacing:"0.06em" }}>SECTION C — LINE ITEMS</div>
          {matCodes.map(mc=>{
            const groupItems = grpMap[mc];
            const poLineForGroup = po.lines?.find(pl=>pl.id===groupItems[0]?.l?.poLineId);
            const groupPoWt = groupItems.reduce((s,{l})=>{ const pl=po.lines?.find(x=>x.id===l.poLineId); return s+(pl?.wtOrdered||0); },0);
            const groupRate = grnGroupRates[mc]||"";
            return (
              <div key={mc} style={{ marginBottom:16, border:`1px solid ${T.border}`, borderRadius:8, overflow:"hidden" }}>
                <div style={{ background:T.bgCard, padding:"8px 12px", display:"flex", justifyContent:"space-between", alignItems:"center", gap:12 }}>
                  <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.accentHi, fontSize:12 }}>{mc}</span>
                  <span style={{ fontSize:11, color:T.textMid }}>{groupItems.length} line{groupItems.length!==1?"s":""} · {fmt.num(Math.round(groupPoWt))} kg PO</span>
                  <div style={{ display:"flex", alignItems:"center", gap:6, marginLeft:"auto" }}>
                    <span style={{ fontSize:10, color:T.textMid }}>Rate ₹/kg:</span>
                    <input type="number" min={0} value={groupRate} placeholder="Enter rate..."
                      onChange={e=>{
                        const r=e.target.value;
                        setGrnGroupRates(gr=>({...gr,[mc]:r}));
                        setGrnForm(f=>{
                          const n=[...f.lines];
                          groupItems.forEach(({i})=>{ if(n[i].checked!==false&&!n[i].manualRate) { const aw=n[i].actualWt||0; n[i]={...n[i],rate:parseFloat(r)||0,lineValue:Math.round(aw*(parseFloat(r)||0)*100)/100}; } });
                          return {...f,lines:n};
                        });
                      }}
                      style={{ width:80, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"2px 6px", color:T.text, fontFamily:T.fontMono, fontSize:11 }} />
                    <button onClick={()=>{
                      const r=parseFloat(grnGroupRates[mc])||0;
                      setGrnForm(f=>{ const n=[...f.lines]; groupItems.forEach(({i})=>{ const aw=n[i].actualWt||0; n[i]={...n[i],rate:r,manualRate:false,lineValue:Math.round(aw*r*100)/100}; }); return {...f,lines:n}; });
                    }} style={{ ...css.btn.sm, fontSize:10 }}>Apply to group</button>
                  </div>
                </div>
                <div style={{ overflowX:"auto" }}>
                <table style={{ width:"100%", borderCollapse:"collapse", fontSize:11 }}>
                  <thead><tr style={{ background:T.bgInput, borderBottom:`1px solid ${T.border}` }}>
                    <th style={{ padding:"4px 8px", width:28 }}>☑</th>
                    <th style={{ padding:"4px 8px", textAlign:"left", color:T.textMid, fontWeight:600 }}>Dimensions</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>PO Qty</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Rcvg Qty</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Calc Wt</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Actual Wt</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Variance</th>
                    <th style={{ padding:"4px 8px", textAlign:"center", color:T.textMid, fontWeight:600 }}>MTC</th>
                    <th style={{ padding:"4px 8px", textAlign:"center", color:T.textMid, fontWeight:600 }}>Bay</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Rate ₹/kg</th>
                    <th style={{ padding:"4px 8px", textAlign:"right", color:T.textMid, fontWeight:600 }}>Value</th>
                  </tr></thead>
                  <tbody>
                    {groupItems.map(({l,i})=>{
                      const pl = po.lines?.find(x=>x.id===l.poLineId)||{};
                      const poQty = (pl.qtyOrdered||pl.qty||0);
                      const vp = l.calculatedWt>0?Math.abs(l.variance||0)/l.calculatedWt*100:0;
                      const vc = vp<=2?T.green:vp<=5?T.amber:T.red;
                      const isChecked = l.checked!==false;
                      return (
                        <tr key={i} style={{ background:isChecked?"transparent":`${T.red}08`, opacity:isChecked?1:0.6, borderBottom:`1px solid ${T.border}` }}>
                          <td style={{ padding:"4px 8px", textAlign:"center" }}>
                            <input type="checkbox" checked={isChecked} onChange={e=>updLine(i,{checked:e.target.checked})} />
                          </td>
                          <td style={{ padding:"4px 8px", fontFamily:T.fontMono, color:T.text }}>{l.materialDesc||pl.sheetDim||pl.description||pl.size||"—"}</td>
                          <td style={{ padding:"4px 8px", textAlign:"right", fontFamily:T.fontMono, color:T.textMid }}>{poQty}</td>
                          <td style={{ padding:"3px 6px", textAlign:"right" }}>
                            <input type="number" min={0} max={poQty} value={l.rcvgQty||""} disabled={!isChecked}
                              onChange={e=>{
                                const q=Math.min(+e.target.value,poQty);
                                const wtPS=pl.wtPerSheet||0;
                                const wtPU=calcGrnWtPU(pl,materials);
                                const cw=wtPS>0?Math.round(wtPS*q*100)/100:wtPU>0?Math.round(wtPU*q):0;
                                const vr=Math.round((l.actualWt||cw)-cw);
                                updLine(i,{rcvgQty:q,calculatedWt:cw,variance:vr,lineValue:Math.round((l.actualWt||cw)*(l.rate||0)*100)/100});
                              }}
                              style={{ width:56, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"2px 4px", color:T.text, fontFamily:T.fontMono, fontSize:11, textAlign:"right" }} />
                          </td>
                          <td style={{ padding:"4px 8px", textAlign:"right", fontFamily:T.fontMono, color:T.textMid }}>{fmt.num(l.calculatedWt||0)} kg</td>
                          <td style={{ padding:"3px 6px", textAlign:"right" }}>
                            <input type="number" min={0} value={l.actualWt||""} disabled={!isChecked}
                              onChange={e=>{
                                const aw=+e.target.value;
                                const vr=Math.round(aw-(l.calculatedWt||0));
                                updLine(i,{actualWt:aw,wtReceived:aw,variance:vr,lineValue:Math.round(aw*(l.rate||0)*100)/100});
                              }}
                              style={{ width:72, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"2px 4px", color:T.text, fontFamily:T.fontMono, fontSize:11, textAlign:"right" }} />
                          </td>
                          <td style={{ padding:"4px 8px", textAlign:"right", fontFamily:T.fontMono, color:vc, fontSize:11 }}>{l.calculatedWt>0?`${(l.variance||0)>=0?"+":""}${l.variance||0} kg`:"—"}</td>
                          <td style={{ padding:"3px 6px", textAlign:"center" }}>
                            {(grnForm.mtcs||[]).length>0
                              ? <Sel value={l.mtcId||""} onChange={e=>{ const mtc=(grnForm.mtcs||[]).find(m=>m.id===e.target.value); updLine(i,{mtcId:e.target.value,heatNo:mtc?.heatNo||l.heatNo}); }} style={{ fontSize:10, padding:"2px 4px" }}>
                                  <option value="">—</option>
                                  {(grnForm.mtcs||[]).map((m,mi)=><option key={m.id} value={m.id}>MTC-{mi+1}</option>)}
                                </Sel>
                              : <input value={l.heatNo||""} onChange={e=>updLine(i,{heatNo:e.target.value})} placeholder="Heat…" style={{ width:70, background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:4, padding:"2px 4px", color:T.text, fontSize:10 }} />
                            }
                          </td>
                          <td style={{ padding:"3px 6px", textAlign:"center" }}>
                            <Sel value={l.bayId||""} disabled={!isChecked} onChange={e=>updLine(i,{bayId:e.target.value})} style={{ fontSize:10, padding:"2px 4px", width:78 }}>
                              <option value="">hdr↓</option>
                              {BAYS.map(b=><option key={b.id} value={b.id}>B{String(b.number).padStart(2,"0")}</option>)}
                            </Sel>
                          </td>
                          <td style={{ padding:"3px 6px", textAlign:"right" }}>
                            <input type="number" min={0} value={l.rate||""} disabled={!isChecked} placeholder="0.00"
                              onChange={e=>{
                                const r=parseFloat(e.target.value)||0;
                                const aw=l.actualWt||0;
                                updLine(i,{rate:r,manualRate:true,lineValue:Math.round(aw*r*100)/100});
                              }}
                              style={{ width:72, background:T.bgInput, border:`1px solid ${!(l.rate>0)&&isChecked?T.amber:T.border}`, borderRadius:4, padding:"2px 4px", color:T.text, fontFamily:T.fontMono, fontSize:11, textAlign:"right" }} />
                          </td>
                          <td style={{ padding:"4px 8px", textAlign:"right", fontFamily:T.fontMono, color:(l.lineValue||0)>0?T.green:T.textLow, fontWeight:(l.lineValue||0)>0?700:400 }}>
                            {(l.lineValue||0)>0?fmt.currency(l.lineValue):"—"}
                          </td>
                        </tr>
                      );
                    })}
                    {/* Heat split rows */}
                    {(grnForm.heatSplits||{})[mc]?.map((hs,hsi)=>(
                      <tr key={`hs-${hsi}`} style={{borderBottom:`1px solid ${T.border}`,background:`${T.accent}08`}}>
                        <td style={{padding:"4px 8px",textAlign:"center"}}>
                          <span style={{fontSize:9,color:T.accent,fontWeight:700}}>HEAT {hsi+1}</span>
                        </td>
                        <td style={{padding:"4px 8px"}}>
                          <input value={hs.heatNo||""} onChange={e=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};sp[mc]=[...sp[mc]];sp[mc][hsi]={...sp[mc][hsi],heatNo:e.target.value};return {...f,heatSplits:sp};})} placeholder="Heat No" style={{width:"100%",background:T.bgInput,border:`1px solid ${T.accent}44`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11}} />
                        </td>
                        <td style={{padding:"4px 8px"}}>
                          <input value={hs.mtcNo||""} onChange={e=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};sp[mc]=[...sp[mc]];sp[mc][hsi]={...sp[mc][hsi],mtcNo:e.target.value};return {...f,heatSplits:sp};})} placeholder="MTC No" style={{width:"100%",background:T.bgInput,border:`1px solid ${T.accent}44`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11}} />
                        </td>
                        <td style={{padding:"4px 6px"}} colSpan={2}>
                          <input type="number" value={hs.qty||""} onChange={e=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};sp[mc]=[...sp[mc]];sp[mc][hsi]={...sp[mc][hsi],qty:+e.target.value};return {...f,heatSplits:sp};})} placeholder="Qty" style={{width:56,background:T.bgInput,border:`1px solid ${T.accent}44`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11,marginRight:4}} />
                          <input type="number" value={hs.wt||""} onChange={e=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};sp[mc]=[...sp[mc]];sp[mc][hsi]={...sp[mc][hsi],wt:+e.target.value};return {...f,heatSplits:sp};})} placeholder="Wt (kg)" style={{width:72,background:T.bgInput,border:`1px solid ${T.accent}44`,borderRadius:4,padding:"2px 4px",color:T.text,fontFamily:T.fontMono,fontSize:11}} />
                        </td>
                        <td colSpan={4} style={{padding:"4px 8px",textAlign:"right"}}>
                          <button onClick={()=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};sp[mc]=sp[mc].filter((_,j)=>j!==hsi);return {...f,heatSplits:sp};})} style={{...css.btn.ghost,color:T.red,fontSize:10,padding:"1px 6px"}}>✕</button>
                        </td>
                      </tr>
                    ))}
                    <tr>
                      <td colSpan={10} style={{padding:"4px 8px"}}>
                        <button onClick={()=>setGrnForm(f=>{const sp={...(f.heatSplits||{})};if(!sp[mc])sp[mc]=[];sp[mc]=[...sp[mc],{heatNo:"",mtcNo:"",qty:0,wt:0}];return {...f,heatSplits:sp};})} style={{...css.btn.ghost,fontSize:10,color:T.accent,padding:"2px 8px"}}>
                          + Add Heat Split for {mc.split("/").slice(-2).join("/")}
                        </button>
                      </td>
                    </tr>
                  </tbody>
                </table>
                </div>
              </div>
            );
          })}

          {/* Totals Footer */}
          <div style={{ background:T.bgCard, border:`1px solid ${T.border}`, borderRadius:8, padding:"12px 16px", marginBottom:16 }}>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(5,1fr)", gap:12, fontSize:12 }}>
              <div><div style={css.label}>Checked Lines</div><div style={{ fontFamily:T.fontMono, fontWeight:700, color:T.text }}>{checkedLines.length} of {(grnForm.lines||[]).length}</div></div>
              <div><div style={css.label}>Total Calc Wt</div><div style={{ fontFamily:T.fontMono, fontWeight:700 }}>{fmt.num(Math.round(totalCalcWt))} kg</div></div>
              <div><div style={css.label}>Total Actual Wt</div><div style={{ fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.num(Math.round(totalActualWt))} kg</div></div>
              <div><div style={css.label}>Variance</div><div style={{ fontFamily:T.fontMono, fontWeight:700, color:totalVariance===0?T.textMid:totalVariance>0?T.green:T.red }}>{totalVariance>=0?"+":""}{fmt.num(Math.round(totalVariance))} kg</div></div>
              <div><div style={css.label}>Total Value</div><div style={{ fontFamily:T.fontMono, fontWeight:700, color:T.green }}>{fmt.currency(Math.round(totalValue))}</div></div>
            </div>
          </div>

          <InfoBanner color="amber">All received lots start as QC Hold regardless of visual inspection. Progress via RM QC module.</InfoBanner>
          <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
            <button onClick={()=>{setGrnModal(false);setGrnForm({lines:[]});setGrnGroupRates({});}} style={css.btn.secondary}>Cancel</button>
            <button onClick={saveGRN} disabled={checkedLines.length===0} style={{ ...css.btn.primary, opacity:checkedLines.length>0?1:0.4 }}>Confirm GRN ({checkedLines.length} lines)</button>
          </div>
        </Modal>
        );
      })()}
      {/* Hidden file input for PODetail CSV import */}
      <input ref={poImpRef} type="file" accept=".csv" style={{display:"none"}} onChange={handlePOImpFile} />
      {poImpModal && <POLineImportModal
        rows={poImpRows} err={poImpErr} mode={poImpMode} setMode={setPoImpMode}
        fileRef={poImpRef} onFile={handlePOImpFile}
        onDownload={downloadPOTemplate}
        onConfirm={confirmPOImpDetail}
        onClose={()=>{setPoImpModal(false);setPoImpRows([]);setPoImpErr("");poImpRef.current.value="";}}
      />}

      {/* Edit PO Line Modal */}
      {editPoLineModal&&(
        <Modal title={`Edit PO Line — ${editPoLineModal.sectionType||""} ${editPoLineModal.size||""} ${editPoLineModal.grade||""}`} onClose={()=>setEditPoLineModal(null)} width={460}>
          <InfoBanner color="amber">This line has no GRN raised against it yet. You can edit qty or rate.</InfoBanner>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,margin:"12px 0"}}>
            <Field label={`Quantity (${editPoLineModal.unit||"MT"})`}>
              <Input type="number" value={editPoLineForm.qty||""} onChange={e=>setEditPoLineForm(f=>({...f,qty:e.target.value}))} />
            </Field>
            <Field label="Rate (₹/unit)">
              <Input type="number" value={editPoLineForm.rate||""} onChange={e=>setEditPoLineForm(f=>({...f,rate:e.target.value}))} />
            </Field>
          </div>
          {editPoLineForm.qty&&editPoLineForm.rate&&(
            <div style={{fontSize:12,color:T.textMid,marginBottom:12}}>
              New total: <span style={{fontFamily:T.fontMono,fontWeight:700,color:T.green}}>₹{fmt.currency(parseFloat(editPoLineForm.qty)*parseFloat(editPoLineForm.rate))}</span>
              <span style={{marginLeft:12,color:T.textLow}}>was ₹{fmt.currency(editPoLineModal.totalPrice)}</span>
            </div>
          )}
          <Field label="Reason for change (mandatory)">
            <Input value={editPoLineReason} onChange={e=>setEditPoLineReason(e.target.value)} placeholder="e.g. Rate revised after negotiation" />
          </Field>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
            <button onClick={()=>setEditPoLineModal(null)} style={css.btn.secondary}>Cancel</button>
            <button onClick={saveEditPoLine} disabled={!editPoLineReason.trim()} style={{...css.btn.primary,opacity:editPoLineReason.trim()?1:0.4}}>Save Changes</button>
          </div>
        </Modal>
      )}

      {/* Cancel PO Modal */}
      {cancelModal && (
        <Modal title={`Cancel ${po.id}`} onClose={()=>setCancelModal(false)} width={480}>
          {(po.grns||[]).some(g=>g.status==="received")
            ? <>
                <InfoBanner color="red">Cannot cancel — one or more GRNs have been received. Reverse all GRNs first, then cancel the PO.</InfoBanner>
                <div style={{ display:"flex", justifyContent:"flex-end", marginTop:12 }}>
                  <button onClick={()=>setCancelModal(false)} style={css.btn.primary}>OK</button>
                </div>
              </>
            : <>
                <InfoBanner color="amber">This will mark the PO as Cancelled. This action is logged and cannot be undone automatically.</InfoBanner>
                <Field label="Cancellation Reason (mandatory)">
                  <textarea value={cancelReason} onChange={e=>setCancelReason(e.target.value)} rows={3} style={{ width:"100%", background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:6, color:T.text, fontSize:13, padding:"8px 10px", fontFamily:T.font, resize:"vertical", boxSizing:"border-box" }} placeholder="State the reason for cancellation..." />
                </Field>
                <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:8 }}>
                  <button onClick={()=>setCancelModal(false)} style={css.btn.secondary}>Back</button>
                  <button onClick={cancelPO} disabled={!cancelReason.trim()} style={{ ...css.btn.primary, background:T.red, opacity:cancelReason.trim()?1:0.5 }}>Confirm Cancel</button>
                </div>
              </>
          }
        </Modal>
      )}

      {/* Edit GRN Modal */}
      {editGrnModal&&(
        <Modal title={`Edit GRN — ${editGrnModal.grnId}`} onClose={()=>{setEditGrnModal(null);setEditGrnForm({});}} width={800}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
            <Field label="Date"><Input type="date" value={editGrnForm.date||""} onChange={e=>setEditGrnForm(f=>({...f,date:e.target.value}))} /></Field>
            <Field label="Vehicle No"><Input value={editGrnForm.vehicleNo||""} onChange={e=>setEditGrnForm(f=>({...f,vehicleNo:e.target.value}))} /></Field>
            <Field label="Challan No"><Input value={editGrnForm.challanNo||""} onChange={e=>setEditGrnForm(f=>({...f,challanNo:e.target.value}))} /></Field>
            <Field label="Supplier DC No"><Input value={editGrnForm.dcNo||""} onChange={e=>setEditGrnForm(f=>({...f,dcNo:e.target.value}))} /></Field>
            <Field label="Storage Bay">
              <Sel value={editGrnForm.bayId||""} onChange={e=>setEditGrnForm(f=>({...f,bayId:e.target.value}))}>
                <option value="">Select bay...</option>
                {BAYS.map(b=><option key={b.id} value={b.id}>Bay {String(b.number).padStart(2,"0")}</option>)}
              </Sel>
            </Field>
            <Field label="Remarks"><Input value={editGrnForm.remarks||""} onChange={e=>setEditGrnForm(f=>({...f,remarks:e.target.value}))} /></Field>
          </div>
          <div style={{fontSize:11,fontWeight:700,color:T.textMid,marginBottom:8}}>LINE ITEMS</div>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11,marginBottom:16}}>
            <thead>
              <tr style={{background:T.bgInput}}>
                {["Material","Qty","Actual Wt (kg)","Heat No","MTC No","Bay"].map(h=>(
                  <th key={h} style={{padding:"6px 8px",textAlign:"left",color:T.textMid,fontWeight:600,borderBottom:`1px solid ${T.border}`}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {(editGrnForm.lines||[]).map((l,i)=>(
                <tr key={i} style={{borderBottom:`1px solid ${T.border}33`}}>
                  <td style={{padding:"4px 8px",fontFamily:T.fontMono,fontSize:10,color:T.accentHi}}>{l.materialDesc||l.poLineId}</td>
                  <td style={{padding:"4px 6px"}}>
                    <input type="number" value={l.qtyReceived||""} onChange={e=>setEditGrnForm(f=>{const n=[...f.lines];n[i]={...n[i],qtyReceived:+e.target.value};return {...f,lines:n};})} style={{width:56,background:T.bgInput,border:`1px solid ${T.border}`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11}} />
                  </td>
                  <td style={{padding:"4px 6px"}}>
                    <input type="number" value={l.actualWt||l.wtReceived||""} onChange={e=>setEditGrnForm(f=>{const n=[...f.lines];n[i]={...n[i],actualWt:+e.target.value,wtReceived:+e.target.value};return {...f,lines:n};})} style={{width:80,background:T.bgInput,border:`1px solid ${T.border}`,borderRadius:4,padding:"2px 4px",color:T.text,fontFamily:T.fontMono,fontSize:11}} />
                  </td>
                  <td style={{padding:"4px 6px"}}>
                    <input value={l.heatNo||""} onChange={e=>setEditGrnForm(f=>{const n=[...f.lines];n[i]={...n[i],heatNo:e.target.value};return {...f,lines:n};})} placeholder="Heat No" style={{width:90,background:T.bgInput,border:`1px solid ${T.border}`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11}} />
                  </td>
                  <td style={{padding:"4px 6px"}}>
                    <input value={l.mtcNo||""} onChange={e=>setEditGrnForm(f=>{const n=[...f.lines];n[i]={...n[i],mtcNo:e.target.value};return {...f,lines:n};})} placeholder="MTC No" style={{width:90,background:T.bgInput,border:`1px solid ${T.border}`,borderRadius:4,padding:"2px 4px",color:T.text,fontSize:11}} />
                  </td>
                  <td style={{padding:"4px 6px"}}>
                    <Sel value={l.bayId||editGrnForm.bayId||""} onChange={e=>setEditGrnForm(f=>{const n=[...f.lines];n[i]={...n[i],bayId:e.target.value};return {...f,lines:n};})} style={{fontSize:10,padding:"2px 4px"}}>
                      <option value="">Default</option>
                      {BAYS.map(b=><option key={b.id} value={b.id}>Bay {String(b.number).padStart(2,"0")}</option>)}
                    </Sel>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          <InfoBanner color="amber">Editing GRN will update stock lot weights and heat numbers. Issued quantities are preserved.</InfoBanner>
          <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:12}}>
            <button onClick={()=>{setEditGrnModal(null);setEditGrnForm({});}} style={css.btn.secondary}>Cancel</button>
            <button onClick={saveEditGRN} style={css.btn.primary}>Save Changes</button>
          </div>
        </Modal>
      )}
      {/* Reverse GRN Modal */}
      {reverseModal && (()=>{
        const grnLots = (stock||[]).filter(s => s.grnId === reverseModal);
        const blockedLot = grnLots.find(s => s.status !== "qc_hold");
        return (
          <Modal title={`Reverse ${reverseModal}`} onClose={()=>setReverseModal(null)} width={480}>
            {blockedLot
              ? <>
                  <InfoBanner color="red">Cannot reverse — lot {blockedLot.lotNo} has been approved or allocated. Contact administrator.</InfoBanner>
                  <div style={{ display:"flex", justifyContent:"flex-end", marginTop:12 }}>
                    <button onClick={()=>setReverseModal(null)} style={css.btn.primary}>OK</button>
                  </div>
                </>
              : <>
                  <InfoBanner color="red">Reversing this GRN will mark all stock lots as Rejected and subtract the received weight from PO line counters. Physical material remains in yard — use Return to Vendor or Re-inspect from Stock module.</InfoBanner>
                  <Field label="Reversal Reason (mandatory)">
                    <textarea value={reverseReason} onChange={e=>setReverseReason(e.target.value)} rows={3} style={{ width:"100%", background:T.bgInput, border:`1px solid ${T.border}`, borderRadius:6, color:T.text, fontSize:13, padding:"8px 10px", fontFamily:T.font, resize:"vertical", boxSizing:"border-box" }} placeholder="State the reason for reversal..." />
                  </Field>
                  <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:8 }}>
                    <button onClick={()=>setReverseModal(null)} style={css.btn.secondary}>Back</button>
                    <button onClick={()=>reverseGRN(reverseModal)} disabled={!reverseReason.trim()} style={{ ...css.btn.primary, background:T.red, opacity:reverseReason.trim()?1:0.5 }}>Confirm Reversal</button>
                  </div>
                </>
            }
          </Modal>
        );
      })()}

      {/* Delete PO Confirm */}
      {deleteConfirm && (
        <Modal title="Delete Purchase Order" onClose={()=>setDeleteConfirm(false)} width={400}>
          <InfoBanner color="red">Delete {po.id}? This cannot be undone.</InfoBanner>
          <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:12 }}>
            <button onClick={()=>setDeleteConfirm(false)} style={css.btn.secondary}>Cancel</button>
            <button onClick={deletePO} style={{ ...css.btn.primary, background:T.red }}>Delete PO</button>
          </div>
        </Modal>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════════════
// RM QC MODULE
// ═══════════════════════════════════════════════════════════════════════════════
const RMQCModule = ({ user, stock, setStock, orders }) => {
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState({});
  const [toast, setToast] = useState(null);
  const [revertModal, setRevertModal] = useState(null); // {type:"qc"|"client"|"reinspect", lot}
  const [revertReason, setRevertReason] = useState("");

  const showToast = (msg,color="green") => { setToast({msg,color}); setTimeout(()=>setToast(null),3000); };
  const canQC = ["super_admin","qc_admin","qc_user","store_admin"].includes(user.role);

  // ── Filters: material / order / PO / GRN / received-date range ──
  const [qfMat, setQfMat] = useState("");
  const [qfOrder, setQfOrder] = useState("");
  const [qfPo, setQfPo] = useState("");
  const [qfGrn, setQfGrn] = useState("");
  const [qfFrom, setQfFrom] = useState("");
  const [qfTo, setQfTo] = useState("");
  const qfApply = (list) => list
    .filter(s=>!qfMat || normMatCode(s.matCode)===normMatCode(qfMat))
    .filter(s=>!qfOrder || (s.reservations||[]).some(r=>r.orderId===qfOrder))
    .filter(s=>!qfPo || s.poId===qfPo)
    .filter(s=>!qfGrn || s.grnId===qfGrn)
    .filter(s=>!qfFrom || (s.receivedDate||"")>=qfFrom)
    .filter(s=>!qfTo || (s.receivedDate||"")<=qfTo);
  const qcPendingAll = stock.filter(s=>s.rmQcStatus==="pending" && !["rejected","returned","written_off"].includes(s.status));
  const qcPending = qfApply(qcPendingAll);
  const qfMats = [...new Set(qcPendingAll.map(s=>s.matCode).filter(Boolean))].sort();
  const qfOrders = [...new Set(qcPendingAll.flatMap(s=>(s.reservations||[]).map(r=>r.orderId)).filter(Boolean))];
  const qfPos = [...new Set(qcPendingAll.map(s=>s.poId).filter(Boolean))].sort();
  const qfGrns = [...new Set(qcPendingAll.filter(s=>!qfPo || s.poId===qfPo).map(s=>s.grnId).filter(Boolean))].sort();
  const clientPending = qfApply(stock.filter(s=>s.rmQcStatus==="approved"&&s.clientInspStatus==="pending"));
  const approved = stock.filter(s=>s.rmQcStatus==="approved"&&s.clientInspStatus==="approved");
  const failed = stock.filter(s=>s.rmQcStatus==="failed");
  const onHold = stock.filter(s=>s.status==="qc_hold");

  // ── Bulk selection & approval ──
  const [selQc, setSelQc] = useState([]);
  const [selCi, setSelCi] = useState([]);
  const toggleSel = (setter) => (id) => setter(prev => prev.includes(id) ? prev.filter(x=>x!==id) : [...prev, id]);
  const bulkQcApprove = (ids) => {
    if (!ids.length) return;
    if (!window.confirm(`Approve RM QC for ${ids.length} lot(s)? (Physical check verified for all)`)) return;
    setStock(prev=>prev.map(s=>ids.includes(s.id)?{...s,
      rmQcStatus:"approved", qcRemarks:"Bulk approved — physical check OK", qcDate:today(), qcBy:user.name
    }:s));
    setSelQc([]); showToast(`RM QC approved for ${ids.length} lot(s) — pending client inspection`);
  };
  const bulkClientApprove = (ids) => {
    if (!ids.length) return;
    if (!window.confirm(`Pass client inspection for ${ids.length} lot(s)? They will be released to available stock.`)) return;
    setStock(prev=>prev.map(s=>ids.includes(s.id)?{...s,
      clientInspStatus:"approved", clientInspRemarks:"Bulk cleared", clientInspDate:today(),
      status:(s.rmQcStatus==="approved")
        ? ((s.reservations||[]).length>1 ? "partially_reserved" : (s.reservations||[]).length===1 ? "reserved" : "available")
        : "qc_hold"
    }:s));
    setSelCi([]); showToast(`Client inspection passed for ${ids.length} lot(s) — released to stock ✓`);
  };

  const doQC = (lotId, result, remarks) => {
    const mtcDoc  = form.mtcLink?.trim()||"";
    const heatNo  = form.heatNo?.trim()||"";
    const mtcNo   = form.mtcNo?.trim()||"";
    setStock(prev=>prev.map(s=>s.id===lotId?{...s,
      rmQcStatus:result, qcRemarks:remarks, qcDate:today(), qcBy:user.name,
      status:result==="failed"?"rejected":s.status,
      mtcDoc: mtcDoc||s.mtcDoc, heatNo: heatNo||s.heatNo, mtcNo: mtcNo||s.mtcNo||"",
      mtcUploaded: !!(mtcDoc||s.mtcDoc) || s.mtcUploaded
    }:s));
    showToast(result==="approved"?"RM QC Approved — pending client inspection":"RM QC result saved");
    setModal(null);
  };

  const doClientInsp = (lotId, result, remarks) => {
    setStock(prev=>prev.map(s=>s.id===lotId?{...s,clientInspStatus:result,clientInspRemarks:remarks,clientInspDate:today(),
      status:(result==="approved"&&s.rmQcStatus==="approved")
        ? ((s.reservations||[]).length>1 ? "partially_reserved" : (s.reservations||[]).length===1 ? "reserved" : "available")
        : "qc_hold"}:s));
    showToast(result==="approved"?"Client Inspection Passed — material added to available stock ✓":"Client inspection result saved");
    setModal(null);
  };

  const revertQC = (lot, reason) => {
    setStock(prev=>prev.map(s=>s.id===lot.id?{...s,rmQcStatus:"pending",qcRemarks:"",qcDate:null,qcBy:null,status:"qc_hold",
      auditLog:[...(s.auditLog||[]),{action:"qc_reverted",by:user.name,date:today(),reason}]}:s));
    setRevertModal(null); setRevertReason("");
    showToast("RM QC approval reverted — lot returned to pending","amber");
  };

  const revertClientInsp = (lot, reason) => {
    if ((lot.wtAllocated||0)>0) { showToast(`Cannot revert — lot has ${fmt.num(lot.wtAllocated)} kg allocated`,"red"); return; }
    setStock(prev=>prev.map(s=>s.id===lot.id?{...s,clientInspStatus:"pending",clientInspRemarks:"",clientInspDate:null,status:"qc_hold",
      auditLog:[...(s.auditLog||[]),{action:"client_insp_reverted",by:user.name,date:today(),reason}]}:s));
    setRevertModal(null); setRevertReason("");
    showToast("Client inspection reverted — lot returned to QC hold","amber");
  };

  const reInspect = (lot, reason) => {
    setStock(prev=>prev.map(s=>s.id===lot.id?{...s,rmQcStatus:"pending",qcRemarks:"",qcDate:null,qcBy:null,status:"qc_hold",
      auditLog:[...(s.auditLog||[]),{action:"reinspect_requested",by:user.name,date:today(),reason}]}:s));
    setRevertModal(null); setRevertReason("");
    showToast("Lot returned to RM QC Pending for re-inspection","green");
  };

  const QCRow = ({ lot, type, actions, selCell }) => {
    // Build dimension display from lot data
    const dimStr = lot.length && lot.width
      ? `${lot.length}×${lot.width}mm`
      : lot.length
      ? `L:${lot.length}mm`
      : lot.size||"—";
    const piecesStr = lot.qtyReceived>0 ? `${lot.qtyReceived} pcs` : "—";
    return (
    <tr style={{ borderBottom:`1px solid ${T.border}` }}>
      {selCell}
      <TD mono>{lot.lotNo}</TD>
      <TD>{lot.matType} {lot.grade}</TD>
      <TD>{lot.sectionType||lot.section}</TD>
      <TD mono>{lot.size}</TD>
      <TD mono style={{fontSize:10,color:T.textMid}}>{dimStr}</TD>
      <TD right mono style={{fontSize:11,color:T.amber,fontWeight:600}}>{piecesStr}</TD>
      <TD right mono bold color={T.gold}>{fmt.num(lot.wtReceived)}</TD>
      <TD><Badge color="teal">{lot.bayId}</Badge></TD>
      <TD>{lot.vendorName}</TD>
      <TD>{fmt.date(lot.receivedDate)}</TD>
      <TD>
        {lot.mtcUploaded
          ? <a href={lot.mtcDoc} target="_blank" rel="noreferrer" style={{ ...css.btn.sm, textDecoration:"none", background:T.greenLo, color:T.green, fontSize:10 }}>MTC ✓</a>
          : <span style={{ fontSize:11, color:T.red }}>⚠ MTC Missing</span>}
      </TD>
      <TD>
        <Badge color={qcStatusBadge[type==="qc"?lot.rmQcStatus:lot.clientInspStatus]||"gray"}>
          {type==="qc"?lot.rmQcStatus:lot.clientInspStatus}
        </Badge>
      </TD>
      <TD>
        <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
          {canQC && type!=="done" && type!=="failed" && (
            <button onClick={()=>{setForm({lotId:lot.id,type,lot,mtcLink:lot.mtcDoc||"",heatNo:lot.heatNo||"",mtcNo:lot.mtcNo||"",mtcOverride:false});setModal("inspect");}} style={{ ...css.btn.sm, background:T.amberBg, color:T.amber, border:`1px solid ${T.amber}` }}>
              {type==="qc"?"Inspect":"Client Insp"}
            </button>
          )}
          {actions}
        </div>
      </TD>
    </tr>
    );
  };

  const Section = ({ title, lots, type, color, actionsFor, sel, onToggle, onBulkApprove, bulkLabel }) => {
    // MTC-missing lots are excluded from bulk approval — they need individual handling
    const bulkable = sel ? lots.filter(l=>l.mtcUploaded||l.mtcDoc) : [];
    const bulkableIds = bulkable.map(l=>l.id);
    const selHere = sel ? sel.filter(id=>bulkableIds.includes(id)) : [];
    const allSel = bulkable.length>0 && selHere.length===bulkable.length;
    return (
    <div style={{ marginBottom:20 }}>
      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
        <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{title}</div>
        <Badge color={color}>{lots.length}</Badge>
        {sel && selHere.length>0 && (
          <button onClick={()=>onBulkApprove(selHere)} style={{ ...css.btn.primary, marginLeft:"auto", fontSize:12, padding:"6px 14px" }}>
            ✓ {bulkLabel} ({selHere.length})
          </button>
        )}
      </div>
      {lots.length===0
        ? <div style={{ ...css.card, textAlign:"center", color:T.textLow, padding:20 }}>No items</div>
        : <div style={{ overflowX:"auto" }}>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
              <thead><tr>
                {sel && <TH><input type="checkbox" checked={allSel} onChange={()=>onToggle(allSel ? {clear:bulkableIds} : {set:bulkableIds})} title="Select all (with MTC)" /></TH>}
                <TH>Lot No</TH><TH>Material</TH><TH>Section</TH><TH>Size</TH><TH>Dimensions</TH><TH right>Pieces</TH><TH right>Wt (kg)</TH><TH>Bay</TH><TH>Vendor</TH><TH>Received</TH><TH>MTC</TH><TH>Status</TH><TH>Action</TH>
              </tr></thead>
              <tbody>{lots.map(l=><QCRow key={l.id} lot={l} type={type} actions={actionsFor?actionsFor(l):null}
                selCell={sel ? (
                  <td style={{ borderBottom:`1px solid ${T.border}`, padding:"6px 8px", verticalAlign:"middle" }}>
                    {(l.mtcUploaded||l.mtcDoc)
                      ? <input type="checkbox" checked={sel.includes(l.id)} onChange={()=>onToggle(l.id)} />
                      : <span title="MTC missing — inspect individually" style={{ color:T.textLow, fontSize:10 }}>—</span>}
                  </td>
                ) : null} />)}</tbody>
            </table>
          </div>
      }
    </div>
    );
  };

  return (
    <div>
      {toast && <div style={{ position:"fixed", top:20, right:20, zIndex:2000, background:toast.color==="green"?T.greenBg:T.redBg, border:`1px solid ${toast.color==="green"?T.green:T.red}`, borderRadius:8, padding:"12px 20px", color:toast.color==="green"?T.green:T.red, fontSize:13, fontWeight:600 }}>{toast.msg}</div>}

      <div style={{ marginBottom:16 }}>
        <div style={{ fontSize:20, fontWeight:800, color:T.text }}>RM Quality Control</div>
        <div style={{ fontSize:12, color:T.textMid }}>RM inspection · MTC verification · Client inspection gate · Stock release</div>
      </div>

      <div style={{ display:"flex", gap:10, marginBottom:18, flexWrap:"wrap" }}>
        <StatCard label="RM QC Pending" value={qcPending.length} color={T.amber} />
        <StatCard label="Client Insp Pending" value={clientPending.length} color={T.gold} sub="HARD GATE — cannot produce" />
        <StatCard label="Approved & Available" value={approved.length} color={T.green} />
        <StatCard label="QC Hold" value={onHold.length} color={T.red} />
      </div>

      {onHold.length>0 && (
        <InfoBanner color="red">
          {(()=>{
            const reasoned = onHold.filter(s=>s.qcHoldReason||s.qcRemarks);
            const fresh = onHold.length - reasoned.length;
            return (
              <>
                {reasoned.length>0 && (<>⚠ <strong>{reasoned.length} lot(s) on QC Hold:</strong>{" "}{reasoned.map(s=>`${s.lotNo} — ${s.qcHoldReason||s.qcRemarks}`).join(" | ")}</>)}
                {fresh>0 && (<div style={{ marginTop:reasoned.length?4:0 }}>{fresh} newly received lot(s) awaiting first inspection (routine — listed in the table below).</div>)}
              </>
            );
          })()}
        </InfoBanner>
      )}

      <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap", margin:"4px 0 10px" }}>
        <span style={{ fontSize:11, fontWeight:700, color:T.textMid }}>FILTER:</span>
        <Sel value={qfMat} onChange={e=>setQfMat(e.target.value)} style={{ width:190 }}>
          <option value="">All materials</option>
          {qfMats.map(m=><option key={m} value={m}>{m}</option>)}
        </Sel>
        <Sel value={qfOrder} onChange={e=>setQfOrder(e.target.value)} style={{ width:170 }}>
          <option value="">All orders</option>
          {qfOrders.map(oid=><option key={oid} value={oid}>{(orders||[]).find(o=>o.id===oid)?.orderNo||oid}</option>)}
        </Sel>
        <Sel value={qfPo} onChange={e=>{setQfPo(e.target.value);setQfGrn("");}} style={{ width:150 }}>
          <option value="">All POs</option>
          {qfPos.map(p=><option key={p} value={p}>{p}</option>)}
        </Sel>
        <Sel value={qfGrn} onChange={e=>setQfGrn(e.target.value)} style={{ width:150 }}>
          <option value="">All GRNs</option>
          {qfGrns.map(g=><option key={g} value={g}>{g}</option>)}
        </Sel>
        <span style={{ fontSize:11, color:T.textMid }}>Received</span>
        <input type="date" value={qfFrom} onChange={e=>setQfFrom(e.target.value)} style={{ ...css.input, width:130 }} />
        <span style={{ fontSize:11, color:T.textMid }}>to</span>
        <input type="date" value={qfTo} onChange={e=>setQfTo(e.target.value)} style={{ ...css.input, width:130 }} />
        {(qfMat||qfOrder||qfPo||qfGrn||qfFrom||qfTo) && (
          <button onClick={()=>{setQfMat("");setQfOrder("");setQfPo("");setQfGrn("");setQfFrom("");setQfTo("");}} style={{ ...css.btn.ghost, fontSize:11 }}>✕ Clear ({qcPending.length}/{qcPendingAll.length})</button>
        )}
      </div>
      <Section title="RM QC Pending — Physical Inspection" lots={qcPending} type="qc" color="amber"
        sel={selQc} onBulkApprove={bulkQcApprove} bulkLabel="Approve QC for selected"
        onToggle={(v)=>{ if(v&&v.set) setSelQc(v.set); else if(v&&v.clear) setSelQc([]); else toggleSel(setSelQc)(v); }} />
      <Section title="Client Inspection Pending" lots={clientPending} type="client" color="gold"
        sel={selCi} onBulkApprove={bulkClientApprove} bulkLabel="Pass client inspection for selected"
        onToggle={(v)=>{ if(v&&v.set) setSelCi(v.set); else if(v&&v.clear) setSelCi([]); else toggleSel(setSelCi)(v); }}
        actionsFor={user.role==="super_admin"?lot=>(
          <button onClick={()=>{setRevertModal({type:"qc",lot});setRevertReason("");}} style={{ ...css.btn.sm, background:T.amberBg, color:T.amber, border:`1px solid ${T.amber}` }}>
            Revert QC ↩
          </button>
        ):null}
      />
      <Section title="Approved & Available in Stock" lots={approved} type="done" color="green"
        actionsFor={user.role==="super_admin"?lot=>(
          <button onClick={()=>{setRevertModal({type:"client",lot});setRevertReason("");}} style={{ ...css.btn.sm, background:T.redBg, color:T.red, border:`1px solid ${T.redLo}` }}>
            Revert Insp ↩
          </button>
        ):null}
      />
      <Section title="Failed / Rejected Lots" lots={failed} type="failed" color="red"
        actionsFor={["super_admin","qc_admin","qc_user"].includes(user.role)?lot=>(
          <div style={{display:"flex",gap:6}}>
            <button onClick={()=>{setRevertModal({type:"reinspect",lot});setRevertReason("");}}
              style={{ ...css.btn.sm, background:T.greenLo, color:T.green, border:`1px solid ${T.green}` }}>
              Re-inspect
            </button>
            <button onClick={()=>{setRevertModal({type:"edit_reason",lot});setRevertReason(lot.qcRemarks||lot.qcRejectionReason||"");}}
              style={{ ...css.btn.sm, background:T.bgInput, color:T.textMid, border:`1px solid ${T.border}` }}>
              Edit Reason
            </button>
          </div>
        ):null}
      />

      {/* Revert / Re-inspect Modal */}
      {revertModal && (
        <Modal title={revertModal.type==="qc"?"Revert RM QC Approval":revertModal.type==="client"?"Revert Client Inspection":revertModal.type==="edit_reason"?"Edit Rejection Reason":"Send for Re-inspection"} onClose={()=>setRevertModal(null)}>
          {revertModal.type==="edit_reason"
            ? (<>
                <div style={{marginBottom:8,fontSize:12,color:T.textMid}}>
                  Lot: <span style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{revertModal.lot.lotNo}</span> · {revertModal.lot.matCode}
                </div>
                <Field label="Current rejection reason">
                  <div style={{padding:"6px 10px",background:T.bg,borderRadius:4,fontSize:12,color:T.textMid,marginBottom:8}}>{revertModal.lot.qcRemarks||revertModal.lot.qcRejectionReason||"—"}</div>
                </Field>
                <Field label="New rejection reason (mandatory)">
                  <textarea value={revertReason} onChange={e=>setRevertReason(e.target.value)} rows={3}
                    style={{...css.input,width:"100%",resize:"vertical"}} placeholder="Enter corrected reason..." />
                </Field>
                <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:12}}>
                  <button onClick={()=>setRevertModal(null)} style={css.btn.secondary}>Cancel</button>
                  <button disabled={!revertReason.trim()} onClick={()=>{
                    if (!revertReason.trim()) return;
                    setStock(prev=>prev.map(s=>s.id!==revertModal.lot.id?s:{
                      ...s, qcRemarks:revertReason, qcRejectionReason:revertReason,
                      auditLog:[...(s.auditLog||[]),{action:"rejection-reason-edited",by:user.name,date:today(),
                        reason:`Changed from: "${revertModal.lot.qcRemarks||revertModal.lot.qcRejectionReason||"—"}" to: "${revertReason}"`}]
                    }));
                    showToast("Rejection reason updated");
                    setRevertModal(null);
                  }} style={{...css.btn.primary,opacity:revertReason.trim()?1:0.4}}>
                    Save Reason
                  </button>
                </div>
              </>)
            : (<>
          <InfoBanner color={revertModal.type==="reinspect"?"blue":"red"}>
            {revertModal.type==="qc"&&"This will set the lot back to RM QC Pending. The QC approval will be cleared."}
            {revertModal.type==="client"&&"This will set the lot back to QC Hold. The client inspection approval will be cleared. Blocked if material is allocated."}
            {revertModal.type==="reinspect"&&"This will return the failed lot to RM QC Pending for a fresh inspection."}
          </InfoBanner>
          {revertModal.type==="client"&&(revertModal.lot.wtAllocated||0)>0&&(
            <InfoBanner color="red">⚠ Cannot revert — this lot has {fmt.num(revertModal.lot.wtAllocated)} kg allocated. Release allocations first.</InfoBanner>
          )}
          <div style={{ marginTop:12 }}>
            <label style={css.label}>Reason *</label>
            <textarea value={revertReason} onChange={e=>setRevertReason(e.target.value)} rows={3}
              placeholder="State the reason for this action..."
              style={{ ...css.input, width:"100%", resize:"vertical", marginTop:4 }} />
          </div>
          <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:14 }}>
            <button onClick={()=>setRevertModal(null)} style={css.btn.secondary}>Cancel</button>
            <button disabled={!revertReason.trim()||(revertModal.type==="client"&&(revertModal.lot.wtAllocated||0)>0)}
              onClick={()=>{
                if (!revertReason.trim()) return;
                if (revertModal.type==="qc") revertQC(revertModal.lot, revertReason);
                else if (revertModal.type==="client") revertClientInsp(revertModal.lot, revertReason);
                else reInspect(revertModal.lot, revertReason);
              }}
              style={{ ...css.btn.primary, opacity:(revertReason.trim()&&!(revertModal.type==="client"&&(revertModal.lot.wtAllocated||0)>0))?1:0.4 }}>
              Confirm
            </button>
          </div>
          </>)}
        </Modal>
      )}

      {/* Inspection Modal */}
      {modal==="inspect" && (
        <Modal title={form.type==="qc"?"RM QC Inspection":"Client Inspection"} onClose={()=>setModal(null)} width={560}>
          <div style={{ ...css.card, background:T.bg, marginBottom:14 }}>
            <div style={{ fontSize:12, fontWeight:700, color:T.textMid, marginBottom:8 }}>LOT DETAILS</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
              {[["Lot No",form.lot?.lotNo],["Material",`${form.lot?.matType} ${form.lot?.grade}`],["Section/Size",`${(form.lot?.sectionType||form.lot?.section||'')} ${form.lot?.size||''}`.trim()],["Wt Received",`${fmt.num(form.lot?.wtReceived)} kg`],["Bay",form.lot?.bayId],["MTC",form.lot?.mtcUploaded?"Uploaded ✓":"⚠ Missing"]].map(([k,v])=>(
                <div key={k}><div style={css.label}>{k}</div><div style={{ fontSize:12, color:v?.includes?.("⚠")?T.red:T.text, fontFamily:k.includes("Lot")||k.includes("Wt")||k.includes("Bay")?T.fontMono:T.font }}>{v}</div></div>
              ))}
            </div>
            <div style={{ display:"flex", gap:16, marginTop:8, flexWrap:"wrap" }}>
              {form.lot?.qtyReceived>0&&<span style={{fontSize:12,color:T.text}}>Pieces: <strong>{form.lot.qtyReceived} pcs</strong></span>}
              {form.lot?.length&&<span style={{fontSize:12,color:T.text}}>Length: <strong>{form.lot.length}mm</strong></span>}
              {form.lot?.width&&<span style={{fontSize:12,color:T.text}}>Width: <strong>{form.lot.width}mm</strong></span>}
              {form.lot?.heatNo&&<span style={{fontSize:12,color:T.accent}}>Heat: <strong style={{fontFamily:T.fontMono}}>{form.lot.heatNo}</strong></span>}
              {form.lot?.mtcNo&&<span style={{fontSize:12,color:T.accent}}>MTC: <strong style={{fontFamily:T.fontMono}}>{form.lot.mtcNo}</strong></span>}
              {form.lot?.batchNo&&<span style={{fontSize:12,color:T.textMid}}>Batch: <strong style={{fontFamily:T.fontMono}}>{form.lot.batchNo}</strong></span>}
            </div>
          </div>

          {form.type==="qc" && (
            <div>
              <div style={{ ...css.card, background:T.bg, marginBottom:14 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
                  <div style={{ fontSize:11, fontWeight:700, color:T.textMid, letterSpacing:"0.06em" }}>MTC DOCUMENT</div>
                  {(form.mtcLink||form.heatNo||form.mtcNo)&&!form.mtcOverride&&(
                    <button onClick={()=>setForm(f=>({...f,mtcOverride:true}))} style={{ ...css.btn.sm, background:T.amberBg, color:T.amber }}>Override MTC</button>
                  )}
                </div>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
                  <div>
                    <label style={css.label}>MTC No</label>
                    <input value={form.mtcNo||""} onChange={e=>setForm(f=>({...f,mtcNo:e.target.value}))}
                      readOnly={!form.mtcOverride && !!(form.lot?.mtcNo)}
                      placeholder="MTC document number"
                      style={{ ...css.input, marginTop:4, opacity:(!form.mtcOverride&&form.mtcNo)?0.7:1 }} />
                  </div>
                  <div>
                    <label style={css.label}>Heat Number</label>
                    <input value={form.heatNo||""} onChange={e=>setForm(f=>({...f,heatNo:e.target.value}))}
                      readOnly={!form.mtcOverride && !!(form.lot?.heatNo)}
                      placeholder="e.g. JSW-HEAT-2026-001"
                      style={{ ...css.input, marginTop:4, opacity:(!form.mtcOverride&&form.heatNo)?0.7:1 }} />
                  </div>
                  <div style={{ gridColumn:"span 2" }}>
                    <label style={css.label}>Drive Link</label>
                    <input value={form.mtcLink||""} onChange={e=>setForm(f=>({...f,mtcLink:e.target.value}))}
                      readOnly={!form.mtcOverride && !!(form.lot?.mtcLink)}
                      placeholder="https://drive.google.com/..."
                      style={{ ...css.input, marginTop:4, width:"100%", opacity:(!form.mtcOverride&&form.mtcLink)?0.7:1 }} />
                  </div>
                </div>
                {(form.mtcLink||form.heatNo||form.mtcNo)&&!form.mtcOverride&&(
                  <div style={{ fontSize:11, color:T.textLow, marginTop:8 }}>Pre-filled from GRN MTC — click Override MTC to modify</div>
                )}
              </div>
              <Field label="Inspection Checks">
                <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {["MTC Verified","Dimensions Checked","Visual Inspection OK","Surface Condition OK","Identification Marking OK"].map(check=>(
                    <div key={check}>
                      <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer" }}>
                        <input type="checkbox" checked={form[check]||false} onChange={e=>setForm(f=>({...f,[check]:e.target.checked}))} />
                        <span style={{ fontSize:12, color:T.text }}>{check}</span>
                      </label>
                      {check==="MTC Verified" && form["MTC Verified"] && !(form.mtcLink||"").trim() && (
                        <div style={{ fontSize:11, color:T.amber, marginTop:3, marginLeft:24 }}>⚠ MTC Verified requires a document link</div>
                      )}
                    </div>
                  ))}
                </div>
              </Field>
              {!form.lot?.mtcUploaded && !(form.mtcLink||"").trim() && <InfoBanner color="red">⚠ MTC not uploaded — system will allow QC but will log warning. Upload MTC before client inspection.</InfoBanner>}
            </div>
          )}

          {form.type==="client" && (
            <InfoBanner color="amber">
              HARD GATE — client must physically inspect and approve before material enters production. Once approved, material becomes available for nesting and production.
            </InfoBanner>
          )}

          <Field label="Remarks / Observations"><Textarea value={form.remarks||""} onChange={e=>setForm(f=>({...f,remarks:e.target.value}))} /></Field>

          <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
            <button onClick={()=>setModal(null)} style={css.btn.secondary}>Cancel</button>
            <button onClick={()=>{ if(form.type==="qc") doQC(form.lotId,"failed",form.remarks); else doClientInsp(form.lotId,"rejected",form.remarks); }} style={css.btn.danger}>
              {form.type==="qc"?"Fail / Hold":"Reject"}
            </button>
            <button onClick={()=>{ if(form.type==="qc") doQC(form.lotId,"approved",form.remarks); else doClientInsp(form.lotId,"approved",form.remarks); }} style={css.btn.primary}>
              {form.type==="qc"?"Pass QC → Client Inspection":"Client Approve → To Stock"}
            </button>
          </div>
        </Modal>
      )}
    </div>
  );
};

