const OrdersModule = ({ user, orders, setOrders, clients, setClients, materials, stock, vendors, tpiAgencies, pos, nestingBatches, releases, instances, purchaseReqs, company, setCompany, dprs, drawingInstances, setDrawingInstances, processTypes }) => {
  const [selected, setSelected] = useState(null);
  const saveOrder = (updated) => { setOrders(prev=>prev.map(o=>o.id===updated.id?updated:o)); setSelected(updated); };
  if (selected) return <OrderDetail order={selected} onBack={()=>setSelected(null)} onSave={saveOrder} user={user} clients={clients} materials={materials} stock={stock} vendors={vendors} tpiAgencies={tpiAgencies} pos={pos||[]} nestingBatches={nestingBatches||[]} releases={releases||[]} instances={instances||[]} purchaseReqs={purchaseReqs||[]} dprs={dprs||[]} drawingInstances={drawingInstances||[]} setDrawingInstances={setDrawingInstances} processTypes={processTypes} />;
  return <OrdersList orders={orders} onOpen={setSelected} user={user} clients={clients} setClients={setClients} onAddOrder={o=>setOrders(prev=>[...prev,o])} company={company} setCompany={setCompany} />;
};

// ─── LOGIN ────────────────────────────────────────────────────────────────────
// ─── SECURITY UTILITIES ──────────────────────────────────────────────────────

const SESSION_TIMEOUT_MS = 8 * 60 * 60 * 1000;  // 8 hours
const SESSION_WARN_MS    = 15 * 60 * 1000;        // warn 15 min before expiry
const MAX_ATTEMPTS       = 5;
const LOCKOUT_MS         = 15 * 60 * 1000;        // 15 min lockout
const SESSION_KEY        = "structo_session";
const ATTEMPTS_KEY       = "structo_login_attempts";

const hashPassword = async (password) => {
  const data = new TextEncoder().encode(password + "structo_salt_v3");
  const buf  = await crypto.subtle.digest("SHA-256", data);
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,"0")).join("");
};

const verifyPassword = async (input, stored) => {
  if (/^[0-9a-f]{64}$/.test(stored)) {
    return (await hashPassword(input)) === stored;
  }
  return input === stored; // legacy plain text — migrated on first login
};

const createSession  = (user) => localStorage.setItem(SESSION_KEY, JSON.stringify({ userId:user.id, username:user.username, expiresAt:Date.now()+SESSION_TIMEOUT_MS }));
const clearSession   = ()     => localStorage.removeItem(SESSION_KEY);
const extendSession  = ()     => { try { const s=JSON.parse(localStorage.getItem(SESSION_KEY)||"null"); if(s){ s.expiresAt=Date.now()+SESSION_TIMEOUT_MS; localStorage.setItem(SESSION_KEY,JSON.stringify(s)); }} catch {} };
const getSession     = ()     => { try { const s=JSON.parse(localStorage.getItem(SESSION_KEY)||"null"); if(!s||Date.now()>s.expiresAt){localStorage.removeItem(SESSION_KEY);return null;} return s; } catch { return null; }};

const getAttempts    = (u)    => { try { return (JSON.parse(localStorage.getItem(ATTEMPTS_KEY)||"{}"))[u]||{count:0,lockedUntil:0}; } catch { return {count:0,lockedUntil:0}; }};
const recordAttempt  = (u,ok) => { try { const a=JSON.parse(localStorage.getItem(ATTEMPTS_KEY)||"{}"); if(ok){delete a[u];}else{const c=(a[u]?.count||0)+1; a[u]={count:c,lockedUntil:c>=MAX_ATTEMPTS?Date.now()+LOCKOUT_MS:0};} localStorage.setItem(ATTEMPTS_KEY,JSON.stringify(a)); return a[u]||{count:0,lockedUntil:0}; } catch { return {count:0,lockedUntil:0}; }};

// ─── SESSION MONITOR ─────────────────────────────────────────────────────────
const SessionMonitor = ({ onSignOut }) => {
  const [minsLeft, setMinsLeft] = React.useState(null);
  React.useEffect(()=>{
    const tick = setInterval(()=>{
      const s = getSession();
      if (!s) { onSignOut(); return; }
      const rem = s.expiresAt - Date.now();
      if (rem <= 0) { clearSession(); onSignOut(); return; }
      setMinsLeft(rem < SESSION_WARN_MS ? Math.ceil(rem/60000) : null);
    }, 30000);
    const act = () => extendSession();
    window.addEventListener("click", act);
    window.addEventListener("keydown", act);
    return ()=>{ clearInterval(tick); window.removeEventListener("click",act); window.removeEventListener("keydown",act); };
  }, []);
  if (!minsLeft) return null;
  return (
    <div style={{position:"fixed",top:0,left:0,right:0,zIndex:9999,background:T.amber,color:"#000",padding:"8px 20px",display:"flex",alignItems:"center",justifyContent:"space-between",fontSize:12,fontWeight:600}}>
      <span>⏱ Session expires in {minsLeft} minute{minsLeft!==1?"s":""}. Click anywhere to stay signed in.</span>
      <button onClick={()=>{extendSession();setMinsLeft(null);}} style={{background:"#000",color:T.amber,border:"none",borderRadius:4,padding:"4px 12px",cursor:"pointer",fontSize:11,fontWeight:700}}>Stay Signed In</button>
    </div>
  );
};

// ─── PASSWORD CHANGE MODAL ────────────────────────────────────────────────────
const PasswordChangeModal = ({ user, appUsers, setAppUsers, onClose }) => {
  const [cur,  setCur]  = React.useState("");
  const [nw,   setNw]   = React.useState("");
  const [conf, setConf] = React.useState("");
  const [err,  setErr]  = React.useState("");
  const [ok,   setOk]   = React.useState(false);
  const [busy, setBusy] = React.useState(false);

  const save = async () => {
    setErr(""); setBusy(true);
    try {
      const rec = (appUsers||[]).find(u=>u.id===user.id);
      if (!rec) { setErr("User not found"); setBusy(false); return; }
      if (!(await verifyPassword(cur, rec.password))) { setErr("Current password incorrect"); setBusy(false); return; }
      if (nw.length < 8)   { setErr("New password must be at least 8 characters"); setBusy(false); return; }
      if (nw !== conf)     { setErr("Passwords do not match"); setBusy(false); return; }
      const hashed = await hashPassword(nw);
      setAppUsers(prev=>prev.map(u=>u.id===user.id?{...u,password:hashed,passwordChangedAt:new Date().toISOString()}:u));
      setOk(true);
    } catch(e) { setErr(e.message); }
    setBusy(false);
  };

  if (ok) return (
    <Modal title="Change Password" onClose={onClose} width={400}>
      <div style={{padding:24,textAlign:"center"}}>
        <div style={{fontSize:40,marginBottom:12}}>✅</div>
        <div style={{fontWeight:700,color:T.green,marginBottom:8}}>Password changed successfully</div>
        <div style={{fontSize:12,color:T.textMid,marginBottom:16}}>Your new password is active from next login.</div>
        <button onClick={onClose} style={css.btn.primary}>Done</button>
      </div>
    </Modal>
  );

  return (
    <Modal title="Change Password" onClose={onClose} width={400}>
      <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:14}}>
        <Field label="Current password">
          <input type="password" value={cur} onChange={e=>setCur(e.target.value)} style={css.input} placeholder="••••••••" />
        </Field>
        <Field label="New password (min 8 characters)">
          <input type="password" value={nw} onChange={e=>setNw(e.target.value)} style={css.input} placeholder="••••••••" />
        </Field>
        <Field label="Confirm new password">
          <input type="password" value={conf} onChange={e=>setConf(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&save()} style={css.input} placeholder="••••••••" />
        </Field>
        {err&&<InfoBanner color="red">{err}</InfoBanner>}
        <div style={{fontSize:11,color:T.textMid,padding:"8px",background:T.bg,borderRadius:5}}>
          Password is stored as a one-way hash — not even the admin can see it.
        </div>
      </div>
      <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
        <button onClick={onClose} style={css.btn.secondary}>Cancel</button>
        <button onClick={save} disabled={busy||!cur||!nw||!conf} style={{...css.btn.primary,opacity:(!cur||!nw||!conf)?0.4:1}}>
          {busy?"Saving...":"Change Password"}
        </button>
      </div>
    </Modal>
  );
};

const Login = ({ onLogin }) => {
  const [u,setU]=useState(""); const [p,setP]=useState(""); const [err,setErr]=useState(""); const [loading,setLoading]=useState(false);

  const go = async () => {
    const username = u.trim();
    setErr(""); setLoading(true);
    try {
      // Lockout check
      const attempts = getAttempts(username);
      if (attempts.lockedUntil > Date.now()) {
        const mins = Math.ceil((attempts.lockedUntil - Date.now()) / 60000);
        setErr(`Account locked — too many failed attempts. Try again in ${mins} minute${mins!==1?"s":""}.`);
        setLoading(false); return;
      }

      const allUsers = window.__STRUCTO_USERS__ || USERS;
      const userRecord = allUsers.find(x=>x.username===username&&x.active!==false);

      if (!userRecord) {
        recordAttempt(username, false);
        setErr("Invalid username or password");
        setLoading(false); return;
      }

      const valid = await verifyPassword(p, userRecord.password);
      if (!valid) {
        const result = recordAttempt(username, false);
        const remaining = MAX_ATTEMPTS - result.count;
        if (remaining <= 0) setErr(`Account locked for 15 minutes after ${MAX_ATTEMPTS} failed attempts.`);
        else setErr(`Invalid username or password. ${remaining} attempt${remaining!==1?"s":""} remaining.`);
        setLoading(false); return;
      }

      // Successful login
      recordAttempt(username, true);
      createSession(userRecord);

      // Auto-migrate plain text password to hash on first successful login
      if (!/^[0-9a-f]{64}$/.test(userRecord.password)) {
        const hashed = await hashPassword(p);
        if (window.__STRUCTO_USERS__) {
          window.__STRUCTO_USERS__ = window.__STRUCTO_USERS__.map(x=>
            x.id===userRecord.id ? {...x, password:hashed} : x
          );
          // Trigger a storage update via custom event
          window.dispatchEvent(new CustomEvent("structo_migrate_password", {detail:{id:userRecord.id, hashed}}));
        }
      }

      onLogin(userRecord);
    } catch(e) { setErr("Login error: " + e.message); }
    setLoading(false);
  };
  return (
    <div style={{ minHeight:"100vh", background:T.bg, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:T.font }}>
      <div style={{ width:"100%", maxWidth:400 }}>
        <div style={{ textAlign:"center", marginBottom:32 }}>
          <div style={{ display:"inline-flex", alignItems:"center", gap:12 }}>
            <div style={{ width:44, height:44, background:T.accent, borderRadius:10, display:"flex", alignItems:"center", justifyContent:"center" }}>
              <span style={{ fontSize:22, fontWeight:900, color:"#fff", fontFamily:T.fontMono }}>S</span>
            </div>
            <div>
              <div style={{ fontSize:22, fontWeight:800, color:T.text, letterSpacing:"-0.02em" }}>STRUCTO</div>
              <div style={{ fontSize:11, color:T.textMid, fontWeight:600, letterSpacing:"0.15em" }}>ERP v3.0 — SESSIONS 1–3</div>
            </div>
          </div>
        </div>
        <div style={{ ...css.card, padding:32 }}>
          <div style={{ fontSize:18, fontWeight:700, color:T.text, marginBottom:18 }}>Sign In</div>
          <div style={{ marginBottom:10 }}><label style={css.label}>Username</label><input value={u} onChange={e=>setU(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} style={css.input} placeholder="username" /></div>
          <div style={{ marginBottom:16 }}><label style={css.label}>Password</label><input type="password" value={p} onChange={e=>setP(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} style={css.input} placeholder="••••••••" /></div>
          {err && <div style={{ background:T.redBg, border:`1px solid ${T.redLo}`, borderRadius:6, padding:"8px 12px", color:T.red, fontSize:12, marginBottom:12 }}>{err}</div>}
          <button onClick={go} disabled={loading} style={{ ...css.btn.primary, width:"100%", padding:"10px 0" }}>{loading?"Signing in...":"Sign In"}</button>
          <div style={{ marginTop:18, padding:12, background:T.bg, borderRadius:8 }}>
            <div style={{ fontSize:10, color:T.textMid, fontWeight:700, marginBottom:6, textTransform:"uppercase", letterSpacing:"0.05em" }}>Quick Logins</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:4 }}>
              {[["Super Admin","rajesh.kumar","admin123"],["Planning Admin","vikram.singh","plan123"],["Prod Admin","ajay.rahangdale","prod123"],["PE Anmol","anmol.vaidya","pe123"],["PE Vibhor","vibhor.suryavanshi","pe123"],["Purchase","pramita.madam","pur123"],["Store Admin","mohan.das","store123"],["QC Admin","priya.mehta","qc123"],["Floor Planner","suresh.patel","prod123"],["Finance Admin","sameer.shah","fin123"],["Dispatch","ramesh.kulkarni","disp123"],["Contractor","krishna.fab","con123"],["Machine Op","ajay.kadam","machine123"],["In-House A","inhouse.a","con123"],["In-House B","inhouse.b","con123"],["Blast/Paint","sachin.blast","con123"]].map(([role,un,pw])=>(
                <button key={role} onClick={()=>{setU(un);setP(pw);}} style={{ ...css.btn.ghost, textAlign:"left", fontSize:11, background:T.bgCard, borderRadius:4, border:`1px solid ${T.border}`, padding:"4px 8px" }}>{role}</button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

