// PRODUCTION: CUTTING CONFIRMATION
// ═══════════════════════════════════════════════════════════════════════════════
// Production components imported from modules/ProductionModule.jsx
// Production components imported from modules/ProductionModule.jsx
const STOCK_LOT_OVERRIDES = {
  'LOT-2026-005': 337.68,   // RHS 100x50x4 E250 — 6 bars × 12 m × 4.69 kg/m
  // LOT-2026-006 is correct (1 524 kg)
  'LOT-2026-007': 1397.76,  // ISA 75x75x8 E250 — 13 bars × 12 m × 8.96 kg/m
};
const migrateStockLots = (lots, materials) => {
  return lots.map(lot => {
    // Ensure reservations array exists
    if (!lot.reservations) lot = { ...lot, reservations: [] };
    // Targeted override takes highest priority
    const override = STOCK_LOT_OVERRIDES[lot.lotNo];
    if (override != null && Math.abs((lot.wtReceived||0) - override) > 1) {
      const alreadyAllocated = (lot.wtAllocated||0) + (lot.wtIssued||0) + (lot.wtConsumed||0);
      const newAvail = Math.max(0, override - alreadyAllocated);
      return { ...lot, wtReceived: override, wtAvailable: newAvail, actualWt: override, calculatedWt: override, wtSource: 'lot-corrected' };
    }
    // General fix: MT×1000 bug — section lots where wtReceived = qtyReceived * 1000
    const qty = lot.qtyReceived||0;
    if (!lot.isPlate && qty > 0 && qty < 200 && Math.abs((lot.wtReceived||0) - qty * 1000) < 1) {
      const libMatch = (materials||[]).find(m =>
        (m.sectionType||'').toLowerCase() === (lot.sectionType||'').toLowerCase() &&
        normSz(m.size) === normSz(lot.size||'') &&
        (m.grade||'').toLowerCase() === (lot.grade||'').toLowerCase()
      );
      if (libMatch?.wtPerMetre) {
        const length = lot.length || 12000;
        const corrected = Math.round(qty * (length / 1000) * libMatch.wtPerMetre * 100) / 100;
        const alreadyAllocated = (lot.wtAllocated||0) + (lot.wtIssued||0) + (lot.wtConsumed||0);
        const newAvail = Math.max(0, corrected - alreadyAllocated);
        return { ...lot, wtReceived: corrected, wtAvailable: newAvail, actualWt: corrected, calculatedWt: corrected, wtSource: 'lot-corrected' };
      }
    }
    return lot;
  });
};

// ─── APP ──────────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(null);
  const [showPwChange, setShowPwChange] = useState(false);
  const [mod, setMod] = useState("dashboard");
  const [sidebar, setSidebar] = useState(true);
  const [stockLookupOpen, setStockLookupOpen] = useState(false);
  const [stockLookupTab, setStockLookupTab] = useState("lot"); // "lot" | "material"
  const [lookupLotNo, setLookupLotNo] = useState("");
  const [lookupMatFilter, setLookupMatFilter] = useState({ sectionType:"", grade:"", size:"" });

  // Keyboard shortcut Ctrl+K / Cmd+K
  React.useEffect(() => {
    const handler = (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "k") {
        e.preventDefault();
        setStockLookupOpen(o => !o);
      }
      if (e.key === "Escape") setStockLookupOpen(false);
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);
  const [dbLoaded, setDbLoaded] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Always start empty — Supabase (prod) or localStorage (dev) fills after mount
  const initVal = (localKey, seedData) => {
    try { const s = localStorage.getItem(localKey); return s ? JSON.parse(s) : seedData; }
    catch { return seedData; }
  };
  const [purchaseReqs, setPurchaseReqs] = useState(() => initVal('structo_purchaseReqs', INIT_PURCHASE_REQS));
  const [pos, setPos]                   = useState(() => { try { const s=localStorage.getItem('structo_pos'); if (s) { const loaded=JSON.parse(s); return migrateGRNLines(migratePOLines(loaded, MATERIALS_LIBRARY), MATERIALS_LIBRARY); } return INIT_POS; } catch { return INIT_POS; } });
  const [stock, setStock]               = useState(() => {
    try {
      const s = localStorage.getItem('structo_stock');
      const loaded = s ? JSON.parse(s) : INIT_STOCK;
      return migrateStockLots(loaded, MATERIALS_LIBRARY);
    } catch { return INIT_STOCK; }
  });
  const [nestingRuns, setNestingRuns]       = useState(() => initVal('structo_nestingRuns', INIT_NESTING_RUNS));
  const [nestingBatches, setNestingBatches] = useState(() => { try { const s=localStorage.getItem('structo_nestingBatches'); if(s){ const p=JSON.parse(s); return Array.isArray(p)?p:[]; } return []; } catch { return []; } });
  const [instances, setInstances]       = useState(() => initVal('structo_instances', INIT_INSTANCES));
  const [dprs, setDprs] = useState(() => {
    try { const s=localStorage.getItem('structo_dprs'); return s?JSON.parse(s):[]; } catch { return []; }
  });
  const [orders, setOrders]             = useState(() => {
    try {
      const s = localStorage.getItem('structo_orders');
      if (!s) return SEED_ORDERS;
      const loaded = JSON.parse(s);
      return loaded.map(o => {
        const base = { drawings:[], parts:[], milestones:[], shippingAddresses:[], amendments:[], quality:{tpiRequired:false,paintCoats:[],approvedMakes:[],mdccDocs:[]}, transport:{transportScope:'per_dispatch',preferredTransporter:'',vehicleType:'',distanceKm:0,freightEstimate:0,insurance:false,odc:false,nightRestriction:false,policeEscort:false,specialReqs:'',freightBilling:'dispatch_line',clientTransporter:'',clientVehicleContact:'',loadingInstructions:''}, projectDesc:'', clientPoNo:'', id:'', status:'active', clientId:'', ...o };
        // Migrate drawings missing poLineItem / assemblyGroup
        base.drawings = (base.drawings||[]).map(d => ({
          ...d,
          ...(d.poLineItem == null ? { poLineItem:0 } : {}),
          ...(d.assemblyGroup == null ? { assemblyGroup:'' } : {}),
        }));
        // Migrate order-level assembly fields
        if (base.assemblyInspectionRequired == null) base.assemblyInspectionRequired = false;
        if (!base.assemblies) base.assemblies = [];
        // Migrate parts missing matCode / requiredOps / drawingLineItem
        const drgCounters = {};
        base.parts = (base.parts||[]).map(p => {
          let updated = p;
          if (!updated.matCode && updated.section && updated.section!=="—" && updated.grade && updated.size) {
            updated = { ...updated, matCode:`${updated.section}/MS/${updated.grade}/${updated.size}` };
          }
          if (!updated.requiredOps && updated.fabType==="Fabricate") {
            updated = { ...updated, requiredOps:['Cut'] };
          }
          if (!updated.drawingLineItem) {
            const key = updated.drawingId||"__none__";
            drgCounters[key] = (drgCounters[key]||0) + 1;
            updated = { ...updated, drawingLineItem:drgCounters[key] };
          }
          return updated;
        });
        return base;
      });
    } catch { return SEED_ORDERS; }
  });
  const [clients, setClients]           = useState(() => initVal('structo_clients', CLIENTS_FULL));
  const [vendors, setVendors]           = useState(() => initVal('structo_vendors', VENDORS));
  const [contractors, setContractors]   = useState(() => initVal('structo_contractors', CONTRACTORS));
  const [welders, setWelders]           = useState(() => initVal('structo_welders', WELDERS_SEED));
  const [bays, setBays]                 = useState(BAYS_SEED);
  const [materials, setMaterials]       = useState(withDensity(MATERIALS_LIBRARY));
  const [paint, setPaint]               = useState(PAINT_LIBRARY);
  const [consumables, setConsumables]   = useState(CONSUMABLES_SEED);
  const [consumableIRs, setConsumableIRs] = useState(() => { try { const s=localStorage.getItem('structo_consumableIRs'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [consumablePRs, setConsumablePRs] = useState(() => { try { const s=localStorage.getItem('structo_consumablePRs'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [consumablePOs, setConsumablePOs] = useState(() => { try { const s=localStorage.getItem('structo_consumablePOs'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [tpiAgencies, setTpiAgencies]   = useState(TPI_AGENCIES);
  const [approvedMakes, setApprovedMakes] = useState(APPROVED_MAKES_LIBRARY);
  const [machines, setMachines]         = useState(() => initVal('structo_machines', MACHINES_SEED));
  const [releases, setReleases]         = useState(() => { try { const s=localStorage.getItem('structo_releases'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [qcRules, setQcRules]           = useState(() => { try { const s=localStorage.getItem('structo_qcRules'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [overrideLog, setOverrideLog]   = useState(() => { try { const s=localStorage.getItem('structo_overrideLog'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [issueRequests, setIssueRequests] = useState(() => { try { const s=localStorage.getItem('structo_issueRequests'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [tpiTemplates, setTpiTemplates] = useState(() => { try { const s=localStorage.getItem('structo_tpiTemplates'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [challans, setChallans] = useState(() => { try { const s=localStorage.getItem('structo_challans'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [drawingInstances, setDrawingInstances] = useState(() => { try { const s=localStorage.getItem('structo_drawingInstances'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [processTypes, setProcessTypes] = useState(() => { try { const s=localStorage.getItem('structo_processTypes'); return s?JSON.parse(s):DEFAULT_PROCESS_TYPES; } catch { return DEFAULT_PROCESS_TYPES; } });
  const [outboundVendors, setOutboundVendors] = useState(() => { try { const s=localStorage.getItem('structo_outboundVendors'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [outboundJobs, setOutboundJobs] = useState(() => { try { const s=localStorage.getItem('structo_outboundJobs'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [ncrs, setNcrs] = useState(() => { try { const s=localStorage.getItem('structo_ncrs'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [notifications, setNotifications] = useState(() => { try { const s=localStorage.getItem('structo_notifications'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [correctionsLog, setCorrectionsLog] = useState(() => { try { const s=localStorage.getItem('structo_correctionsLog'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [scrapQueue, setScrapQueue] = useState(() => { try { const s=localStorage.getItem('structo_scrapQueue'); return s?JSON.parse(s):[]; } catch { return []; } });
  const [appUsers, setAppUsers] = useState(() => { try { const s=localStorage.getItem('structo_users'); return s?JSON.parse(s):USERS; } catch { return USERS; } });
  const [productionEngineers, setProductionEngineers] = useState(() => {
    const peSeed = [
      { id:"PE-001", userId:"anmol.vaidya",          name:"Anmol Vaidya",        stages:["welding","blasting"], orderIds:[] },
      { id:"PE-002", userId:"vibhor.suryavanshi",     name:"Vibhor Suryavanshi",  stages:["cutting","welding"],  orderIds:[] },
    ];
    return initVal('structo_productionEngineers', peSeed);
  });
  const [productionStandards, setProductionStandards] = useState({
    blastThresholds: { amberHours: 3, redHours: 4 },
    cuttingCapacity: { plateTPD: 0, sectionTPD: 0, minSegmentMm: 1500, jointAllowanceMm: 3, lastUpdated: "" },
    tiers: [
      { id:'simple',  label:'Simple',  maxParts:5,   maxKg:200,   cutting:4,  fitup:4,  welding:8,  blasting:2, paintPerCoat:1 },
      { id:'medium',  label:'Medium',  maxParts:10,  maxKg:800,   cutting:8,  fitup:8,  welding:16, blasting:3, paintPerCoat:2 },
      { id:'complex', label:'Complex', maxParts:20,  maxKg:2000,  cutting:12, fitup:16, welding:30, blasting:4, paintPerCoat:3 },
      { id:'heavy',   label:'Heavy',   maxParts:999, maxKg:99999, cutting:20, fitup:30, welding:60, blasting:6, paintPerCoat:4 },
    ],
    stampLocations: [
      { sectionTypes:['ISA','ISMC','ISMB'], location:'Web face, 50mm from left end, top edge' },
      { sectionTypes:['RHS','SHS'],         location:'Flat face (widest), 50mm from left end' },
      { sectionTypes:['PLATE','Flat Bar'],  location:'Top face, bottom-left corner, 50mm from each edge' },
      { sectionTypes:['OTHER'],             location:'Top face, centre of piece' },
    ]
  });
  const [company, setCompany]           = useState(() => {
    const defaults = { name:"Structo Fabricators", tradingName:"STRUCTO", gstin:"", pan:"", state:"Maharashtra", stateCode:"27", address:"", worksAddress:"", phone:"", email:"", bankName:"", bankAccount:"", ifsc:"", logoUrl:"", orderPrefix:"FXL", orderNextNo:1 };
    try { const s=localStorage.getItem('structo_company'); return s?JSON.parse(s):defaults; } catch { return defaults; }
  });

  // ── Sync state to Supabase + localStorage cache ──
  // Debounced sync — waits 800ms after last change before writing to Supabase
  // localStorage is written immediately as a fast local cache
  // Debounced sync — ref-based so no hook rules violated
  const _syncTimers = React.useRef({});
  const syncToSupa = React.useCallback((key, value) => {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch(e) {}
    // CRITICAL: never write to Supabase before data has been successfully loaded from it.
    // This prevents seed/default state from overwriting real Supabase data on startup.
    if (!dbLoaded || dbError) return;
    clearTimeout(_syncTimers.current[key]);
    _syncTimers.current[key] = setTimeout(() => { supaSet(key, value); }, 800);
  }, [dbLoaded, dbError]);

  useEffect(() => { syncToSupa('structo_orders',            orders);            }, [orders]);
  useEffect(() => { syncToSupa('structo_clients',           clients);           }, [clients]);
  useEffect(() => { syncToSupa('structo_vendors',           vendors);           }, [vendors]);
  useEffect(() => { syncToSupa('structo_pos',               pos);               }, [pos]);
  useEffect(() => { syncToSupa('structo_stock',             stock);             }, [stock]);
  useEffect(() => { syncToSupa('structo_purchaseReqs',      purchaseReqs);      }, [purchaseReqs]);
  useEffect(() => { syncToSupa('structo_company',           company);           }, [company]);
  useEffect(() => { syncToSupa('structo_nestingBatches',    nestingBatches);    }, [nestingBatches]);
  useEffect(() => { syncToSupa('structo_nestingRuns',       nestingRuns);       }, [nestingRuns]);
  useEffect(() => { syncToSupa('structo_instances',         instances);         }, [instances]);
  useEffect(() => { syncToSupa('structo_dprs',              dprs);              }, [dprs]);
  useEffect(() => { syncToSupa('structo_releases',          releases);          }, [releases]);
  useEffect(() => { syncToSupa('structo_qcRules',           qcRules);           }, [qcRules]);
  useEffect(() => { syncToSupa('structo_overrideLog',       overrideLog);       }, [overrideLog]);
  useEffect(() => { syncToSupa('structo_issueRequests',     issueRequests);     }, [issueRequests]);
  useEffect(() => { syncToSupa('structo_tpiTemplates',      tpiTemplates);      }, [tpiTemplates]);
  useEffect(() => { syncToSupa('structo_productionEngineers', productionEngineers); }, [productionEngineers]);
  useEffect(() => { syncToSupa('structo_challans',          challans);          }, [challans]);
  useEffect(() => { syncToSupa('structo_drawingInstances',   drawingInstances);   }, [drawingInstances]);

  // Listen for password hash migration event from Login (must be before any conditional return)
  useEffect(()=>{
    const handler = (e) => {
      const {id, hashed} = e.detail;
      setAppUsers(prev=>prev.map(u=>u.id===id?{...u,password:hashed}:u));
    };
    window.addEventListener("structo_migrate_password", handler);
    return ()=>window.removeEventListener("structo_migrate_password", handler);
  }, []);

  // ── Auto-migrate drawing instances (must be before any conditional returns) ──
  useEffect(()=>{
    if (!orders||orders.length===0) return;
    const newInstances = migrateDrawingInstances(orders, drawingInstances);
    if (newInstances.length>0) {
      setDrawingInstances(prev=>[...prev,...newInstances]);
    }
  },[]);
  useEffect(() => { syncToSupa('structo_processTypes',       processTypes);       }, [processTypes]);
  useEffect(() => { syncToSupa('structo_outboundVendors',    outboundVendors);    }, [outboundVendors]);
  useEffect(() => { syncToSupa('structo_outboundJobs',       outboundJobs);       }, [outboundJobs]);
  useEffect(() => { syncToSupa('structo_ncrs',               ncrs);               }, [ncrs]);
  useEffect(() => { syncToSupa('structo_notifications',      notifications);      }, [notifications]);
  useEffect(() => { syncToSupa('structo_correctionsLog',     correctionsLog);     }, [correctionsLog]);
  useEffect(() => { syncToSupa('structo_scrapQueue',         scrapQueue);         }, [scrapQueue]);
  useEffect(() => { syncToSupa('structo_consumableIRs',      consumableIRs);      }, [consumableIRs]);
  useEffect(() => { syncToSupa('structo_consumablePRs',      consumablePRs);      }, [consumablePRs]);
  useEffect(() => { syncToSupa('structo_consumablePOs',      consumablePOs);      }, [consumablePOs]);
  useEffect(() => { syncToSupa('structo_users',             appUsers);           }, [appUsers]);
  useEffect(() => { syncToSupa('structo_bays',              bays);               }, [bays]);
  useEffect(() => { syncToSupa('structo_paint',             paint);              }, [paint]);
  useEffect(() => { syncToSupa('structo_materials',         materials);          }, [materials]);
  useEffect(() => { syncToSupa('structo_consumables',       consumables);        }, [consumables]);
  useEffect(() => { syncToSupa('structo_approvedMakes',     approvedMakes);      }, [approvedMakes]);
  useEffect(() => { syncToSupa('structo_tpiAgencies',       tpiAgencies);        }, [tpiAgencies]);
  useEffect(() => { syncToSupa('structo_productionStandards', productionStandards); }, [productionStandards]);
  // Expose current users to window so Login component can check dynamic users
  useEffect(() => { window.__STRUCTO_USERS__ = appUsers; }, [appUsers]);
  // Expose setDrawingInstances globally so pipeline editor save always reaches App state
  useEffect(() => { window.__SET_DRAWING_INSTANCES__ = setDrawingInstances; }, [setDrawingInstances]);
  useEffect(() => { window.__DRAWING_INSTANCES__ = drawingInstances; }, [drawingInstances]);

  // Listen for materials added from part import flow
  useEffect(() => {
    const handler = (e) => {
      const toAdd = e.detail || [];
      if(!toAdd.length) return;
      setMaterials(prev => {
        const existing = prev||[];
        const newItems = toAdd.map((item, i) => ({
          id: `ML-IMP-${Date.now()}-${i}`,
          sectionType: item.section||"",
          matType: item.matType||"MS",
          grade: item.grade||"E250",
          size: item.size||"",
          isPlate: item.isPlate||false,
          wtPerMetre: item.isPlate ? null : (parseFloat(item.wtPerMetre)||null),
          wtPerM2: item.isPlate ? (parseFloat(item.wtPerM2)||null) : null,
          standardLengths: item.isPlate ? [] : [6000,9000,12000],
          active: true,
          matCode: buildMatCode(item.section, item.matType||"MS", item.grade||"E250", item.size),
          addedFrom: "import",
        })).filter(m => !existing.some(e => e.matCode===m.matCode));
        return [...existing, ...newItems];
      });
    };
    window.addEventListener('structo:addMaterials', handler);
    return () => window.removeEventListener('structo:addMaterials', handler);
  }, []);
  useEffect(() => { syncToSupa('structo_welders',           welders);           }, [welders]);
  useEffect(() => { syncToSupa('structo_contractors',       contractors);       }, [contractors]);
  useEffect(() => { syncToSupa('structo_machines',          machines);          }, [machines]);


  // ── Load all data from Supabase on first mount (production only) ─────────────
  useEffect(() => {
    if (!IS_PROD) { setDbLoaded(true); return; } // localhost: skip, use localStorage
    const KEYS = [
      "structo_orders","structo_clients","structo_vendors","structo_pos",
      "structo_stock","structo_purchaseReqs","structo_company",
      "structo_nestingBatches","structo_nestingRuns","structo_instances",
      "structo_dprs","structo_releases","structo_qcRules","structo_overrideLog",
      "structo_issueRequests","structo_tpiTemplates","structo_productionEngineers",
      "structo_challans","structo_welders","structo_contractors","structo_machines",
      "structo_ncrs","structo_notifications","structo_correctionsLog","structo_scrapQueue",
      "structo_drawingInstances","structo_processTypes","structo_outboundVendors","structo_outboundJobs",
      "structo_users","structo_bays","structo_paint","structo_materials",
      "structo_consumables","structo_approvedMakes","structo_tpiAgencies",
      "structo_productionStandards",
    ];
    supaLoadAll(KEYS).then(data => {
      // Production: Supabase is the ONLY source of truth.
      // If key exists in Supabase → use it. If missing → set to empty (fresh start).
      // This prevents seed data from bleeding into production.
      const get = (key, fallback=[]) => key in data ? (data[key] ?? fallback) : fallback;
      const getObj = (key, fallback={}) => key in data ? (data[key] ?? fallback) : fallback;

      setOrders(              data["structo_orders"]              ?? []);
      setClients(             data["structo_clients"]             ?? []);
      setVendors(             data["structo_vendors"]             ?? []);
      setPos(                 data["structo_pos"]                 ?? []);
      setStock(               data["structo_stock"]               ?? []);
      setPurchaseReqs(        data["structo_purchaseReqs"]        ?? []);
      setNestingBatches(      data["structo_nestingBatches"]      ?? []);
      setNestingRuns(         data["structo_nestingRuns"]         ?? []);
      setInstances(           data["structo_instances"]           ?? []);
      setDprs(                data["structo_dprs"]                ?? []);
      setReleases(            data["structo_releases"]            ?? []);
      setQcRules(             data["structo_qcRules"]             ?? []);
      setOverrideLog(         data["structo_overrideLog"]         ?? []);
      setIssueRequests(       data["structo_issueRequests"]       ?? []);
      setTpiTemplates(        data["structo_tpiTemplates"]        ?? []);
      setProductionEngineers( data["structo_productionEngineers"] ?? []);
      setChallans(            data["structo_challans"]            ?? []);
      setNcrs(                data["structo_ncrs"]                ?? []);
      setNotifications(       data["structo_notifications"]       ?? []);
      setCorrectionsLog(      data["structo_correctionsLog"]      ?? []);
      setScrapQueue(          data["structo_scrapQueue"]          ?? []);
      if (data["structo_drawingInstances"]?.length>0) setDrawingInstances(data["structo_drawingInstances"]);
      if (data["structo_processTypes"]?.length>0)     setProcessTypes(data["structo_processTypes"]);
      if (data["structo_outboundVendors"]?.length>0)  setOutboundVendors(data["structo_outboundVendors"]);
      if (data["structo_outboundJobs"]?.length>0)     setOutboundJobs(data["structo_outboundJobs"]);
      setWelders(             data["structo_welders"]             ?? []);
      setContractors(         data["structo_contractors"]         ?? []);
      setMachines(            data["structo_machines"]            ?? []);
      if (data["structo_users"]?.length>0)         setAppUsers(data["structo_users"]);
      if (data["structo_bays"]?.length>0)          setBays(data["structo_bays"]);
      if (data["structo_paint"]?.length>0)         setPaint(data["structo_paint"]);
      if (data["structo_materials"]?.length>0)     setMaterials(withDensity(data["structo_materials"]));
      if (data["structo_consumables"]?.length>0)   setConsumables(data["structo_consumables"]);
      if (data["structo_approvedMakes"]?.length>0) setApprovedMakes(data["structo_approvedMakes"]);
      if (data["structo_tpiAgencies"]?.length>0)   setTpiAgencies(data["structo_tpiAgencies"]);
      if (data["structo_productionStandards"]?.length>0) setProductionStandards(data["structo_productionStandards"]);
      // Company: use Supabase value or default blank
      if (data["structo_company"] && Object.keys(data["structo_company"]).length>0) {
        setCompany(data["structo_company"]);
      }
      setDbLoaded(true);
    }).catch(err => {
      console.warn("Supabase load failed:", err);
      // CRITICAL: do NOT set dbLoaded=true here — this would allow seed data
      // to sync back to Supabase and overwrite real data.
      // Instead show the error state and let the user retry.
      setDbError(true);
      // Only set dbLoaded after a deliberate retry — not automatically.
      // The user must click "Retry" or refresh.
    });
  }, []); // run once on mount

  // Show loading/error screen while Supabase loads
  if (!dbLoaded) return (
    <div style={{
      display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center",
      height:"100vh", background:"#0A0E1A", color:"#F1F5F9", fontFamily:"'IBM Plex Sans',sans-serif"
    }}>
      <div style={{fontSize:32, marginBottom:16}}>⚙</div>
      <div style={{fontSize:18, fontWeight:700, marginBottom:8}}>STRUCTO ERP</div>
      {!dbError ? (<>
        <div style={{fontSize:13, color:"#94A3B8", marginBottom:24}}>Loading data from server...</div>
        <div style={{width:200, height:3, background:"#1E2D45", borderRadius:2, overflow:"hidden"}}>
          <div style={{width:"40%", height:"100%", background:"#3B82F6", borderRadius:2,
            animation:"supaload 1.2s ease-in-out infinite"}} />
        </div>
      </>) : (<>
        <div style={{fontSize:13, color:"#F59E0B", marginBottom:8}}>⚠ Could not connect to server</div>
        <div style={{fontSize:12, color:"#64748B", marginBottom:24, textAlign:"center", maxWidth:320}}>
          Your data is safe. The app will not start until the server is reachable — this prevents any data loss.
        </div>
        <button onClick={()=>window.location.reload()} style={{
          padding:"10px 28px", background:"#3B82F6", color:"#fff", border:"none",
          borderRadius:8, fontSize:14, fontWeight:600, cursor:"pointer"
        }}>Retry Connection</button>
        <div style={{marginTop:12, fontSize:11, color:"#475569"}}>
          Check your internet connection and try again
        </div>
      </>)}
      <style>{`@keyframes supaload { 0%{transform:translateX(-100%)} 100%{transform:translateX(500%)} }`}</style>
    </div>
  );

  if (!user) return <Login onLogin={u=>{setUser(u);setMod("dashboard");}} />;

  const visibleNav = NAV.filter(n=>canSee(user,n.module));
  const myUnreadNotifs = (notifications||[]).filter(n=>!n.readBy?.includes(user?.id)&&(n.forRoles?.includes(user?.role)||n.forUsers?.includes(user?.id)||user?.role==="super_admin")).length;
  const pendingScrapDecisions = (scrapQueue||[]).filter(s=>s.status==="pending_decision").length;
  const roleLabel = ROLES_LABEL[user.role]||user.role;
  const initials = user.name.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase();


  // ── Production Admin: Drawing Assignment Screen ─────────────────────────────
  const ProductionAdminScreen = () => {
    const [selDrawings, setSelDrawings] = useState(new Set());
    const [assignForm, setAssignForm]   = useState({ peId:"", stage:"welding", contractorId:"" });
    const [filterOrder, setFilterOrder] = useState("");
    const [filterUnassigned, setFilterUnassigned] = useState(true);
    const [view, setView] = useState("assign"); // assign | pe_overview

    const allDrawings = (orders||[]).filter(o=>o.status==="active").flatMap(o=>
      (o.drawings||[]).map(d=>{
        const dpr = (dprs||[]).find(dp=>dp.drawingId===d.id&&dp.orderId===o.id);
        const pe  = (productionEngineers||[]).find(p=>
          (dpr?.peAssignments||[]).some(a=>a.peId===p.id)
        );
        return { drawing:d, order:o, dpr, peAssigned:pe?.name||"", stage:dpr?.currentStage||"pending" };
      })
    ).filter(x=>filterOrder?x.order.id===filterOrder:true)
     .filter(x=>filterUnassigned?(!(dprs||[]).find(d=>d.drawingId===x.drawing.id)?.peAssignments?.length):true);

    const doAssign = () => {
      if (!assignForm.peId||selDrawings.size===0) return;
      const pe = (productionEngineers||[]).find(p=>p.id===assignForm.peId);
      const con = (contractors||[]).find(c=>c.id===assignForm.contractorId);
      const ts = new Date().toISOString();
      // Update DPRs with PE assignment
      setDprs(prev=>prev.map(dpr=>{
        if (!selDrawings.has(dpr.drawingId)) return dpr;
        return {...dpr,
          peAssignments:[...(dpr.peAssignments||[]),{
            peId:assignForm.peId, peName:pe?.name||"",
            stage:assignForm.stage,
            contractorId:assignForm.contractorId||"",
            contractorName:con?.name||"",
            assignedAt:ts, assignedBy:user.username
          }],
          ...(assignForm.contractorId&&assignForm.stage==="welding"?{weldContractorId:assignForm.contractorId,weldContractorName:con?.name||""}:{}),
          ...(assignForm.contractorId&&assignForm.stage==="fitup"?{fitupContractorId:assignForm.contractorId,fitupContractorName:con?.name||""}:{}),
          ...(assignForm.contractorId&&assignForm.stage==="blasting"?{blastContractorId:assignForm.contractorId,blastContractorName:con?.name||""}:{}),
          ...(assignForm.contractorId&&assignForm.stage==="painting"?{paintContractorId:assignForm.contractorId,paintContractorName:con?.name||""}:{}),
        };
      }));
      // Update PE order assignments
      if (pe) {
        const orderIds = [...new Set([...(pe.orderIds||[]), ...[...selDrawings].map(dId=>{
          const o=(orders||[]).find(x=>(x.drawings||[]).some(d=>d.id===dId));
          return o?.id;
        }).filter(Boolean)])];
        setProductionEngineers(prev=>prev.map(p=>p.id===pe.id?{...p,orderIds}:p));
      }
      setSelDrawings(new Set()); setAssignForm({peId:"",stage:"welding",contractorId:""});
    };

    const STAGE_OPTIONS = ["cutting","fitup","welding","blasting","painting"];

    return (
      <div>
        <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:20}}>
          <div style={{fontSize:18,fontWeight:800,color:T.text}}>Production Admin</div>
          <div style={{flex:1}}/>
          <button onClick={()=>setView("assign")} style={{...css.btn[view==="assign"?"primary":"ghost"]}}>Drawing Assignment</button>
          <button onClick={()=>setView("pe_overview")} style={{...css.btn[view==="pe_overview"?"primary":"ghost"]}}>PE Overview</button>
        </div>

        {view==="assign"&&(
          <div style={{display:"flex",gap:16}}>
            {/* Left: Drawing list */}
            <div style={{flex:1}}>
              <div style={{...css.card,marginBottom:12,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
                <select value={filterOrder} onChange={e=>setFilterOrder(e.target.value)} style={{...css.input,width:200}}>
                  <option value="">All Orders</option>
                  {(orders||[]).filter(o=>o.status==="active").map(o=><option key={o.id} value={o.id}>{o.id}</option>)}
                </select>
                <label style={{display:"flex",alignItems:"center",gap:6,fontSize:12,cursor:"pointer"}}>
                  <input type="checkbox" checked={filterUnassigned} onChange={e=>setFilterUnassigned(e.target.checked)} />
                  Unassigned only
                </label>
                <div style={{flex:1}}/>
                <button onClick={()=>setSelDrawings(new Set(allDrawings.map(x=>x.drawing.id)))} style={css.btn.ghost}>Select All</button>
                <button onClick={()=>setSelDrawings(new Set())} style={css.btn.ghost}>Clear</button>
                <span style={{fontSize:12,color:T.textMid}}>{selDrawings.size} selected</span>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:4,maxHeight:"65vh",overflowY:"auto"}}>
                {allDrawings.length===0&&<div style={{color:T.textLow,padding:24,textAlign:"center"}}>No drawings match filter.</div>}
                {allDrawings.map(({drawing,order,dpr,peAssigned,stage})=>{
                  const sel = selDrawings.has(drawing.id);
                  const meta = DPR_STAGE_META[stage]||{label:"Pending",color:T.textLow,bg:"#F1F5F9"};
                  return (
                    <div key={drawing.id} onClick={()=>{const ns=new Set(selDrawings);sel?ns.delete(drawing.id):ns.add(drawing.id);setSelDrawings(ns);}}
                      style={{...css.card,cursor:"pointer",borderLeft:`3px solid ${sel?T.accent:T.border}`,background:sel?`${T.accent}11`:T.bgCard,padding:"8px 12px"}}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                        <div style={{display:"flex",alignItems:"center",gap:10}}>
                          <input type="checkbox" checked={sel} onChange={()=>{}} style={{pointerEvents:"none"}} />
                          <div>
                            <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent,fontSize:12}}>{drawing.drawingNo}</div>
                            <div style={{fontSize:10,color:T.textMid}}>{order.id} · {((drawing.totalWt||0)/1000).toFixed(2)}T</div>
                          </div>
                        </div>
                        <div style={{display:"flex",gap:8,alignItems:"center"}}>
                          {peAssigned&&<span style={{fontSize:10,color:T.green}}>PE: {peAssigned}</span>}
                          <span style={{display:"inline-block",padding:"2px 8px",borderRadius:99,fontSize:10,fontWeight:700,background:meta.bg,color:meta.color}}>{meta.label}</span>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            {/* Right: Assignment form */}
            <div style={{width:280}}>
              <div style={{...css.card}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>Assign Selected</div>
                <label style={css.label}>Production Engineer <span style={{color:T.red}}>*</span></label>
                <select value={assignForm.peId} onChange={e=>setAssignForm(p=>({...p,peId:e.target.value}))} style={{...css.input,marginBottom:10}}>
                  <option value="">Select PE...</option>
                  {(productionEngineers||[]).map(pe=>(
                    <option key={pe.id} value={pe.id}>{pe.name} ({pe.stages?.join(", ")||"all stages"})</option>
                  ))}
                </select>
                <label style={css.label}>Stage</label>
                <select value={assignForm.stage} onChange={e=>setAssignForm(p=>({...p,stage:e.target.value}))} style={{...css.input,marginBottom:10}}>
                  {STAGE_OPTIONS.map(s=><option key={s} value={s}>{s.charAt(0).toUpperCase()+s.slice(1)}</option>)}
                </select>
                <label style={css.label}>Contractor (optional)</label>
                <select value={assignForm.contractorId} onChange={e=>setAssignForm(p=>({...p,contractorId:e.target.value}))} style={{...css.input,marginBottom:14}}>
                  <option value="">Assign later</option>
                  {(contractors||[]).filter(c=>c.active!==false).map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
                <button onClick={doAssign} disabled={!assignForm.peId||selDrawings.size===0}
                  style={{...css.btn.primary,width:"100%",padding:"10px 0",opacity:(!assignForm.peId||selDrawings.size===0)?0.4:1}}>
                  ✓ Assign {selDrawings.size} Drawing{selDrawings.size!==1?"s":""}
                </button>
              </div>
            </div>
          </div>
        )}

        {view==="pe_overview"&&(
          <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:12}}>
            {(productionEngineers||[]).map(pe=>{
              const peDprs=(dprs||[]).filter(d=>(d.peAssignments||[]).some(a=>a.peId===pe.id));
              const byStage={};
              peDprs.forEach(d=>{ byStage[d.currentStage]=(byStage[d.currentStage]||0)+1; });
              return (
                <div key={pe.id} style={{...css.card}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
                    <div>
                      <div style={{fontSize:14,fontWeight:700,color:T.text}}>{pe.name}</div>
                      <div style={{fontSize:11,color:T.textMid,marginTop:2}}>Stages: {(pe.stages||[]).join(", ")||"all"}</div>
                    </div>
                    <div style={{textAlign:"right"}}>
                      <div style={{fontSize:20,fontWeight:800,color:T.accent}}>{peDprs.length}</div>
                      <div style={{fontSize:10,color:T.textLow}}>drawings</div>
                    </div>
                  </div>
                  <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                    {Object.entries(byStage).map(([stage,cnt])=>{
                      const meta=DPR_STAGE_META[stage]||{label:stage,color:T.textMid,bg:"#F1F5F9"};
                      return <span key={stage} style={{padding:"2px 8px",borderRadius:99,fontSize:10,fontWeight:700,background:meta.bg,color:meta.color}}>{meta.label}: {cnt}</span>;
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    );
  };

  // ── Production Engineer: Scoped Dashboard ───────────────────────────────────
  const ProductionEngineerDashboard = () => {
    const [peTab, setPeTab] = useState("work");
    // Find this user's PE record
    const myPe = (productionEngineers||[]).find(p=>p.userId===user.username);
    const myDprs = myPe
      ? (dprs||[]).filter(d=>(d.peAssignments||[]).some(a=>a.peId===myPe.id))
      : [];
    const myOrders = (orders||[]).filter(o=>myPe?(myPe.orderIds||[]).includes(o.id)||myDprs.some(d=>d.orderId===o.id):false);

    const DONE_STAGES = new Set(["cutting_qc","fitup","fit_up","welding","weld_qc","tpi_fitup","tpi_weld","blasting","blast_qc","tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);
    const WELD_DONE   = new Set(["weld_qc","tpi_weld","blasting","blast_qc","tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);

    // MTD weight cleared
    const now = new Date();
    const mtdStart = new Date(now.getFullYear(),now.getMonth(),1);
    const mtdWt = myDprs.filter(d=>WELD_DONE.has(d.currentStage)).reduce((s,d)=>{
      const o=(orders||[]).find(x=>x.id===d.orderId)||{};
      const dr=(o.drawings||[]).find(x=>x.id===d.drawingId)||{};
      return s+(dr.totalWt||0)/1000;
    },0);

    // All PEs for race comparison
    const allPeStats = (productionEngineers||[]).map(pe=>{
      const peDprs=(dprs||[]).filter(d=>(d.peAssignments||[]).some(a=>a.peId===pe.id));
      const wt = peDprs.filter(d=>WELD_DONE.has(d.currentStage)).reduce((s,d)=>{
        const o=(orders||[]).find(x=>x.id===d.orderId)||{};
        const dr=(o.drawings||[]).find(x=>x.id===d.drawingId)||{};
        return s+(dr.totalWt||0)/1000;
      },0);
      return { ...pe, wt, isMe: pe.id===myPe?.id };
    }).sort((a,b)=>b.wt-a.wt);
    const maxWt = Math.max(...allPeStats.map(p=>p.wt),1);

    if (!myPe) return (
      <div style={{...css.card,textAlign:"center",padding:40}}>
        <div style={{fontSize:32,marginBottom:12}}>👷</div>
        <div style={{fontSize:14,fontWeight:700,color:T.text}}>Not yet assigned</div>
        <div style={{fontSize:12,color:T.textMid,marginTop:6}}>Ask your Production Admin to assign drawings to you.</div>
      </div>
    );

    return (
      <div>
        <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:20}}>
          <div>
            <div style={{fontSize:18,fontWeight:800,color:T.text}}>My Work — {user.name}</div>
            <div style={{fontSize:12,color:T.textMid}}>Stages: {(myPe.stages||[]).join(", ")} · {myDprs.length} drawings assigned</div>
          </div>
        </div>
        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["work","My Drawings"],["stats","My Stats / Race"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setPeTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:peTab===id?700:400,color:peTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:peTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {peTab==="work"&&(
          <div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
              {[["Assigned",myDprs.length,T.accent],["In Progress",myDprs.filter(d=>!["pending","complete"].includes(d.currentStage)).length,T.amber],["Complete",myDprs.filter(d=>d.currentStage==="complete").length,T.green]].map(([lbl,val,col])=>(
                <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
                  <div style={{fontSize:11,color:T.textMid,textTransform:"uppercase",letterSpacing:"0.05em"}}>{lbl}</div>
                  <div style={{fontSize:24,fontWeight:800,color:col,marginTop:4}}>{val}</div>
                </div>
              ))}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {myDprs.length===0&&<div style={{color:T.textLow,padding:24,textAlign:"center"}}>No drawings assigned yet.</div>}
              {myDprs.map(dpr=>{
                const o=(orders||[]).find(x=>x.id===dpr.orderId)||{};
                const dr=(o.drawings||[]).find(x=>x.id===dpr.drawingId)||{};
                const meta=DPR_STAGE_META[dpr.currentStage]||{label:"Pending",color:T.textLow,bg:"#F1F5F9"};
                const myAssignment=(dpr.peAssignments||[]).find(a=>a.peId===myPe.id)||{};
                return (
                  <div key={dpr.id} style={{...css.card,padding:"8px 14px",borderLeft:`3px solid ${meta.color}`}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <div>
                        <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent,fontSize:13}}>{dpr.drawingNo}</div>
                        <div style={{fontSize:11,color:T.textMid,marginTop:2}}>{o.id} · {((dr.totalWt||0)/1000).toFixed(2)}T · {myAssignment.stage||""}</div>
                        {myAssignment.contractorName&&<div style={{fontSize:11,color:T.textLow}}>Contractor: {myAssignment.contractorName}</div>}
                      </div>
                      <span style={{display:"inline-block",padding:"3px 10px",borderRadius:99,fontSize:11,fontWeight:700,background:meta.bg,color:meta.color}}>{meta.label}</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {peTab==="stats"&&(
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:4}}>MTD Performance Race</div>
              <div style={{fontSize:11,color:T.textLow,marginBottom:16}}>Tonnes cleared (weld done and beyond) this month</div>
              {allPeStats.map((pe,i)=>(
                <div key={pe.id} style={{marginBottom:14}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <span style={{fontSize:13,fontWeight:600,color:pe.isMe?T.accent:T.text}}>{i+1}. {pe.name}</span>
                      {pe.isMe&&<span style={{fontSize:10,background:`${T.accent}22`,color:T.accent,padding:"1px 6px",borderRadius:99,fontWeight:700}}>You</span>}
                    </div>
                    <span style={{fontSize:13,fontWeight:700,color:pe.isMe?T.accent:T.text}}>{pe.wt.toFixed(1)}T</span>
                  </div>
                  <div style={{height:12,background:T.bgInput,borderRadius:6,overflow:"hidden",border:`1px solid ${T.border}`}}>
                    <div style={{width:`${Math.round(pe.wt/maxWt*100)}%`,height:"100%",background:pe.isMe?T.accent:"rgba(0,0,0,0.15)",borderRadius:6,transition:"width 0.5s ease"}} />
                  </div>
                </div>
              ))}
            </div>
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>My Stage Breakdown</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8}}>
                {(myPe.stages||[]).map(stage=>{
                  const cnt=myDprs.filter(d=>{
                    if(stage==="welding") return WELD_DONE.has(d.currentStage);
                    if(stage==="cutting") return DONE_STAGES.has(d.currentStage);
                    return d.currentStage===stage||d.currentStage===`${stage}_qc`;
                  }).length;
                  return (
                    <div key={stage} style={{background:T.bgInput,borderRadius:8,padding:"10px 14px"}}>
                      <div style={{fontSize:11,fontWeight:700,color:T.textMid,textTransform:"uppercase"}}>{stage} done</div>
                      <div style={{fontSize:22,fontWeight:800,color:T.green,marginTop:4}}>{cnt}</div>
                      <div style={{fontSize:10,color:T.textLow}}>of {myDprs.length} assigned</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}
      </div>
    );
  };

  // ── Purchase Admin Dashboard ─────────────────────────────────────────────────
  const PurchaseAdminDashboard = () => {
    const [pTab, setPTab] = useState("pr");
    const pendingPRs = (purchaseReqs||[]).filter(p=>p.status==="pending"||p.status==="approved");
    const allPos = (pos||[]);
    const pendingPos = allPos.filter(p=>p.status!=="fully_received"&&p.status!=="cancelled");
    const overduePos = pendingPos.filter(p=>p.expectedDelivery&&new Date(p.expectedDelivery)<new Date());

    return (
      <div>
        <div style={{fontSize:18,fontWeight:800,color:T.text,marginBottom:20}}>Purchase Dashboard — {user.name}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
          {[["Pending PRs",pendingPRs.length,T.amber],["Open POs",pendingPos.length,T.accent],["Overdue POs",overduePos.length,overduePos.length>0?T.red:T.green],["Total PO Value",`₹${(allPos.reduce((s,p)=>s+(p.totalValue||p.lines?.reduce((ls,l)=>ls+(l.totalPrice||0),0)||0),0)/100000).toFixed(1)}L`,T.text]].map(([lbl,val,col])=>(
            <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
              <div style={{fontSize:11,color:T.textMid,textTransform:"uppercase",letterSpacing:"0.05em"}}>{lbl}</div>
              <div style={{fontSize:22,fontWeight:800,color:col,marginTop:4}}>{val}</div>
            </div>
          ))}
        </div>
        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["pr","PR Queue"],["po","PO Tracker"],["grn","GRN Pending"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setPTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:pTab===id?700:400,color:pTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:pTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {pTab==="pr"&&(
          <div>
            {pendingPRs.length===0&&<div style={{color:T.textLow,padding:24,textAlign:"center"}}>✓ No pending purchase requisitions</div>}
            {pendingPRs.map(pr=>(
              <div key={pr.id} style={{...css.card,marginBottom:8,borderLeft:`3px solid ${T.amber}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div>
                    <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{pr.id}</div>
                    <div style={{fontSize:11,color:T.textMid,marginTop:2}}>{pr.nestingBatchId} · {(pr.lots||[]).length} materials · {(pr.lots||[]).reduce((s,l)=>s+(l.sheetCount||0),0)} sheets</div>
                  </div>
                  <div style={{display:"flex",gap:8,alignItems:"center"}}>
                    <Badge color="amber">{pr.status}</Badge>
                    <span style={{fontSize:11,color:T.textLow}}>{pr.createdAt?.slice(0,10)||""}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {pTab==="po"&&(
          <div>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead><tr style={{background:T.bgInput}}>{["PO No","Vendor","Type","Value","Expected","Status","Payment Terms"].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`}}>{h}</th>)}</tr></thead>
              <tbody>
                {pendingPos.map((po,i)=>{
                  const val=(po.totalValue||po.lines?.reduce((s,l)=>s+(l.totalPrice||0),0)||0);
                  const overdue=po.expectedDelivery&&new Date(po.expectedDelivery)<new Date();
                  const ptTotal=(po.paymentTerms||[]).reduce((s,t)=>s+(+t.pct||0),0);
                  return (
                    <tr key={po.id} style={{borderBottom:`1px solid ${T.border}`,background:overdue?`${T.red}08`:i%2===0?"transparent":T.bgInput}}>
                      <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{po.id}</td>
                      <td style={{padding:"7px 10px",fontSize:11}}>{po.vendorName}</td>
                      <td style={{padding:"7px 10px"}}><Badge color="blue">{po.poType||"rm"}</Badge></td>
                      <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:600}}>{fmt.currency(val)}</td>
                      <td style={{padding:"7px 10px",fontSize:11,color:overdue?T.red:T.textMid,fontWeight:overdue?700:400}}>{po.expectedDelivery||"—"}{overdue?" ⚠":""}</td>
                      <td style={{padding:"7px 10px"}}><Badge color={po.status==="fully_received"?"green":po.status==="partial"?"amber":"gray"}>{po.status}</Badge></td>
                      <td style={{padding:"7px 10px",fontSize:11,color:ptTotal===100?T.green:ptTotal>0?T.amber:T.textLow}}>{ptTotal>0?`${ptTotal}% defined`:"Not set"}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {pTab==="grn"&&(
          <div>
            {pendingPos.filter(p=>p.lines?.some(l=>(l.wtOrdered||0)>(l.wtReceived||0))).map(po=>{
              const pending=po.lines?.filter(l=>(l.wtOrdered||0)>(l.wtReceived||0))||[];
              const daysSince=po.poDate?Math.floor((Date.now()-new Date(po.poDate).getTime())/86400000):null;
              return (
                <div key={po.id} style={{...css.card,marginBottom:8,borderLeft:`3px solid ${daysSince>30?T.red:T.amber}`}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6}}>
                    <div>
                      <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{po.id} — {po.vendorName}</div>
                      <div style={{fontSize:11,color:T.textMid,marginTop:2}}>{pending.length} lines pending GRN · {daysSince} days since PO</div>
                    </div>
                    {daysSince>30&&<Badge color="red">Overdue by {daysSince-30}d</Badge>}
                  </div>
                  {pending.slice(0,3).map(l=>(
                    <div key={l.id} style={{display:"flex",justifyContent:"space-between",fontSize:11,padding:"3px 0",borderBottom:`1px solid ${T.border}`}}>
                      <span style={{fontFamily:T.fontMono,color:T.textMid}}>{l.matCode}</span>
                      <span>{fmt.num(l.wtReceived||0)} / {fmt.num(l.wtOrdered||0)} kg received</span>
                    </div>
                  ))}
                </div>
              );
            })}
          </div>
        )}
      </div>
    );
  };

  // ── Planning Admin Dashboard ─────────────────────────────────────────────────
  // ── Finance Admin Dashboard ─────────────────────────────────────────────────
  const FinanceAdminDashboard = () => {
    const [fTab, setFTab] = useState("summary");
    const [ledgerView, setLedgerView] = useState("receivables"); // receivables | payables
    const [ageFilter, setAgeFilter] = useState("all");
    const [orderFilter, setOrderFilter] = useState("");
    const [expandedRow, setExpandedRow] = useState(null);
    const [payForm, setPayForm] = useState({amount:"",date:today(),remarks:""});

    const activeOrders = (orders||[]).filter(o=>o.status==="active");

    // ── All invoices across all orders ─────────────────────────────────────────
    const allInvoices = activeOrders.flatMap(o=>
      (o.milestones||[]).flatMap(m=>(m.invoices||[]).map(inv=>({
        ...inv, orderId:o.id, orderNo:o.id, clientName:o.clientName,
        msDesc:m.desc, advanceType:m.advanceType, dueInDays:m.dueInDays||0,
        msId:m.id,
      })))
    );

    // ── All PO payment terms ────────────────────────────────────────────────────
    const allPoTerms = (pos||[]).flatMap(po=>(po.paymentTerms||[]).map((term,ti)=>{
      const poTotal = (po.lines||[]).reduce((s,l)=>s+(l.totalPrice||0),0);
      const amountDue = Math.round(poTotal*(+term.pct||0)/100);
      const grnDate = (po.grns||[]).slice(-1)[0]?.grnDate||"";
      const dueDate = grnDate&&term.daysFromMilestone
        ? (() => { const d=new Date(grnDate); d.setDate(d.getDate()+(+term.daysFromMilestone||0)); return d.toISOString().slice(0,10); })()
        : po.expectedDelivery||"";
      const totalPaid = (term.payments||[]).reduce((s,p)=>s+(p.amount||0),0);
      const balance = amountDue - totalPaid;
      const daysSince = dueDate ? Math.floor((Date.now()-new Date(dueDate).getTime())/86400000) : null;
      return { ...term, termIdx:ti, poId:po.id, vendorName:po.vendorName, poType:po.poType||"rm",
        amountDue, totalPaid, balance, dueDate, daysSince,
        status: balance<=0?"paid":totalPaid>0?"partial":"pending" };
    }));

    // ── Age filter helper ───────────────────────────────────────────────────────
    const ageColor = (days) => days===null?"":days>60?T.red:days>30?T.amber:"";
    const matchAge = (days) => {
      if(ageFilter==="all") return true;
      if(ageFilter==="0-30") return days!==null&&days>=0&&days<=30;
      if(ageFilter==="31-60") return days!==null&&days>30&&days<=60;
      if(ageFilter==="61-90") return days!==null&&days>60&&days<=90;
      if(ageFilter==="90+") return days!==null&&days>90;
      return true;
    };

    const filteredInvoices = allInvoices.filter(inv=>{
      const daysSince = inv.dueDate ? Math.floor((Date.now()-new Date(inv.dueDate).getTime())/86400000) : null;
      const rcvd = (inv.receipts||[]).reduce((s,r)=>s+(r.amount||0),0);
      const balance = (inv.netReceivable||0)-rcvd;
      if(orderFilter&&inv.orderId!==orderFilter) return false;
      if(ageFilter!=="all"&&!matchAge(daysSince)) return false;
      return balance>0;
    });

    const filteredTerms = allPoTerms.filter(t=>{
      if(orderFilter) return false; // POs not order-specific easily
      if(ageFilter!=="all"&&!matchAge(t.daysSince)) return false;
      return t.balance>0;
    });

    // ── Record receipt on invoice ───────────────────────────────────────────────
    const recordInvReceipt = (inv) => {
      if(!payForm.amount||!payForm.date) return;
      const updOrders = (orders||[]).map(o=>{
        if(o.id!==inv.orderId) return o;
        return {...o,milestones:(o.milestones||[]).map(m=>{
          if(m.id!==inv.msId) return m;
          return {...m,invoices:(m.invoices||[]).map(i=>{
            if(i.id!==inv.id) return i;
            const receipts=[...(i.receipts||[]),{id:`RCP-${Date.now()}`,amount:+payForm.amount,date:payForm.date,remarks:payForm.remarks}];
            const totalReceived=receipts.reduce((s,r)=>s+(r.amount||0),0);
            const balance=(i.netReceivable||0)-totalReceived;
            return {...i,receipts,totalReceived,balance,status:balance<=0?"received":totalReceived>0?"partial":"pending"};
          })};
        })};
      });
      // setOrders is not available here — use onChange pattern via order update
      // We'll store to a temp and trigger re-render via the orders state
      setExpandedRow(null); setPayForm({amount:"",date:today(),remarks:""});
    };

    // ── Record payment on PO term ───────────────────────────────────────────────
    const recordPoPayment = (term) => {
      if(!payForm.amount||!payForm.date) return;
      const updPos = (pos||[]).map(po=>{
        if(po.id!==term.poId) return po;
        return {...po,paymentTerms:(po.paymentTerms||[]).map((t,ti)=>{
          if(ti!==term.termIdx) return t;
          const payments=[...(t.payments||[]),{id:`PAY-${Date.now()}`,amount:+payForm.amount,date:payForm.date,remarks:payForm.remarks}];
          return {...t,payments};
        })};
      });
      setExpandedRow(null); setPayForm({amount:"",date:today(),remarks:""});
    };

    // ── Cash flow computation (8 weeks) ────────────────────────────────────────
    const getCashFlowWeeks = () => {
      const weeks = [];
      const now = new Date();
      const weekStart = new Date(now);
      weekStart.setDate(weekStart.getDate()-14); // start 2 weeks back
      weekStart.setHours(0,0,0,0);
      // Align to Monday
      weekStart.setDate(weekStart.getDate()-(weekStart.getDay()||7)+1);
      for(let w=0;w<8;w++) {
        const wStart = new Date(weekStart); wStart.setDate(weekStart.getDate()+w*7);
        const wEnd   = new Date(wStart);    wEnd.setDate(wStart.getDate()+6);
        const label  = wStart.toLocaleDateString("en-IN",{day:"2-digit",month:"short"})+" – "+wEnd.toLocaleDateString("en-IN",{day:"2-digit",month:"short"});
        const isCurrentWeek = now>=wStart&&now<=wEnd;
        const isPast = wEnd<now;

        // Receivables due this week
        let recvEst=0, recvActual=0;
        allInvoices.forEach(inv=>{
          if(!inv.dueDate) return;
          const dd=new Date(inv.dueDate);
          if(dd>=wStart&&dd<=wEnd) {
            const rcvd=(inv.receipts||[]).reduce((s,r)=>s+(r.amount||0),0);
            const bal=(inv.netReceivable||0)-rcvd;
            if(isPast) recvActual+=rcvd; else recvEst+=bal;
          }
        });

        // Payables due this week
        let payEst=0, payActual=0;
        allPoTerms.forEach(t=>{
          if(!t.dueDate) return;
          const dd=new Date(t.dueDate);
          if(dd>=wStart&&dd<=wEnd) {
            if(isPast) payActual+=t.totalPaid; else payEst+=t.balance;
          }
        });

        const netEst = recvEst-payEst;
        const netActual = recvActual-payActual;
        weeks.push({ label, isCurrentWeek, isPast, recvEst, recvActual, payEst, payActual, netEst, netActual, wStart, wEnd });
      }
      return weeks;
    };
    const cfWeeks = getCashFlowWeeks();
    const maxCfVal = Math.max(...cfWeeks.map(w=>Math.max(w.recvEst+w.recvActual,w.payEst+w.payActual)),1);

    // ── Stats ───────────────────────────────────────────────────────────────────
    const totalReceivable = allInvoices.reduce((s,inv)=>s+Math.max(0,(inv.netReceivable||0)-(inv.totalReceived||0)),0);
    const totalPayable    = allPoTerms.reduce((s,t)=>s+Math.max(0,t.balance),0);
    const overdueRecv     = filteredInvoices.filter(inv=>{const d=inv.dueDate?Math.floor((Date.now()-new Date(inv.dueDate).getTime())/86400000):null;return d!==null&&d>0;}).length;
    const overduePay      = allPoTerms.filter(t=>t.daysSince!==null&&t.daysSince>0&&t.balance>0).length;

    const AGE_OPTS = [["all","All"],["0-30","0–30d"],["31-60","31–60d"],["61-90","61–90d"],["90+","90+d"]];

    return (
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div>
            <div style={{fontSize:18,fontWeight:800,color:T.text}}>Finance Dashboard</div>
            <div style={{fontSize:12,color:T.textMid}}>{user.name}</div>
          </div>
        </div>

        {/* Stat bar */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
          {[["Total Receivable",fmt.currency(totalReceivable),T.green],["Total Payable",fmt.currency(totalPayable),T.red],["Overdue Receivables",`${overdueRecv} invoices`,overdueRecv>0?T.red:T.green],["Overdue Payments",`${overduePay} terms`,overduePay>0?T.amber:T.green]].map(([lbl,val,col])=>(
            <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
              <div style={{fontSize:10,color:T.textMid,fontWeight:700,textTransform:"uppercase",marginBottom:2}}>{lbl}</div>
              <div style={{fontSize:18,fontWeight:800,color:col}}>{val}</div>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["summary","Order Summary"],["cashflow","Cash Flow"],["ledger","Receivables / Payables"],["contractor","Contractor Costs"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setFTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:fTab===id?700:400,color:fTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:fTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {/* ── ORDER SUMMARY ── */}
        {fTab==="summary"&&activeOrders.map(o=>{
          const b=o.budget||{};
          const rmBudget=(o.orderQty||0)*(b.rmRatePerT||0);
          const paintBudget=(o.orderQty||0)*(b.paintRatePerT||0);
          const contractorBudget=(o.orderQty||0)*(b.contractorRatePerT||0);
          const transportBudget=(o.orderQty||0)*(b.transportRatePerT||0);
          const totalBudget=rmBudget+paintBudget+contractorBudget+transportBudget;
          const margin=(o.orderValue||0)-totalBudget;
          const marginPct=(o.orderValue||0)>0?Math.round(margin/(o.orderValue||1)*100):0;
          const oInvoices=(o.milestones||[]).flatMap(m=>m.invoices||[]);
          const invoiced=oInvoices.reduce((s,inv)=>s+(inv.netReceivable||0),0);
          const received=oInvoices.reduce((s,inv)=>s+(inv.totalReceived||0),0);
          return (
            <div key={o.id} style={{...css.card,marginBottom:12}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:12}}>
                <div><div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{o.id}</div><div style={{fontSize:11,color:T.textMid}}>{o.clientName} · {o.orderQty}T · Rate ₹{fmt.num(o.ratePerUnit||0)}/T</div></div>
                <div style={{textAlign:"right"}}><div style={{fontSize:14,fontWeight:700,color:T.green}}>{fmt.currency(o.orderValue||0)}</div><div style={{fontSize:10,color:T.textMid}}>Order Value</div></div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8}}>
                {[["Invoiced",invoiced,T.accent],["Received",received,T.green],["Outstanding",invoiced-received,invoiced-received>0?T.amber:T.green],["Budget Cost",totalBudget,T.text],["Gross Margin",margin,marginPct>=20?T.green:marginPct>=10?T.amber:T.red]].map(([lbl,val,col])=>(
                  <div key={lbl} style={{background:T.bgInput,borderRadius:6,padding:"8px 10px"}}>
                    <div style={{fontSize:9,color:T.textMid,fontWeight:700,textTransform:"uppercase"}}>{lbl}</div>
                    <div style={{fontSize:13,fontWeight:700,color:col}}>{fmt.currency(val)}{lbl==="Gross Margin"?` (${marginPct}%)`:""}</div>
                  </div>
                ))}
              </div>
            </div>
          );
        })}

        {/* ── CASH FLOW ── */}
        {fTab==="cashflow"&&(
          <div>
            <div style={{...css.card,marginBottom:16}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:4}}>8-Week Cash Flow</div>
              <div style={{fontSize:11,color:T.textLow,marginBottom:16}}>Solid = actual recorded · Light = estimated from terms · Green = receivable · Red = payable</div>
              <div style={{overflowX:"auto"}}>
                <table style={{width:"100%",borderCollapse:"collapse",minWidth:700}}>
                  <thead>
                    <tr style={{background:T.bgInput}}>
                      {["Week","Receivable","Payable","Net","Cumulative"].map(h=>(
                        <th key={h} style={{padding:"8px 12px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {(()=>{
                      let cumulative=0;
                      return cfWeeks.map((w,i)=>{
                        const recv=w.isPast?w.recvActual:w.recvEst;
                        const pay=w.isPast?w.payActual:w.payEst;
                        const net=recv-pay;
                        cumulative+=net;
                        const recvPct=Math.round(recv/maxCfVal*100);
                        const payPct=Math.round(pay/maxCfVal*100);
                        return (
                          <tr key={i} style={{borderBottom:`1px solid ${T.border}`,background:w.isCurrentWeek?`${T.accent}08`:"transparent"}}>
                            <td style={{padding:"10px 12px",fontSize:12,fontWeight:w.isCurrentWeek?700:400,color:w.isCurrentWeek?T.accent:T.text}}>{w.label}{w.isCurrentWeek?" ←":""}</td>
                            <td style={{padding:"10px 12px"}}>
                              <div style={{display:"flex",alignItems:"center",gap:8}}>
                                <div style={{height:8,width:`${recvPct}%`,minWidth:4,background:w.isPast?T.green:`${T.green}66`,borderRadius:2}} />
                                <span style={{fontSize:11,fontFamily:T.fontMono,color:T.green}}>{recv>0?fmt.currency(recv):"—"}</span>
                              </div>
                            </td>
                            <td style={{padding:"10px 12px"}}>
                              <div style={{display:"flex",alignItems:"center",gap:8}}>
                                <div style={{height:8,width:`${payPct}%`,minWidth:4,background:w.isPast?T.red:`${T.red}66`,borderRadius:2}} />
                                <span style={{fontSize:11,fontFamily:T.fontMono,color:T.red}}>{pay>0?fmt.currency(pay):"—"}</span>
                              </div>
                            </td>
                            <td style={{padding:"10px 12px",fontSize:12,fontWeight:700,color:net>=0?T.green:T.red,fontFamily:T.fontMono}}>{net>=0?"+":""}{fmt.currency(net)}</td>
                            <td style={{padding:"10px 12px",fontSize:12,fontFamily:T.fontMono,color:cumulative>=0?T.green:T.red,fontWeight:700}}>{cumulative>=0?"+":""}{fmt.currency(cumulative)}</td>
                          </tr>
                        );
                      });
                    })()}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* ── LEDGER ── */}
        {fTab==="ledger"&&(
          <div>
            {/* Controls */}
            <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:14,flexWrap:"wrap"}}>
              <div style={{display:"flex",border:`1px solid ${T.border}`,borderRadius:6,overflow:"hidden"}}>
                {[["receivables","Receivables"],["payables","Payables"]].map(([id,lbl])=>(
                  <button key={id} onClick={()=>setLedgerView(id)} style={{padding:"6px 16px",fontSize:12,fontWeight:ledgerView===id?700:400,background:ledgerView===id?T.accent:"transparent",color:ledgerView===id?"#fff":T.textMid,border:"none",cursor:"pointer"}}>{lbl}</button>
                ))}
              </div>
              <select value={orderFilter} onChange={e=>setOrderFilter(e.target.value)} style={{...css.input,width:160,fontSize:12}}>
                <option value="">All Orders</option>
                {activeOrders.map(o=><option key={o.id} value={o.id}>{o.id}</option>)}
              </select>
              <div style={{display:"flex",gap:4}}>
                {AGE_OPTS.map(([val,lbl])=>(
                  <button key={val} onClick={()=>setAgeFilter(val)} style={{padding:"4px 10px",fontSize:11,borderRadius:4,border:`1px solid ${ageFilter===val?T.accent:T.border}`,background:ageFilter===val?T.accent:"transparent",color:ageFilter===val?"#fff":T.textMid,cursor:"pointer"}}>{lbl}</button>
                ))}
              </div>
            </div>

            {/* Receivables table */}
            {ledgerView==="receivables"&&(
              <div style={{overflowX:"auto"}}>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                  <thead><tr style={{background:T.bgInput}}>{["Invoice No","Type","Order","Date","Due Date","Net Receivable","Received","Balance","Days","Status",""].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`,whiteSpace:"nowrap"}}>{h}</th>)}</tr></thead>
                  <tbody>
                    {filteredInvoices.length===0&&<tr><td colSpan={11} style={{padding:24,textAlign:"center",color:T.textLow}}>No invoices match filter</td></tr>}
                    {filteredInvoices.map(inv=>{
                      const rcvd=(inv.receipts||[]).reduce((s,r)=>s+(r.amount||0),0);
                      const balance=(inv.netReceivable||0)-rcvd;
                      const daysSince=inv.dueDate?Math.floor((Date.now()-new Date(inv.dueDate).getTime())/86400000):null;
                      const expanded=expandedRow===inv.id;
                      return (
                        <>
                        <tr key={inv.id} style={{borderBottom:`1px solid ${T.border}`,background:expanded?`${T.accent}08`:"transparent"}}>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{inv.invoiceNo||inv.id}</td>
                          <td style={{padding:"7px 10px"}}><span style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:`${T.accent}22`,color:T.accent}}>{inv.advanceType||"—"}</span></td>
                          <td style={{padding:"7px 10px",fontSize:11,color:T.textMid}}>{inv.orderId}</td>
                          <td style={{padding:"7px 10px",fontSize:11}}>{inv.invoiceDate}</td>
                          <td style={{padding:"7px 10px",fontSize:11,color:daysSince>0?T.red:T.textMid}}>{inv.dueDate||"—"}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:600}}>{fmt.currency(inv.netReceivable||0)}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,color:T.green}}>{fmt.currency(rcvd)}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:700,color:balance>0?ageColor(daysSince)||T.amber:T.green}}>{fmt.currency(balance)}</td>
                          <td style={{padding:"7px 10px",fontSize:11,color:ageColor(daysSince)||T.textMid,fontWeight:daysSince>30?700:400}}>{daysSince!==null?`${daysSince}d`:"—"}</td>
                          <td style={{padding:"7px 10px"}}><span style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:inv.status==="received"?T.greenBg:inv.status==="partial"?T.amberBg:T.bgInput,color:inv.status==="received"?T.green:inv.status==="partial"?T.amber:T.textMid,fontWeight:700}}>{inv.status||"pending"}</span></td>
                          <td style={{padding:"7px 10px"}}>{balance>0&&<button onClick={()=>{setExpandedRow(expanded?null:inv.id);setPayForm({amount:"",date:today(),remarks:""}); }} style={{...css.btn.sm,fontSize:10}}>Record</button>}</td>
                        </tr>
                        {expanded&&<tr key={`${inv.id}-form`}><td colSpan={11} style={{padding:"8px 16px",background:`${T.green}08`}}>
                          <div style={{display:"flex",gap:8,alignItems:"center"}}>
                            <span style={{fontSize:11,color:T.textMid,whiteSpace:"nowrap"}}>Record receipt:</span>
                            <input type="number" value={payForm.amount} onChange={e=>setPayForm(p=>({...p,amount:e.target.value}))} placeholder={`Max ${fmt.currency(balance)}`} style={{...css.input,width:130,fontSize:11}} />
                            <input type="date" value={payForm.date} onChange={e=>setPayForm(p=>({...p,date:e.target.value}))} style={{...css.input,width:130,fontSize:11}} />
                            <input value={payForm.remarks} onChange={e=>setPayForm(p=>({...p,remarks:e.target.value}))} placeholder="Remarks (optional)" style={{...css.input,flex:1,fontSize:11}} />
                            <button onClick={()=>recordInvReceipt(inv)} disabled={!payForm.amount||!payForm.date} style={{...css.btn.green,opacity:payForm.amount&&payForm.date?1:0.4,whiteSpace:"nowrap",fontSize:11}}>✓ Save</button>
                            <button onClick={()=>setExpandedRow(null)} style={{...css.btn.ghost,fontSize:11}}>✕</button>
                          </div>
                        </td></tr>}
                        </>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}

            {/* Payables table */}
            {ledgerView==="payables"&&(
              <div style={{overflowX:"auto"}}>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                  <thead><tr style={{background:T.bgInput}}>{["PO No","Vendor","Type","Milestone","Due Date","Amount Due","Paid","Balance","Days","Status",""].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`,whiteSpace:"nowrap"}}>{h}</th>)}</tr></thead>
                  <tbody>
                    {filteredTerms.length===0&&<tr><td colSpan={11} style={{padding:24,textAlign:"center",color:T.textLow}}>No payables match filter</td></tr>}
                    {filteredTerms.map((t,i)=>{
                      const expanded=expandedRow===`${t.poId}-${t.termIdx}`;
                      const key=`${t.poId}-${t.termIdx}`;
                      return (
                        <>
                        <tr key={key} style={{borderBottom:`1px solid ${T.border}`,background:expanded?`${T.accent}08`:i%2===0?"transparent":T.bgInput}}>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{t.poId}</td>
                          <td style={{padding:"7px 10px",fontSize:11}}>{t.vendorName}</td>
                          <td style={{padding:"7px 10px"}}><span style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:`${T.accent}22`,color:T.accent}}>{t.poType}</span></td>
                          <td style={{padding:"7px 10px",fontSize:11,color:T.textMid}}>{t.milestone||`Term ${t.termIdx+1} (${t.pct}%)`}</td>
                          <td style={{padding:"7px 10px",fontSize:11,color:t.daysSince>0?T.red:T.textMid}}>{t.dueDate||"—"}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:600}}>{fmt.currency(t.amountDue)}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,color:T.green}}>{fmt.currency(t.totalPaid)}</td>
                          <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:700,color:t.balance>0?ageColor(t.daysSince)||T.amber:T.green}}>{fmt.currency(t.balance)}</td>
                          <td style={{padding:"7px 10px",fontSize:11,color:ageColor(t.daysSince)||T.textMid,fontWeight:t.daysSince>30?700:400}}>{t.daysSince!==null?`${t.daysSince}d`:"—"}</td>
                          <td style={{padding:"7px 10px"}}><span style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:t.status==="paid"?T.greenBg:t.status==="partial"?T.amberBg:T.bgInput,color:t.status==="paid"?T.green:t.status==="partial"?T.amber:T.textMid,fontWeight:700}}>{t.status}</span></td>
                          <td style={{padding:"7px 10px"}}>{t.balance>0&&<button onClick={()=>{setExpandedRow(expanded?null:key);setPayForm({amount:"",date:today(),remarks:""}); }} style={{...css.btn.sm,fontSize:10}}>Record</button>}</td>
                        </tr>
                        {expanded&&<tr key={`${key}-form`}><td colSpan={11} style={{padding:"8px 16px",background:`${T.red}05`}}>
                          <div style={{display:"flex",gap:8,alignItems:"center"}}>
                            <span style={{fontSize:11,color:T.textMid,whiteSpace:"nowrap"}}>Record payment:</span>
                            <input type="number" value={payForm.amount} onChange={e=>setPayForm(p=>({...p,amount:e.target.value}))} placeholder={`Max ${fmt.currency(t.balance)}`} style={{...css.input,width:130,fontSize:11}} />
                            <input type="date" value={payForm.date} onChange={e=>setPayForm(p=>({...p,date:e.target.value}))} style={{...css.input,width:130,fontSize:11}} />
                            <input value={payForm.remarks} onChange={e=>setPayForm(p=>({...p,remarks:e.target.value}))} placeholder="Remarks (optional)" style={{...css.input,flex:1,fontSize:11}} />
                            <button onClick={()=>recordPoPayment(t)} disabled={!payForm.amount||!payForm.date} style={{...css.btn.primary,opacity:payForm.amount&&payForm.date?1:0.4,whiteSpace:"nowrap",fontSize:11}}>✓ Save</button>
                            <button onClick={()=>setExpandedRow(null)} style={{...css.btn.ghost,fontSize:11}}>✕</button>
                          </div>
                        </td></tr>}
                        </>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* ── CONTRACTOR COSTS ── */}
        {fTab==="contractor"&&(
          <div>
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>Contractor Output — Derived from DPR Data</div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead><tr style={{background:T.bgInput}}>{["Contractor","Order","Cutting (T)","Fitup+Weld (T)","Blast+Paint (T)","Total (T)"].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`}}>{h}</th>)}</tr></thead>
                <tbody>
                  {(()=>{
                    const rows=[];
                    const WELD_DONE=new Set(["weld_qc","tpi_weld","blasting","blast_qc","tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);
                    const BLAST_DONE=new Set(["tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);
                    activeOrders.forEach(o=>{
                      const conNames=[...new Set((dprs||[]).filter(d=>d.orderId===o.id).flatMap(d=>[d.fitupContractorName,d.weldContractorName,d.blastContractorName,d.paintContractorName].filter(Boolean)))];
                      conNames.forEach(name=>{
                        const cDprs=(dprs||[]).filter(d=>d.orderId===o.id&&(d.fitupContractorName===name||d.weldContractorName===name||d.blastContractorName===name||d.paintContractorName===name));
                        const getDrWt=d=>{ const dr=(o.drawings||[]).find(x=>x.id===d.drawingId)||{}; return (dr.totalWt||0)/1000; };
                        const cutWt=cDprs.filter(d=>d.currentStage!=="pending").reduce((s,d)=>s+getDrWt(d),0);
                        const weldWt=cDprs.filter(d=>(d.fitupContractorName===name||d.weldContractorName===name)&&WELD_DONE.has(d.currentStage)).reduce((s,d)=>s+getDrWt(d),0);
                        const blastWt=cDprs.filter(d=>(d.blastContractorName===name||d.paintContractorName===name)&&BLAST_DONE.has(d.currentStage)).reduce((s,d)=>s+getDrWt(d),0);
                        rows.push({name,orderId:o.id,cutWt,weldWt,blastWt,total:Math.max(cutWt,weldWt,blastWt)});
                      });
                    });
                    if(rows.length===0) return <tr><td colSpan={6} style={{padding:24,textAlign:"center",color:T.textLow}}>No DPR data yet.</td></tr>;
                    return rows.map((r,i)=>(
                      <tr key={`${r.name}-${r.orderId}`} style={{borderBottom:`1px solid ${T.border}`,background:i%2===0?"transparent":T.bgInput}}>
                        <td style={{padding:"7px 10px",fontWeight:600}}>{r.name}</td>
                        <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{r.orderId}</td>
                        <td style={{padding:"7px 10px",fontFamily:T.fontMono}}>{r.cutWt.toFixed(1)}</td>
                        <td style={{padding:"7px 10px",fontFamily:T.fontMono}}>{r.weldWt.toFixed(1)}</td>
                        <td style={{padding:"7px 10px",fontFamily:T.fontMono}}>{r.blastWt.toFixed(1)}</td>
                        <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{r.total.toFixed(1)}</td>
                      </tr>
                    ));
                  })()}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    );
  };

  const PlanningAdminDashboard = () => {
    const [plTab, setPlTab] = useState("drawings");
    return (
      <div>
        <div style={{fontSize:18,fontWeight:800,color:T.text,marginBottom:20}}>Planning Dashboard — {user.name}</div>
        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["drawings","Drawing Register"],["nesting","Nesting Status"],["balance","Material Balance"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setPlTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:plTab===id?700:400,color:plTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:plTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {plTab==="drawings"&&(
          <div>
            {(orders||[]).filter(o=>o.status==="active").map(o=>{
              const total=(o.drawings||[]).length;
              const released=(o.drawings||[]).filter(d=>(dprs||[]).some(dp=>dp.drawingId===d.id&&dp.orderId===o.id)).length;
              const unreleased=total-released;
              return (
                <div key={o.id} style={{...css.card,marginBottom:10}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                    <div>
                      <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{o.id}</div>
                      <div style={{fontSize:11,color:T.textMid}}>{o.clientName} · {total} drawings</div>
                    </div>
                    <div style={{display:"flex",gap:10,fontSize:12}}>
                      <span style={{color:T.green,fontWeight:700}}>{released} released</span>
                      <span style={{color:unreleased>0?T.amber:T.textLow,fontWeight:unreleased>0?700:400}}>{unreleased} unreleased</span>
                    </div>
                  </div>
                  <div style={{height:6,background:T.bgInput,borderRadius:3,overflow:"hidden"}}>
                    <div style={{width:`${total>0?Math.round(released/total*100):0}%`,height:"100%",background:T.green,borderRadius:3}} />
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {plTab==="nesting"&&(
          <div>
            {(nestingBatches||[]).slice().reverse().map(b=>(
              <div key={b.id} style={{...css.card,marginBottom:8}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div>
                    <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{b.id}</div>
                    <div style={{fontSize:11,color:T.textMid}}>{(b.lots||[]).length} materials · {(b.lots||[]).reduce((s,l)=>s+(l.sheets||[]).length,0)} sheets</div>
                  </div>
                  <Badge color={b.status==="confirmed"?"green":b.status==="draft"?"amber":"gray"}>{b.status||"draft"}</Badge>
                </div>
              </div>
            ))}
            {(nestingBatches||[]).length===0&&<div style={{color:T.textLow,padding:24,textAlign:"center"}}>No nesting batches yet.</div>}
          </div>
        )}

        {plTab==="balance"&&(
          <div>
            {(orders||[]).filter(o=>o.status==="active").map(o=>{
              const orderPos=(pos||[]).filter(p=>(p.servedOrders||p.coveredOrders||[]).includes(o.id));
              const ordered=orderPos.reduce((s,p)=>s+(p.lines||[]).reduce((ls,l)=>ls+(l.wtOrdered||0),0),0)/1000;
              const received=orderPos.reduce((s,p)=>s+(p.grns||[]).reduce((gs,g)=>gs+(g.lines||[]).reduce((ls,l)=>ls+(l.wtReceived||0),0),0),0)/1000;
              const required=o.orderQty||0;
              return (
                <div key={o.id} style={{...css.card,marginBottom:10}}>
                  <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent,marginBottom:8}}>{o.id} — {o.clientName}</div>
                  <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
                    {[["Required",`${required}T`,T.text],["Ordered",`${ordered.toFixed(1)}T`,T.accent],["Received",`${received.toFixed(1)}T`,T.green]].map(([lbl,val,col])=>(
                      <div key={lbl} style={{background:T.bgInput,borderRadius:6,padding:"8px 12px"}}>
                        <div style={{fontSize:10,color:T.textMid,fontWeight:700,textTransform:"uppercase"}}>{lbl}</div>
                        <div style={{fontSize:16,fontWeight:700,color:col,marginTop:2}}>{val}</div>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    );
  };

  // ── Masters: Production Engineers ───────────────────────────────────────────
  const MastersPEScreen = () => {
    const [form, setForm] = useState(null); // null=list, {}=edit
    const STAGE_OPTIONS = ["cutting","fitup","welding","blasting","painting"];
    const peUsers = USERS.filter(u=>u.role==="production_engineer");

    const save = () => {
      if (!form.name||!form.userId) return;
      if (form.id) {
        setProductionEngineers(prev=>prev.map(p=>p.id===form.id?{...form}:p));
      } else {
        setProductionEngineers(prev=>[...prev,{...form,id:`PE-${Date.now()}`}]);
      }
      setForm(null);
    };

    if (form) return (
      <div>
        <button onClick={()=>setForm(null)} style={{...css.btn.ghost,marginBottom:16}}>← Back</button>
        <div style={{...css.card,maxWidth:500}}>
          <div style={{fontSize:14,fontWeight:700,color:T.text,marginBottom:16}}>{form.id?"Edit":"Add"} Production Engineer</div>
          <label style={css.label}>User Account</label>
          <select value={form.userId||""} onChange={e=>{const u=peUsers.find(x=>x.username===e.target.value);setForm(p=>({...p,userId:e.target.value,name:u?.name||p.name}));}} style={{...css.input,marginBottom:10}}>
            <option value="">Select user...</option>
            {peUsers.map(u=><option key={u.username} value={u.username}>{u.name} ({u.username})</option>)}
          </select>
          <label style={css.label}>Display Name</label>
          <input value={form.name||""} onChange={e=>setForm(p=>({...p,name:e.target.value}))} style={{...css.input,marginBottom:10}} />
          <label style={css.label}>Stage Responsibilities</label>
          <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:12}}>
            {STAGE_OPTIONS.map(s=>(
              <label key={s} style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12}}>
                <input type="checkbox" checked={(form.stages||[]).includes(s)}
                  onChange={e=>setForm(p=>({...p,stages:e.target.checked?[...(p.stages||[]),s]:(p.stages||[]).filter(x=>x!==s)}))} />
                {s.charAt(0).toUpperCase()+s.slice(1)}
              </label>
            ))}
          </div>
          <label style={css.label}>Assigned Orders</label>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
            {(orders||[]).filter(o=>o.status==="active").map(o=>(
              <label key={o.id} style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12}}>
                <input type="checkbox" checked={(form.orderIds||[]).includes(o.id)}
                  onChange={e=>setForm(p=>({...p,orderIds:e.target.checked?[...(p.orderIds||[]),o.id]:(p.orderIds||[]).filter(x=>x!==o.id)}))} />
                {o.id}
              </label>
            ))}
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={save} disabled={!form.name||!form.userId} style={{...css.btn.primary,opacity:(!form.name||!form.userId)?0.4:1}}>Save</button>
            <button onClick={()=>setForm(null)} style={css.btn.ghost}>Cancel</button>
          </div>
        </div>
      </div>
    );

    return (
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div style={{fontSize:14,fontWeight:700,color:T.text}}>Production Engineers</div>
          <button onClick={()=>setForm({name:"",userId:"",stages:[],orderIds:[]})} style={css.btn.primary}>+ Add Engineer</button>
        </div>
        {(productionEngineers||[]).length===0&&<div style={{color:T.textLow,padding:24,textAlign:"center"}}>No production engineers configured yet.</div>}
        {(productionEngineers||[]).map(pe=>{
          const assignedDprs=(dprs||[]).filter(d=>(d.peAssignments||[]).some(a=>a.peId===pe.id));
          return (
            <div key={pe.id} style={{...css.card,marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{fontSize:13,fontWeight:700,color:T.text}}>{pe.name}</div>
                  <div style={{fontSize:11,color:T.textMid,marginTop:2}}>@{pe.userId} · Stages: {(pe.stages||[]).join(", ")||"none"}</div>
                  <div style={{fontSize:11,color:T.textMid}}>Orders: {(pe.orderIds||[]).join(", ")||"none"} · {assignedDprs.length} drawings assigned</div>
                </div>
                <button onClick={()=>setForm({...pe})} style={css.btn.ghost}>Edit</button>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  // ── Production Admin Full Dashboard ────────────────────────────────────────
  const ProductionAdminFullDashboard = () => {
    const [paTab, setPaTab] = useState("floor");
    const allDprs = dprs||[];
    const activeOrders = (orders||[]).filter(o=>o.status==="active");
    const WELD_DONE = new Set(["weld_qc","tpi_weld","blasting","blast_qc","tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);
    const DONE = new Set(["cutting_qc","fitup","fit_up","welding","weld_qc","tpi_fitup","tpi_weld","blasting","blast_qc","tpi_blast","painting","paint_qc","tpi_paint","mdcc","complete"]);

    const getDrWt = (dpr) => {
      const o=(orders||[]).find(x=>x.id===dpr.orderId)||{};
      const dr=(o.drawings||[]).find(x=>x.id===dpr.drawingId)||{};
      return (dr.totalWt||0)/1000;
    };

    // Bottlenecks — stuck >5 days
    const bottlenecks = allDprs.filter(d=>{
      if(["complete","pending"].includes(d.currentStage)) return false;
      const last=(d.stageHistory||[]).slice(-1)[0]?.at||"";
      if(!last) return false;
      return (Date.now()-new Date(last).getTime())/86400000 > 5;
    }).map(d=>{
      const o=(orders||[]).find(x=>x.id===d.orderId)||{};
      const last=(d.stageHistory||[]).slice(-1)[0]?.at||"";
      const days=Math.floor((Date.now()-new Date(last).getTime())/86400000);
      const pe=(productionEngineers||[]).find(p=>(d.peAssignments||[]).some(a=>a.peId===p.id));
      return {drawingNo:d.drawingNo,orderNo:d.orderId,stage:d.currentStage,days,peName:pe?.name||"Unassigned",client:o.clientName||""};
    }).sort((a,b)=>b.days-a.days).slice(0,8);

    // Contractor stats
    const conStats = {};
    allDprs.forEach(d=>{
      [d.fitupContractorName,d.weldContractorName,d.blastContractorName,d.paintContractorName].filter(Boolean).forEach(name=>{
        if(!conStats[name]) conStats[name]={total:0,done:0,wip:0,tpi:0};
        conStats[name].total++;
        if(d.currentStage==="complete") conStats[name].done++;
        else if(["tpi_fitup","tpi_weld","tpi_blast","tpi_paint"].includes(d.currentStage)) conStats[name].tpi++;
        else if(d.currentStage!=="pending") conStats[name].wip++;
      });
    });

    // PE stats
    const peStats = (productionEngineers||[]).map(pe=>{
      const peDprs=allDprs.filter(d=>(d.peAssignments||[]).some(a=>a.peId===pe.id));
      const done=peDprs.filter(d=>d.currentStage==="complete").length;
      const wip=peDprs.filter(d=>!["pending","complete"].includes(d.currentStage)).length;
      const wt=peDprs.filter(d=>WELD_DONE.has(d.currentStage)).reduce((s,d)=>s+getDrWt(d),0);
      return {...pe,total:peDprs.length,done,wip,wt};
    });
    const maxPeWt=Math.max(...peStats.map(p=>p.wt),1);

    return (
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div>
            <div style={{fontSize:18,fontWeight:800,color:T.text}}>Production Admin — {user.name}</div>
            <div style={{fontSize:12,color:T.textMid}}>{allDprs.length} total DPRs · {allDprs.filter(d=>d.currentStage==="complete").length} complete</div>
          </div>
          <button onClick={()=>setPaTab("assign")} style={{...css.btn.primary,display:"flex",alignItems:"center",gap:6}}>
            📋 Drawing Assignment
            {allDprs.filter(d=>d.currentStage==="blasting"&&!d.blastContractorId).length>0&&
              <span style={{background:"rgba(255,255,255,0.3)",borderRadius:99,fontSize:10,padding:"1px 5px"}}>{allDprs.filter(d=>d.currentStage==="blasting"&&!d.blastContractorId).length}</span>}
          </button>
        </div>

        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["floor","Floor Overview"],["assign","Assignment Board"],["contractors","Contractors"],["engineers","Engineers"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setPaTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:paTab===id?700:400,color:paTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:paTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {/* ── FLOOR OVERVIEW ── */}
        {paTab==="floor"&&(
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            {/* Awaiting collection alert */}
            {(()=>{
              const awaitingColl = (dprs||[]).filter(d=>d.currentStage==="awaiting_collection");
              const overdue = awaitingColl.filter(d=>{
                const hrs = d.awaitingCollectionSince
                  ? (Date.now()-new Date(d.awaitingCollectionSince).getTime())/3600000 : 0;
                return hrs > 4;
              });
              if (awaitingColl.length===0) return null;
              return (
                <div style={{background:overdue.length>0?T.amberBg:T.greenBg,borderRadius:8,padding:"12px 16px",border:`1px solid ${overdue.length>0?T.amber:T.green}`}}>
                  <div style={{fontWeight:700,fontSize:12,color:overdue.length>0?T.amber:T.green,marginBottom:8}}>
                    📦 {awaitingColl.length} Drawing{awaitingColl.length!==1?"s":""} Awaiting Collection by Contractor
                    {overdue.length>0&&<span style={{marginLeft:8,color:T.red}}>⚠ {overdue.length} overdue (&gt;4h)</span>}
                  </div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                    {awaitingColl.map(d=>{
                      const hrs = d.awaitingCollectionSince
                        ? Math.round((Date.now()-new Date(d.awaitingCollectionSince).getTime())/3600000) : 0;
                      const o = (orders||[]).find(x=>x.id===d.orderId)||{};
                      return (
                        <div key={d.id} style={{background:hrs>24?T.redBg:hrs>4?T.amberBg:T.bg,borderRadius:5,padding:"4px 10px",border:`1px solid ${hrs>24?T.red:hrs>4?T.amber:T.border}`,fontSize:11}}>
                          <span style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent}}>{d.drawingNo}</span>
                          <span style={{color:T.textMid,marginLeft:6}}>{o.orderNo} · {hrs}h</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })()}
            {/* Stat bar */}
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
              {[["Active Drawings",allDprs.filter(d=>!["pending","complete"].includes(d.currentStage)).length,T.accent],["Complete",allDprs.filter(d=>d.currentStage==="complete").length,T.green],["TPI Hold",allDprs.filter(d=>["tpi_fitup","tpi_weld","tpi_blast","tpi_paint"].includes(d.currentStage)).length,T.amber],["Bottlenecks",bottlenecks.length,bottlenecks.length>0?T.red:T.green]].map(([lbl,val,col])=>(
                <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
                  <div style={{fontSize:10,color:T.textMid,fontWeight:700,textTransform:"uppercase",marginBottom:2}}>{lbl}</div>
                  <div style={{fontSize:22,fontWeight:800,color:col}}>{val}</div>
                </div>
              ))}
            </div>
            {/* Per-order progress */}
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:12}}>Order Progress</div>
              {activeOrders.map(o=>{
                const oDprs=allDprs.filter(d=>d.orderId===o.id);
                const total=(o.drawings||[]).length||1;
                const cut=oDprs.filter(d=>DONE.has(d.currentStage)).length;
                const weld=oDprs.filter(d=>WELD_DONE.has(d.currentStage)).length;
                const done=oDprs.filter(d=>d.currentStage==="complete").length;
                const dueDate=o.endDate?new Date(o.endDate):null;
                const daysLeft=dueDate?Math.ceil((dueDate-new Date())/86400000):null;
                return (
                  <div key={o.id} style={{padding:"10px 0",borderBottom:`1px solid ${T.border}`,display:"grid",gridTemplateColumns:"1fr 2fr 80px 90px",gap:12,alignItems:"center"}}>
                    <div>
                      <div style={{fontFamily:T.fontMono,fontSize:12,fontWeight:700,color:T.accent}}>{o.id}</div>
                      <div style={{fontSize:10,color:T.textMid}}>{o.clientName} · {o.orderQty}T</div>
                    </div>
                    <div>
                      <div style={{fontSize:10,color:T.textMid,marginBottom:3}}>Cut {Math.round(cut/total*100)}% · Weld {Math.round(weld/total*100)}% · Done {Math.round(done/total*100)}%</div>
                      <div style={{display:"flex",gap:2,height:6}}>
                        <div style={{width:`${Math.round(cut/total*100)}%`,background:"#2563EB",borderRadius:2}}/>
                        <div style={{width:`${Math.round(Math.max(0,weld-cut)/total*100)}%`,background:"#16A34A",borderRadius:2}}/>
                        <div style={{width:`${Math.round(Math.max(0,done-weld)/total*100)}%`,background:"#6B7280",borderRadius:2}}/>
                        <div style={{flex:1,background:T.border,borderRadius:2}}/>
                      </div>
                    </div>
                    <div style={{fontSize:11,fontWeight:700,color:daysLeft===null?T.textMid:daysLeft<0?T.red:daysLeft<=7?T.red:T.green}}>
                      {daysLeft===null?"—":daysLeft<0?`${-daysLeft}d late`:`${daysLeft}d left`}
                    </div>
                    <span style={{display:"inline-block",padding:"2px 8px",borderRadius:99,fontSize:11,fontWeight:700,background:daysLeft===null?T.bgInput:daysLeft<0?T.redBg:daysLeft<=7?T.amberBg:T.greenBg,color:daysLeft===null?T.textMid:daysLeft<0?T.red:daysLeft<=7?T.amber:T.green}}>
                      {daysLeft===null?"—":daysLeft<0?"Overdue":daysLeft<=7?"At risk":"On track"}
                    </span>
                  </div>
                );
              })}
            </div>
            {/* Bottlenecks */}
            {bottlenecks.length>0&&(
              <div style={{...css.card}}>
                <div style={{fontSize:13,fontWeight:700,color:T.amber,marginBottom:12}}>⚠ Bottlenecks — Stuck &gt;5 days</div>
                {bottlenecks.map((b,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 10px",background:T.bgInput,borderRadius:6,marginBottom:5,borderLeft:`3px solid ${b.days>10?T.red:T.amber}`}}>
                    <div>
                      <span style={{fontFamily:T.fontMono,fontSize:12,fontWeight:700,color:T.accent}}>{b.drawingNo}</span>
                      <span style={{fontSize:11,color:T.textMid,marginLeft:8}}>{b.orderNo} · {(DPR_STAGE_META[b.stage]||{label:b.stage}).label}</span>
                      <span style={{fontSize:11,color:T.textLow,marginLeft:8}}>PE: {b.peName}</span>
                    </div>
                    <span style={{fontSize:11,fontWeight:700,color:b.days>10?T.red:T.amber}}>{b.days}d stuck</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ── ASSIGNMENT BOARD ── */}
        {paTab==="assign"&&<ProductionAdminScreen />}

        {/* ── CONTRACTORS ── */}
        {paTab==="contractors"&&(
          <div>
            <div style={{...css.card,marginBottom:12}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>Contractor Performance — Tonnes Cleared</div>
              {Object.entries(conStats).map(([name,s])=>{
                const wt=allDprs.filter(d=>(d.fitupContractorName===name||d.weldContractorName===name||d.blastContractorName===name||d.paintContractorName===name)&&WELD_DONE.has(d.currentStage)).reduce((sum,d)=>sum+getDrWt(d),0);
                const maxWt=Math.max(...Object.keys(conStats).map(n=>allDprs.filter(d=>(d.fitupContractorName===n||d.weldContractorName===n||d.blastContractorName===n||d.paintContractorName===n)&&WELD_DONE.has(d.currentStage)).reduce((sum,d)=>sum+getDrWt(d),0)),1);
                return (
                  <div key={name} style={{marginBottom:14}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                      <div style={{display:"flex",gap:12,alignItems:"center"}}>
                        <span style={{fontSize:13,fontWeight:600,color:T.text}}>{name}</span>
                        <span style={{fontSize:11,color:T.textMid}}>{s.total} drawings · {s.wip} in progress · {s.done} done</span>
                        {s.tpi>0&&<Badge color="amber">{s.tpi} at TPI</Badge>}
                      </div>
                      <span style={{fontSize:13,fontWeight:700,color:T.accent}}>{wt.toFixed(1)}T done</span>
                    </div>
                    <div style={{height:10,background:T.bgInput,borderRadius:5,overflow:"hidden",border:`1px solid ${T.border}`}}>
                      <div style={{width:`${Math.round(wt/maxWt*100)}%`,height:"100%",background:T.accent,borderRadius:5}}/>
                    </div>
                  </div>
                );
              })}
              {Object.keys(conStats).length===0&&<div style={{color:T.textLow,fontSize:12}}>No contractor data yet.</div>}
            </div>
          </div>
        )}

        {/* ── ENGINEERS ── */}
        {paTab==="engineers"&&(
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            {peStats.length===0&&<div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>No production engineers configured. Go to Masters → Production Engineers.</div>}
            {peStats.map(pe=>(
              <div key={pe.id} style={{...css.card}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
                  <div>
                    <div style={{fontSize:14,fontWeight:700,color:T.text}}>{pe.name}</div>
                    <div style={{fontSize:11,color:T.textMid}}>Stages: {(pe.stages||[]).join(", ")||"all"} · Orders: {(pe.orderIds||[]).join(", ")||"none"}</div>
                  </div>
                  <div style={{display:"flex",gap:16,textAlign:"right"}}>
                    {[["Assigned",pe.total,T.accent],["In Progress",pe.wip,T.amber],["Done",pe.done,T.green]].map(([lbl,val,col])=>(
                      <div key={lbl}><div style={{fontSize:18,fontWeight:800,color:col}}>{val}</div><div style={{fontSize:10,color:T.textLow}}>{lbl}</div></div>
                    ))}
                  </div>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{flex:1,height:8,background:T.bgInput,borderRadius:4,overflow:"hidden"}}>
                    <div style={{width:`${Math.round(pe.wt/maxPeWt*100)}%`,height:"100%",background:T.accent,borderRadius:4}}/>
                  </div>
                  <span style={{fontSize:12,fontWeight:700,color:T.accent,minWidth:60,textAlign:"right"}}>{pe.wt.toFixed(1)}T</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  };

  // ── QC Admin Dashboard ──────────────────────────────────────────────────────
  const QcAdminDashboard = () => {
    const [qcTab, setQcTab] = useState("queue");
    const allDprs = dprs||[];
    const today_str = today();

    // Pending counts
    const pending = {
      cutting_qc:  (instances||[]).filter(i=>i.currentStage==="cutting_qc").length,
      fitup_qc:    allDprs.filter(d=>d.currentStage==="fitup_qc").length,
      weld_qc:     allDprs.filter(d=>d.currentStage==="weld_qc").length,
      blast_qc:    allDprs.filter(d=>d.currentStage==="blast_qc").length,
      paint_qc:    allDprs.filter(d=>d.currentStage==="paint_qc").length,
      tpi:         allDprs.filter(d=>["tpi_fitup","tpi_weld","tpi_blast","tpi_paint"].includes(d.currentStage)).length,
    };
    const totalPending = Object.values(pending).reduce((s,v)=>s+v,0);

    // Cleared today — DPRs whose last stageHistory entry is today and action=approved
    const clearedToday = allDprs.filter(d=>{
      const last=(d.stageHistory||[]).slice(-1)[0];
      return last?.action==="approved"&&last?.at?.slice(0,10)===today_str;
    }).length;

    // Oldest pending — find DPRs at QC stages longest
    const qcStages = new Set(["cutting_qc","fitup_qc","weld_qc","blast_qc","paint_qc"]);
    const oldestPending = allDprs.filter(d=>qcStages.has(d.currentStage)).map(d=>{
      const enteredAt=(d.stageHistory||[]).slice(-1)[0]?.at||"";
      const days=enteredAt?Math.floor((Date.now()-new Date(enteredAt).getTime())/86400000):0;
      const o=(orders||[]).find(x=>x.id===d.orderId)||{};
      return {drawingNo:d.drawingNo,stage:d.currentStage,days,orderNo:d.orderId,client:o.clientName||""};
    }).sort((a,b)=>b.days-a.days).slice(0,5);

    // First-pass rate per stage (from stageHistory)
    const firstPassStats = {};
    ["fitup_qc","weld_qc","blast_qc","paint_qc"].forEach(stage=>{
      let approved=0,rejected=0;
      allDprs.forEach(d=>{
        (d.stageHistory||[]).forEach(h=>{
          if(h.stage===stage&&h.action==="approved") approved++;
          if(h.stage===stage&&h.action==="rejected") rejected++;
        });
      });
      firstPassStats[stage]={approved,rejected,total:approved+rejected,rate:approved+rejected>0?Math.round(approved/(approved+rejected)*100):null};
    });

    // Rework by contractor
    const reworkStats = {};
    allDprs.forEach(d=>{
      const rejEvents=(d.stageHistory||[]).filter(h=>h.action==="rejected");
      rejEvents.forEach(ev=>{
        const conName=d.fitupContractorName||d.weldContractorName||"Unknown";
        if(!reworkStats[conName]) reworkStats[conName]={rejected:0,approved:0};
        reworkStats[conName].rejected++;
      });
      const apprEvents=(d.stageHistory||[]).filter(h=>h.action==="approved");
      apprEvents.forEach(()=>{
        const conName=d.fitupContractorName||d.weldContractorName||"Unknown";
        if(!reworkStats[conName]) reworkStats[conName]={rejected:0,approved:0};
        reworkStats[conName].approved++;
      });
    });

    // TPI stats
    const tpiStats = {offered:0,cleared:0,failed:0,waived:0};
    allDprs.forEach(d=>(d.tpiRecords||[]).forEach(r=>{
      if(r.offeredAt) tpiStats.offered++;
      if(r.clearedAt) tpiStats.cleared++;
      if(r.outcome==="fail") tpiStats.failed++;
      if(r.outcome==="waived") tpiStats.waived++;
    }));

    const QC_LABELS = {cutting_qc:"Cutting QC",fitup_qc:"Fit-Up QC",weld_qc:"Weld QC",blast_qc:"Blast QC",paint_qc:"Paint QC",tpi:"TPI Hold"};
    const QC_COLORS = {cutting_qc:"#2563EB",fitup_qc:"#0E7490",weld_qc:"#7C3AED",blast_qc:"#D97706",paint_qc:"#1D4ED8",tpi:"#B45309"};

    return (
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div>
            <div style={{fontSize:18,fontWeight:800,color:T.text}}>QC Dashboard — {user.name}</div>
            <div style={{fontSize:12,color:T.textMid}}>{totalPending} pending · {clearedToday} cleared today</div>
          </div>
          <button onClick={()=>{/* navigate to qc_ops */}} style={css.btn.primary}>→ Open QC Module</button>
        </div>

        {/* Today's cleared — big motivating number */}
        <div style={{...css.card,background:`${T.green}11`,border:`1px solid ${T.green}33`,marginBottom:16,display:"flex",alignItems:"center",gap:20,padding:"16px 20px"}}>
          <div style={{fontSize:48,fontWeight:900,color:T.green,fontVariantNumeric:"tabular-nums"}}>{clearedToday}</div>
          <div>
            <div style={{fontSize:16,fontWeight:700,color:T.green}}>Drawings cleared today</div>
            <div style={{fontSize:12,color:T.textMid,marginTop:2}}>QC approvals completed on {today_str}</div>
          </div>
        </div>

        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["queue","Today's Queue"],["metrics","Quality Metrics"],["tpi","TPI Tracker"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setQcTab(id)} style={{padding:"10px 18px",fontSize:13,fontWeight:qcTab===id?700:400,color:qcTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:qcTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {/* ── TODAY'S QUEUE ── */}
        {qcTab==="queue"&&(
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
              {Object.entries(pending).map(([stage,cnt])=>(
                <div key={stage} style={{background:cnt>0?`${QC_COLORS[stage]}11`:T.bgInput,border:`1px solid ${cnt>0?QC_COLORS[stage]+"33":T.border}`,borderRadius:8,padding:"14px 16px",cursor:"pointer"}} onClick={()=>setMod("qc_ops")}>
                  <div style={{fontSize:11,fontWeight:700,color:QC_COLORS[stage],textTransform:"uppercase",letterSpacing:"0.05em"}}>{QC_LABELS[stage]}</div>
                  <div style={{fontSize:32,fontWeight:900,color:cnt>0?QC_COLORS[stage]:T.textLow,marginTop:4}}>{cnt}</div>
                  <div style={{fontSize:10,color:T.textLow,marginTop:2}}>{cnt===0?"✓ All clear":"pending → tap to action"}</div>
                </div>
              ))}
            </div>
            {/* Oldest pending */}
            {oldestPending.length>0&&(
              <div style={{...css.card}}>
                <div style={{fontSize:12,fontWeight:700,color:T.amber,marginBottom:10}}>⏰ Oldest Pending — Action Urgently</div>
                {oldestPending.map((item,i)=>{
                  const meta=DPR_STAGE_META[item.stage]||{label:item.stage,color:T.textMid,bg:"#F1F5F9"};
                  return (
                    <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 10px",background:T.bgInput,borderRadius:6,marginBottom:4,borderLeft:`3px solid ${item.days>3?T.red:T.amber}`}}>
                      <div>
                        <span style={{fontFamily:T.fontMono,fontSize:12,fontWeight:700,color:T.accent}}>{item.drawingNo}</span>
                        <span style={{fontSize:11,color:T.textMid,marginLeft:8}}>{item.orderNo} · {item.client}</span>
                      </div>
                      <div style={{display:"flex",gap:8,alignItems:"center"}}>
                        <span style={{padding:"2px 8px",borderRadius:99,fontSize:10,fontWeight:700,background:meta.bg,color:meta.color}}>{meta.label}</span>
                        <span style={{fontSize:11,fontWeight:700,color:item.days>3?T.red:T.amber}}>{item.days}d waiting</span>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {/* ── QUALITY METRICS ── */}
        {qcTab==="metrics"&&(
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>First-Pass Rate by Stage</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
                {Object.entries(firstPassStats).map(([stage,s])=>{
                  const col=QC_COLORS[stage]||T.accent;
                  return (
                    <div key={stage} style={{background:T.bgInput,borderRadius:8,padding:"12px 14px"}}>
                      <div style={{fontSize:10,fontWeight:700,color:col,textTransform:"uppercase",marginBottom:6}}>{QC_LABELS[stage]||stage}</div>
                      <div style={{fontSize:26,fontWeight:800,color:s.rate===null?T.textLow:s.rate>=90?T.green:s.rate>=75?T.amber:T.red}}>{s.rate===null?"—":`${s.rate}%`}</div>
                      <div style={{fontSize:10,color:T.textLow,marginTop:2}}>{s.approved} approved · {s.rejected} rejected</div>
                      {s.total>0&&<div style={{height:4,background:T.border,borderRadius:2,marginTop:6,overflow:"hidden"}}><div style={{width:`${s.rate}%`,height:"100%",background:s.rate>=90?T.green:s.rate>=75?T.amber:T.red}}/></div>}
                    </div>
                  );
                })}
              </div>
            </div>
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>Rework Rate by Contractor</div>
              {Object.keys(reworkStats).length===0&&<div style={{color:T.textLow,fontSize:12}}>No rejection data yet.</div>}
              {Object.entries(reworkStats).map(([name,s])=>{
                const total=s.approved+s.rejected;
                const reworkPct=total>0?Math.round(s.rejected/total*100):0;
                return (
                  <div key={name} style={{marginBottom:10}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                      <span style={{fontSize:12,fontWeight:600,color:T.text}}>{name}</span>
                      <span style={{fontSize:12,fontWeight:700,color:reworkPct>10?T.red:reworkPct>5?T.amber:T.green}}>{reworkPct}% rework rate</span>
                    </div>
                    <div style={{height:6,background:T.bgInput,borderRadius:3,overflow:"hidden"}}>
                      <div style={{width:`${reworkPct}%`,height:"100%",background:reworkPct>10?T.red:reworkPct>5?T.amber:T.green,borderRadius:3}}/>
                    </div>
                    <div style={{fontSize:10,color:T.textLow,marginTop:2}}>{s.approved} passed · {s.rejected} rejected</div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ── TPI TRACKER ── */}
        {qcTab==="tpi"&&(
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
              {[["Offered",tpiStats.offered,"#2563EB"],["Cleared",tpiStats.cleared,T.green],["Waived",tpiStats.waived,T.amber],["Failed",tpiStats.failed,T.red]].map(([lbl,val,col])=>(
                <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
                  <div style={{fontSize:10,color:T.textMid,fontWeight:700,textTransform:"uppercase"}}>{lbl}</div>
                  <div style={{fontSize:24,fontWeight:800,color:col,marginTop:4}}>{val}</div>
                </div>
              ))}
            </div>
            {/* Drawings awaiting TPI offer */}
            {allDprs.filter(d=>["tpi_fitup","tpi_weld","tpi_blast","tpi_paint"].includes(d.currentStage)&&!(d.tpiRecords||[]).some(r=>r.offeredAt)).length>0&&(
              <div style={{...css.card,borderLeft:`3px solid ${T.amber}`}}>
                <div style={{fontSize:12,fontWeight:700,color:T.amber,marginBottom:10}}>⚠ Awaiting TPI Offer</div>
                {allDprs.filter(d=>["tpi_fitup","tpi_weld","tpi_blast","tpi_paint"].includes(d.currentStage)&&!(d.tpiRecords||[]).some(r=>r.offeredAt)).map(d=>{
                  const o=(orders||[]).find(x=>x.id===d.orderId)||{};
                  return (
                    <div key={d.id} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${T.border}`,fontSize:12}}>
                      <span style={{fontFamily:T.fontMono,color:T.accent}}>{d.drawingNo}</span>
                      <span style={{color:T.textMid}}>{o.id}</span>
                      <span style={{color:T.amber}}>{d.currentStage.replace("_"," ").toUpperCase()}</span>
                    </div>
                  );
                })}
              </div>
            )}
            {/* Certificate register */}
            <div style={{...css.card}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:12}}>TPI Certificate Register</div>
              {allDprs.flatMap(d=>(d.tpiRecords||[]).filter(r=>r.certNo).map(r=>({...r,drawingNo:d.drawingNo,orderId:d.orderId}))).length===0&&<div style={{color:T.textLow,fontSize:12}}>No certificates recorded yet.</div>}
              {allDprs.flatMap(d=>(d.tpiRecords||[]).filter(r=>r.certNo).map(r=>({...r,drawingNo:d.drawingNo,orderId:d.orderId}))).map((r,i)=>(
                <div key={i} style={{display:"grid",gridTemplateColumns:"140px 80px 120px 1fr 80px",gap:8,alignItems:"center",padding:"6px 0",borderBottom:`1px solid ${T.border}`,fontSize:11}}>
                  <span style={{fontFamily:T.fontMono,color:T.accent}}>{r.drawingNo}</span>
                  <span style={{color:T.textMid}}>{r.holdPoint}</span>
                  <span style={{fontFamily:T.fontMono,fontWeight:700}}>{r.certNo}</span>
                  <span style={{color:T.textMid}}>{r.inspector||"—"}</span>
                  <Badge color={r.outcome==="pass"?"green":r.outcome==="fail"?"red":"amber"}>{r.outcome}</Badge>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  // ── Store Admin Dashboard ───────────────────────────────────────────────────
  const StoreAdminDashboard = () => {
    const [sTab, setSTab] = useState("stock");
    const allStock = stock||[];
    const allIssueReqs = issueRequests||[];

    // Stock summary
    const available = allStock.filter(s=>s.status==="available");
    const allocated = allStock.filter(s=>s.status==="allocated");
    const issued    = allStock.filter(s=>s.status==="issued");
    const offcuts   = allStock.filter(s=>s.isOffcut);

    const availWt  = available.reduce((s,l)=>{const wt=l.sheetWt||0; return s+wt/1000;},0);
    const allocWt  = allocated.reduce((s,l)=>{const wt=l.sheetWt||0; return s+wt/1000;},0);
    const issuedWt = issued.reduce((s,l)=>{const wt=l.sheetWt||0; return s+wt/1000;},0);

    // Stock by matCode
    const byMat = {};
    allStock.forEach(lot=>{
      const mc=lot.matCode||`${lot.sectionType||""}/${lot.matType||""}/${lot.grade||""}`;
      if(!byMat[mc]) byMat[mc]={avail:0,alloc:0,issued:0,lots:0};
      const wt=(lot.sheetWt||0)/1000;
      byMat[mc].lots++;
      if(lot.status==="available") byMat[mc].avail+=wt;
      else if(lot.status==="allocated") byMat[mc].alloc+=wt;
      else if(lot.status==="issued") byMat[mc].issued+=wt;
    });

    // Pending issue requests
    const pendingIssues = allIssueReqs.filter(r=>r.status==="pending"||r.status==="approved");
    const pendingGRNs   = (pos||[]).filter(p=>p.grns?.length>0&&p.lines?.some(l=>(l.rmQcStatus||"pending")==="pending")).length;

    return (
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div>
            <div style={{fontSize:18,fontWeight:800,color:T.text}}>Store Dashboard — {user.name}</div>
            <div style={{fontSize:12,color:T.textMid}}>{allStock.length} lots · {pendingIssues.length} issue requests pending</div>
          </div>
          <button onClick={()=>setMod("stock")} style={css.btn.primary}>→ Open Stock Module</button>
        </div>

        {/* Stat bar */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
          {[["Available",`${availWt.toFixed(1)}T`,T.green],["Allocated",`${allocWt.toFixed(1)}T`,T.amber],["Issued",`${issuedWt.toFixed(1)}T`,T.accent],["Issue Requests",pendingIssues.length,pendingIssues.length>0?T.red:T.green]].map(([lbl,val,col])=>(
            <div key={lbl} style={{background:T.bgInput,borderRadius:8,padding:"12px 16px"}}>
              <div style={{fontSize:10,color:T.textMid,fontWeight:700,textTransform:"uppercase",marginBottom:2}}>{lbl}</div>
              <div style={{fontSize:20,fontWeight:800,color:col}}>{val}</div>
            </div>
          ))}
        </div>

        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
          {[["stock","Stock Position"],["issues","Issue Requests"],["grn","GRN / RM QC"],["offcuts","Offcuts"]].map(([id,lbl])=>(
            <button key={id} onClick={()=>setSTab(id)} style={{padding:"10px 16px",fontSize:13,fontWeight:sTab===id?700:400,color:sTab===id?T.accent:T.textMid,background:"transparent",border:"none",borderBottom:sTab===id?`2px solid ${T.accent}`:"2px solid transparent",cursor:"pointer"}}>{lbl}</button>
          ))}
        </div>

        {/* ── STOCK POSITION ── */}
        {sTab==="stock"&&(
          <div style={{...css.card}}>
            <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:14}}>Stock by Material Code</div>
            {Object.keys(byMat).length===0&&<div style={{color:T.textLow,fontSize:12}}>No stock data.</div>}
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead><tr style={{background:T.bgInput}}>{["Material Code","Lots","Available (T)","Allocated (T)","Issued (T)","Utilisation"].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`}}>{h}</th>)}</tr></thead>
              <tbody>
                {Object.entries(byMat).map(([mc,v],i)=>{
                  const total=v.avail+v.alloc+v.issued;
                  const usedPct=total>0?Math.round((v.alloc+v.issued)/total*100):0;
                  return (
                    <tr key={mc} style={{borderBottom:`1px solid ${T.border}`,background:i%2===0?"transparent":T.bgInput}}>
                      <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{mc}</td>
                      <td style={{padding:"7px 10px",color:T.textMid}}>{v.lots}</td>
                      <td style={{padding:"7px 10px",fontWeight:600,color:T.green}}>{v.avail.toFixed(3)}</td>
                      <td style={{padding:"7px 10px",color:T.amber}}>{v.alloc.toFixed(3)}</td>
                      <td style={{padding:"7px 10px",color:T.textMid}}>{v.issued.toFixed(3)}</td>
                      <td style={{padding:"7px 10px"}}>
                        <div style={{display:"flex",alignItems:"center",gap:6}}>
                          <div style={{width:60,height:4,background:T.border,borderRadius:2,overflow:"hidden"}}><div style={{width:`${usedPct}%`,height:"100%",background:usedPct>80?T.amber:T.accent}}/></div>
                          <span style={{fontSize:10,color:T.textMid}}>{usedPct}%</span>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* ── ISSUE REQUESTS ── */}
        {sTab==="issues"&&(
          <div>
            {pendingIssues.length===0&&<div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>✓ No pending issue requests</div>}
            {pendingIssues.map(req=>(
              <div key={req.id} style={{...css.card,marginBottom:8,borderLeft:`3px solid ${T.amber}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                  <div>
                    <div style={{fontFamily:T.fontMono,fontWeight:700,color:T.accent,fontSize:12}}>{req.id}</div>
                    <div style={{fontSize:11,color:T.textMid,marginTop:2}}>{req.contractorName||"—"} · {req.drawingNo||"—"} · {req.requestedAt?.slice(0,10)||"—"}</div>
                    {(req.items||[]).slice(0,2).map((item,i)=>(
                      <div key={i} style={{fontSize:11,color:T.textLow}}>{item.matCode} · {item.qtyRequested||item.wtRequested} {item.unit||"kg"}</div>
                    ))}
                  </div>
                  <div style={{display:"flex",gap:6,alignItems:"center"}}>
                    <Badge color={req.status==="approved"?"green":"amber"}>{req.status}</Badge>
                    <button onClick={()=>setMod("stock")} style={{...css.btn.sm,fontSize:10}}>→ Issue</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ── GRN / RM QC ── */}
        {sTab==="grn"&&(
          <div>
            <div style={{...css.card,marginBottom:12,padding:"10px 14px",background:pendingGRNs>0?T.amberBg:T.bgInput}}>
              <span style={{fontSize:12,color:pendingGRNs>0?T.amber:T.green,fontWeight:700}}>{pendingGRNs>0?`⚠ ${pendingGRNs} PO(s) have GRN items pending RM QC`:"✓ All GRN items have been QC'd"}</span>
            </div>
            {allStock.filter(s=>s.rmQcStatus==="pending").slice(0,10).map(lot=>(
              <div key={lot.id} style={{...css.card,marginBottom:6,borderLeft:`3px solid ${T.amber}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div>
                    <div style={{fontFamily:T.fontMono,fontSize:12,fontWeight:700,color:T.accent}}>{lot.lotNo||lot.id}</div>
                    <div style={{fontSize:11,color:T.textMid}}>{lot.matCode} · {((lot.sheetWt||0)/1000).toFixed(3)}T · Heat: {lot.heatNo||"—"}</div>
                  </div>
                  <div style={{display:"flex",gap:6}}>
                    <Badge color="amber">RM QC Pending</Badge>
                    <button onClick={()=>setMod("qc")} style={{...css.btn.sm,fontSize:10}}>→ QC</button>
                  </div>
                </div>
              </div>
            ))}
            {allStock.filter(s=>s.rmQcStatus==="pending").length===0&&<div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>✓ No RM QC pending</div>}
          </div>
        )}

        {/* ── OFFCUTS ── */}
        {sTab==="offcuts"&&(
          <div>
            {offcuts.length===0&&<div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>No offcuts in stock.</div>}
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead><tr style={{background:T.bgInput}}>{["Lot No","Material","Dimensions","Weight","Source","Status"].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,fontWeight:700,color:T.textMid,textTransform:"uppercase",borderBottom:`1px solid ${T.border}`}}>{h}</th>)}</tr></thead>
              <tbody>
                {offcuts.map((lot,i)=>(
                  <tr key={lot.id} style={{borderBottom:`1px solid ${T.border}`,background:i%2===0?"transparent":T.bgInput}}>
                    <td style={{padding:"7px 10px",fontFamily:T.fontMono,fontSize:11,color:T.accent}}>{lot.lotNo||lot.id}</td>
                    <td style={{padding:"7px 10px",fontSize:11}}>{lot.matCode}</td>
                    <td style={{padding:"7px 10px",fontSize:11,color:T.textMid}}>{lot.sheetDim||lot.sheetLength&&`${lot.sheetLength}×${lot.sheetWidth}`||"—"}</td>
                    <td style={{padding:"7px 10px",fontFamily:T.fontMono}}>{((lot.sheetWt||0)/1000).toFixed(3)}T</td>
                    <td style={{padding:"7px 10px",fontSize:11,color:T.textMid}}>{lot.sourceRmUnitId||"—"}</td>
                    <td style={{padding:"7px 10px"}}><Badge color={lot.status==="available"?"green":lot.status==="allocated"?"amber":"gray"}>{lot.status}</Badge></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    );
  };





  const renderMod = () => {
    // Role-specific routing overrides — consumables always goes to switch
    if (mod==="consumables") return <ConsumablesModule user={user} consumables={consumables} setConsumables={setConsumables} setPurchaseReqs={setPurchaseReqs} consumableIRs={consumableIRs||[]} setConsumableIRs={setConsumableIRs} consumablePRs={consumablePRs||[]} setConsumablePRs={setConsumablePRs} consumablePOs={consumablePOs||[]} setConsumablePOs={setConsumablePOs} orders={orders||[]} notifications={notifications||[]} setNotifications={setNotifications} />;
    if (user.role==="production_admin")   return mod==="masters" ? <MastersModule user={user} clients={clients} setClients={setClients} vendors={vendors} setVendors={setVendors} contractors={contractors} setContractors={setContractors} bays={bays} setBays={setBays} materials={materials} setMaterials={setMaterials} paint={paint} setPaint={setPaint} consumables={consumables} setConsumables={setConsumables} tpiAgencies={tpiAgencies} setTpiAgencies={setTpiAgencies} approvedMakes={approvedMakes} setApprovedMakes={setApprovedMakes} company={company} setCompany={setCompany} machines={machines} setMachines={setMachines} productionStandards={productionStandards} setProductionStandards={setProductionStandards} orders={orders} setOrders={setOrders} pos={pos} setPos={setPos} stock={stock} welders={welders} setWelders={setWelders} setMod={setMod} setInstances={setInstances} releases={releases||[]} setReleases={setReleases} setNestingRuns={setNestingRuns} productionEngineers={productionEngineers} setProductionEngineers={setProductionEngineers} dprs={dprs||[]} setDprs={setDprs} nestingBatches={nestingBatches||[]} setNestingBatches={setNestingBatches} drawingInstances={drawingInstances||[]} setDrawingInstances={setDrawingInstances} outboundJobs={outboundJobs||[]} setOutboundJobs={setOutboundJobs} issueRequests={issueRequests||[]} setIssueRequests={setIssueRequests} appUsers={appUsers} setAppUsers={setAppUsers} processTypes={processTypes||DEFAULT_PROCESS_TYPES} setProcessTypes={setProcessTypes} outboundVendors={outboundVendors||[]} setOutboundVendors={setOutboundVendors} /> : <ProductionAdminFullDashboard />;
    if (user.role==="production_engineer") return <ProductionEngineerDashboard />;
    if (user.role==="purchase_admin")      return <PurchaseAdminDashboard />;
    if (user.role==="finance_admin")       return <FinanceAdminDashboard />;
    if (user.role==="qc_admin"||user.role==="qc_user") return mod==="qc_ops" ? <QcAdminScreen user={user} instances={instances} setInstances={setInstances} orders={orders} qcRules={qcRules} setQcRules={setQcRules} overrideLog={overrideLog} setOverrideLog={setOverrideLog} dprs={dprs||[]} setDprs={setDprs} contractors={contractors||[]} tpiTemplates={tpiTemplates||[]} setTpiTemplates={setTpiTemplates} ncrs={ncrs||[]} setNcrs={setNcrs} notifications={notifications||[]} setNotifications={setNotifications} correctionsLog={correctionsLog||[]} setCorrectionsLog={setCorrectionsLog} scrapQueue={scrapQueue||[]} setScrapQueue={setScrapQueue} stock={stock||[]} /> : <QcAdminDashboard />;
    if (user.role==="store_admin") {
      if (mod==="stock") return <StockModule user={user} stock={stock} setStock={setStock} orders={orders} contractors={contractors} materials={materials} setMaterials={setMaterials} issueRequests={issueRequests} setIssueRequests={setIssueRequests} correctionsLog={correctionsLog} setCorrectionsLog={setCorrectionsLog} notifications={notifications} setNotifications={setNotifications} setPurchaseReqs={setPurchaseReqs} consumables={consumables} />;
      if (mod==="purchase") return <PurchaseModule user={user} pos={pos} setPos={setPos} purchaseReqs={purchaseReqs} setPurchaseReqs={setPurchaseReqs} stock={stock} setStock={setStock} orders={orders} vendors={vendors} setVendors={setVendors} materials={materials} setMaterials={setMaterials} paint={paint} consumables={consumables} setMod={setMod} nestingBatches={nestingBatches} />;
      return <StoreAdminDashboard />;
    }
    if (user.role==="planning_admin")      return mod==="dashboard" ? <PlanningAdminDashboard /> : null;
    switch(mod) {
      case "dashboard": return <Dashboard user={user} pos={pos||[]} stock={stock||[]} purchaseReqs={purchaseReqs||[]} orders={orders||[]} dprs={dprs||[]} instances={instances||[]} nestingBatches={nestingBatches||[]} releases={releases||[]} vendors={vendors||[]} />;
      case "mrp":       return <MRPModule user={user} purchaseReqs={purchaseReqs} setPurchaseReqs={setPurchaseReqs} pos={pos} setPos={setPos} stock={stock} setStock={setStock} orders={orders} materials={materials} nestingRuns={nestingRuns} setNestingRuns={setNestingRuns} nestingBatches={nestingBatches} setNestingBatches={setNestingBatches} machines={machines} vendors={vendors} setVendors={setVendors} setMod={setMod} productionStandards={productionStandards} />;
      case "purchase":  return <PurchaseModule user={user} pos={pos} setPos={setPos} purchaseReqs={purchaseReqs} setPurchaseReqs={setPurchaseReqs} stock={stock} setStock={setStock} orders={orders} vendors={vendors} setVendors={setVendors} materials={materials} setMaterials={setMaterials} paint={paint} consumables={consumables} setMod={setMod} nestingBatches={nestingBatches} />;
      case "consumables": return <ConsumablesModule user={user} consumables={consumables} setConsumables={setConsumables} setPurchaseReqs={setPurchaseReqs} consumableIRs={consumableIRs||[]} setConsumableIRs={setConsumableIRs} consumablePRs={consumablePRs||[]} setConsumablePRs={setConsumablePRs} consumablePOs={consumablePOs||[]} setConsumablePOs={setConsumablePOs} orders={orders||[]} notifications={notifications||[]} setNotifications={setNotifications} />;
      case "qc":        return <RMQCModule user={user} stock={stock} setStock={setStock} orders={orders} />;
      case "qc_ops":    return <QcAdminScreen user={user} instances={instances} setInstances={setInstances} orders={orders} qcRules={qcRules} setQcRules={setQcRules} overrideLog={overrideLog} setOverrideLog={setOverrideLog} dprs={dprs||[]} setDprs={setDprs} contractors={contractors||[]} tpiTemplates={tpiTemplates||[]} setTpiTemplates={setTpiTemplates} ncrs={ncrs||[]} setNcrs={setNcrs} notifications={notifications||[]} setNotifications={setNotifications} correctionsLog={correctionsLog||[]} setCorrectionsLog={setCorrectionsLog} scrapQueue={scrapQueue||[]} setScrapQueue={setScrapQueue} stock={stock||[]} />;
      case "stock":     return <StockModule user={user} stock={stock} setStock={setStock} orders={orders} contractors={contractors} materials={materials} setMaterials={setMaterials} issueRequests={issueRequests} setIssueRequests={setIssueRequests} correctionsLog={correctionsLog} setCorrectionsLog={setCorrectionsLog} notifications={notifications} setNotifications={setNotifications} setPurchaseReqs={setPurchaseReqs} consumables={consumables} />;
      case "orders":    return <OrdersModule user={user} orders={orders} setOrders={setOrders} clients={clients} setClients={setClients} materials={materials} stock={stock} vendors={vendors} tpiAgencies={tpiAgencies} pos={pos} nestingBatches={nestingBatches} releases={releases} instances={instances} purchaseReqs={purchaseReqs} company={company} setCompany={setCompany} dprs={dprs||[]} drawingInstances={drawingInstances||[]} setDrawingInstances={setDrawingInstances} processTypes={processTypes||DEFAULT_PROCESS_TYPES} />;
      case "production":return <ProductionModule user={user} instances={instances} setInstances={setInstances} orders={orders} setOrders={setOrders} stock={stock} setStock={setStock} nestingRuns={nestingRuns} setNestingRuns={setNestingRuns} nestingBatches={nestingBatches} machines={machines} contractors={contractors} materials={materials} vendors={vendors} tpiAgencies={tpiAgencies} releases={releases} setReleases={setReleases} productionStandards={productionStandards} issueRequests={issueRequests} setIssueRequests={setIssueRequests} welders={welders} pos={pos} purchaseReqs={purchaseReqs} dprs={dprs||[]} setDprs={setDprs} correctionsLog={correctionsLog||[]} setCorrectionsLog={setCorrectionsLog} notifications={notifications||[]} setNotifications={setNotifications} ncrs={ncrs||[]} setNcrs={setNcrs} scrapQueue={scrapQueue||[]} setScrapQueue={setScrapQueue} drawingInstances={drawingInstances||[]} setDrawingInstances={setDrawingInstances} processTypes={processTypes||DEFAULT_PROCESS_TYPES} appUsers={appUsers||[]} />;
      case "finance":   return <Placeholder title="Finance" session="Session 5" icon="₹" desc="Milestone invoices, tranches, receipts, credit notes." />;
      case "notifications": return (
        <div>
          <div style={{fontSize:18,fontWeight:800,color:T.text,marginBottom:16}}>🔔 Notifications</div>
          {(()=>{
            const myNotifs = (notifications||[]).filter(n=>!n.readBy?.includes(user?.id)&&(n.forRoles?.includes(user?.role)||n.forUsers?.includes(user?.id)||user?.role==="super_admin")).reverse();
            const dismissAll = () => setNotifications(prev=>prev.map(n=>({...n,readBy:[...(n.readBy||[]),user?.id]})));
            const dismiss = (id) => setNotifications(prev=>prev.map(n=>n.id!==id?n:{...n,readBy:[...(n.readBy||[]),user?.id]}));
            if (myNotifs.length===0) return <div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>No unread notifications</div>;
            return (<>
              <div style={{display:"flex",justifyContent:"flex-end",marginBottom:8}}>
                <button onClick={dismissAll} style={{...css.btn.ghost,fontSize:11}}>Dismiss all</button>
              </div>
              {myNotifs.map(n=>(
                <div key={n.id} style={{...css.card,marginBottom:8,borderLeft:`3px solid ${n.type==="ncr"?T.red:n.type==="scrap_queue"?T.amber:n.type==="correction"?T.accent:T.textMid}`}}>
                  <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
                    <div style={{flex:1}}>
                      <div style={{fontSize:12,color:T.text,marginBottom:4}}>{n.message}</div>
                      <div style={{fontSize:10,color:T.textLow}}>
                        <Badge color={n.type==="ncr"?"red":n.type==="scrap_queue"?"amber":n.type==="correction"?"blue":"gray"}>{n.type?.replace(/_/g," ")}</Badge>
                        <span style={{marginLeft:6}}>{n.raisedBy} · {n.raisedAt?.slice(0,10)}</span>
                      </div>
                    </div>
                    <button onClick={()=>dismiss(n.id)} style={{...css.btn.ghost,fontSize:10,padding:"2px 8px"}}>Dismiss</button>
                  </div>
                </div>
              ))}
            </>);
          })()}
        </div>
      );
      case "scrap_queue": return (
        <div>
          <div style={{fontSize:18,fontWeight:800,color:T.text,marginBottom:16}}>⚠ Scrap Queue — Planning Decision Required</div>
          {(scrapQueue||[]).filter(s=>s.status==="pending_decision").length===0&&<div style={{...css.card,textAlign:"center",padding:32,color:T.textLow}}>No items pending decision</div>}
          {(scrapQueue||[]).filter(s=>s.status==="pending_decision").map(sq=>(
            <div key={sq.id} style={{...css.card,marginBottom:10,borderLeft:`3px solid ${T.amber}`}}>
              <div style={{display:"flex",gap:12,alignItems:"flex-start"}}>
                <div style={{flex:1}}>
                  <div style={{fontFamily:T.fontMono,fontSize:12,fontWeight:700,color:T.accent,marginBottom:4}}>{sq.ncrNo}</div>
                  <div style={{fontSize:13,color:T.text,marginBottom:4}}>{sq.markNo} — {sq.drawingNo}</div>
                  <div style={{fontSize:11,color:T.textMid,marginBottom:4}}>{sq.description}</div>
                  <div style={{fontSize:11,color:T.textMid}}>Order: {sq.orderNo} · Raised by {sq.raisedBy} on {sq.raisedAt}</div>
                </div>
                {can(user,"mrp.raise_pr")&&(
                  <div style={{display:"flex",gap:6,flexDirection:"column"}}>
                    <button onClick={()=>setScrapQueue(prev=>prev.map(s=>s.id!==sq.id?s:{...s,status:"replacement_approved",decidedBy:user.name,decidedAt:today()}))}
                      style={{...css.btn.green,fontSize:11,padding:"4px 10px"}}>✓ Approve replacement cutting</button>
                    <button onClick={()=>setScrapQueue(prev=>prev.map(s=>s.id!==sq.id?s:{...s,status:"no_replacement",decidedBy:user.name,decidedAt:today()}))}
                      style={{...css.btn.ghost,fontSize:11,color:T.red,border:`1px solid ${T.red}`,padding:"4px 10px"}}>✕ No replacement needed</button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      );
      case "dispatch":  return <DispatchModule dprs={dprs||[]} setDprs={setDprs} orders={orders||[]} challans={challans||[]} setChallans={setChallans} user={user} />;
      case "tools":     return <ToolsModule user={user} orders={orders} materials={materials} nestingRuns={nestingRuns} setNestingRuns={setNestingRuns} correctionsLog={correctionsLog||[]} setInstances={setInstances} setReleases={setReleases} setDprs={setDprs} setNestingBatches={setNestingBatches} setDrawingInstances={setDrawingInstances} setOutboundJobs={setOutboundJobs} setIssueRequests={setIssueRequests} setOrders={setOrders} setMod={setMod} />;
      case "masters":   return <MastersModule user={user} clients={clients} setClients={setClients} vendors={vendors} setVendors={setVendors} contractors={contractors} setContractors={setContractors} bays={bays} setBays={setBays} materials={materials} setMaterials={setMaterials} paint={paint} setPaint={setPaint} consumables={consumables} setConsumables={setConsumables} tpiAgencies={tpiAgencies} setTpiAgencies={setTpiAgencies} approvedMakes={approvedMakes} setApprovedMakes={setApprovedMakes} company={company} setCompany={setCompany} machines={machines} setMachines={setMachines} productionStandards={productionStandards} setProductionStandards={setProductionStandards} orders={orders} setOrders={setOrders} pos={pos} setPos={setPos} stock={stock} welders={welders} setWelders={setWelders} setMod={setMod} setInstances={setInstances} releases={releases||[]} setReleases={setReleases} setNestingRuns={setNestingRuns} productionEngineers={productionEngineers} setProductionEngineers={setProductionEngineers} dprs={dprs||[]} setDprs={setDprs} nestingBatches={nestingBatches||[]} setNestingBatches={setNestingBatches} drawingInstances={drawingInstances||[]} setDrawingInstances={setDrawingInstances} outboundJobs={outboundJobs||[]} setOutboundJobs={setOutboundJobs} issueRequests={issueRequests||[]} setIssueRequests={setIssueRequests} appUsers={appUsers} setAppUsers={setAppUsers} processTypes={processTypes||DEFAULT_PROCESS_TYPES} setProcessTypes={setProcessTypes} outboundVendors={outboundVendors||[]} setOutboundVendors={setOutboundVendors} />;
      default:          return <Dashboard user={user} pos={pos||[]} stock={stock||[]} purchaseReqs={purchaseReqs||[]} orders={orders||[]} dprs={dprs||[]} instances={instances||[]} nestingBatches={nestingBatches||[]} releases={releases||[]} vendors={vendors||[]} />;
    }
  };

  return (
    <div style={{ display:"flex", height:"100vh", background:T.bg, fontFamily:T.font, color:T.text, fontSize:14 }}>
      <SessionMonitor onSignOut={()=>{clearSession();setUser(null);}} />
      {showPwChange&&<PasswordChangeModal user={user} appUsers={appUsers} setAppUsers={setAppUsers} onClose={()=>setShowPwChange(false)} />}
      {/* Sidebar */}
      <div style={{ width:sidebar?216:52, minWidth:sidebar?216:52, background:T.bgSidebar, borderRight:"none", display:"flex", flexDirection:"column", transition:"width 0.2s", overflow:"hidden" }}>
        <div style={{ padding:"12px 12px 10px", borderBottom:"1px solid rgba(165,243,252,0.15)", display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:30, height:30, background:"rgba(6,182,212,0.3)", borderRadius:7, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
            <span style={{ fontSize:15, fontWeight:900, color:"#fff", fontFamily:T.fontMono }}>S</span>
          </div>
          {sidebar && <div><div style={{ fontSize:13, fontWeight:800, color:"#fff" }}>STRUCTO</div><div style={{ fontSize:9, color:T.sidebarText, letterSpacing:"0.12em" }}>ERP v3.0 · S3</div></div>}
        </div>
        <nav style={{ flex:1, overflowY:"auto", padding:"4px 0" }}>
          {visibleNav.map(item=>{
            const active=mod===item.id;
            return (
              <button key={item.id} onClick={()=>setMod(item.id)} title={!sidebar?item.label:""} style={{ display:"flex", alignItems:"center", gap:8, width:"100%", padding:sidebar?"7px 12px":"7px 10px", background:active?T.bgSidebarActive:"transparent", border:"none", borderLeft:active?"2px solid #93C5FD":"2px solid transparent", color:active?T.sidebarTextActive:T.sidebarText, cursor:"pointer", fontFamily:T.font, fontSize:12, fontWeight:active?700:400, textAlign:"left" }}>
                <span style={{ fontSize:13, flexShrink:0, width:18, textAlign:"center" }}>{item.icon}</span>
                {sidebar && <span style={{flex:1}}>{item.label}</span>}
                {sidebar && item.id==="notifications" && myUnreadNotifs>0 && <span style={{background:"#EF9F27",color:"#fff",borderRadius:9,fontSize:10,fontWeight:700,padding:"1px 6px",minWidth:18,textAlign:"center"}}>{myUnreadNotifs}</span>}
                {sidebar && item.id==="scrap_queue" && pendingScrapDecisions>0 && <span style={{background:"#E24B4A",color:"#fff",borderRadius:9,fontSize:10,fontWeight:700,padding:"1px 6px",minWidth:18,textAlign:"center"}}>{pendingScrapDecisions}</span>}
              </button>
            );
          })}
        </nav>
        <div style={{ padding:8, borderTop:"1px solid rgba(165,243,252,0.15)" }}>
          <div style={{ display:"flex", alignItems:"center", gap:8 }}>
            <div style={{ width:28, height:28, borderRadius:"50%", background:"rgba(6,182,212,0.3)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:10, fontWeight:700, color:"#fff", flexShrink:0 }}>{initials}</div>
            {sidebar && <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:11, fontWeight:700, color:"#fff", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{user.name}</div>
              <div style={{ fontSize:10, color:T.sidebarText, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{roleLabel}</div>
            </div>}
          </div>
          {sidebar && <>
            <button onClick={()=>setShowPwChange(true)} style={{ background:"transparent", color:T.textMid, border:"none", cursor:"pointer", fontFamily:T.font, fontSize:11, marginTop:4, width:"100%", textAlign:"left", padding:"2px 0" }}>🔑 Change Password</button>
            <button onClick={()=>{clearSession();setUser(null);}} style={{ background:"transparent", color:"#FCA5A5", border:"none", cursor:"pointer", fontFamily:T.font, fontSize:11, marginTop:2, width:"100%", textAlign:"left", padding:"2px 0" }}>Sign Out</button>
          </>}
        </div>
      </div>

      {/* Main */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
        <div style={{ height:46, background:T.bgCard, borderBottom:`1px solid ${T.border}`, display:"flex", alignItems:"center", padding:"0 16px", gap:12, flexShrink:0 }}>
          <button onClick={()=>setSidebar(!sidebar)} style={{ background:"transparent", border:"none", color:T.textMid, cursor:"pointer", fontSize:16, padding:"4px 6px" }}>☰</button>
          <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{NAV.find(n=>n.id===mod)?.label||"Dashboard"}</div>
          <div style={{ flex:1 }} />
          {/* Notification bell */}
          {(()=>{
            const myNotifs = (notifications||[]).filter(n=>
              !n.readBy?.includes(user?.id) &&
              (n.forRoles?.includes(user?.role) || n.forUsers?.includes(user?.id) || user?.role==="super_admin")
            );
            return myNotifs.length>0?(
              <button onClick={()=>setMod("notifications")} style={{ background:"none", border:`1px solid ${T.amber}`, borderRadius:6, color:T.amber, cursor:"pointer", fontSize:12, padding:"4px 10px", display:"flex", alignItems:"center", gap:5, position:"relative" }}>
                🔔 <span style={{ fontFamily:T.fontMono, fontSize:11, fontWeight:700 }}>{myNotifs.length}</span>
              </button>
            ):null;
          })()}
          <button onClick={()=>setStockLookupOpen(true)} title="Stock Lookup (Ctrl+K / Cmd+K)" style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.textMid, cursor:"pointer", fontSize:12, padding:"4px 10px", display:"flex", alignItems:"center", gap:5 }}>
            🔍 <span style={{ fontFamily:T.fontMono, fontSize:10 }}>Ctrl+K</span>
          </button>
          <Badge color="gold">{roleLabel}</Badge>
          <div style={{ fontSize:11, color:T.textMid }}>{new Date().toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"})}</div>
        </div>
        <div style={{ flex:1, overflowY:"auto", padding:18 }}>
          {renderMod()}
        </div>
      </div>

    {/* ── STOCK LOOKUP PANEL ── */}
    {stockLookupOpen && (
      <>
        <div onClick={()=>setStockLookupOpen(false)} style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.4)", zIndex:900 }} />
        <div style={{ position:"fixed", top:0, right:0, width:520, height:"100vh", background:T.bgCard, borderLeft:`1px solid ${T.borderHi}`, zIndex:901, display:"flex", flexDirection:"column", boxShadow:"-8px 0 32px rgba(0,0,0,0.4)" }}>
          <div style={{ padding:"14px 16px", borderBottom:`1px solid ${T.border}`, display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ fontSize:14, fontWeight:700, color:T.text }}>🔍 Stock Lookup</div>
            <div style={{ flex:1 }}/>
            <span style={{ fontSize:10, color:T.textLow, fontFamily:T.fontMono }}>Esc to close</span>
            <button onClick={()=>setStockLookupOpen(false)} style={{ background:"none", border:"none", color:T.textMid, cursor:"pointer", fontSize:18, lineHeight:1 }}>×</button>
          </div>
          <div style={{ display:"flex", borderBottom:`1px solid ${T.border}` }}>
            {[["lot","By Lot No"],["material","By Material"]].map(([t,l])=>(
              <button key={t} onClick={()=>setStockLookupTab(t)} style={{ flex:1, padding:"10px 0", background:"none", border:"none", borderBottom:`2px solid ${stockLookupTab===t?T.accent:"transparent"}`, color:stockLookupTab===t?T.accent:T.textMid, fontWeight:stockLookupTab===t?700:400, cursor:"pointer", fontSize:12, fontFamily:T.font }}>{l}</button>
            ))}
          </div>
          <div style={{ flex:1, overflowY:"auto", padding:16 }}>
            {stockLookupTab==="lot" && (()=>{
              const lot = (stock||[]).find(s=>(s.lotNo||"").toUpperCase()===(lookupLotNo||"").toUpperCase().trim());
              return (
                <div>
                  <div style={{ marginBottom:12 }}>
                    <label style={{ fontSize:11, color:T.textMid, display:"block", marginBottom:4 }}>ENTER LOT NUMBER</label>
                    <input autoFocus value={lookupLotNo} onChange={e=>setLookupLotNo(e.target.value)} placeholder="e.g. A342" style={{ ...css.input, width:"100%", fontFamily:T.fontMono, fontSize:16, letterSpacing:2 }} />
                  </div>
                  {lookupLotNo && !lot && <div style={{ color:T.amber, fontSize:12, padding:"8px 0" }}>⚠ No lot found for "{lookupLotNo}"</div>}
                  {lot && (()=>{
                    const isPlate = (lot.sectionType||lot.section||"").toUpperCase()==="PLATE";
                    return (
                      <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                        <div style={{ background:T.bg, borderRadius:8, padding:12, border:`1px solid ${T.border}` }}>
                          <div style={{ fontFamily:T.fontMono, fontSize:18, fontWeight:700, color:T.accent, marginBottom:6 }}>{lot.lotNo}</div>
                          <div style={{ fontSize:13, color:T.text, marginBottom:4 }}>{lot.matCode||`${lot.sectionType} ${lot.grade} ${lot.size}`}</div>
                          {lot.sheetDim&&<div style={{ fontSize:11, color:T.textMid }}>Dimensions: <span style={{ fontFamily:T.fontMono, color:T.text }}>{lot.sheetDim}</span></div>}
                          {lot.isOffcut&&<div style={{ marginTop:4 }}><Badge color="amber">Offcut</Badge></div>}
                        </div>
                        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8 }}>
                          {[
                            {l:"Received",v:`${fmt.num(lot.wtReceived)} kg`,c:T.text},
                            {l:"Available",v:`${fmt.num(lot.wtAvailable)} kg`,c:lot.wtAvailable>0?T.green:T.textLow},
                            {l:"Consumed",v:`${fmt.num(lot.wtConsumed)} kg`,c:T.textMid},
                          ].map(({l,v,c})=>(
                            <div key={l} style={{ background:T.bg, borderRadius:6, padding:"8px 10px", border:`1px solid ${T.border}` }}>
                              <div style={{ fontSize:10, color:T.textLow, marginBottom:2 }}>{l}</div>
                              <div style={{ fontFamily:T.fontMono, fontSize:13, fontWeight:700, color:c }}>{v}</div>
                            </div>
                          ))}
                        </div>
                        <div style={{ background:T.bg, borderRadius:8, padding:12, border:`1px solid ${T.border}` }}>
                          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:6, fontSize:11 }}>
                            {[["Vendor Batch",lot.batchNo||"—"],["Heat No",lot.heatNo||"—"],["GRN",lot.grnId||"—"],["PO",lot.poId||"—"],["Bay",lot.bayId||"—"],["Received",lot.receivedDate||"—"],["RM QC",lot.rmQcStatus||"—"],["Status",lot.status||"—"]].map(([k,v])=>(
                              <div key={k}><span style={{ color:T.textLow }}>{k}: </span><span style={{ fontFamily:T.fontMono, color:T.text }}>{v}</span></div>
                            ))}
                          </div>
                        </div>
                        {(lot.allocations||[]).length>0&&(
                          <div style={{ background:T.bg, borderRadius:8, padding:12, border:`1px solid ${T.border}` }}>
                            <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:6 }}>ALLOCATIONS</div>
                            {(lot.allocations||[]).map((a,i)=>(
                              <div key={i} style={{ fontSize:11, color:T.text, padding:"2px 0", display:"flex", justifyContent:"space-between" }}>
                                <span style={{ fontFamily:T.fontMono, color:T.accent }}>{a.orderId}</span>
                                <span style={{ fontFamily:T.fontMono }}>{fmt.num(a.wt)} kg</span>
                              </div>
                            ))}
                          </div>
                        )}
                        {lot.isOffcut&&lot.parentLotId&&(()=>{
                          const parent=(stock||[]).find(s=>s.id===lot.parentLotId);
                          return parent?(<div style={{ background:T.amberBg, borderRadius:8, padding:10, border:`1px solid ${T.amber}`, fontSize:11 }}>
                            <span style={{ color:T.textMid }}>Parent lot: </span>
                            <button onClick={()=>setLookupLotNo(parent.lotNo)} style={{ background:"none", border:"none", cursor:"pointer", color:T.accent, fontFamily:T.fontMono, fontWeight:700 }}>{parent.lotNo}</button>
                            <span style={{ color:T.textMid }}> — {parent.matCode}</span>
                          </div>):null;
                        })()}
                      </div>
                    );
                  })()}
                </div>
              );
            })()}
            {stockLookupTab==="material" && (()=>{
              const sectionTypes = [...new Set((stock||[]).map(s=>s.sectionType||s.section||"").filter(Boolean))].sort();
              const grades = [...new Set((stock||[]).filter(s=>!lookupMatFilter.sectionType||(s.sectionType||s.section)===lookupMatFilter.sectionType).map(s=>s.grade||"").filter(Boolean))].sort();
              const sizes = [...new Set((stock||[]).filter(s=>(!lookupMatFilter.sectionType||(s.sectionType||s.section)===lookupMatFilter.sectionType)&&(!lookupMatFilter.grade||s.grade===lookupMatFilter.grade)).map(s=>s.size||"").filter(Boolean))].sort();
              const matched = (stock||[]).filter(s=>{
                if (s.isOffcut) return false;
                if (lookupMatFilter.sectionType && (s.sectionType||s.section)!==lookupMatFilter.sectionType) return false;
                if (lookupMatFilter.grade && s.grade!==lookupMatFilter.grade) return false;
                if (lookupMatFilter.size && s.size!==lookupMatFilter.size) return false;
                return s.status==="available"||s.status==="allocated"||s.status==="reserved";
              });
              const matchedOffcuts = (stock||[]).filter(s=>{
                if (!s.isOffcut) return false;
                if (lookupMatFilter.sectionType && (s.sectionType||s.section)!==lookupMatFilter.sectionType) return false;
                if (lookupMatFilter.grade && s.grade!==lookupMatFilter.grade) return false;
                if (lookupMatFilter.size && s.size!==lookupMatFilter.size) return false;
                return s.status!=="consumed"&&s.status!=="written_off"&&s.status!=="rejected";
              });
              return (
                <div>
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8, marginBottom:14 }}>
                    <Field label="Section Type"><Sel value={lookupMatFilter.sectionType} onChange={e=>setLookupMatFilter(f=>({...f,sectionType:e.target.value,grade:"",size:""}))}>
                      <option value="">All</option>{sectionTypes.map(s=><option key={s}>{s}</option>)}
                    </Sel></Field>
                    <Field label="Grade"><Sel value={lookupMatFilter.grade} onChange={e=>setLookupMatFilter(f=>({...f,grade:e.target.value,size:""}))}>
                      <option value="">All</option>{grades.map(g=><option key={g}>{g}</option>)}
                    </Sel></Field>
                    <Field label="Size"><Sel value={lookupMatFilter.size} onChange={e=>setLookupMatFilter(f=>({...f,size:e.target.value}))}>
                      <option value="">All</option>{sizes.map(s=><option key={s}>{s}</option>)}
                    </Sel></Field>
                  </div>
                  <div style={{ fontSize:11, fontWeight:700, color:T.textMid, marginBottom:6 }}>REGULAR LOTS ({matched.length})</div>
                  {matched.length===0?<div style={{ fontSize:11, color:T.textLow, marginBottom:16 }}>No available lots match the filter</div>:(
                    <div style={{ display:"flex", flexDirection:"column", gap:6, marginBottom:16 }}>
                      {matched.map(s=>(
                        <div key={s.id} onClick={()=>{ setLookupLotNo(s.lotNo); setStockLookupTab("lot"); }} style={{ background:T.bg, borderRadius:6, padding:"8px 12px", border:`1px solid ${T.border}`, cursor:"pointer", display:"flex", alignItems:"center", gap:10 }}>
                          <div style={{ flex:1 }}>
                            <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                              <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.accent }}>{s.lotNo}</span>
                              <Badge color={s.status==="available"?"green":s.status==="allocated"?"blue":"amber"}>{s.status}</Badge>
                            </div>
                            <div style={{ fontSize:11, color:T.textMid, marginTop:2 }}>{s.matCode||`${s.sectionType} ${s.grade} ${s.size}`}{s.sheetDim?` · ${s.sheetDim}`:""}</div>
                          </div>
                          <div style={{ textAlign:"right" }}>
                            <div style={{ fontFamily:T.fontMono, fontSize:12, fontWeight:700, color:T.green }}>{fmt.num(s.wtAvailable)} kg</div>
                            <div style={{ fontSize:10, color:T.textLow }}>{s.bayId||"—"}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                  <div style={{ fontSize:11, fontWeight:700, color:T.amber, marginBottom:6, paddingTop:8, borderTop:`1px solid ${T.border}` }}>OFFCUTS ({matchedOffcuts.length})</div>
                  {matchedOffcuts.length===0?<div style={{ fontSize:11, color:T.textLow }}>No offcuts match the filter</div>:(
                    <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                      {matchedOffcuts.map(s=>(
                        <div key={s.id} onClick={()=>{ setLookupLotNo(s.lotNo); setStockLookupTab("lot"); }} style={{ background:T.amberBg, borderRadius:6, padding:"8px 12px", border:`1px solid ${T.amber}`, cursor:"pointer", display:"flex", alignItems:"center", gap:10 }}>
                          <div style={{ flex:1 }}>
                            <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                              <span style={{ fontFamily:T.fontMono, fontWeight:700, color:T.amber }}>{s.lotNo}</span>
                              <Badge color="amber">Offcut</Badge>
                              <Badge color={s.status==="available"?"green":"amber"}>{s.status}</Badge>
                            </div>
                            <div style={{ fontSize:11, color:T.textMid, marginTop:2 }}>{s.offcutDimensions||s.sheetDim||"—"} · from {s.parentLotId||"—"}</div>
                          </div>
                          <div style={{ textAlign:"right" }}>
                            <div style={{ fontFamily:T.fontMono, fontSize:12, fontWeight:700, color:T.amber }}>{fmt.num(s.wtAvailable)} kg</div>
                            <div style={{ fontSize:10, color:T.textLow }}>{s.bayId||"—"}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })()}
          </div>
        </div>
      </>
    )}
    </div>
  );
}
